# ── QtWebEngine accessibility crash workaround ────────────────────────────
# On macOS + Qt6, Chromium's accessibility subsystem calls
# QAccessible::uniqueId(QAccessibleInterface*) with a null pointer whenever
# the accessibility tree is updated during navigation. This is a known Qt bug
# (crashes at frame 0 in the main thread).
# Setting --disable-blink-features=AccessibilityObjectModel prevents Chromium
# from sending those null-interface notifications to Qt.
# MUST be set before QApplication is constructed — it has no effect afterward.
_existing_flags = os.environ.get('QTWEBENGINE_CHROMIUM_FLAGS', '')
# --disable-blink-features=AccessibilityObjectModel  : disables the Blink
#   accessibility object model so Chromium never builds a11y nodes.
# --disable-renderer-accessibility                   : disables the renderer-side
#   accessibility bridge entirely (stronger guard against the QAccessible
#   null-ptr crash when navigating on macOS + Qt6).
_a11y_flags = (
    '--disable-blink-features=AccessibilityObjectModel '
    '--disable-renderer-accessibility'
)
for _f in _a11y_flags.split():
    if _f not in _existing_flags:
        _existing_flags = (_existing_flags + ' ' + _f).strip()
os.environ['QTWEBENGINE_CHROMIUM_FLAGS'] = _existing_flags
