def set_dock_icon_visible(visible: bool, activate: bool = False) -> bool:
    if NSApp is None:
        logging.warning("PyObjC AppKit is unavailable; cannot change Dock icon visibility.")
        return False
    try:
        NSApp.setActivationPolicy_(0 if visible else 1)
        if visible and activate:
            NSApp.activateIgnoringOtherApps_(True)
        return True
    except Exception:
        logging.exception("Failed to change Dock icon visibility.")
        return False


