if NSObject is not None and objc is not None:
    class ThemeObserver(NSObject):
        def initWithApp_(self, app_obj):
            self = objc.super(ThemeObserver, self).init()
            self.app = app_obj
            return self

        def themeChanged_(self, notification):
            apply_theme(self.app)
else:
    class ThemeObserver:
        pass


def install_theme_observer(app_obj):
    if NSDistributedNotificationCenter is None or NSSelectorFromString is None or NSObject is None or objc is None:
        return None
    try:
        observer = ThemeObserver.alloc().initWithApp_(app_obj)
        center = NSDistributedNotificationCenter.defaultCenter()
        center.addObserver_selector_name_object_(
            observer,
            NSSelectorFromString("themeChanged:"),
            "AppleInterfaceThemeChangedNotification",
            None
        )
        return observer
    except Exception:
        return None


class MacNormalButton(QPushButton):
    def __init__(self, text, parent=None, always_dark=False):
        super().__init__(text, parent)
        self.setAutoDefault(False)
        self.setFixedHeight(22)
        self._always_dark = bool(always_dark)
        self._alert = False
        self._updating_style = False
        self.update_theme()

    def update_theme(self):
        if self._updating_style:
            return
        self._updating_style = True
        try:
            if self._alert:
                bg = "#FF4D4D"
                bg_hover = "#FF6666"
                bg_pressed = "#CC3D3D"
                bg_disabled = "#E6E6E6"
                text = "#FFFFFF"
                text_disabled = "#777777"
            else:
                dark = self._always_dark or bool(getattr(self, '_force_dark', False)) or is_dark_theme(app)
                if dark:
                    bg = "#404145"
                    bg_hover = "#4A4B4F"
                    bg_pressed = "#343538"
                    bg_disabled = "#2F3033"
                    text = "#FFFFFF"
                    text_disabled = "#777777"
                else:
                    bg = "#E7E7E7"
                    bg_hover = "#EEEEEE"
                    bg_pressed = "#DCDCDC"
                    bg_disabled = "#E1E1E1"
                    text = "#111111"
                    text_disabled = "#777777"
            self.setStyleSheet(f"""
                QPushButton {{
                    border: 1px solid transparent;
                    background-color: {bg};
                    border-radius: 6px;
                    padding: 1px 8px;
                    color: {text};
                }}
                QPushButton:hover {{
                    background-color: {bg_hover};
                }}
                QPushButton:pressed {{
                    background-color: {bg_pressed};
                }}
                QPushButton:disabled {{
                    background-color: {bg_disabled};
                    color: {text_disabled};
                }}
            """)
        finally:
            self._updating_style = False

    def changeEvent(self, event):
        super().changeEvent(event)
        if self._updating_style:
            return
        if event.type() in (
            QEvent.Type.PaletteChange,
            QEvent.Type.ApplicationPaletteChange,
        ):
            self.update_theme()

    def set_alert(self, enabled):
        enabled = bool(enabled)
        if self._alert == enabled:
            return
        self._alert = enabled
        self.update_theme()


