class BroccoliMessageDialog(QDialog):
    def __init__(self,
                 title: str,
                 message: str,
                 button_text: str = 'OK',
                 parent=None,
                 buttons: list[str] | None = None,
                 default_button_text: str | None = None,
                 size: QSize | None = None):
        super().__init__(parent)
        self._theme_updating = False
        self._panel_margin = 16
        self._panel_radius = 20
        self.selected_button = ''
        self.setModal(True)
        self.setWindowFlags(Qt.WindowType.Dialog | Qt.WindowType.FramelessWindowHint)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        dialog_size = size if isinstance(size, QSize) else QSize(420, 178)
        self.setFixedSize(dialog_size)

        root_layout = QVBoxLayout(self)
        root_layout.setContentsMargins(34, 30, 34, 30)
        root_layout.setSpacing(10)

        self.title_lbl = QLabel(str(title or ''), self)
        self.message_lbl = QLabel(str(message or ''), self)
        self.message_lbl.setWordWrap(True)
        self.message_lbl.setAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignTop)

        root_layout.addWidget(self.title_lbl)
        root_layout.addWidget(self.message_lbl, 1)

        button_row = QHBoxLayout()
        button_row.setContentsMargins(0, 8, 0, 0)
        button_row.setSpacing(6)
        button_row.addStretch()
        labels = [str(item) for item in (buttons or [button_text]) if str(item).strip()]
        if not labels:
            labels = ['OK']
        self._dialog_buttons = []
        default_label = str(default_button_text or labels[0])
        for label in labels:
            button = MacNormalButton(label, self)
            button.setFixedWidth(max(84, button.sizeHint().width()))
            button.clicked.connect(lambda _checked=False, chosen=label: self._choose_button(chosen))
            if label == default_label:
                self.setFocusProxy(button)
                button.setFocus()
            self._dialog_buttons.append(button)
            button_row.addWidget(button)
        root_layout.addLayout(button_row)

        self._apply_theme()

    def _choose_button(self, label: str):
        self.selected_button = str(label or '')
        self.accept()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        dark = is_dark_theme(app)
        panel_rect = QRectF(
            self._panel_margin,
            self._panel_margin,
            self.width() - self._panel_margin * 2,
            self.height() - self._panel_margin * 2,
        )
        bg_path = QPainterPath()
        bg_path.addRoundedRect(panel_rect, self._panel_radius, self._panel_radius)
        painter.fillPath(bg_path, QColor('#2D2D2D' if dark else '#FFFFFF'))
        painter.setPen(QPen(QColor('#3A3A3A' if dark else '#ECECEC'), 1))
        painter.drawPath(bg_path)
        painter.end()

    def _apply_theme(self):
        if self._theme_updating:
            return
        self._theme_updating = True
        dark = is_dark_theme(app)
        try:
            self.title_lbl.setStyleSheet(
                f'font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; '
                f'font-size: 14px; font-weight: 600; color: {"#F2F2F7" if dark else "#20242B"};'
            )
            self.message_lbl.setStyleSheet(
                f'font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; '
                f'font-size: 13px; color: {"#C6CBD4" if dark else "#4A4F58"};'
            )
            for button in getattr(self, '_dialog_buttons', []):
                button.update_theme()
            self.update()
        finally:
            self._theme_updating = False

    def changeEvent(self, event):
        super().changeEvent(event)
        if self._theme_updating:
            return
        if event.type() in (QEvent.Type.PaletteChange, QEvent.Type.ApplicationPaletteChange):
            self._apply_theme()


def _center_broccoli_dialog(dialog: QDialog, parent=None):
    dialog.adjustSize()
    parent_widget = parent if isinstance(parent, QWidget) else QApplication.activeWindow()
    parent_geometry = parent_widget.frameGeometry() if parent_widget is not None else QApplication.primaryScreen().availableGeometry()
    dialog_geometry = dialog.frameGeometry()
    dialog_geometry.moveCenter(parent_geometry.center())
    dialog.move(dialog_geometry.topLeft())


def show_broccoli_message(parent, title: str, message: str, button_text: str = 'OK'):
    dialog = BroccoliMessageDialog(title, message, button_text, parent)
    _center_broccoli_dialog(dialog, parent)
    dialog.exec()
    return dialog.selected_button or button_text


def ask_broccoli_message(parent,
                         title: str,
                         message: str,
                         buttons: list[str],
                         default_button_text: str | None = None,
                         size: QSize | None = None) -> str:
    dialog = BroccoliMessageDialog(
        title,
        message,
        parent=parent,
        buttons=buttons,
        default_button_text=default_button_text,
        size=size,
    )
    _center_broccoli_dialog(dialog, parent)
    dialog.exec()
    return dialog.selected_button or (default_button_text or (buttons[0] if buttons else ''))


class MacWindowButton(QPushButton):
    def __init__(self, color, symbol, parent=None):
        super().__init__(parent)
        self.setFixedSize(16, 16)
        self.base_color = QColor(color)
        self.symbol = symbol
        self.hovered = False
        self.setStyleSheet('border: none; background: transparent;')

    def enterEvent(self, event):
        self.hovered = True
        self.update()
        super().enterEvent(event)

    def leaveEvent(self, event):
        self.hovered = False
        self.update()
        super().leaveEvent(event)

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        painter.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform)
        painter.setBrush(self.base_color)
        painter.setPen(Qt.PenStyle.NoPen)
        painter.drawEllipse(0, 0, self.width(), self.height())
        if self.hovered:
            pen = QPen(QColor('black'))
            pen.setWidth(2)
            painter.setPen(pen)
            margin = 5
            if self.symbol == 'x':
                painter.drawLine(margin, margin, self.width() - margin, self.height() - margin)
                painter.drawLine(self.width() - margin, margin, margin, self.height() - margin)
            elif self.symbol == '-':
                painter.drawLine(margin, self.height() // 2, self.width() - margin, self.height() // 2)
            elif self.symbol == '+':
                painter.drawLine(self.width() // 2, margin, self.width() // 2, self.height() - margin)
                painter.drawLine(margin, self.height() // 2, self.width() - margin, self.height() // 2)


class WebFetchWatchEventBridge(QObject):
    file_detected = pyqtSignal(str)


class _WebFetchWatchdogHandler(FileSystemEventHandler):
    def __init__(self, bridge):
        super().__init__()
        self._bridge = bridge

    def _emit_if_candidate(self, path: str):
        if not path:
            return
        name = os.path.basename(path)
        if is_matching_webfetch_filename(name):
            self._bridge.file_detected.emit(path)

    def on_created(self, event):
        if not getattr(event, 'is_directory', False):
            self._emit_if_candidate(getattr(event, 'src_path', ''))

    def on_moved(self, event):
        if not getattr(event, 'is_directory', False):
            self._emit_if_candidate(getattr(event, 'dest_path', '') or getattr(event, 'src_path', ''))


class WebFetchWatchManager(QObject):
    file_imported = pyqtSignal(dict)
    status_changed = pyqtSignal(str)

    def __init__(self, parent=None):
        super().__init__(parent)
        self._observer = None
        self._watch_dir = ''
        self._bridge = WebFetchWatchEventBridge()
        self._bridge.file_detected.connect(self._on_file_detected)

    @property
    def available(self) -> bool:
        return WATCHDOG_AVAILABLE

    @property
    def watch_dir(self) -> str:
        return self._watch_dir

    def stop(self):
        observer = self._observer
        self._observer = None
        self._watch_dir = ''
        if observer is not None:
            try:
                observer.stop()
                observer.join(timeout=2)
            except Exception:
                pass

    def start(self, folder: str):
        folder = str(folder or '').strip()
        if not self.available:
            self.status_changed.emit('watchdog is unavailable.')
            self.stop()
            return
        if not folder or not os.path.isdir(folder):
            self.stop()
            self.status_changed.emit('WebFetch download folder is not set.')
            return
        if self._observer is not None and self._watch_dir == folder:
            return
        self.stop()
        observer = Observer()
        handler = _WebFetchWatchdogHandler(self._bridge)
        observer.schedule(handler, folder, recursive=False)
        observer.daemon = True
        observer.start()
        self._observer = observer
        self._watch_dir = folder
        self.status_changed.emit(f'Watching {folder}')

    def _on_file_detected(self, path: str):
        QTimer.singleShot(400, lambda p=path: self._process_candidate(p, 0))

    def _process_candidate(self, path: str, attempt: int):
        if not path or not os.path.exists(path):
            return
        record = import_webfetch_file_to_inbox(path)
        if record is not None:
            self.file_imported.emit(record)
            return
        if attempt < 8:
            QTimer.singleShot(300, lambda p=path, a=attempt + 1: self._process_candidate(p, a))


