class DropdownPopup(QWidget):
    item_selected = pyqtSignal(int)

    def __init__(self, parent_button):
        super().__init__(None)
        self.parent_button = parent_button
        self.items = []
        self.current_index = -1
        self.hovered_index = -1
        self.item_height = 28
        self.padding = 6
        self.scroll_offset = 0
        self.setWindowFlags(Qt.WindowType.Popup | Qt.WindowType.FramelessWindowHint | Qt.WindowType.NoDropShadowWindowHint)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        self.setFocusPolicy(Qt.FocusPolicy.StrongFocus)
        self.setMouseTracking(True)

    def set_items(self, items):
        self.items = list(items)
        self.scroll_offset = 0
        self.hovered_index = -1
        self._update_size()

    def set_current_index(self, index):
        if 0 <= index < len(self.items):
            self.current_index = index
            self._ensure_index_visible(index)
        else:
            self.current_index = -1
        self.update()

    def _visible_item_capacity(self) -> int:
        return max(1, (self.height() - self.padding * 2) // self.item_height)

    def _max_scroll_offset(self) -> int:
        return max(0, len(self.items) - self._visible_item_capacity())

    def _clamp_scroll_offset(self):
        self.scroll_offset = max(0, min(self.scroll_offset, self._max_scroll_offset()))

    def _ensure_index_visible(self, index: int):
        if not (0 <= index < len(self.items)):
            return
        visible_count = self._visible_item_capacity()
        if index < self.scroll_offset:
            self.scroll_offset = index
        elif index >= self.scroll_offset + visible_count:
            self.scroll_offset = index - visible_count + 1
        self._clamp_scroll_offset()

    def _index_at_y(self, y_pos: float) -> int:
        local_y = y_pos - self.padding
        if local_y < 0:
            return -1
        row = int(local_y // self.item_height)
        index = self.scroll_offset + row
        visible_limit = min(len(self.items), self.scroll_offset + self._visible_item_capacity())
        if index >= visible_limit:
            return -1
        return index

    def _scroll_by(self, steps: int) -> bool:
        if not self.items or steps == 0:
            return False
        previous = self.scroll_offset
        self.scroll_offset = max(0, min(self.scroll_offset + steps, self._max_scroll_offset()))
        return self.scroll_offset != previous

    def _update_size(self):
        if not self.items:
            return
        fm = self.fontMetrics()
        max_width = self.parent_button.width() if getattr(self.parent_button, '_popup_min_width_to_button', True) else 0
        for item in self.items:
            text_width = fm.horizontalAdvance(str(item)) + 24
            max_width = max(max_width, text_width)
        height = len(self.items) * self.item_height + self.padding * 2
        max_height = 400
        if height > max_height:
            height = max_height
        self.setFixedSize(max_width, height)
        self._clamp_scroll_offset()

    def show_above_button(self):
        if not self.items:
            return
        self._update_size()
        no_focus = bool(getattr(self.parent_button, '_popup_no_focus', False))
        self.setAttribute(Qt.WidgetAttribute.WA_ShowWithoutActivating, no_focus)
        self.setWindowFlag(Qt.WindowType.WindowDoesNotAcceptFocus, no_focus)
        self.setFocusPolicy(Qt.FocusPolicy.NoFocus if no_focus else Qt.FocusPolicy.StrongFocus)
        btn_pos = self.parent_button.mapToGlobal(self.parent_button.rect().topLeft())
        self.move(btn_pos.x(), btn_pos.y() - self.height() - 2)
        self.show()
        if not no_focus:
            self.activateWindow()
            self.setFocus(Qt.FocusReason.PopupFocusReason)
        app.installEventFilter(self)

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        dark = (
            bool(getattr(self.parent_button, '_always_dark', False))
            or bool(getattr(self.parent_button, '_force_dark', False))
            or is_dark_theme(app)
        )
        bg_color = QColor(45, 45, 48, 245) if dark else QColor(255, 255, 255, 248)
        border_color = QColor(70, 70, 75) if dark else QColor(232, 232, 232)
        hover_color = QColor(80, 80, 85) if dark else QColor(245, 245, 245)
        select_color = QColor(0, 122, 255, 100) if dark else QColor(17, 17, 17, 18)
        text_color = QColor(240, 240, 240) if dark else QColor(32, 36, 43)

        bg_path = QPainterPath()
        bg_path.addRoundedRect(QRectF(0, 0, self.width(), self.height()), 8, 8)
        painter.fillPath(bg_path, bg_color)
        painter.setPen(QPen(border_color, 1))
        painter.drawPath(bg_path)

        y = self.padding
        visible_count = self._visible_item_capacity()
        start_index = self.scroll_offset
        end_index = min(len(self.items), start_index + visible_count)
        for i in range(start_index, end_index):
            item = self.items[i]
            item_rect = QRectF(self.padding, y, self.width() - self.padding * 2, self.item_height)
            if i == self.hovered_index:
                hover_path = QPainterPath()
                hover_path.addRoundedRect(item_rect, 4, 4)
                painter.fillPath(hover_path, hover_color)
            elif i == self.current_index:
                select_path = QPainterPath()
                select_path.addRoundedRect(item_rect, 4, 4)
                painter.fillPath(select_path, select_color)
            painter.setPen(text_color)
            text_rect = item_rect.adjusted(8, 0, -8, 0)
            painter.drawText(text_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, str(item))
            y += self.item_height
            if y > self.height() - self.padding:
                break

    def mouseMoveEvent(self, event):
        index = self._index_at_y(event.position().y())
        if 0 <= index < len(self.items):
            if self.hovered_index != index:
                self.hovered_index = index
                self.update()
        elif self.hovered_index != -1:
            self.hovered_index = -1
            self.update()

    def mousePressEvent(self, event):
        if event.button() == Qt.MouseButton.LeftButton:
            index = self._index_at_y(event.position().y())
            if 0 <= index < len(self.items):
                self.current_index = index
                self.item_selected.emit(index)
                self.hide()

    def wheelEvent(self, event):
        delta = event.angleDelta().y()
        if delta == 0:
            event.ignore()
            return
        steps = max(1, abs(delta) // 120)
        direction = -steps if delta > 0 else steps
        if self._scroll_by(direction):
            self.update()
            event.accept()
            return
        event.ignore()

    def leaveEvent(self, event):
        self.hovered_index = -1
        self.update()

    def focusOutEvent(self, event):
        if not bool(getattr(self.parent_button, '_popup_no_focus', False)):
            self.hide()

    def hideEvent(self, event):
        try:
            app.removeEventFilter(self)
        except Exception:
            pass
        super().hideEvent(event)

    def eventFilter(self, obj, event):
        if self.isVisible() and event.type() == QEvent.Type.MouseButtonPress:
            try:
                global_pos = event.globalPosition().toPoint()
            except Exception:
                try:
                    global_pos = event.globalPos()
                except Exception:
                    global_pos = None
            if global_pos is not None:
                popup_rect = QRect(self.mapToGlobal(QPoint(0, 0)), self.size())
                button_rect = QRect(self.parent_button.mapToGlobal(QPoint(0, 0)), self.parent_button.size())
                if not popup_rect.contains(global_pos) and not button_rect.contains(global_pos):
                    self.hide()
        return super().eventFilter(obj, event)


class DropdownButton(QPushButton):
    currentIndexChanged = pyqtSignal(int)

    def __init__(self, parent=None, always_dark=False, compact_light=False):
        super().__init__(parent)
        self.setAutoDefault(False)
        self._items = []
        self._item_data = []
        self._current_index = -1
        self._always_dark = bool(always_dark)
        self._compact_light = bool(compact_light)
        self._enabled = True
        self._signals_blocked = False
        self._updating_style = False
        self._placeholder = ''
        self._popup_min_width_to_button = True
        self._popup = DropdownPopup(self)
        self._popup.item_selected.connect(self._on_item_selected)
        self.clicked.connect(self._show_popup)
        self.setFixedHeight(22 if (always_dark or compact_light) else 30)
        self._update_style()

    def _update_style(self):
        if self._updating_style:
            return
        self._updating_style = True
        dark = self._always_dark or bool(getattr(self, '_force_dark', False)) or is_dark_theme(app)
        try:
            if self._enabled:
                if dark:
                    bg = "#404145"
                    bg_hover = "#4A4B4F"
                    bg_pressed = "#343538"
                    text = "#FFFFFF"
                    if self._compact_light:
                        radius = 6
                        padding = "1px 8px"
                    else:
                        radius = 15
                        padding = "5px 20px"
                else:
                    if self._compact_light:
                        bg = "#E7E7E7"
                        bg_hover = "#EEEEEE"
                        bg_pressed = "#DCDCDC"
                        text = "#111111"
                        radius = 6
                        padding = "1px 8px"
                    else:
                        bg = "#FFFFFF"
                        bg_hover = "#F5F5F5"
                        bg_pressed = "#ECECEC"
                        text = "#444444"
                        radius = 15
                        padding = "5px 20px"
            else:
                if dark:
                    bg = "#2F3033"
                    bg_hover = "#2F3033"
                    bg_pressed = "#2F3033"
                    text = "#777777"
                    if self._compact_light:
                        radius = 6
                        padding = "1px 8px"
                    else:
                        radius = 15
                        padding = "5px 20px"
                else:
                    if self._compact_light:
                        bg = "#E1E1E1"
                        bg_hover = "#E1E1E1"
                        bg_pressed = "#E1E1E1"
                        text = "#777777"
                        radius = 6
                        padding = "1px 8px"
                    else:
                        bg = "#F2F2F2"
                        bg_hover = "#F2F2F2"
                        bg_pressed = "#F2F2F2"
                        text = "#9A9A9A"
                        radius = 15
                        padding = "5px 20px"

            self.setStyleSheet(f"""
                QPushButton {{
                    border: 1px solid transparent;
                    background-color: {bg};
                    border-radius: {radius}px;
                    padding: {padding};
                    color: {text};
                    text-align: left;
                }}
                QPushButton:hover {{
                    background-color: {bg_hover};
                }}
                QPushButton:pressed {{
                    background-color: {bg_pressed};
                }}
                QPushButton::menu-indicator {{
                    width: 0px;
                }}
            """)
        finally:
            self._updating_style = False

    def changeEvent(self, event):
        super().changeEvent(event)
        if self._updating_style:
            return
        if event.type() in (
            QEvent.Type.PaletteChange,
            QEvent.Type.ApplicationPaletteChange,
        ):
            self._update_style()
            if self._popup.isVisible():
                self._popup.update()

    def _show_popup(self):
        if not self._enabled or not self._items:
            return
        if self._popup.isVisible():
            self._popup.hide()
            return
        self._popup.set_items(self._items)
        self._popup.set_current_index(self._current_index)
        self._popup.show_above_button()

    def _on_item_selected(self, index):
        if index != self._current_index:
            self._current_index = index
            self._update_text()
            if not self._signals_blocked:
                self.currentIndexChanged.emit(index)

    def _update_text(self):
        if 0 <= self._current_index < len(self._items):
            full_text = str(self._items[self._current_index])
            fm = self.fontMetrics()
            available_width = max(24, self.width() - 20)
            self.setText(fm.elidedText(full_text, Qt.TextElideMode.ElideRight, available_width))
        else:
            self.setText(self._placeholder)

    def resizeEvent(self, event):
        super().resizeEvent(event)
        self._update_text()

    def showEvent(self, event):
        super().showEvent(event)
        self._update_text()

    def addItem(self, text, data=None):
        self._items.append(text)
        self._item_data.append(data)
        if self._current_index == -1:
            self.setCurrentIndex(0)

    def addItems(self, texts):
        for text in texts:
            self._items.append(text)
            self._item_data.append(None)
        if self._current_index == -1 and self._items:
            self.setCurrentIndex(0)

    def clear(self):
        self._items = []
        self._item_data = []
        self._current_index = -1
        self._update_text()

    def count(self):
        return len(self._items)

    def currentIndex(self):
        return self._current_index

    def setCurrentIndex(self, index):
        if 0 <= index < len(self._items):
            old_index = self._current_index
            self._current_index = index
            self._update_text()
            if old_index != index and not self._signals_blocked:
                self.currentIndexChanged.emit(index)
        elif index == -1 or not self._items:
            self._current_index = -1
            self._update_text()

    def currentText(self):
        if 0 <= self._current_index < len(self._items):
            return str(self._items[self._current_index])
        return ''

    def itemText(self, index):
        if 0 <= index < len(self._items):
            return str(self._items[index])
        return ''

    def itemData(self, index):
        if 0 <= index < len(self._item_data):
            return self._item_data[index]
        return None

    def setItemData(self, index, data):
        if 0 <= index < len(self._item_data):
            self._item_data[index] = data

    def currentData(self):
        return self.itemData(self._current_index)

    def findData(self, data):
        for index, item_data in enumerate(self._item_data):
            if item_data == data:
                return index
        return -1

    def setEnabled(self, enabled):
        self._enabled = enabled
        super().setEnabled(enabled)
        self._update_style()

    def blockSignals(self, block):
        self._signals_blocked = block
        return super().blockSignals(block)

    def setPlaceholderText(self, text):
        self._placeholder = str(text or '')
        if self._current_index == -1:
            self._update_text()

    def setPopupMinWidthToButton(self, enabled: bool):
        self._popup_min_width_to_button = bool(enabled)


class TargetSelectorPopup(QWidget):
    """Custom popup for Active / All / multi-site target selection."""
    def __init__(self, parent_button):
        super().__init__(None)
        self.parent_button = parent_button
        self.rows = []
        self.hovered_index = -1
        self.item_height = 28
        self.padding = 6
        self.scroll_offset = 0
        self.setWindowFlags(Qt.WindowType.Popup | Qt.WindowType.FramelessWindowHint | Qt.WindowType.NoDropShadowWindowHint)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        self.setMouseTracking(True)

    def set_rows(self, rows):
        self.rows = list(rows or [])
        self.scroll_offset = 0
        self.hovered_index = -1
        self._update_size()

    def _visible_item_capacity(self) -> int:
        return max(1, (self.height() - self.padding * 2) // self.item_height)

    def _max_scroll_offset(self) -> int:
        return max(0, len(self.rows) - self._visible_item_capacity())

    def _clamp_scroll_offset(self):
        self.scroll_offset = max(0, min(self.scroll_offset, self._max_scroll_offset()))

    def _row_at_pos(self, pos) -> int:
        try:
            x_pos = float(pos.x())
            y_pos = float(pos.y())
        except Exception:
            return -1
        if x_pos < 0 or x_pos > self.width() or y_pos < 0 or y_pos > self.height():
            return -1
        local_y = y_pos - self.padding
        if local_y < 0:
            return -1
        row = int(local_y // self.item_height)
        index = self.scroll_offset + row
        visible_limit = min(len(self.rows), self.scroll_offset + self._visible_item_capacity())
        if index >= visible_limit:
            return -1
        return index

    def _scroll_by(self, steps: int) -> bool:
        if not self.rows or steps == 0:
            return False
        previous = self.scroll_offset
        self.scroll_offset = max(0, min(self.scroll_offset + steps, self._max_scroll_offset()))
        return self.scroll_offset != previous

    def _update_size(self):
        fm = self.fontMetrics()
        max_width = max(130, self.parent_button.width())
        for row in self.rows:
            label = str(row.get('label', '') or '')
            max_width = max(max_width, fm.horizontalAdvance(label) + 54)
        height = max(1, len(self.rows)) * self.item_height + self.padding * 2
        self.setFixedSize(max_width, min(420, height))
        self._clamp_scroll_offset()

    def show_above_button(self):
        self.set_rows(self.parent_button.popup_rows())
        if not self.rows:
            return
        btn_pos = self.parent_button.mapToGlobal(self.parent_button.rect().topLeft())
        self.move(btn_pos.x(), btn_pos.y() - self.height() - 2)
        self.show()
        self.activateWindow()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        dark = (
            bool(getattr(self.parent_button, '_always_dark', False))
            or bool(getattr(self.parent_button, '_force_dark', False))
            or is_dark_theme(app)
        )
        bg_color = QColor(45, 45, 48, 245) if dark else QColor(255, 255, 255, 248)
        border_color = QColor(70, 70, 75) if dark else QColor(232, 232, 232)
        hover_color = QColor(80, 80, 85) if dark else QColor(245, 245, 245)
        selected_color = QColor(0, 122, 255, 95) if dark else QColor(17, 17, 17, 18)
        text_color = QColor(240, 240, 240) if dark else QColor(32, 36, 43)
        muted_color = QColor(150, 150, 155) if dark else QColor(120, 126, 134)
        check_color = QColor(10, 132, 255)

        bg_path = QPainterPath()
        bg_path.addRoundedRect(QRectF(0, 0, self.width(), self.height()), 8, 8)
        painter.fillPath(bg_path, bg_color)
        painter.setPen(QPen(border_color, 1))
        painter.drawPath(bg_path)

        y = self.padding
        visible_count = self._visible_item_capacity()
        end_index = min(len(self.rows), self.scroll_offset + visible_count)
        for i in range(self.scroll_offset, end_index):
            row = self.rows[i]
            kind = row.get('kind', 'site')
            rect = QRectF(self.padding, y, self.width() - self.padding * 2, self.item_height)
            if kind == 'separator':
                painter.setPen(QPen(border_color, 1))
                painter.drawLine(int(rect.left() + 8), int(rect.center().y()), int(rect.right() - 8), int(rect.center().y()))
                y += self.item_height
                continue
            if i == self.hovered_index:
                hover_path = QPainterPath()
                hover_path.addRoundedRect(rect, 4, 4)
                painter.fillPath(hover_path, hover_color)
            selected = bool(row.get('checked', False))
            if selected:
                select_path = QPainterPath()
                select_path.addRoundedRect(rect, 4, 4)
                painter.fillPath(select_path, selected_color)

            indicator = QRectF(rect.left() + 8, rect.top() + 7, 14, 14)
            painter.setPen(QPen(check_color if selected else muted_color, 1.5))
            painter.setBrush(QColor(check_color) if selected else QBrush(Qt.BrushStyle.NoBrush))
            if kind in ('active', 'all'):
                painter.drawEllipse(indicator)
                if selected:
                    painter.setBrush(QColor('#FFFFFF'))
                    painter.setPen(Qt.PenStyle.NoPen)
                    painter.drawEllipse(indicator.adjusted(4, 4, -4, -4))
            else:
                painter.drawRoundedRect(indicator, 3, 3)
                if selected:
                    painter.setPen(QPen(QColor('#FFFFFF'), 2))
                    painter.drawLine(int(indicator.left() + 3), int(indicator.center().y()), int(indicator.left() + 6), int(indicator.bottom() - 4))
                    painter.drawLine(int(indicator.left() + 6), int(indicator.bottom() - 4), int(indicator.right() - 3), int(indicator.top() + 4))

            painter.setPen(text_color)
            label_rect = rect.adjusted(30, 0, -8, 0)
            painter.drawText(label_rect, Qt.AlignmentFlag.AlignVCenter | Qt.AlignmentFlag.AlignLeft, str(row.get('label', '') or ''))
            y += self.item_height
        painter.end()

    def mouseMoveEvent(self, event):
        index = self._row_at_pos(event.position())
        if index != self.hovered_index:
            self.hovered_index = index
            self.update()

    def mousePressEvent(self, event):
        if event.button() != Qt.MouseButton.LeftButton:
            return
        if not QRectF(0, 0, self.width(), self.height()).contains(event.position()):
            self.hide()
            event.accept()
            return
        index = self._row_at_pos(event.position())
        if 0 <= index < len(self.rows):
            self.parent_button.handle_popup_row(self.rows[index])
            self.set_rows(self.parent_button.popup_rows())
            self.update()
            event.accept()

    def wheelEvent(self, event):
        delta = event.angleDelta().y()
        if delta == 0:
            event.ignore()
            return
        steps = max(1, abs(delta) // 120)
        direction = -steps if delta > 0 else steps
        if self._scroll_by(direction):
            self.update()
            event.accept()
            return
        event.ignore()

    def leaveEvent(self, event):
        self.hovered_index = -1
        self.update()

    def focusOutEvent(self, event):
        self.hide()


class TargetSelectorButton(QPushButton):
    targetChanged = pyqtSignal()

    def __init__(self, parent=None, always_dark=False):
        super().__init__(parent)
        self._always_dark = bool(always_dark)
        self._force_dark = False
        self._theme_updating = False
        self._panel = None
        self._target_mode = 'active'
        self._custom_indices = set()
        self._popup = TargetSelectorPopup(self)
        self.clicked.connect(self._show_popup)
        self.setFixedHeight(30)
        self.setCursor(Qt.CursorShape.PointingHandCursor)
        self._apply_theme()
        self._update_text()

    def set_panel(self, panel):
        self._panel = panel
        self._normalize_selection()
        self._update_text()

    def _target_items(self) -> list[dict]:
        panel = self._panel
        if panel is not None and hasattr(panel, 'target_items'):
            return list(panel.target_items())
        return []

    def _normalize_selection(self):
        items = self._target_items()
        count = len(items)
        if count <= 0:
            self._target_mode = 'active'
            self._custom_indices.clear()
            return
        valid = {int(item.get('index', -1)) for item in items}
        self._custom_indices = {idx for idx in self._custom_indices if idx in valid}
        if self._target_mode == 'custom':
            if not self._custom_indices:
                self._target_mode = 'active'
            elif len(self._custom_indices) == count:
                self._target_mode = 'all'
                self._custom_indices.clear()
        elif self._target_mode not in ('active', 'all'):
            self._target_mode = 'active'

    def _set_mode(self, mode: str):
        mode = mode if mode in ('active', 'all', 'custom') else 'active'
        self._target_mode = mode
        if mode != 'custom':
            self._custom_indices.clear()
        self._normalize_selection()
        self._update_text()
        self.targetChanged.emit()

    def _set_custom_indices(self, indices):
        self._target_mode = 'custom'
        self._custom_indices = {int(idx) for idx in indices}
        self._normalize_selection()
        self._update_text()
        self.targetChanged.emit()

    def shift_target_indices_after_insert(self, index: int):
        index = int(index)
        if self._target_mode == 'custom':
            self._custom_indices = {idx + 1 if idx >= index else idx for idx in self._custom_indices}
        self._normalize_selection()
        self._update_text()

    def shift_target_indices_after_delete(self, index: int):
        index = int(index)
        if self._target_mode == 'custom':
            shifted = set()
            for idx in self._custom_indices:
                if idx == index:
                    continue
                shifted.add(idx - 1 if idx > index else idx)
            self._custom_indices = shifted
        self._normalize_selection()
        self._update_text()

    def popup_rows(self):
        self._normalize_selection()
        rows = [
            {'kind': 'active', 'label': 'Active', 'checked': self._target_mode == 'active'},
            {'kind': 'all', 'label': 'All', 'checked': self._target_mode == 'all'},
        ]
        items = self._target_items()
        if items:
            rows.append({'kind': 'separator', 'label': '', 'checked': False})
        for item in items:
            idx = int(item.get('index', -1))
            checked = self._target_mode == 'all' or (self._target_mode == 'custom' and idx in self._custom_indices)
            label = str(item.get('label', '') or item.get('url', '') or f'Tab {idx + 1}')
            rows.append({'kind': 'site', 'label': label, 'index': idx, 'checked': checked})
        return rows

    def handle_popup_row(self, row):
        kind = row.get('kind')
        if kind == 'active':
            self._set_mode('active')
            return
        if kind == 'all':
            self._set_mode('all')
            return
        if kind == 'site':
            idx = int(row.get('index', -1))
            if idx < 0:
                return
            current = set()
            if self._target_mode == 'all':
                current = {int(item.get('index', -1)) for item in self._target_items()}
                current.discard(-1)
            elif self._target_mode == 'custom':
                current = set(self._custom_indices)
            if idx in current:
                current.remove(idx)
            else:
                current.add(idx)
            self._set_custom_indices(current)

    def selected_target_indices(self, panel=None) -> list[int]:
        if panel is not None and panel is not self._panel:
            self.set_panel(panel)
        self._normalize_selection()
        panel = self._panel
        if panel is None or not hasattr(panel, '_views'):
            return []
        count = len(panel._views)
        if count <= 0:
            return []
        if self._target_mode == 'all':
            return [idx for idx, view in enumerate(panel._views) if view is not None]
        if self._target_mode == 'custom':
            indices = [idx for idx in sorted(self._custom_indices) if 0 <= idx < count and panel._views[idx] is not None]
            if indices:
                return indices
        active = int(getattr(panel, '_active_idx', 0) or 0)
        return [active] if 0 <= active < count and panel._views[active] is not None else []

    def selected_target_views(self, panel=None) -> list:
        if panel is not None and panel is not self._panel:
            self.set_panel(panel)
        panel = self._panel
        if panel is None or not hasattr(panel, '_views'):
            return []
        return [panel._views[idx] for idx in self.selected_target_indices(panel)]

    def target_all(self) -> bool:
        self._normalize_selection()
        return self._target_mode == 'all'

    def _display_text(self) -> str:
        self._normalize_selection()
        if self._target_mode == 'all':
            return 'All'
        if self._target_mode == 'custom':
            return 'Customized'
        return 'Active'

    def _update_text(self):
        self.setText(self._display_text())

    def _show_popup(self):
        if self._popup.isVisible():
            self._popup.hide()
            return
        self._popup.show_above_button()

    def _apply_theme(self):
        if self._theme_updating:
            return
        self._theme_updating = True
        dark = self._always_dark or self._force_dark or is_dark_theme(app)
        try:
            if dark:
                bg = "#404145"
                hover = "#4A4B4F"
                pressed = "#343538"
                text = "#FFFFFF"
            else:
                bg = "#FFFFFF"
                hover = "#F5F5F5"
                pressed = "#ECECEC"
                text = "#444444"
            self.setStyleSheet(f"""
                QPushButton {{
                    border: 1px solid transparent;
                    background-color: {bg};
                    border-radius: 15px;
                    padding: 5px 20px;
                    color: {text};
                    text-align: left;
                }}
                QPushButton:hover {{ background-color: {hover}; }}
                QPushButton:pressed {{ background-color: {pressed}; }}
            """)
        finally:
            self._theme_updating = False

    def changeEvent(self, event):
        super().changeEvent(event)
        if self._theme_updating:
            return
        if event.type() in (QEvent.Type.PaletteChange, QEvent.Type.ApplicationPaletteChange):
            self._apply_theme()
            if self._popup.isVisible():
                self._popup.update()


def normalize_profile_entry(entry: dict, fallback_name: str) -> dict:
    profile = {
        'name': str(entry.get('name', fallback_name)).strip() or fallback_name,
        'endpoint': normalize_endpoint_value(str(entry.get('endpoint', DEFAULT_ENDPOINT)).strip() or DEFAULT_ENDPOINT),
        'append_v1': bool(entry.get('append_v1', True)),
        'api_key': str(entry.get('api_key', '')).strip(),
        'model': str(entry.get('model', DEFAULT_MODEL)).strip() or DEFAULT_MODEL,
        'timeout': str(entry.get('timeout', '60')).strip() or '60',
        'show_references': bool(entry.get('show_references', False)),
        'remember_history': bool(entry.get('remember_history', False)),
        'remember_memory': bool(entry.get('remember_memory', True)),
    }
    return profile


def default_specialized_profiles() -> dict:
    base = {'router': ''}
    for capability, _label in SPECIALIZED_CAPABILITIES:
        base[capability] = ''
    return base


def normalize_specialized_profiles(raw: dict | None) -> dict:
    normalized = default_specialized_profiles()
    if isinstance(raw, dict):
        for key in normalized.keys():
            normalized[key] = str(raw.get(key, normalized[key]) or '').strip()
    return normalized


def default_specialized_execution_modes() -> dict:
    modes = {}
    for capability, _label in SPECIALIZED_CAPABILITIES:
        options = SPECIALIZED_EXECUTION_OPTIONS.get(capability, [])
        modes[capability] = str(options[0][1] if options else '').strip()
    return modes


def normalize_specialized_execution_modes(raw: dict | None) -> dict:
    normalized = default_specialized_execution_modes()
    if not isinstance(raw, dict):
        return normalized
    for capability, default_value in normalized.items():
        allowed = {value for _label, value in SPECIALIZED_EXECUTION_OPTIONS.get(capability, [])}
        candidate = str(raw.get(capability, default_value) or '').strip()
        normalized[capability] = candidate if candidate in allowed else default_value
    return normalized


def normalize_display_history_context_max_chars(value, default: int = DISPLAY_HISTORY_CONTEXT_MAX_CHARS) -> int:
    try:
        parsed = int(value or default)
    except (TypeError, ValueError):
        parsed = default
    return max(500, parsed)


def normalize_external_context_max_chars(value, default: int = DEFAULT_EXTERNAL_CONTEXT_MAX_CHARS) -> int:
    try:
        parsed = int(value or default)
    except (TypeError, ValueError):
        parsed = default
    return max(1000, parsed)


def _split_context_patterns(value: str) -> list[str]:
    patterns = []
    for part in re.split(r'[,;\n]+', str(value or '')):
        part = part.strip()
        if part:
            patterns.append(part)
    return patterns


def _new_external_context_source_id(prefix: str = 'ctx') -> str:
    return f'{prefix}-{int(time.time() * 1000)}'


def normalize_mcp_transport(value) -> str:
    candidate = str(value or 'auto').strip().lower().replace('-', '_')
    allowed = {key for key, _label in MCP_TRANSPORT_OPTIONS}
    return candidate if candidate in allowed else 'auto'


def default_external_context_sources() -> list[dict]:
    sources = []
    if os.path.isdir(DEFAULT_WATERMELON_CONTEXT_PATH):
        sources.append(
            {
                'id': 'default-watermelon-app-path',
                'enabled': True,
                'auto_context': True,
                'type': 'local_path',
                'name': 'WatermelonAppPath',
                'path': DEFAULT_WATERMELON_CONTEXT_PATH,
                'include_patterns': DEFAULT_EXTERNAL_CONTEXT_INCLUDE_PATTERNS,
                'exclude_patterns': DEFAULT_EXTERNAL_CONTEXT_EXCLUDE_PATTERNS,
                'max_chars': DEFAULT_EXTERNAL_CONTEXT_MAX_CHARS,
                'use_embedding': True,
            }
        )
    return sources


def normalize_external_context_source_record(item: dict, fallback_index: int = 1) -> dict | None:
    if not isinstance(item, dict):
        return None
    source_type = str(item.get('type', 'local_path') or 'local_path').strip().lower()
    if source_type not in {'local_path', 'mcp_stdio', 'mcp_http'}:
        source_type = 'local_path'
    name = str(item.get('name', '') or '').strip()
    if not name:
        name = {'local_path': 'Local context', 'mcp_stdio': 'MCP stdio', 'mcp_http': 'MCP HTTP'}[source_type]
        name = f'{name} {fallback_index}'
    record = {
        'id': str(item.get('id', '') or _new_external_context_source_id()).strip(),
        'enabled': bool(item.get('enabled', True)),
        'auto_context': bool(item.get('auto_context', True)),
        'type': source_type,
        'name': name,
        'path': str(item.get('path', '') or '').strip(),
        'include_patterns': str(item.get('include_patterns', DEFAULT_EXTERNAL_CONTEXT_INCLUDE_PATTERNS) or DEFAULT_EXTERNAL_CONTEXT_INCLUDE_PATTERNS).strip(),
        'exclude_patterns': str(item.get('exclude_patterns', DEFAULT_EXTERNAL_CONTEXT_EXCLUDE_PATTERNS) or '').strip(),
        'max_chars': normalize_external_context_max_chars(item.get('max_chars', DEFAULT_EXTERNAL_CONTEXT_MAX_CHARS)),
        'use_embedding': bool(item.get('use_embedding', True)),
        'command': str(item.get('command', '') or '').strip(),
        'args': str(item.get('args', '') or '').strip(),
        'cwd': str(item.get('cwd', '') or '').strip(),
        'env': str(item.get('env', '') or '').strip(),
        'endpoint': str(item.get('endpoint', '') or '').strip(),
        'transport': normalize_mcp_transport(item.get('transport', 'auto')),
        'auth_token': str(item.get('auth_token', '') or '').strip(),
        'toolsets': str(item.get('toolsets', '') or '').strip(),
        'headers': str(item.get('headers', '') or '').strip(),
        'read_only': bool(item.get('read_only', True)),
        'use_in_tool_runtime': bool(item.get('use_in_tool_runtime', True)),
        'mcp_protocol_version': str(item.get('mcp_protocol_version', '') or '').strip(),
        'mcp_server_name': str(item.get('mcp_server_name', '') or '').strip(),
        'mcp_server_version': str(item.get('mcp_server_version', '') or '').strip(),
        'discovered_at': str(item.get('discovered_at', '') or '').strip(),
        'discovery_error': str(item.get('discovery_error', '') or '').strip(),
        'discovered_tools': item.get('discovered_tools', []) if isinstance(item.get('discovered_tools', []), list) else [],
        'discovered_resources': item.get('discovered_resources', []) if isinstance(item.get('discovered_resources', []), list) else [],
        'discovered_prompts': item.get('discovered_prompts', []) if isinstance(item.get('discovered_prompts', []), list) else [],
    }
    if source_type == 'local_path' and not record['path']:
        return None
    if source_type == 'mcp_stdio' and not record['command']:
        return None
    if source_type == 'mcp_http' and not record['endpoint']:
        return None
    return record


def normalize_external_context_sources(records) -> list[dict]:
    normalized = []
    if not isinstance(records, list):
        return normalized
    for index, item in enumerate(records, start=1):
        record = normalize_external_context_source_record(item, index)
        if record is not None:
            normalized.append(record)
    return normalized


CODE_RUNNER_LANGUAGE_ALIASES = {
    'py': 'python',
    'python3': 'python',
    'python': 'python',
    'js': 'node',
    'javascript': 'node',
    'nodejs': 'node',
    'node': 'node',
}


def normalize_code_runner_language(value: str, fallback: str = 'python') -> str:
    candidate = str(value or '').strip().lower()
    candidate = CODE_RUNNER_LANGUAGE_ALIASES.get(candidate, candidate)
    candidate = re.sub(r'[^a-z0-9_+.-]+', '', candidate)
    return candidate or fallback


def normalize_code_execution_timeout(value, default: int = CODE_EXECUTION_DEFAULT_TIMEOUT_SECONDS) -> int:
    try:
        parsed = int(value or default)
    except (TypeError, ValueError):
        parsed = default
    return max(1, min(parsed, 120))


def _first_existing_executable(paths: list[str]) -> str:
    for path in paths:
        candidate = str(path or '').strip()
        if not candidate:
            continue
        if os.path.isabs(candidate) and os.path.isfile(candidate) and os.access(candidate, os.X_OK):
            return candidate
        resolved = shutil.which(candidate)
        if resolved:
            return resolved
    return ''


def auto_detect_code_runner_command(language: str) -> str:
    lang = normalize_code_runner_language(language, '')
    if lang == 'python':
        return _first_existing_executable(
            [
                sys.executable,
                os.path.join(os.getcwd(), '.venv', 'bin', 'python3'),
                os.path.join(str(Path.home()), 'Documents', 'A-workingfilewithp3.11', '.venv', 'bin', 'python3'),
                'python3',
                'python',
                '/opt/homebrew/bin/python3',
                '/usr/local/bin/python3',
                '/usr/bin/python3',
            ]
        )
    if lang == 'node':
        return _first_existing_executable(
            [
                'node',
                '/opt/homebrew/bin/node',
                '/usr/local/bin/node',
                '/usr/bin/node',
            ]
        )
    return _first_existing_executable([lang])


def default_code_runner_args(language: str) -> str:
    lang = normalize_code_runner_language(language, '')
    if lang == 'python':
        return '-I -c {code}'
    if lang == 'node':
        return '-e {code}'
    return '{code}'


def default_code_runner_records() -> list[dict]:
    return [
        {
            'language': 'python',
            'command': auto_detect_code_runner_command('python'),
            'args': default_code_runner_args('python'),
            'enabled': True,
        },
        {
            'language': 'node',
            'command': auto_detect_code_runner_command('node'),
            'args': default_code_runner_args('node'),
            'enabled': True,
        },
    ]


def normalize_code_runner_record(record, fallback_index: int = 1) -> dict | None:
    if not isinstance(record, dict):
        return None
    language = normalize_code_runner_language(record.get('language', ''), f'runner{fallback_index}')
    command = str(record.get('command', '') or '').strip()
    args = str(record.get('args', '') or '').strip() or default_code_runner_args(language)
    return {
        'language': language,
        'command': command,
        'args': args,
        'enabled': bool(record.get('enabled', True)),
    }


def normalize_code_runner_records(records) -> list[dict]:
    source = records if isinstance(records, list) else []
    if not source:
        source = default_code_runner_records()
    normalized = []
    seen = set()
    for index, record in enumerate(source, start=1):
        item = normalize_code_runner_record(record, index)
        if item is None:
            continue
        language_key = item['language'].lower()
        if language_key in seen:
            continue
        seen.add(language_key)
        normalized.append(item)
    return normalized or default_code_runner_records()


def load_code_runner_records_from_store(store: dict | None = None, *, enabled_only: bool = False) -> list[dict]:
    if store is None:
        store = load_settings_store()
    globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
    records = normalize_code_runner_records(globals_store.get('code_runners', []))
    if enabled_only:
        records = [record for record in records if record.get('enabled', True)]
    return records


def code_runner_catalog_text(store: dict | None = None) -> str:
    if store is None:
        store = load_settings_store()
    globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
    if not bool(globals_store.get('code_execution_enabled', True)):
        return 'Code execution is disabled.'
    records = load_code_runner_records_from_store(store, enabled_only=True)
    supported = []
    unavailable = []
    for record in records:
        language = normalize_code_runner_language(record.get('language', ''), '')
        command = str(record.get('command', '') or '').strip()
        if command and _resolve_runner_command(command):
            supported.append(language)
        else:
            unavailable.append(language)
    if supported:
        text = 'Configured executable code runners: ' + ', '.join(supported) + '.'
        if unavailable:
            text += ' Configured but unavailable: ' + ', '.join(unavailable) + '.'
        text += ' If execution is needed, use one of the executable languages; prefer the first listed language when converting from unsupported code.'
        return text
    if unavailable:
        return 'Code runners are configured but unavailable: ' + ', '.join(unavailable) + '.'
    return 'No executable code runners are configured.'


def supported_code_runner_languages(store: dict | None = None) -> list[str]:
    if store is None:
        store = load_settings_store()
    globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
    if not bool(globals_store.get('code_execution_enabled', True)):
        return []
    languages = []
    for record in load_code_runner_records_from_store(store, enabled_only=True):
        command = str(record.get('command', '') or '').strip()
        if command and _resolve_runner_command(command):
            languages.append(normalize_code_runner_language(record.get('language', ''), ''))
    return [language for language in languages if language]


def _resolve_runner_command(command: str) -> str:
    raw = str(command or '').strip()
    if not raw:
        return ''
    if os.path.isabs(raw):
        return raw if os.path.isfile(raw) and os.access(raw, os.X_OK) else ''
    return shutil.which(raw) or ''


def _build_runner_argv(command: str, args_template: str, code: str) -> list[str]:
    resolved = _resolve_runner_command(command)
    if not resolved:
        return []
    template = str(args_template or '').strip()
    try:
        parts = shlex.split(template)
    except ValueError:
        parts = template.split()
    argv = [resolved]
    replaced = False
    for part in parts:
        if '{code}' in part:
            argv.append(part.replace('{code}', code))
            replaced = True
        elif part:
            argv.append(part)
    if not replaced:
        argv.append(code)
    return argv


def _parse_mcp_header_lines(text: str) -> dict:
    headers = {}
    for raw_line in str(text or '').splitlines():
        line = raw_line.strip()
        if not line or ':' not in line:
            continue
        key, value = line.split(':', 1)
        key = key.strip()
        value = value.strip()
        if not key:
            continue
        if key.lower() == 'authorization' and '<stored token>' in value:
            continue
        headers[key] = value
    return headers


def _mcp_http_headers(source: dict, protocol_version: str, session_id: str = '') -> dict:
    headers = {
        'Accept': 'application/json, text/event-stream',
        'Content-Type': 'application/json',
        'MCP-Protocol-Version': protocol_version,
    }
    headers.update(_parse_mcp_header_lines(source.get('headers', '')))
    token = str(source.get('auth_token', '') or '').strip()
    if token:
        headers['Authorization'] = f'Bearer {token}'
    toolsets = str(source.get('toolsets', '') or '').strip()
    if toolsets:
        headers['X-MCP-Toolsets'] = toolsets
    if bool(source.get('read_only', True)):
        headers['X-MCP-Readonly'] = 'true'
    if session_id:
        headers['Mcp-Session-Id'] = session_id
    return headers


def _parse_mcp_http_payload(response) -> dict:
    text = response.text or ''
    stripped = text.strip()
    if not stripped:
        return {}
    content_type = str(response.headers.get('content-type', '') or '').lower()
    if 'text/event-stream' in content_type or stripped.startswith('event:') or stripped.startswith('data:'):
        payloads = []
        current_data = []
        for line in text.splitlines():
            if not line.strip():
                if current_data:
                    payloads.append('\n'.join(current_data).strip())
                    current_data = []
                continue
            if line.startswith('data:'):
                data = line[5:].strip()
                if data and data != '[DONE]':
                    current_data.append(data)
        if current_data:
            payloads.append('\n'.join(current_data).strip())
        for payload in payloads:
            try:
                parsed = json.loads(payload)
            except Exception:
                continue
            if isinstance(parsed, dict) and ('result' in parsed or 'error' in parsed or 'jsonrpc' in parsed):
                return parsed
        return {}
    parsed = response.json()
    if isinstance(parsed, list):
        for item in parsed:
            if isinstance(item, dict) and ('result' in item or 'error' in item):
                return item
        return {}
    return parsed if isinstance(parsed, dict) else {}


def _mcp_error_message(payload: dict) -> str:
    error = payload.get('error') if isinstance(payload, dict) else None
    if isinstance(error, dict):
        message = str(error.get('message', '') or '').strip()
        code = error.get('code')
        if code is not None and message:
            return f'{code}: {message}'
        if message:
            return message
        return json.dumps(error, ensure_ascii=False)
    return str(error or '').strip()


def _mcp_http_rpc(
    endpoint: str,
    source: dict,
    method: str,
    params: dict | None,
    request_id,
    protocol_version: str,
    session_id: str = '',
) -> tuple[dict, str]:
    payload = {'jsonrpc': '2.0', 'method': method}
    if params is not None:
        payload['params'] = params
    if request_id is not None:
        payload['id'] = request_id
    response = requests.post(
        endpoint,
        headers=_mcp_http_headers(source, protocol_version, session_id),
        json=payload,
        timeout=MCP_HTTP_DISCOVERY_TIMEOUT,
    )
    next_session_id = response.headers.get('Mcp-Session-Id') or response.headers.get('mcp-session-id') or session_id
    if request_id is None and response.status_code in {200, 202, 204}:
        return {}, next_session_id
    if response.status_code >= 400:
        body = (response.text or '').strip()
        if len(body) > 700:
            body = body[:700] + '...'
        raise RuntimeError(f'HTTP {response.status_code}: {body or response.reason}')
    payload = _parse_mcp_http_payload(response)
    message = _mcp_error_message(payload)
    if message:
        raise RuntimeError(message)
    return payload, next_session_id


def _parse_mcp_env_lines(text: str) -> dict:
    env = {}
    for raw_line in str(text or '').splitlines():
        line = raw_line.strip()
        if not line or line.startswith('#') or '=' not in line:
            continue
        key, value = line.split('=', 1)
        key = key.strip()
        if key:
            env[key] = value.strip()
    return env


def _mcp_stdio_argv(source: dict) -> list[str]:
    command = str(source.get('command', '') or '').strip()
    args = str(source.get('args', '') or '').strip()
    if not command:
        raise RuntimeError('MCP stdio command is empty')
    return shlex.split(command) + (shlex.split(args) if args else [])


class McpStdioSession:
    def __init__(self, source: dict, timeout: int = MCP_HTTP_DISCOVERY_TIMEOUT):
        self.source = source
        self.timeout = timeout
        self._next_id = 1
        self._queue = queue.Queue()
        self._process = None
        self._reader_thread = None
        self._stderr_thread = None

    def start(self):
        argv = _mcp_stdio_argv(self.source)
        env = os.environ.copy()
        env.update(_parse_mcp_env_lines(self.source.get('env', '')))
        cwd = str(self.source.get('cwd', '') or '').strip() or None
        self._process = subprocess.Popen(
            argv,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            encoding='utf-8',
            errors='replace',
            cwd=cwd,
            env=env,
        )
        self._reader_thread = threading.Thread(target=self._read_stdout, daemon=True)
        self._reader_thread.start()
        self._stderr_thread = threading.Thread(target=self._drain_stderr, daemon=True)
        self._stderr_thread.start()
        return self

    def _read_stdout(self):
        try:
            while self._process and self._process.stdout:
                line = self._process.stdout.readline()
                if not line:
                    break
                try:
                    payload = json.loads(line)
                except Exception:
                    continue
                self._queue.put(payload)
        except Exception:
            pass

    def _drain_stderr(self):
        try:
            while self._process and self._process.stderr:
                if not self._process.stderr.readline():
                    break
        except Exception:
            pass

    def _send(self, payload: dict):
        if self._process is None or self._process.stdin is None:
            raise RuntimeError('MCP stdio process is not running')
        if self._process.poll() is not None:
            raise RuntimeError('MCP stdio process exited')
        self._process.stdin.write(json.dumps(payload, ensure_ascii=False) + '\n')
        self._process.stdin.flush()

    def request(self, method: str, params: dict | None = None) -> dict:
        request_id = self._next_id
        self._next_id += 1
        payload = {'jsonrpc': '2.0', 'id': request_id, 'method': method}
        if params is not None:
            payload['params'] = params
        self._send(payload)
        deadline = time.time() + self.timeout
        while time.time() < deadline:
            try:
                item = self._queue.get(timeout=max(0.05, min(0.5, deadline - time.time())))
            except queue.Empty:
                continue
            if isinstance(item, dict) and item.get('id') == request_id:
                message = _mcp_error_message(item)
                if message:
                    raise RuntimeError(message)
                return item
        raise RuntimeError(f'MCP stdio request timed out: {method}')

    def notify(self, method: str, params: dict | None = None):
        payload = {'jsonrpc': '2.0', 'method': method}
        if params is not None:
            payload['params'] = params
        self._send(payload)

    def close(self):
        process = self._process
        self._process = None
        if process is None:
            return
        try:
            if process.poll() is None:
                process.terminate()
                try:
                    process.wait(timeout=1.5)
                except subprocess.TimeoutExpired:
                    process.kill()
        except Exception:
            pass


class McpSseSession:
    def __init__(self, source: dict, protocol_version: str, timeout: int = MCP_HTTP_DISCOVERY_TIMEOUT):
        self.source = source
        self.protocol_version = protocol_version
        self.timeout = timeout
        self.endpoint = str(source.get('endpoint', '') or '').strip()
        self.message_endpoint = ''
        self._next_id = 1
        self._queue = queue.Queue()
        self._endpoint_event = threading.Event()
        self._session = requests.Session()
        self._response = None
        self._reader_thread = None

    def start(self):
        headers = _mcp_http_headers(self.source, self.protocol_version)
        headers['Accept'] = 'text/event-stream'
        self._response = self._session.get(self.endpoint, headers=headers, stream=True, timeout=self.timeout)
        if self._response.status_code >= 400:
            raise RuntimeError(f'HTTP {self._response.status_code}: {(self._response.text or self._response.reason)[:700]}')
        self._reader_thread = threading.Thread(target=self._read_events, daemon=True)
        self._reader_thread.start()
        if not self._endpoint_event.wait(self.timeout):
            raise RuntimeError('SSE endpoint event was not received')
        return self

    def _emit_event(self, event_name: str, data_lines: list[str]):
        data = '\n'.join(data_lines).strip()
        if not data:
            return
        if event_name == 'endpoint':
            self.message_endpoint = urljoin(self.endpoint, data)
            self._endpoint_event.set()
            return
        try:
            payload = json.loads(data)
        except Exception:
            return
        self._queue.put(payload)

    def _read_events(self):
        event_name = 'message'
        data_lines = []
        try:
            for raw_line in self._response.iter_lines(decode_unicode=True):
                line = raw_line or ''
                if line == '':
                    self._emit_event(event_name, data_lines)
                    event_name = 'message'
                    data_lines = []
                    continue
                if line.startswith('event:'):
                    event_name = line[6:].strip() or 'message'
                elif line.startswith('data:'):
                    data_lines.append(line[5:].strip())
            if data_lines:
                self._emit_event(event_name, data_lines)
        except Exception:
            pass

    def _post(self, payload: dict):
        if not self.message_endpoint:
            raise RuntimeError('SSE message endpoint is not ready')
        response = self._session.post(
            self.message_endpoint,
            headers=_mcp_http_headers(self.source, self.protocol_version),
            json=payload,
            timeout=self.timeout,
        )
        if response.status_code >= 400:
            raise RuntimeError(f'HTTP {response.status_code}: {(response.text or response.reason)[:700]}')

    def request(self, method: str, params: dict | None = None) -> dict:
        request_id = self._next_id
        self._next_id += 1
        payload = {'jsonrpc': '2.0', 'id': request_id, 'method': method}
        if params is not None:
            payload['params'] = params
        self._post(payload)
        deadline = time.time() + self.timeout
        while time.time() < deadline:
            try:
                item = self._queue.get(timeout=max(0.05, min(0.5, deadline - time.time())))
            except queue.Empty:
                continue
            if isinstance(item, dict) and item.get('id') == request_id:
                message = _mcp_error_message(item)
                if message:
                    raise RuntimeError(message)
                return item
        raise RuntimeError(f'MCP SSE request timed out: {method}')

    def notify(self, method: str, params: dict | None = None):
        payload = {'jsonrpc': '2.0', 'method': method}
        if params is not None:
            payload['params'] = params
        self._post(payload)

    def close(self):
        try:
            if self._response is not None:
                self._response.close()
        except Exception:
            pass
        try:
            self._session.close()
        except Exception:
            pass


def _compact_mcp_item(item) -> dict:
    if not isinstance(item, dict):
        return {'name': str(item)}
    compact = {}
    for key in ('name', 'title', 'description', 'uri', 'uriTemplate', 'mimeType'):
        value = item.get(key)
        if value is not None and str(value).strip():
            compact[key] = str(value).strip()
    return compact or {'name': json.dumps(item, ensure_ascii=False)[:240]}


def _mcp_list_result(payload: dict, key: str) -> list[dict]:
    result = payload.get('result', {}) if isinstance(payload, dict) else {}
    if not isinstance(result, dict):
        return []
    value = result.get(key, [])
    if not isinstance(value, list):
        return []
    return [_compact_mcp_item(item) for item in value]


def _mcp_raw_list_result(payload: dict, key: str) -> list[dict]:
    result = payload.get('result', {}) if isinstance(payload, dict) else {}
    if not isinstance(result, dict):
        return []
    value = result.get(key, [])
    return value if isinstance(value, list) else []


def _mcp_discovery_list_call(endpoint: str, source: dict, method: str, key: str, request_id: int, protocol_version: str, session_id: str) -> tuple[list[dict], str]:
    try:
        payload, session_id = _mcp_http_rpc(endpoint, source, method, {}, request_id, protocol_version, session_id)
        return _mcp_list_result(payload, key), session_id
    except Exception as exc:
        return [{'name': f'Unavailable: {exc}'}], session_id


def discover_mcp_streamable_http_source(source: dict) -> dict:
    endpoint = str(source.get('endpoint', '') or '').strip()
    if not endpoint:
        raise RuntimeError('Endpoint URL is empty')
    last_error = None
    for protocol_version in MCP_HTTP_PROTOCOL_VERSIONS:
        session_id = ''
        try:
            init_payload, session_id = _mcp_http_rpc(
                endpoint,
                source,
                'initialize',
                {
                    'protocolVersion': protocol_version,
                    'capabilities': {},
                    'clientInfo': {'name': NAME, 'version': VERSION},
                },
                1,
                protocol_version,
                session_id,
            )
            init_result = init_payload.get('result', {}) if isinstance(init_payload, dict) else {}
            if not isinstance(init_result, dict):
                init_result = {}
            negotiated_version = str(init_result.get('protocolVersion') or protocol_version)
            server_info = init_result.get('serverInfo', {}) if isinstance(init_result.get('serverInfo'), dict) else {}
            _mcp_http_rpc(endpoint, source, 'notifications/initialized', {}, None, negotiated_version, session_id)
            tools, session_id = _mcp_discovery_list_call(endpoint, source, 'tools/list', 'tools', 2, negotiated_version, session_id)
            resources, session_id = _mcp_discovery_list_call(endpoint, source, 'resources/list', 'resources', 3, negotiated_version, session_id)
            prompts, session_id = _mcp_discovery_list_call(endpoint, source, 'prompts/list', 'prompts', 4, negotiated_version, session_id)
            return {
                'ok': True,
                'mcp_protocol_version': negotiated_version,
                'mcp_server_name': str(server_info.get('name', '') or '').strip(),
                'mcp_server_version': str(server_info.get('version', '') or '').strip(),
                'discovered_tools': tools,
                'discovered_resources': resources,
                'discovered_prompts': prompts,
                'discovered_at': datetime.datetime.now().isoformat(timespec='seconds'),
                'discovery_error': '',
            }
        except Exception as exc:
            last_error = exc
    raise RuntimeError(str(last_error or 'MCP discovery failed'))


def discover_mcp_stdio_source(source: dict) -> dict:
    session = McpStdioSession(source).start()
    try:
        init_payload = session.request(
            'initialize',
            {
                'protocolVersion': MCP_HTTP_PROTOCOL_VERSIONS[0],
                'capabilities': {},
                'clientInfo': {'name': NAME, 'version': VERSION},
            },
        )
        init_result = init_payload.get('result', {}) if isinstance(init_payload, dict) else {}
        if not isinstance(init_result, dict):
            init_result = {}
        negotiated_version = str(init_result.get('protocolVersion') or MCP_HTTP_PROTOCOL_VERSIONS[0])
        server_info = init_result.get('serverInfo', {}) if isinstance(init_result.get('serverInfo'), dict) else {}
        session.notify('notifications/initialized', {})
        try:
            tools = _mcp_list_result(session.request('tools/list', {}), 'tools')
        except Exception as exc:
            tools = [{'name': f'Unavailable: {exc}'}]
        try:
            resources = _mcp_list_result(session.request('resources/list', {}), 'resources')
        except Exception as exc:
            resources = [{'name': f'Unavailable: {exc}'}]
        try:
            prompts = _mcp_list_result(session.request('prompts/list', {}), 'prompts')
        except Exception as exc:
            prompts = [{'name': f'Unavailable: {exc}'}]
        return {
            'ok': True,
            'mcp_protocol_version': negotiated_version,
            'mcp_server_name': str(server_info.get('name', '') or '').strip(),
            'mcp_server_version': str(server_info.get('version', '') or '').strip(),
            'discovered_tools': tools,
            'discovered_resources': resources,
            'discovered_prompts': prompts,
            'discovered_at': datetime.datetime.now().isoformat(timespec='seconds'),
            'discovery_error': '',
        }
    finally:
        session.close()


def _discover_mcp_sse_with_protocol(source: dict, protocol_version: str) -> dict:
    session = McpSseSession(source, protocol_version).start()
    try:
        init_payload = session.request(
            'initialize',
            {
                'protocolVersion': protocol_version,
                'capabilities': {},
                'clientInfo': {'name': NAME, 'version': VERSION},
            },
        )
        init_result = init_payload.get('result', {}) if isinstance(init_payload, dict) else {}
        if not isinstance(init_result, dict):
            init_result = {}
        negotiated_version = str(init_result.get('protocolVersion') or protocol_version)
        server_info = init_result.get('serverInfo', {}) if isinstance(init_result.get('serverInfo'), dict) else {}
        session.notify('notifications/initialized', {})
        try:
            tools = _mcp_list_result(session.request('tools/list', {}), 'tools')
        except Exception as exc:
            tools = [{'name': f'Unavailable: {exc}'}]
        try:
            resources = _mcp_list_result(session.request('resources/list', {}), 'resources')
        except Exception as exc:
            resources = [{'name': f'Unavailable: {exc}'}]
        try:
            prompts = _mcp_list_result(session.request('prompts/list', {}), 'prompts')
        except Exception as exc:
            prompts = [{'name': f'Unavailable: {exc}'}]
        return {
            'ok': True,
            'mcp_protocol_version': negotiated_version,
            'mcp_server_name': str(server_info.get('name', '') or '').strip(),
            'mcp_server_version': str(server_info.get('version', '') or '').strip(),
            'discovered_tools': tools,
            'discovered_resources': resources,
            'discovered_prompts': prompts,
            'discovered_at': datetime.datetime.now().isoformat(timespec='seconds'),
            'discovery_error': '',
        }
    finally:
        session.close()


def discover_mcp_sse_source(source: dict) -> dict:
    last_error = None
    for protocol_version in MCP_HTTP_PROTOCOL_VERSIONS:
        try:
            return _discover_mcp_sse_with_protocol(source, protocol_version)
        except Exception as exc:
            last_error = exc
    raise RuntimeError(str(last_error or 'MCP SSE discovery failed'))


def discover_mcp_http_source(source: dict) -> dict:
    transport = normalize_mcp_transport(source.get('transport', 'auto'))
    if transport == 'streamable_http':
        return discover_mcp_streamable_http_source(source)
    if transport == 'sse':
        return discover_mcp_sse_source(source)
    try:
        return discover_mcp_streamable_http_source(source)
    except Exception as streamable_exc:
        try:
            return discover_mcp_sse_source(source)
        except Exception as sse_exc:
            raise RuntimeError(f'Streamable HTTP failed: {streamable_exc}; SSE failed: {sse_exc}')


def discover_mcp_source(source: dict) -> dict:
    source_type = str(source.get('type', '') or '').strip().lower()
    if source_type == 'mcp_stdio':
        return discover_mcp_stdio_source(source)
    if source_type == 'mcp_http':
        return discover_mcp_http_source(source)
    raise RuntimeError(f'Unsupported MCP source type: {source_type}')


def _open_mcp_streamable_http_session(source: dict) -> tuple[str, str, str]:
    endpoint = str(source.get('endpoint', '') or '').strip()
    if not endpoint:
        raise RuntimeError('Endpoint URL is empty')
    last_error = None
    for protocol_version in MCP_HTTP_PROTOCOL_VERSIONS:
        session_id = ''
        try:
            init_payload, session_id = _mcp_http_rpc(
                endpoint,
                source,
                'initialize',
                {
                    'protocolVersion': protocol_version,
                    'capabilities': {},
                    'clientInfo': {'name': NAME, 'version': VERSION},
                },
                1,
                protocol_version,
                session_id,
            )
            init_result = init_payload.get('result', {}) if isinstance(init_payload, dict) else {}
            negotiated_version = str(init_result.get('protocolVersion') or protocol_version) if isinstance(init_result, dict) else protocol_version
            _mcp_http_rpc(endpoint, source, 'notifications/initialized', {}, None, negotiated_version, session_id)
            return endpoint, negotiated_version, session_id
        except Exception as exc:
            last_error = exc
    raise RuntimeError(str(last_error or 'MCP HTTP initialization failed'))


def list_mcp_streamable_http_tools(source: dict) -> list[dict]:
    endpoint, protocol_version, session_id = _open_mcp_streamable_http_session(source)
    payload, _session_id = _mcp_http_rpc(endpoint, source, 'tools/list', {}, 2, protocol_version, session_id)
    return _mcp_raw_list_result(payload, 'tools')


def call_mcp_streamable_http_tool(source: dict, tool_name: str, arguments: dict | None = None) -> dict:
    endpoint, protocol_version, session_id = _open_mcp_streamable_http_session(source)
    payload, _session_id = _mcp_http_rpc(
        endpoint,
        source,
        'tools/call',
        {'name': tool_name, 'arguments': arguments or {}},
        2,
        protocol_version,
        session_id,
    )
    return payload.get('result', {}) if isinstance(payload, dict) else {}


def list_mcp_stdio_tools(source: dict) -> list[dict]:
    session = McpStdioSession(source).start()
    try:
        session.request(
            'initialize',
            {
                'protocolVersion': MCP_HTTP_PROTOCOL_VERSIONS[0],
                'capabilities': {},
                'clientInfo': {'name': NAME, 'version': VERSION},
            },
        )
        session.notify('notifications/initialized', {})
        return _mcp_raw_list_result(session.request('tools/list', {}), 'tools')
    finally:
        session.close()


def call_mcp_stdio_tool(source: dict, tool_name: str, arguments: dict | None = None) -> dict:
    session = McpStdioSession(source).start()
    try:
        session.request(
            'initialize',
            {
                'protocolVersion': MCP_HTTP_PROTOCOL_VERSIONS[0],
                'capabilities': {},
                'clientInfo': {'name': NAME, 'version': VERSION},
            },
        )
        session.notify('notifications/initialized', {})
        payload = session.request('tools/call', {'name': tool_name, 'arguments': arguments or {}})
        return payload.get('result', {}) if isinstance(payload, dict) else {}
    finally:
        session.close()


def _open_mcp_sse_session(source: dict) -> McpSseSession:
    last_error = None
    for protocol_version in MCP_HTTP_PROTOCOL_VERSIONS:
        session = None
        try:
            session = McpSseSession(source, protocol_version).start()
            init_payload = session.request(
                'initialize',
                {
                    'protocolVersion': protocol_version,
                    'capabilities': {},
                    'clientInfo': {'name': NAME, 'version': VERSION},
                },
            )
            init_result = init_payload.get('result', {}) if isinstance(init_payload, dict) else {}
            negotiated_version = str(init_result.get('protocolVersion') or protocol_version) if isinstance(init_result, dict) else protocol_version
            session.protocol_version = negotiated_version
            session.notify('notifications/initialized', {})
            return session
        except Exception as exc:
            last_error = exc
            try:
                if session is not None:
                    session.close()
            except Exception:
                pass
    raise RuntimeError(str(last_error or 'MCP SSE initialization failed'))


def list_mcp_sse_tools(source: dict) -> list[dict]:
    session = _open_mcp_sse_session(source)
    try:
        return _mcp_raw_list_result(session.request('tools/list', {}), 'tools')
    finally:
        session.close()


def call_mcp_sse_tool(source: dict, tool_name: str, arguments: dict | None = None) -> dict:
    session = _open_mcp_sse_session(source)
    try:
        payload = session.request('tools/call', {'name': tool_name, 'arguments': arguments or {}})
        return payload.get('result', {}) if isinstance(payload, dict) else {}
    finally:
        session.close()


def list_mcp_http_tools(source: dict) -> list[dict]:
    transport = normalize_mcp_transport(source.get('transport', 'auto'))
    if transport == 'streamable_http':
        return list_mcp_streamable_http_tools(source)
    if transport == 'sse':
        return list_mcp_sse_tools(source)
    try:
        return list_mcp_streamable_http_tools(source)
    except Exception:
        return list_mcp_sse_tools(source)


def call_mcp_http_tool(source: dict, tool_name: str, arguments: dict | None = None) -> dict:
    transport = normalize_mcp_transport(source.get('transport', 'auto'))
    if transport == 'streamable_http':
        return call_mcp_streamable_http_tool(source, tool_name, arguments)
    if transport == 'sse':
        return call_mcp_sse_tool(source, tool_name, arguments)
    try:
        return call_mcp_streamable_http_tool(source, tool_name, arguments)
    except Exception:
        return call_mcp_sse_tool(source, tool_name, arguments)


def list_mcp_source_tools(source: dict) -> list[dict]:
    source_type = str(source.get('type', '') or '').strip().lower()
    if source_type == 'mcp_stdio':
        return list_mcp_stdio_tools(source)
    if source_type == 'mcp_http':
        return list_mcp_http_tools(source)
    return []


def call_mcp_source_tool(source: dict, tool_name: str, arguments: dict | None = None) -> dict:
    source_type = str(source.get('type', '') or '').strip().lower()
    if source_type == 'mcp_stdio':
        return call_mcp_stdio_tool(source, tool_name, arguments)
    if source_type == 'mcp_http':
        return call_mcp_http_tool(source, tool_name, arguments)
    raise RuntimeError(f'Unsupported MCP source type: {source_type}')


def is_mcp_tool_potentially_mutating(tool_name: str) -> bool:
    name = str(tool_name or '').strip().lower()
    mutating_tokens = (
        'create', 'update', 'delete', 'remove', 'write', 'merge', 'close',
        'assign', 'run', 'rerun', 'cancel', 'approve', 'reject', 'submit',
        'send', 'post', 'put', 'patch', 'star_', 'unstar', 'fork',
    )
    return any(token in name for token in mutating_tokens)


def _safe_openai_tool_name(source_index: int, tool_index: int, tool_name: str) -> str:
    cleaned = re.sub(r'[^A-Za-z0-9_-]+', '_', str(tool_name or 'tool')).strip('_') or 'tool'
    return f'mcp_{source_index}_{tool_index}_{cleaned}'[:64]


def build_mcp_tool_runtime_bundle(sources: list[dict]) -> tuple[list[dict], dict]:
    tool_defs = []
    tool_map = {}
    for source_index, source in enumerate(normalize_external_context_sources(sources), start=1):
        if source.get('type') not in {'mcp_http', 'mcp_stdio'}:
            continue
        if not source.get('enabled', True) or not source.get('use_in_tool_runtime', True):
            continue
        try:
            tools = list_mcp_source_tools(source)
        except Exception:
            continue
        for tool_index, tool in enumerate(tools, start=1):
            if not isinstance(tool, dict):
                continue
            tool_name = str(tool.get('name', '') or '').strip()
            if not tool_name:
                continue
            function_name = _safe_openai_tool_name(source_index, tool_index, tool_name)
            schema = tool.get('inputSchema', {}) if isinstance(tool.get('inputSchema', {}), dict) else {}
            if not schema:
                schema = {'type': 'object', 'properties': {}}
            description = str(tool.get('description', '') or '').strip()
            source_name = str(source.get('name', '') or source.get('endpoint', '') or source.get('command', '') or 'MCP source').strip()
            tool_defs.append(
                {
                    'type': 'function',
                    'function': {
                        'name': function_name,
                        'description': f'[{source_name}] {description or tool_name}',
                        'parameters': schema,
                    },
                }
            )
            tool_map[function_name] = {
                'source': source,
                'source_name': source_name,
                'tool_name': tool_name,
                'read_only': bool(source.get('read_only', True)),
                'mutating': is_mcp_tool_potentially_mutating(tool_name),
            }
    return tool_defs, tool_map


def _mcp_tool_result_to_text(result) -> str:
    if not isinstance(result, dict):
        return str(result or '')
    blocks = []
    structured = result.get('structuredContent')
    if structured:
        try:
            blocks.append(json.dumps(structured, ensure_ascii=False, indent=2))
        except Exception:
            blocks.append(str(structured))
    content = result.get('content', [])
    if isinstance(content, list):
        for item in content:
            if isinstance(item, dict):
                if str(item.get('type', '') or '').lower() == 'text' and item.get('text') is not None:
                    blocks.append(str(item.get('text') or ''))
                else:
                    try:
                        blocks.append(json.dumps(item, ensure_ascii=False, indent=2))
                    except Exception:
                        blocks.append(str(item))
            elif item is not None:
                blocks.append(str(item))
    if not blocks and result:
        try:
            blocks.append(json.dumps(result, ensure_ascii=False, indent=2))
        except Exception:
            blocks.append(str(result))
    return '\n\n'.join(block.strip() for block in blocks if str(block or '').strip())


def _find_mcp_tool(tools: list[dict], names: list[str]) -> dict | None:
    by_name = {
        str(tool.get('name', '') or '').strip().lower(): tool
        for tool in tools
        if isinstance(tool, dict)
    }
    for name in names:
        found = by_name.get(name.lower())
        if found:
            return found
    for name in names:
        name_lower = name.lower()
        for tool_name, tool in by_name.items():
            if name_lower in tool_name:
                return tool
    return None


def _mcp_tool_required_fields(tool: dict) -> set[str]:
    schema = tool.get('inputSchema', {}) if isinstance(tool, dict) else {}
    required = schema.get('required', []) if isinstance(schema, dict) else []
    return {str(item) for item in required} if isinstance(required, list) else set()


def _mcp_tool_properties(tool: dict) -> dict:
    schema = tool.get('inputSchema', {}) if isinstance(tool, dict) else {}
    properties = schema.get('properties', {}) if isinstance(schema, dict) else {}
    return properties if isinstance(properties, dict) else {}


def _collect_values_by_keys(data, keys: set[str], found: list[str] | None = None) -> list[str]:
    found = found if found is not None else []
    if isinstance(data, dict):
        for key, value in data.items():
            if str(key).lower() in keys and isinstance(value, (str, int)):
                candidate = str(value).strip()
                if candidate and candidate not in found:
                    found.append(candidate)
            _collect_values_by_keys(value, keys, found)
    elif isinstance(data, list):
        for item in data:
            _collect_values_by_keys(item, keys, found)
    return found


def _mcp_text_to_json_candidates(text: str) -> list:
    candidates = []
    text = str(text or '').strip()
    if not text:
        return candidates
    for raw in (text,):
        try:
            candidates.append(json.loads(raw))
        except Exception:
            pass
    if not candidates:
        for match in re.finditer(r'(\{.*?\}|\[.*?\])', text, re.DOTALL):
            try:
                candidates.append(json.loads(match.group(1)))
            except Exception:
                continue
            if len(candidates) >= 3:
                break
    return candidates


def _mcp_is_probable_timestamp_token(value: str) -> bool:
    text = str(value or '').strip()
    if not text:
        return False
    if re.match(r'^\d{4}-\d{2}-\d{2}(?:[T\s]\d{2}.*)?$', text):
        return True
    if re.match(r'^\d{4}-\d{2}-\d{2}T?\d*$', text):
        return True
    if re.match(r'^\d{2,4}[-/]\d{1,2}[-/]\d{1,2}', text):
        return True
    return False


def _mcp_is_identity_candidate(value: str) -> bool:
    text = str(value or '').strip()
    if not text or len(text) > 80:
        return False
    lower = text.lower()
    if lower in {'null', 'none', 'true', 'false', 'unknown'}:
        return False
    if _mcp_is_probable_timestamp_token(text):
        return False
    if re.fullmatch(r'\d+', text):
        return False
    if any(token in text for token in ('://', '/', '\\', '@')):
        return False
    return bool(re.fullmatch(r'[A-Za-z][A-Za-z0-9_.-]{2,79}', text))


def _mcp_identity_terms_from_url(value: str) -> list[str]:
    text = str(value or '').strip().rstrip('/')
    if not text or '/' not in text:
        return []
    tail = text.rsplit('/', 1)[-1].strip()
    return [tail] if _mcp_is_identity_candidate(tail) else []


def _mcp_identity_terms_from_text(text: str) -> list[str]:
    keys = {'login', 'username', 'user', 'name', 'account', 'owner'}
    url_keys = {'profile_url', 'html_url', 'account_url'}
    terms = []
    for parsed in _mcp_text_to_json_candidates(text):
        for value in _collect_values_by_keys(parsed, keys):
            if _mcp_is_identity_candidate(value) and value not in terms:
                terms.append(value)
        for value in _collect_values_by_keys(parsed, url_keys):
            for term in _mcp_identity_terms_from_url(value):
                if term not in terms:
                    terms.append(term)
    for match in re.finditer(r'\b[A-Za-z0-9][A-Za-z0-9_.-]{2,}\b', str(text or '')):
        token = match.group(0)
        if '-' in token and _mcp_is_identity_candidate(token) and token not in terms:
            terms.append(token)
    return terms[:5]


def _mcp_question_keywords(question_text: str) -> str:
    text = str(question_text or '').strip()
    if not text:
        return ''
    replacements = {
        '模板': 'template',
        '简介': 'description',
        '仓库': 'repository',
        '项目': 'project',
        '文件': 'file',
        '内容': 'content',
        '读取': 'read',
        '查找': 'search',
    }
    expanded_parts = [text]
    protected_terms = []
    for zh, en in replacements.items():
        if zh in text:
            protected_terms.append(en)
    cjk_term_map = {
        'latex模板': ['latex', 'template'],
        'LaTeX模板': ['latex', 'template'],
        '简历模板': ['resume', 'template'],
        '论文模板': ['thesis', 'template'],
        '项目简介': ['description'],
        '仓库简介': ['description'],
    }
    for zh, terms in cjk_term_map.items():
        if zh.lower() in text.lower():
            protected_terms.extend(terms)
    if protected_terms:
        expanded_parts.append(' '.join(protected_terms))
    expanded = ' '.join(expanded_parts)
    tokens = re.findall(r'[A-Za-z0-9_.:-]+|[\u4e00-\u9fff]+', expanded)
    stopwords = {
        '我', '我的', '帮我', '看看', '一下', '怎么', '如何', '什么', '这个', '那个',
        '上', '里', '里面', '写的', '是', '吗', '呢', 'github', 'GitHub',
        '帮我看看', '请', '看看github上我的', 'the', 'a', 'an', 'of',
    }
    kept = []
    for term in protected_terms:
        lower = term.lower()
        if lower not in kept:
            kept.append(lower)
    for token in tokens:
        lower = token.lower()
        if lower in stopwords or token in stopwords:
            continue
        if not token.isascii() and len(token) > 2:
            for zh, en in replacements.items():
                if zh in token:
                    lower = en
                    break
            else:
                continue
        if len(token) == 1 and not token.isascii():
            continue
        if lower not in kept:
            kept.append(lower if token.isascii() else token)
    return ' '.join(kept[:8]).strip()


def _mcp_question_needs_identity_scope(question_text: str) -> bool:
    return bool(re.search(r'\b(my|mine|me)\b|我的|我\b', str(question_text or ''), re.IGNORECASE))


def _mcp_tool_supports_identity_qualifiers(tool: dict) -> bool:
    if not isinstance(tool, dict):
        return False
    name = str(tool.get('name', '') or '').strip().lower()
    description = str(tool.get('description', '') or '').lower()
    schema_text = json.dumps(tool.get('inputSchema', {}), ensure_ascii=False).lower()
    haystack = f'{name} {description} {schema_text}'
    if any(token in haystack for token in ('user:', 'owner:', 'repo:', 'advanced search syntax', 'github')):
        return True
    return name in {
        'search_code',
        'search_repositories',
        'search_issues',
        'search_pull_requests',
        'get_file_contents',
    }


def _mcp_identity_scoped_query(query: str,
                               identity_terms: list[str],
                               tool: dict,
                               question_text: str) -> str:
    raw_query = re.sub(r'\s+', ' ', str(query or '')).strip()
    if not raw_query or not _mcp_question_needs_identity_scope(question_text):
        return raw_query
    if not identity_terms or not _mcp_tool_supports_identity_qualifiers(tool):
        return raw_query
    if re.search(r'\b(user|owner|repo):[^\s]+', raw_query, re.IGNORECASE):
        return raw_query
    identity = str(identity_terms[0] or '').strip()
    if not _mcp_is_identity_candidate(identity):
        return raw_query
    scoped_query = raw_query
    scoped_query = re.sub(re.escape(identity), ' ', scoped_query, flags=re.IGNORECASE)
    scoped_query = re.sub(r'\s+', ' ', scoped_query).strip()
    return f'user:{identity}' + (f' {scoped_query}' if scoped_query else '')


def _mcp_query_variants(question_text: str, identity_terms: list[str], tool: dict) -> list[str]:
    original = re.sub(r'\s+', ' ', str(question_text or '')).strip()
    keywords = _mcp_question_keywords(question_text)
    keyword_terms = [term for term in keywords.split() if term]
    broad_terms = [
        term for term in keyword_terms
        if term.lower() not in {'description', 'project', 'repository', 'read', 'search', 'content'}
    ]
    focused_keywords = ' '.join(
        term for term in broad_terms
    ).strip() or keywords
    schema_text = json.dumps(tool.get('inputSchema', {}), ensure_ascii=False).lower() if isinstance(tool, dict) else ''
    variants = []
    identity_first = _mcp_question_needs_identity_scope(question_text)
    supports_identity_qualifiers = _mcp_tool_supports_identity_qualifiers(tool)
    if identity_first:
        for identity in identity_terms:
            identity = str(identity or '').strip()
            if not identity:
                continue
            if supports_identity_qualifiers or 'user:' in schema_text or 'advanced search syntax' in schema_text:
                for term in broad_terms:
                    value = f'user:{identity} {term}'.strip()
                    if value and value not in variants:
                        variants.append(value)
                for value in (
                    f'user:{identity} {focused_keywords}'.strip(),
                    f'user:{identity} {keywords}'.strip(),
                    f'user:{identity}'.strip(),
                ):
                    if value and value not in variants:
                        variants.append(value)
            if supports_identity_qualifiers or 'owner:' in schema_text:
                for term in broad_terms:
                    value = f'owner:{identity} {term}'.strip()
                    if value and value not in variants:
                        variants.append(value)
                for value in (
                    f'owner:{identity} {focused_keywords}'.strip(),
                    f'owner:{identity} {keywords}'.strip(),
                    f'owner:{identity}'.strip(),
                ):
                    if value and value not in variants:
                        variants.append(value)
            for value in (
                *(f'{identity} {term}'.strip() for term in broad_terms),
                *(f'{term} {identity}'.strip() for term in broad_terms),
                f'{identity} {focused_keywords}'.strip(),
                f'{focused_keywords} {identity}'.strip(),
                f'{identity} {keywords}'.strip(),
                identity,
            ):
                if value and value not in variants:
                    variants.append(value)
    for value in (*broad_terms, focused_keywords, keywords):
        if value and value not in variants:
            variants.append(value)
    if not identity_first:
        for identity in identity_terms:
            identity = str(identity or '').strip()
            if not identity:
                continue
            for value in (
                *(f'{identity} {term}'.strip() for term in broad_terms),
                *(f'{term} {identity}'.strip() for term in broad_terms),
                f'{identity} {focused_keywords}'.strip(),
                f'{focused_keywords} {identity}'.strip(),
                f'{identity} {keywords}'.strip(),
            ):
                if value and value not in variants:
                    variants.append(value)
            if supports_identity_qualifiers or 'user:' in schema_text or 'advanced search syntax' in schema_text:
                for term in broad_terms:
                    value = f'user:{identity} {term}'.strip()
                    if value and value not in variants:
                        variants.append(value)
                for value in (
                    f'user:{identity} {focused_keywords}'.strip(),
                    f'user:{identity} {keywords}'.strip(),
                    f'user:{identity}'.strip(),
                ):
                    if value and value not in variants:
                        variants.append(value)
            if supports_identity_qualifiers or 'owner:' in schema_text:
                for term in broad_terms:
                    value = f'owner:{identity} {term}'.strip()
                    if value and value not in variants:
                        variants.append(value)
                for value in (
                    f'owner:{identity} {focused_keywords}'.strip(),
                    f'owner:{identity} {keywords}'.strip(),
                    f'owner:{identity}'.strip(),
                ):
                    if value and value not in variants:
                        variants.append(value)
    if original and original not in variants and not query_contains_cjk(original):
        variants.append(original)
    return variants[:MCP_RETRIEVAL_QUERY_VARIANTS]


def _mcp_field_role(field_name: str, field_schema: dict) -> str:
    name = str(field_name or '').strip().lower()
    description = str((field_schema or {}).get('description', '') or '').lower()
    joined = f'{name} {description}'
    if name in {'query', 'q', 'search', 'keyword', 'keywords', 'term', 'terms', 'text'}:
        return 'query'
    if any(token in joined for token in ('search query', 'keyword', 'query string', 'free text')):
        return 'query'
    if name in {'limit', 'first', 'top', 'count', 'perpage', 'per_page', 'pagesize', 'page_size', 'max_results'}:
        return 'limit'
    if name == 'page' or name.endswith('_page'):
        return 'page'
    if name in {'minimal_output', 'minimal', 'summary_only'}:
        return 'minimal'
    if name in {'sort', 'order'}:
        return 'sort'
    return ''


def _mcp_tool_accepts_query(tool: dict) -> bool:
    properties = _mcp_tool_properties(tool)
    return any(_mcp_field_role(key, value if isinstance(value, dict) else {}) == 'query' for key, value in properties.items())


def _mcp_args_for_query(tool: dict, query: str) -> dict | None:
    properties = _mcp_tool_properties(tool)
    required = _mcp_tool_required_fields(tool)
    args = {}
    for field_name, field_schema in properties.items():
        field_schema = field_schema if isinstance(field_schema, dict) else {}
        role = _mcp_field_role(field_name, field_schema)
        if role == 'query':
            args[field_name] = query
        elif role == 'limit':
            args[field_name] = 10
        elif role == 'page':
            args[field_name] = 1
        elif role == 'minimal':
            args[field_name] = True
        elif role == 'sort' and field_name in required:
            enum = field_schema.get('enum', [])
            if isinstance(enum, list) and enum:
                args[field_name] = enum[0]
    missing = required - set(args.keys())
    if missing:
        return None
    return args


def _mcp_args_for_noarg_tool(tool: dict) -> dict | None:
    required = _mcp_tool_required_fields(tool)
    if required:
        return None
    args = {}
    for field_name, field_schema in _mcp_tool_properties(tool).items():
        role = _mcp_field_role(field_name, field_schema if isinstance(field_schema, dict) else {})
        if role == 'limit':
            args[field_name] = 10
        elif role == 'page':
            args[field_name] = 1
        elif role == 'minimal':
            args[field_name] = True
    return args


def _mcp_call_signature(tool_name: str, args: dict) -> tuple[str, str]:
    try:
        args_key = json.dumps(args or {}, ensure_ascii=False, sort_keys=True)
    except Exception:
        args_key = str(args or {})
    return str(tool_name or '').strip(), args_key


def _mcp_emit_progress(progress_callback, message: str) -> None:
    if progress_callback is None:
        return
    try:
        progress_callback(str(message or '').strip())
    except Exception:
        pass


def _mcp_text_preview(text: str, limit: int = 700) -> str:
    compact = re.sub(r'\s+', ' ', str(text or '')).strip()
    if len(compact) <= limit:
        return compact
    return compact[:limit].rstrip() + '...'


def _mcp_tool_retrieval_score(tool: dict, question_text: str) -> int:
    if not isinstance(tool, dict):
        return -100
    name = str(tool.get('name', '') or '').strip()
    if not name or is_mcp_tool_potentially_mutating(name):
        return -100
    haystack = f"{name} {tool.get('description', '')}".lower()
    score = 0
    if any(token in haystack for token in ('search', 'find', 'query', 'lookup')):
        score += 80
    if any(token in haystack for token in ('list', 'read', 'get', 'fetch', 'content')):
        score += 35
    for term in _mcp_question_keywords(question_text).split():
        if len(term) > 2 and term.lower() in haystack:
            score += 8
    if _mcp_tool_accepts_query(tool):
        score += 20
    elif _mcp_args_for_noarg_tool(tool) is not None:
        score += 8
    return score


def _mcp_identity_tools(tools: list[dict]) -> list[dict]:
    candidates = []
    identity_tokens = (
        'get_me',
        'whoami',
        'who am i',
        'current user',
        'current_user',
        'authenticated user',
        'authenticated_user',
        'profile',
        'account',
        'me',
        'viewer',
        'self',
        'self_info',
        'current',
        'session user',
        'session_user',
        'user info',
        'user_info',
        'identity',
        'auth identity',
        'auth_identity',
        'principal',
    )
    for tool in tools:
        if not isinstance(tool, dict) or _mcp_args_for_noarg_tool(tool) is None:
            continue
        name = str(tool.get('name', '') or '').lower()
        description = str(tool.get('description', '') or '').lower()
        normalized = f'{name} {description}'.replace('-', '_')
        if any(token in normalized for token in identity_tokens):
            candidates.append(tool)
    return candidates[:1]


def _mcp_tool_lookup(tools: list[dict]) -> dict[str, dict]:
    lookup = {}
    for tool in tools:
        if not isinstance(tool, dict):
            continue
        name = str(tool.get('name', '') or '').strip()
        if name:
            lookup[name.lower()] = tool
    return lookup


def _mcp_planner_candidate_tools(tools: list[dict], question_text: str) -> list[dict]:
    selected = []

    def add_tool(tool: dict):
        name = str(tool.get('name', '') or '').strip()
        if not name or is_mcp_tool_potentially_mutating(name):
            return
        if all(str(existing.get('name', '') or '').strip().lower() != name.lower() for existing in selected):
            selected.append(tool)

    for tool in _mcp_identity_tools(tools):
        add_tool(tool)
    scored = []
    for tool in tools:
        score = _mcp_tool_retrieval_score(tool, question_text)
        if score > 0:
            scored.append((score, str(tool.get('name', '') or ''), tool))
    scored.sort(key=lambda item: (-item[0], item[1]))
    for _score, _name, tool in scored:
        add_tool(tool)
        if len(selected) >= MCP_RETRIEVAL_PLANNER_MAX_TOOLS:
            break
    if len(selected) < MCP_RETRIEVAL_PLANNER_MAX_TOOLS:
        for tool in tools:
            add_tool(tool)
            if len(selected) >= MCP_RETRIEVAL_PLANNER_MAX_TOOLS:
                break
    return selected[:MCP_RETRIEVAL_PLANNER_MAX_TOOLS]


def _mcp_tool_summary_for_planner(tool: dict) -> dict:
    properties = _mcp_tool_properties(tool)
    required = _mcp_tool_required_fields(tool)
    summarized_properties = {}
    for index, (field_name, field_schema) in enumerate(properties.items()):
        if index >= 16:
            break
        field_schema = field_schema if isinstance(field_schema, dict) else {}
        item = {
            'type': field_schema.get('type', ''),
            'description': _mcp_text_preview(str(field_schema.get('description', '') or ''), 180),
            'required': field_name in required,
        }
        enum = field_schema.get('enum')
        if isinstance(enum, list) and enum:
            item['enum'] = enum[:12]
        summarized_properties[field_name] = item
    return {
        'name': str(tool.get('name', '') or '').strip(),
        'description': _mcp_text_preview(str(tool.get('description', '') or ''), 420),
        'input': {
            'required': sorted(required),
            'properties': summarized_properties,
        },
    }


def build_mcp_retrieval_planner_messages(source_name: str,
                                         question_text: str,
                                         identity_terms: list[str],
                                         tools: list[dict],
                                         observations: list[dict],
                                         attempted_signatures: set[tuple[str, str]]) -> list[dict]:
    tool_summaries = [_mcp_tool_summary_for_planner(tool) for tool in tools]
    observation_summaries = []
    for item in observations[-8:]:
        observation_summaries.append(
            {
                'tool': item.get('tool_name', ''),
                'arguments': item.get('arguments', {}),
                'has_value': bool(item.get('has_value', False)),
                'preview': _mcp_text_preview(str(item.get('text', '') or ''), 900),
            }
        )
    attempted = [
        {'tool': tool_name, 'arguments_json': args_json}
        for tool_name, args_json in list(attempted_signatures)[-12:]
    ]
    return [
        {
            'role': 'system',
            'content': (
                'You are a retrieval planner for one MCP server.\n\n'
                'Your job is to choose the next read-only MCP tool calls that can gather context for the user request.\n'
                'Rules:\n'
                '- Return JSON only.\n'
                '- Use only tool names listed in Available tools.\n'
                '- Do not call tools that create, update, delete, write, post, patch, merge, approve, run, or otherwise mutate state.\n'
                '- Match arguments to the provided input schema. Do not invent required fields.\n'
                '- Do not repeat calls listed in Attempted calls.\n'
                '- Known identity terms are validated account/login/owner handles. Use them for owner/user qualifiers only as-is.\n'
                '- Never use dates, timestamps, numeric IDs, URL fragments, or error-code fragments as account/user/owner qualifiers.\n'
                '- If previous observations are empty because the query was too specific, broaden the query or choose a different search/read/list tool.\n'
                '- Prefer 1-3 high-value calls. If no safe useful call exists, return an empty calls list.\n\n'
                'Output format:\n'
                '{\n'
                '  "calls": [\n'
                '    {"tool": "tool_name", "arguments": {"key": "value"}, "reason": "short reason"}\n'
                '  ]\n'
                '}'
            ),
        },
        {
            'role': 'user',
            'content': json.dumps(
                {
                    'source': source_name,
                    'user_request': str(question_text or '').strip(),
                    'known_identity_terms': identity_terms,
                    'available_tools': tool_summaries,
                    'previous_observations': observation_summaries,
                    'attempted_calls': attempted,
                },
                ensure_ascii=False,
                indent=2,
            ),
        },
    ]


def _mcp_normalize_planned_args(tool: dict, args: dict | None) -> dict | None:
    if args is None:
        args = {}
    if not isinstance(args, dict):
        return None
    normalized = {str(key): value for key, value in args.items() if value is not None}
    properties = _mcp_tool_properties(tool)
    required = _mcp_tool_required_fields(tool)
    for field_name, field_schema in properties.items():
        field_schema = field_schema if isinstance(field_schema, dict) else {}
        role = _mcp_field_role(field_name, field_schema)
        if field_name in normalized:
            continue
        if role == 'limit':
            normalized[field_name] = 10
        elif role == 'page':
            normalized[field_name] = 1
        elif role == 'minimal':
            normalized[field_name] = True
        elif role == 'sort' and field_name in required:
            enum = field_schema.get('enum', [])
            if isinstance(enum, list) and enum:
                normalized[field_name] = enum[0]
    if required - set(normalized.keys()):
        return None
    return normalized


def normalize_mcp_retrieval_plan(plan: dict | None,
                                 tools: list[dict],
                                 attempted_signatures: set[tuple[str, str]],
                                 question_text: str = '',
                                 identity_terms: list[str] | None = None) -> list[dict]:
    if not isinstance(plan, dict):
        return []
    raw_calls = plan.get('calls')
    if not isinstance(raw_calls, list):
        raw_calls = plan.get('tool_calls') if isinstance(plan.get('tool_calls'), list) else []
    lookup = _mcp_tool_lookup(tools)
    calls = []
    for item in raw_calls:
        if not isinstance(item, dict):
            continue
        tool_name = str(item.get('tool', '') or item.get('tool_name', '') or item.get('name', '')).strip()
        tool = lookup.get(tool_name.lower())
        if tool is None:
            continue
        actual_tool_name = str(tool.get('name', '') or '').strip()
        if not actual_tool_name or is_mcp_tool_potentially_mutating(actual_tool_name):
            continue
        args = _mcp_normalize_planned_args(tool, item.get('arguments', item.get('args', {})))
        if args is None:
            continue
        for field_name, field_schema in _mcp_tool_properties(tool).items():
            field_schema = field_schema if isinstance(field_schema, dict) else {}
            if _mcp_field_role(field_name, field_schema) == 'query' and field_name in args:
                args[field_name] = _mcp_identity_scoped_query(
                    str(args.get(field_name, '') or ''),
                    list(identity_terms or []),
                    tool,
                    question_text,
                )
        signature = _mcp_call_signature(actual_tool_name, args)
        if signature in attempted_signatures:
            continue
        calls.append(
            {
                'tool': tool,
                'tool_name': actual_tool_name,
                'arguments': args,
                'reason': str(item.get('reason', '') or '').strip(),
            }
        )
        if len(calls) >= MCP_RETRIEVAL_PLANNER_MAX_CALLS:
            break
    return calls


def run_mcp_retrieval_planner(source_name: str,
                              question_text: str,
                              identity_terms: list[str],
                              tools: list[dict],
                              observations: list[dict],
                              attempted_signatures: set[tuple[str, str]]) -> list[dict]:
    store = load_settings_store()
    profile = get_planner_profile_from_store(store)
    api_key = str(profile.get('api_key', '') or '').strip()
    model = str(profile.get('model', '') or '').strip()
    if not api_key or not model:
        return []
    try:
        timeout = max(8, min(30, int(profile.get('timeout', 60) or 60)))
    except (TypeError, ValueError):
        timeout = 30
    candidate_tools = _mcp_planner_candidate_tools(tools, question_text)
    if not candidate_tools:
        return []
    messages = build_mcp_retrieval_planner_messages(
        source_name,
        question_text,
        identity_terms,
        candidate_tools,
        observations,
        attempted_signatures,
    )
    client = create_openai_client(api_key, profile_runtime_base_url(profile), timeout)
    response = client.chat.completions.create(
        model=model,
        messages=messages,
        stream=False,
    )
    plan_text = str(response.choices[0].message.content or '').strip()
    return normalize_mcp_retrieval_plan(
        parse_json_object_from_text(plan_text),
        candidate_tools,
        attempted_signatures,
        question_text,
        identity_terms,
    )


def _mcp_result_has_value(text: str) -> bool:
    stripped = str(text or '').strip()
    if not stripped or stripped in {'{}', '[]', 'null'}:
        return False
    for parsed in _mcp_text_to_json_candidates(stripped):
        if isinstance(parsed, dict):
            if parsed.get('total_count') == 0:
                return False
            if parsed.get('items') == []:
                return False
            if parsed:
                return True
        elif isinstance(parsed, list):
                return bool(parsed)
    return len(stripped) > 20


def _mcp_compact_result_text(text: str, max_items: int = 5) -> str:
    stripped = str(text or '').strip()
    if not stripped:
        return stripped
    candidates = _mcp_text_to_json_candidates(stripped)
    if not candidates:
        return stripped
    parsed = candidates[0]
    if not isinstance(parsed, dict) or not isinstance(parsed.get('items'), list):
        return stripped
    compact_items = []
    for item in parsed.get('items', [])[:max_items]:
        if not isinstance(item, dict):
            continue
        compact = {}
        for key in ('name', 'path', 'full_name', 'description', 'html_url', 'url'):
            if item.get(key) not in (None, ''):
                compact[key] = item.get(key)
        owner = item.get('owner') if isinstance(item.get('owner'), dict) else {}
        if owner.get('login'):
            compact['owner'] = owner.get('login')
        repository = item.get('repository') if isinstance(item.get('repository'), dict) else {}
        if repository:
            repo_compact = {}
            for key in ('full_name', 'name', 'description', 'html_url', 'private', 'fork'):
                if repository.get(key) not in (None, ''):
                    repo_compact[key] = repository.get(key)
            repo_owner = repository.get('owner') if isinstance(repository.get('owner'), dict) else {}
            if repo_owner.get('login'):
                repo_compact['owner'] = repo_owner.get('login')
            if repo_compact:
                compact['repository'] = repo_compact
        text_matches = item.get('text_matches')
        if isinstance(text_matches, list) and text_matches:
            fragments = []
            for match in text_matches[:2]:
                if isinstance(match, dict) and str(match.get('fragment', '') or '').strip():
                    fragments.append(_mcp_text_preview(str(match.get('fragment', '') or ''), 320))
            if fragments:
                compact['text_matches'] = fragments
        if compact:
            compact_items.append(compact)
    compact_result = {
        'total_count': parsed.get('total_count'),
        'incomplete_results': parsed.get('incomplete_results'),
        'items': compact_items,
    }
    try:
        return json.dumps(compact_result, ensure_ascii=False, indent=2)
    except Exception:
        return stripped


def _mcp_result_mentions_identity(text: str, identity_terms: list[str]) -> bool:
    identities = [
        str(term or '').strip().lower()
        for term in (identity_terms or [])
        if _mcp_is_identity_candidate(str(term or '').strip())
    ]
    if not identities:
        return True
    lowered = str(text or '').lower()
    return any(identity in lowered for identity in identities)


def _mcp_relevance_terms(question_text: str) -> list[str]:
    generic = {'description', 'project', 'repository', 'read', 'search', 'content'}
    terms = []
    for term in _mcp_question_keywords(question_text).split():
        lower = term.lower().strip()
        if not lower or lower in generic:
            continue
        if lower not in terms:
            terms.append(lower)
    return terms[:5]


def _mcp_result_relevance_tokens(text: str) -> set[str]:
    tokens = set()
    for token in re.findall(r'[A-Za-z0-9]+', str(text or '').lower()):
        if token:
            tokens.add(token)
    return tokens


def _mcp_term_aliases(term: str) -> set[str]:
    lower = str(term or '').lower().strip()
    aliases = {lower} if lower else set()
    if lower == 'latex':
        aliases.update({'latex', 'tex'})
    elif lower == 'template':
        aliases.update({'template', 'templates', 'templating'})
    elif lower.endswith('s') and len(lower) > 3:
        aliases.add(lower[:-1])
    else:
        aliases.add(lower + 's')
    return {alias for alias in aliases if alias}


def _mcp_result_matches_question_terms(text: str, question_text: str) -> bool:
    terms = _mcp_relevance_terms(question_text)
    if not terms:
        return True
    tokens = _mcp_result_relevance_tokens(text)
    if not tokens:
        return False
    return any(_mcp_term_aliases(term) & tokens for term in terms)


def _mcp_context_doc(source_name: str, source_type: str, tool_name: str, args: dict, content: str, max_chars: int, suffix: str = '') -> dict:
    label = tool_name + (f' / {suffix}' if suffix else '')
    args_preview = json.dumps(args or {}, ensure_ascii=False)
    body = f'Tool: {tool_name}\nArguments: {args_preview}\n\n{str(content or "").strip()}'
    return {
        'name': f'{source_name} / {label}',
        'content': body[:max_chars],
        'source_name': source_name,
        'source_type': source_type,
        'tool_name': tool_name,
    }


def _limit_documents_to_budget(documents: list[dict], max_chars: int) -> list[dict]:
    limited = []
    remaining = max(0, int(max_chars))
    for document in documents:
        content = str(document.get('content', '') or '')
        if not content or remaining <= 0:
            continue
        item = dict(document)
        item['content'] = content[:remaining]
        remaining -= len(item['content'])
        limited.append(item)
    return limited


def collect_mcp_external_context_documents(source: dict,
                                           question_text: str = '',
                                           progress_callback=None) -> list[dict]:
    documents = []
    source_type = str(source.get('type', 'mcp_http') or 'mcp_http').strip()
    source_name = str(source.get('name', '') or source.get('mcp_server_name', '') or 'MCP source').strip()
    _mcp_emit_progress(progress_callback, f'MCP {source_name}: discovering tools')
    try:
        tools = list_mcp_source_tools(source)
    except Exception as exc:
        return [{
            'name': f'{source_name} / connection error',
            'content': f'MCP source could not be queried: {exc}',
            'source_name': source_name,
            'source_type': source_type,
        }]

    max_chars = min(
        normalize_external_context_max_chars(source.get('max_chars', DEFAULT_EXTERNAL_CONTEXT_MAX_CHARS)),
        MCP_RETRIEVAL_SOURCE_BUDGET_CHARS,
    )
    identity_terms = []
    used_noarg_tools = set()
    attempted_signatures: set[tuple[str, str]] = set()
    observations: list[dict] = []
    diagnostics: list[str] = []
    no_value_counts_by_tool: dict[str, int] = {}
    tool_call_count = 0

    def call_and_record(tool: dict, args: dict, suffix: str = '') -> tuple[str, bool]:
        nonlocal tool_call_count
        tool_name = str(tool.get('name', '') or '').strip()
        if not tool_name:
            return '', False
        if no_value_counts_by_tool.get(tool_name, 0) >= MCP_RETRIEVAL_MAX_NO_VALUE_CALLS_PER_TOOL:
            diagnostics.append(f'{tool_name} skipped after repeated empty results.')
            return '', False
        signature = _mcp_call_signature(tool_name, args or {})
        if signature in attempted_signatures:
            return '', False
        if tool_call_count >= MCP_RETRIEVAL_MAX_TOOL_CALLS_PER_SOURCE:
            return '', False
        attempted_signatures.add(signature)
        tool_call_count += 1
        suffix_for_progress = f' ({suffix})' if suffix else ''
        _mcp_emit_progress(progress_callback, f'MCP {source_name}: {tool_name}{suffix_for_progress}')
        failed = False
        try:
            result = call_mcp_source_tool(source, tool_name, args or {})
            text = _mcp_tool_result_to_text(result)
        except Exception as exc:
            failed = True
            text = f'MCP tool call failed: {exc}'
        if not failed:
            text = _mcp_compact_result_text(text)
        has_value = (not failed) and _mcp_result_has_value(text)
        identity_mismatch = False
        relevance_mismatch = False
        if (
            has_value
            and _mcp_question_needs_identity_scope(question_text)
            and identity_terms
            and _mcp_tool_accepts_query(tool)
            and _mcp_tool_supports_identity_qualifiers(tool)
            and not _mcp_result_mentions_identity(text, identity_terms)
        ):
            identity_mismatch = True
            has_value = False
        if (
            has_value
            and _mcp_tool_accepts_query(tool)
            and not _mcp_result_matches_question_terms(text, question_text)
        ):
            relevance_mismatch = True
            has_value = False
        if not str(text or '').strip():
            text = 'MCP tool returned an empty result.'
        observations.append(
            {
                'tool_name': tool_name,
                'arguments': args or {},
                'text': text,
                'has_value': has_value,
                'failed': failed,
            }
        )
        if has_value and len(documents) < MCP_RETRIEVAL_MAX_STEPS_PER_SOURCE:
            documents.append(_mcp_context_doc(source_name, source_type, tool_name, args or {}, text, max_chars, suffix))
        elif failed:
            no_value_counts_by_tool[tool_name] = no_value_counts_by_tool.get(tool_name, 0) + 1
            diagnostics.append(f'{tool_name} {json.dumps(args or {}, ensure_ascii=False)} failed: {_mcp_text_preview(text)}')
        elif identity_mismatch:
            no_value_counts_by_tool[tool_name] = no_value_counts_by_tool.get(tool_name, 0) + 1
            diagnostics.append(
                f'{tool_name} {json.dumps(args or {}, ensure_ascii=False)} returned data outside requested identity '
                f'{identity_terms[:2]}: {_mcp_text_preview(text)}'
            )
        elif relevance_mismatch:
            no_value_counts_by_tool[tool_name] = no_value_counts_by_tool.get(tool_name, 0) + 1
            diagnostics.append(
                f'{tool_name} {json.dumps(args or {}, ensure_ascii=False)} returned data that does not match request keywords '
                f'{_mcp_relevance_terms(question_text)}: {_mcp_text_preview(text)}'
            )
        else:
            no_value_counts_by_tool[tool_name] = no_value_counts_by_tool.get(tool_name, 0) + 1
            diagnostics.append(f'{tool_name} {json.dumps(args or {}, ensure_ascii=False)} returned no matching data: {_mcp_text_preview(text)}')
        if _mcp_args_for_noarg_tool(tool) is not None:
            used_noarg_tools.add(tool_name)
        return text, has_value

    for tool in _mcp_identity_tools(tools):
        args = _mcp_args_for_noarg_tool(tool) or {}
        text, _has_value = call_and_record(tool, args, 'identity')
        for term in _mcp_identity_terms_from_text(text):
            if term not in identity_terms:
                identity_terms.append(term)
        if len(documents) >= MCP_RETRIEVAL_MAX_STEPS_PER_SOURCE:
            return _limit_documents_to_budget(documents, max_chars)

    for planner_round in range(MCP_RETRIEVAL_PLANNER_ROUNDS):
        if len(documents) >= MCP_RETRIEVAL_MAX_STEPS_PER_SOURCE:
            break
        if tool_call_count >= MCP_RETRIEVAL_MAX_TOOL_CALLS_PER_SOURCE:
            break
        _mcp_emit_progress(progress_callback, f'MCP {source_name}: planning retrieval step {planner_round + 1}')
        try:
            planned_calls = run_mcp_retrieval_planner(
                source_name,
                question_text,
                identity_terms,
                tools,
                observations,
                attempted_signatures,
            )
        except Exception as exc:
            diagnostics.append(f'planner failed: {exc}')
            planned_calls = []
        if not planned_calls:
            break
        calls_before = tool_call_count
        for planned in planned_calls:
            if len(documents) >= MCP_RETRIEVAL_MAX_STEPS_PER_SOURCE:
                break
            if tool_call_count >= MCP_RETRIEVAL_MAX_TOOL_CALLS_PER_SOURCE:
                break
            reason = str(planned.get('reason', '') or 'planner').strip()
            suffix = 'planner' + (f': {reason[:60]}' if reason else '')
            call_and_record(planned['tool'], planned.get('arguments') or {}, suffix)
        if tool_call_count == calls_before:
            break

    scored_tools = []
    for tool in tools:
        score = _mcp_tool_retrieval_score(tool, question_text)
        if score <= 0:
            continue
        scored_tools.append((score, str(tool.get('name', '') or ''), tool))
    scored_tools.sort(key=lambda item: (-item[0], item[1]))

    for _score, _name, tool in scored_tools:
        if len(documents) >= MCP_RETRIEVAL_MAX_STEPS_PER_SOURCE:
            break
        if tool_call_count >= MCP_RETRIEVAL_MAX_TOOL_CALLS_PER_SOURCE:
            break
        tool_name = str(tool.get('name', '') or '').strip()
        query_variants = _mcp_query_variants(question_text, identity_terms, tool)
        tried = False
        if _mcp_tool_accepts_query(tool):
            variants_tried_for_tool = 0
            for query in query_variants:
                if tool_call_count >= MCP_RETRIEVAL_MAX_TOOL_CALLS_PER_SOURCE:
                    break
                if variants_tried_for_tool >= MCP_RETRIEVAL_MAX_QUERY_VARIANTS_PER_TOOL:
                    break
                if no_value_counts_by_tool.get(tool_name, 0) >= MCP_RETRIEVAL_MAX_NO_VALUE_CALLS_PER_TOOL:
                    break
                args = _mcp_args_for_query(tool, query)
                if args is None:
                    continue
                for field_name, field_schema in _mcp_tool_properties(tool).items():
                    field_schema = field_schema if isinstance(field_schema, dict) else {}
                    if _mcp_field_role(field_name, field_schema) == 'query' and field_name in args:
                        args[field_name] = _mcp_identity_scoped_query(
                            str(args.get(field_name, '') or ''),
                            identity_terms,
                            tool,
                            question_text,
                        )
                if _mcp_call_signature(tool_name, args) in attempted_signatures:
                    continue
                tried = True
                variants_tried_for_tool += 1
                _text, has_value = call_and_record(tool, args, query[:80])
                if has_value or len(documents) >= MCP_RETRIEVAL_MAX_STEPS_PER_SOURCE:
                    break
            if tried:
                continue
        args = _mcp_args_for_noarg_tool(tool)
        if args is not None and tool_name not in used_noarg_tools:
            call_and_record(tool, args, 'list/read')

    if diagnostics and len(documents) < MCP_RETRIEVAL_MAX_STEPS_PER_SOURCE:
        diagnostic_text = (
            'MCP retrieval diagnostics. These calls were attempted but did not provide usable context.\n'
            'This is included so the model can see retrieval gaps instead of assuming the source was not queried.\n\n'
            + '\n'.join(f'- {line}' for line in diagnostics[-10:])
        )
        documents.append(
            {
                'name': f'{source_name} / retrieval diagnostics',
                'content': diagnostic_text[:max_chars],
                'source_name': source_name,
                'source_type': source_type,
                'tool_name': 'retrieval_diagnostics',
            }
        )
    elif not documents:
        documents.append(
            {
                'name': f'{source_name} / retrieval diagnostics',
                'content': 'MCP retrieval found no safe tool call that could gather context for this request.',
                'source_name': source_name,
                'source_type': source_type,
                'tool_name': 'retrieval_diagnostics',
            }
        )

    return _limit_documents_to_budget(documents, max_chars)


def format_mcp_discovery_summary(result: dict) -> str:
    if not result:
        return 'Click Discover to read tools, resources, and prompts from this MCP endpoint.'
    if not result.get('ok'):
        return f"Discovery failed:\n{result.get('discovery_error') or result.get('error') or 'Unknown error'}"
    server_name = result.get('mcp_server_name') or 'Unknown server'
    server_version = result.get('mcp_server_version') or ''
    protocol_version = result.get('mcp_protocol_version') or ''
    header = f'Server: {server_name}'
    if server_version:
        header += f' {server_version}'
    if protocol_version:
        header += f'\nProtocol: {protocol_version}'

    def names(key: str) -> str:
        items = result.get(key, [])
        if not isinstance(items, list) or not items:
            return 'none'
        values = []
        for item in items[:12]:
            if isinstance(item, dict):
                values.append(str(item.get('name') or item.get('uri') or item.get('title') or '').strip())
            else:
                values.append(str(item).strip())
        values = [value for value in values if value]
        suffix = '' if len(items) <= 12 else f' ... +{len(items) - 12}'
        return ', '.join(values) + suffix if values else 'none'

    return (
        f'{header}\n'
        f"Tools ({len(result.get('discovered_tools', []) or [])}): {names('discovered_tools')}\n"
        f"Resources ({len(result.get('discovered_resources', []) or [])}): {names('discovered_resources')}\n"
        f"Prompts ({len(result.get('discovered_prompts', []) or [])}): {names('discovered_prompts')}"
    )


TERMINAL_SHELL_MODE_OPTIONS = [
    ('full', 'Full (login + interactive)'),
    ('login', 'Login only'),
    ('interactive', 'Interactive only'),
    ('default', 'Default shell behavior'),
    ('clean', 'Clean (no rc files)'),
]
DEFAULT_TERMINAL_SHELL_MODE = 'interactive'


def normalize_terminal_shell_mode(value) -> str:
    candidate = str(value or DEFAULT_TERMINAL_SHELL_MODE).strip().lower()
    allowed = {key for key, _label in TERMINAL_SHELL_MODE_OPTIONS}
    return candidate if candidate in allowed else DEFAULT_TERMINAL_SHELL_MODE


def legacy_profile_snapshot() -> dict:
    third_party = read_text_file(BasePath + 'third.txt', '0') == '1'
    endpoint = DEFAULT_ENDPOINT
    api_key = read_text_file(BasePath + 'api.txt', '')
    if third_party:
        endpoint = normalize_endpoint_value(read_text_file(BasePath + 'bear.txt', DEFAULT_ENDPOINT))
        api_key = read_text_file(BasePath + 'api2.txt', api_key)
    model_value = read_text_file(BasePath + 'modelnow.txt', '')
    if not model_value:
        model_value = read_text_file(MODEL_LIST_PATH, DEFAULT_MODEL).splitlines()[0].strip() if read_text_file(MODEL_LIST_PATH, '') else DEFAULT_MODEL
    return normalize_profile_entry(
        {
            'name': 'Default',
            'endpoint': endpoint,
            'append_v1': True,
            'api_key': api_key,
            'model': model_value,
            'timeout': read_text_file(BasePath + 'timeout.txt', '60'),
            'show_references': read_text_file(BasePath + 'showref.txt', '0') == '1',
            'remember_history': read_text_file(BasePath + 'history.txt', '0') == '1',
            'remember_memory': True,
        },
        'Default',
    )


def normalize_userscript_records(records) -> list[dict]:
    normalized = []
    if not isinstance(records, list):
        return normalized
    for item in records:
        if not isinstance(item, dict):
            continue
        path = str(item.get('path', '') or '').strip()
        name = str(item.get('name', '') or '').strip() or os.path.basename(path)
        if not path:
            continue
        normalized.append({'name': name, 'path': path})
    return normalized


def parse_userscript_metadata(source: str) -> dict:
    meta = {'name': '', 'matches': [], 'includes': [], 'excludes': []}
    in_block = False
    for line in str(source or '').splitlines():
        stripped = line.strip()
        if stripped == '// ==UserScript==':
            in_block = True
            continue
        if stripped == '// ==/UserScript==':
            break
        if not in_block:
            continue
        match = re.match(r'//\s*@(\S+)\s*(.*)$', stripped)
        if not match:
            continue
        key, value = match.group(1), match.group(2).strip()
        if key == 'name' and value and not meta['name']:
            meta['name'] = value
        elif key == 'match' and value:
            meta['matches'].append(value)
        elif key == 'include' and value:
            meta['includes'].append(value)
        elif key == 'exclude' and value:
            meta['excludes'].append(value)
    return meta


def build_qt_userscript_source(source: str, index: int) -> str:
    meta = parse_userscript_metadata(source)
    script_name = meta.get('name') or f'userscript_{index}'
    source_url_name = re.sub(r'[^A-Za-z0-9_.-]+', '-', script_name).strip('-')[:80] or f'userscript-{index}'
    payload = {
        'id': f'userscript_{index}',
        'name': script_name,
        'matches': meta.get('matches', []),
        'includes': meta.get('includes', []),
        'excludes': meta.get('excludes', []),
    }
    prefix = r"""
(function () {
  const __broccoliMeta = %(meta)s;

  function __broccoliPatternMatches(pattern, href) {
    if (!pattern) return false;
    if (pattern === '<all_urls>') {
      return /^(https?|file):/i.test(href);
    }
    const escaped = String(pattern)
      .replace(/[|\\{}()[\]^$+?.]/g, '\\$&')
      .replace(/\*/g, '.*');
    try {
      return new RegExp('^' + escaped + '$').test(href);
    } catch (_) {
      return false;
    }
  }

  const __positivePatterns = []
    .concat(__broccoliMeta.matches || [])
    .concat(__broccoliMeta.includes || []);
  if (__positivePatterns.length &&
      !__positivePatterns.some((pattern) => __broccoliPatternMatches(pattern, location.href))) {
    return;
  }
  if ((__broccoliMeta.excludes || [])
      .some((pattern) => __broccoliPatternMatches(pattern, location.href))) {
    return;
  }

  const __storagePrefix = 'BroccoliUserscript:' + (__broccoliMeta.name || __broccoliMeta.id) + ':';
  const __menuCommands = new Map();
  let __menuCommandId = 1;

  function __GM_addStyle(css) {
    const style = document.createElement('style');
    style.textContent = String(css || '');
    (document.head || document.documentElement).appendChild(style);
    return style;
  }

  function __GM_getValue(key, defaultValue) {
    try {
      const raw = localStorage.getItem(__storagePrefix + String(key));
      if (raw === null || raw === undefined) return defaultValue;
      return JSON.parse(raw).value;
    } catch (_) {
      return defaultValue;
    }
  }

  function __GM_setValue(key, value) {
    try {
      localStorage.setItem(__storagePrefix + String(key), JSON.stringify({ value }));
    } catch (err) {
      console.warn('[Broccoli userscript] GM_setValue failed', err);
    }
  }

  function __GM_registerMenuCommand(label, callback) {
    const id = __menuCommandId++;
    __menuCommands.set(id, { label: String(label || ''), callback });
    return id;
  }

  function __GM_unregisterMenuCommand(id) {
    __menuCommands.delete(id);
  }

  function __GM_xmlhttpRequest(details) {
    const opts = details || {};
    const xhr = new XMLHttpRequest();
    xhr.open(opts.method || 'GET', opts.url, true);
    if (opts.responseType) xhr.responseType = opts.responseType;
    if (opts.timeout) xhr.timeout = opts.timeout;
    const headers = opts.headers || {};
    Object.keys(headers).forEach((key) => xhr.setRequestHeader(key, headers[key]));
    const buildResponse = () => {
      let responseText = '';
      try { responseText = xhr.responseText; } catch (_) {}
      return {
        finalUrl: xhr.responseURL || opts.url,
        readyState: xhr.readyState,
        response: xhr.response,
        responseHeaders: xhr.getAllResponseHeaders(),
        responseText,
        status: xhr.status,
        statusText: xhr.statusText,
      };
    };
    xhr.onload = () => { if (typeof opts.onload === 'function') opts.onload(buildResponse()); };
    xhr.onerror = () => { if (typeof opts.onerror === 'function') opts.onerror(buildResponse()); };
    xhr.onabort = () => { if (typeof opts.onabort === 'function') opts.onabort(buildResponse()); };
    xhr.ontimeout = () => { if (typeof opts.ontimeout === 'function') opts.ontimeout(buildResponse()); };
    xhr.send(opts.data === undefined ? null : opts.data);
    return { abort: () => xhr.abort() };
  }

  const GM = {
    addStyle: __GM_addStyle,
    getValue: __GM_getValue,
    setValue: __GM_setValue,
    registerMenuCommand: __GM_registerMenuCommand,
    unregisterMenuCommand: __GM_unregisterMenuCommand,
    xmlHttpRequest: __GM_xmlhttpRequest,
    xmlhttpRequest: __GM_xmlhttpRequest,
  };

  try {
    (function (
      GM,
      GM_addStyle,
      GM_getValue,
      GM_setValue,
      GM_registerMenuCommand,
      GM_unregisterMenuCommand,
      GM_xmlhttpRequest,
      unsafeWindow
    ) {
""" % {
        'meta': json.dumps(payload, ensure_ascii=False),
    }
    suffix = r"""
//# sourceURL=broccoli-%(source_url)s.user.js
    }).call(
      window,
      GM,
      __GM_addStyle,
      __GM_getValue,
      __GM_setValue,
      __GM_registerMenuCommand,
      __GM_unregisterMenuCommand,
      __GM_xmlhttpRequest,
      window
    );
  } catch (err) {
    console.error('[Broccoli userscript] ' + (__broccoliMeta.name || __broccoliMeta.id) + ' failed', err);
  }
})();
""" % {
        'source_url': source_url_name,
    }
    return prefix + '\n' + str(source or '') + '\n' + suffix


