def load_settings_store() -> dict:
    ensure_broccoli_data_dir()
    store = {}
    if os.path.exists(SETTINGS_PROFILES_PATH):
        try:
            with open(SETTINGS_PROFILES_PATH, 'r', encoding='utf-8') as handle:
                loaded = json.load(handle)
            if isinstance(loaded, dict):
                store = loaded
        except Exception:
            store = {}

    raw_profiles = store.get('profiles', [])
    profiles = []
    if isinstance(raw_profiles, list):
        for index, item in enumerate(raw_profiles, start=1):
            if isinstance(item, dict):
                profiles.append(normalize_profile_entry(item, f'Profile {index}'))
    if not profiles:
        profiles = [legacy_profile_snapshot()]

    globals_store = default_global_settings()
    if isinstance(store.get('globals'), dict):
        globals_store.update(
            {
                'custom_prompt': str(store['globals'].get('custom_prompt', globals_store['custom_prompt'])),
                'languages': str(store['globals'].get('languages', globals_store['languages'])),
                'ui_shortcut': str(store['globals'].get('ui_shortcut', globals_store['ui_shortcut'])) or DEFAULT_UI_SHORTCUT,
                'same_position_screenshot_shortcut': safe_normalize_optional_shortcut_text(
                    store['globals'].get(
                        'same_position_screenshot_shortcut',
                        globals_store['same_position_screenshot_shortcut'],
                    )
                ),
                'pdf_max_pages': int(store['globals'].get('pdf_max_pages', globals_store['pdf_max_pages'])),
                'embedding_profile': str(store['globals'].get('embedding_profile', globals_store['embedding_profile'])).strip(),
                'webfetch_download_path': str(store['globals'].get('webfetch_download_path', globals_store['webfetch_download_path'])).strip(),
                'always_on_top': bool(store['globals'].get('always_on_top', globals_store['always_on_top'])),
                'start_on_login': bool(store['globals'].get('start_on_login', globals_store['start_on_login'])),
                'terminal_shell_mode': normalize_terminal_shell_mode(
                    store['globals'].get('terminal_shell_mode', globals_store['terminal_shell_mode'])
                ),
                'terminal_use_bash': bool(store['globals'].get('terminal_use_bash', globals_store['terminal_use_bash'])),
                'annotation_pen_color': str(store['globals'].get('annotation_pen_color', globals_store['annotation_pen_color'])).strip() or '#FF3B30',
                'web_auto_send_after_inject': bool(store['globals'].get('web_auto_send_after_inject', globals_store['web_auto_send_after_inject'])),
                'webfetch_context_use_embedding': bool(store['globals'].get('webfetch_context_use_embedding', globals_store['webfetch_context_use_embedding'])),
                'generated_output_context_use_embedding': bool(store['globals'].get('generated_output_context_use_embedding', globals_store['generated_output_context_use_embedding'])),
                'external_context_enabled': bool(store['globals'].get('external_context_enabled', globals_store['external_context_enabled'])),
                'external_context_use_embedding': bool(store['globals'].get('external_context_use_embedding', globals_store['external_context_use_embedding'])),
                'external_context_max_chars': normalize_external_context_max_chars(
                    store['globals'].get('external_context_max_chars', globals_store['external_context_max_chars'])
                ),
                'mcp_tool_runtime_enabled': bool(store['globals'].get('mcp_tool_runtime_enabled', globals_store['mcp_tool_runtime_enabled'])),
                'prefer_displayed_history_context': bool(store['globals'].get('prefer_displayed_history_context', globals_store['prefer_displayed_history_context'])),
                'display_history_context_max_chars': normalize_display_history_context_max_chars(
                    store['globals'].get('display_history_context_max_chars', globals_store['display_history_context_max_chars'])
                ),
                'allow_blank_prompt_with_attachments': bool(
                    store['globals'].get('allow_blank_prompt_with_attachments', globals_store['allow_blank_prompt_with_attachments'])
                ),
                'skip_retrieval_for_blank_prompt': bool(
                    store['globals'].get('skip_retrieval_for_blank_prompt', globals_store['skip_retrieval_for_blank_prompt'])
                ),
                'clear_attachments_after_send': bool(
                    store['globals'].get('clear_attachments_after_send', globals_store['clear_attachments_after_send'])
                ),
                'code_execution_enabled': bool(store['globals'].get('code_execution_enabled', globals_store['code_execution_enabled'])),
                'code_execution_timeout': normalize_code_execution_timeout(
                    store['globals'].get('code_execution_timeout', globals_store['code_execution_timeout'])
                ),
                'memory_text': str(store['globals'].get('memory_text', globals_store['memory_text'])),
                'memory_retention_days': int(store['globals'].get('memory_retention_days', globals_store['memory_retention_days'])),
                'memory_last_rollup_date': str(store['globals'].get('memory_last_rollup_date', globals_store['memory_last_rollup_date'])).strip(),
            }
        )
        globals_store['skills'] = normalize_skill_records(store['globals'].get('skills', globals_store['skills']))
        globals_store['code_runners'] = normalize_code_runner_records(store['globals'].get('code_runners', globals_store['code_runners']))
        globals_store['specialized_profiles'] = normalize_specialized_profiles(
            store['globals'].get('specialized_profiles', globals_store.get('specialized_profiles'))
        )
        globals_store['specialized_execution_modes'] = normalize_specialized_execution_modes(
            store['globals'].get('specialized_execution_modes', globals_store.get('specialized_execution_modes'))
        )
        raw_userscripts = store['globals'].get('userscripts', globals_store['userscripts'])
        globals_store['userscripts'] = normalize_userscript_records(raw_userscripts)
        if 'external_context_sources' in store['globals']:
            globals_store['external_context_sources'] = normalize_external_context_sources(
                store['globals'].get('external_context_sources', [])
            )
        raw_memory_items = store['globals'].get('memory_items', globals_store['memory_items'])
        globals_store['memory_items'] = normalize_memory_item_records(raw_memory_items)
        globals_store.update(normalize_background_vision_settings(store['globals']))

    active_profile = str(store.get('active_profile', profiles[0]['name'])).strip()
    if active_profile not in {profile['name'] for profile in profiles}:
        active_profile = profiles[0]['name']

    return {
        'active_profile': active_profile,
        'profiles': profiles,
        'globals': globals_store,
    }


def save_settings_store(store: dict) -> None:
    ensure_broccoli_data_dir()
    with open(SETTINGS_PROFILES_PATH, 'w', encoding='utf-8') as handle:
        json.dump(store, handle, ensure_ascii=False, indent=2)


def is_matching_webfetch_filename(name: str) -> bool:
    name = str(name or '').strip()
    return bool(WEBFETCH_STRICT_RE.match(name) or WEBFETCH_LOOSE_RE.match(name))


def normalize_webfetch_page(page: dict, index: int) -> dict | None:
    if not isinstance(page, dict):
        return None
    url = str(page.get('url', '')).strip()
    title = str(page.get('title', '')).strip()
    text = str(page.get('text', '')).strip()
    if not url and not text:
        return None
    display_title = title or url or f'Page {index + 1}'
    page_id = str(page.get('id', '')).strip() or f'page-{index + 1}'
    return {
        'id': page_id,
        'url': url,
        'title': display_title,
        'domain': str(page.get('domain', '')).strip(),
        'captured_at': str(page.get('capturedAt', '')).strip(),
        'text': text,
        'links': page.get('links') if isinstance(page.get('links'), list) else [],
        'meta': page.get('meta') if isinstance(page.get('meta'), dict) else {},
    }


def load_webfetch_export(path: str) -> dict | None:
    if not path or not os.path.exists(path):
        return None
    try:
        with open(path, 'r', encoding='utf-8') as handle:
            data = json.load(handle)
    except Exception:
        return None
    if not isinstance(data, dict):
        return None
    schema = str(data.get('schema', '')).strip()
    if not schema.startswith('broccoli-webfetch'):
        return None
    raw_pages = data.get('pages')
    if not isinstance(raw_pages, list):
        return None
    pages = []
    for index, page in enumerate(raw_pages):
        normalized = normalize_webfetch_page(page, index)
        if normalized:
            pages.append(normalized)
    if not pages:
        return None
    exported_at = str(data.get('exportedAt', '')).strip() or datetime.datetime.now().isoformat(timespec='seconds')
    return {
        'path': path,
        'name': os.path.basename(path),
        'schema': schema,
        'exported_at': exported_at,
        'count': len(pages),
        'pages': pages,
    }


def list_webfetch_exports(folder: str) -> list[dict]:
    folder_path = Path(str(folder or '').strip())
    if not folder_path.exists():
        return []
    results = []
    for file_path in folder_path.glob('Broccoli-WebFetch_*.json'):
        if not is_matching_webfetch_filename(file_path.name):
            continue
        record = load_webfetch_export(str(file_path))
        if record:
            results.append(record)
    results.sort(key=lambda item: item.get('exported_at', ''), reverse=True)
    return results


def import_webfetch_file_to_inbox(source_path: str) -> dict | None:
    if not source_path or not os.path.exists(source_path):
        return None
    source = Path(source_path)
    if not is_matching_webfetch_filename(source.name):
        return None
    record = load_webfetch_export(str(source))
    if record is None:
        return None
    ensure_broccoli_data_dir()
    target = Path(WEBFETCH_INBOX_DIR) / source.name
    if source.resolve() != target.resolve():
        base = source.stem
        suffix = source.suffix
        counter = 2
        while target.exists():
            target = Path(WEBFETCH_INBOX_DIR) / f'{base}-{counter}{suffix}'
            counter += 1
        shutil.move(str(source), str(target))
    return load_webfetch_export(str(target))


def webfetch_documents_from_pages(pages: list[dict]) -> list[dict]:
    documents = []
    for index, page in enumerate(pages or []):
        normalized = normalize_webfetch_page(page, index)
        if normalized is None:
            continue
        text = normalized['text'].strip()
        if not text:
            continue
        header = []
        if normalized['title']:
            header.append(f"Title: {normalized['title']}")
        if normalized['url']:
            header.append(f"URL: {normalized['url']}")
        body = '\n'.join(header + [text]).strip()
        documents.append(
            {
                'name': normalized['title'] or normalized['url'] or f'Page {index + 1}',
                'content': body,
                'page': normalized,
            }
        )
    return documents


def load_webfetch_selection_attachment(path: str) -> dict | None:
    if not path or not os.path.exists(path):
        return None
    try:
        with open(path, 'r', encoding='utf-8') as handle:
            data = json.load(handle)
    except Exception:
        return None
    if not isinstance(data, dict):
        return None
    schema = str(data.get('schema', '')).strip()
    if not schema.startswith('broccoli-webfetch-selection'):
        return None
    raw_pages = data.get('pages')
    if not isinstance(raw_pages, list):
        return None
    pages = []
    for index, page in enumerate(raw_pages):
        normalized = normalize_webfetch_page(page, index)
        if normalized:
            pages.append(normalized)
    if not pages:
        return None
    exported_at = str(data.get('generatedAt', '')).strip() or datetime.datetime.now().isoformat(timespec='seconds')
    return {
        'path': path,
        'name': os.path.basename(path),
        'schema': schema,
        'exported_at': exported_at,
        'count': len(pages),
        'pages': pages,
        'source_path': str(data.get('sourcePath', '')).strip(),
    }


def normalize_webfetch_attachment_record(item: dict) -> dict | None:
    normalized = normalize_attachment_record(item)
    if normalized is None:
        return None
    stored_path = str(normalized.get('stored_path', '')).strip()
    if not stored_path:
        return None
    record = load_webfetch_selection_attachment(stored_path)
    if record is None:
        return None
    return normalized


def collect_webfetch_attachments_from_messages(messages: list[dict]) -> list[dict]:
    collected = []
    seen_paths = set()
    for message in messages or []:
        for attachment in (message.get('attachments') or []):
            normalized = normalize_webfetch_attachment_record(attachment)
            if normalized is None:
                continue
            stored_path = str(normalized.get('stored_path', '')).strip()
            if stored_path in seen_paths:
                continue
            seen_paths.add(stored_path)
            collected.append(normalized)
    return collected


