def probe_embedding_capability(profile: dict | None, force: bool = False) -> tuple[bool, str]:
    if profile is None:
        return False, 'No embedding profile selected.'
    endpoint = profile_runtime_base_url(profile)
    api_key = str(profile.get('api_key', '')).strip()
    model = str(profile.get('model', '')).strip()
    timeout = max(5, min(20, int(profile.get('timeout', 60) or 60)))
    if not api_key or not model:
        return False, 'Selected profile is missing API key or model.'

    cache_key = (endpoint, model, api_key[:12])
    if not force and cache_key in EMBEDDING_CAPABILITY_CACHE:
        return EMBEDDING_CAPABILITY_CACHE[cache_key]

    try:
        client = create_openai_client(api_key, endpoint, timeout)
        response = client.embeddings.create(model=model, input='Broccoli embedding capability probe')
        ok = bool(getattr(response, 'data', None) and getattr(response.data[0], 'embedding', None))
        result = (ok, 'Embedding endpoint is available.' if ok else 'Embedding request returned no vector.')
    except Exception as exc:
        result = (False, f'Embedding unavailable: {str(exc)}')

    EMBEDDING_CAPABILITY_CACHE[cache_key] = result
    return result


def serialize_shortcut(flags: int, key_token: str) -> str:
    parts = []
    for modifier in ('ctrl', 'alt', 'shift', 'cmd'):
        if flags & MODIFIER_FLAG_BITS[modifier]:
            parts.append(f'<{modifier}>')
    parts.append(key_token)
    return '+'.join(parts)


def normalize_shortcut_text(shortcut_text: str, default_shortcut: str) -> str:
    text = shortcut_text.strip().lower() if shortcut_text.strip() else default_shortcut
    tokens = [token.strip() for token in text.split('+') if token.strip()]
    flags = 0
    key_token = None

    for token in tokens:
        if token in MODIFIER_ALIASES:
            flags |= MODIFIER_FLAG_BITS[MODIFIER_ALIASES[token]]
            continue

        normalized_token = KEY_TOKEN_ALIASES.get(token, token)
        if len(normalized_token) == 1 and normalized_token in ANSI_KEYCODES:
            key_token = normalized_token
            continue
        if normalized_token in SPECIAL_KEYCODES:
            key_token = normalized_token
            continue
        raise ValueError(f'Unsupported shortcut token: {token}')

    if key_token is None:
        raise ValueError('Shortcut must contain a non-modifier key.')
    if flags == 0:
        raise ValueError('Shortcut must include at least one modifier key.')

    return serialize_shortcut(flags, key_token)


def normalize_optional_shortcut_text(shortcut_text: str) -> str:
    if not str(shortcut_text or '').strip():
        return ''
    return normalize_shortcut_text(str(shortcut_text), str(shortcut_text))


def safe_normalize_optional_shortcut_text(shortcut_text: str) -> str:
    try:
        return normalize_optional_shortcut_text(shortcut_text)
    except ValueError:
        return ''


def build_shortcut_spec(shortcut_text: str, default_shortcut: str) -> dict:
    normalized = normalize_shortcut_text(shortcut_text, default_shortcut)
    tokens = normalized.split('+')
    key_token = tokens[-1]
    flags = 0
    for token in tokens[:-1]:
        flags |= MODIFIER_FLAG_BITS[token.strip('<>')]
    if key_token in ANSI_KEYCODES:
        keycode = ANSI_KEYCODES[key_token]
    else:
        keycode = SPECIAL_KEYCODES[key_token]
    return {
        'normalized': normalized,
        'flags': flags,
        'keycode': keycode,
    }


MARKER_BLOCK_RE = re.compile(r'「「START」」([\s\S]*?)「「END」」')
BROCCOLI_OUTPUT_BLOCK_RE = re.compile(r'<broccoli-output\b([^>]*)>([\s\S]*?)</broccoli-output>', re.IGNORECASE)
BROCCOLI_OUTPUT_ATTR_RE = re.compile(r'([a-zA-Z_][\w-]*)\s*=\s*("([^"]*)"|\'([^\']*)\')')

OUTPUT_CAPTURE_INSTRUCTIONS = """
If this answer produces one final reusable deliverable for the user, append exactly one machine-readable block after the human-readable answer.
Use this exact format:
<broccoli-output type="code|text" title="Short title" filename="optional-name.ext">
final deliverable only
</broccoli-output>
Use type="code" for source code or scripts, and type="text" for a rewritten/transformed final text. Do not put alternatives in this block. If you discuss multiple options in the answer, still choose only the final recommended deliverable for this block. Do not include this block when there is no reusable final deliverable.
""".strip()


def normalize_conversation_text(text: str) -> str:
    normalized = text.replace('\r\n', '\n').replace('\r', '\n')
    normalized = re.sub(r'(?m)^([ \t]*)- A:\s*\n+', r'\1- A: ', normalized)
    normalized = re.sub(r'(?m)^([ \t]*)- Q:\s*\n+', r'\1- Q: ', normalized)
    normalized = re.sub(r'(?m)^[ \t]+(?=- [AQ]: )', '', normalized)
    normalized = re.sub(r'(?m)(?:^[ \t]*---[ \t]*\n?){2,}', '---\n', normalized)
    normalized = re.sub(r'(?m)^[ \t]*---[ \t]*\n*(?=- Q: )', '---\n\n', normalized)
    normalized = normalized.rstrip()
    return normalized


def ensure_message_separator(text: str) -> str:
    stripped = text.rstrip()
    if not stripped:
        return ''
    return stripped + '\n\n---\n\n'


def sanitize_custom_prompt_name(name: str, fallback: str = 'Prompt') -> str:
    cleaned = str(name or '').replace('<|', ' ').replace('|><|', ' ').replace('|>', ' ').replace('---', ' ')
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    return cleaned or fallback


def parse_custom_prompt_storage(raw_text: str) -> list[dict]:
    records = []
    for index, block in enumerate(str(raw_text or '').split('---'), start=1):
        piece = block.strip()
        if not piece:
            continue
        if '|><|' in piece:
            name_part, body_part = piece.split('|><|', 1)
            name = sanitize_custom_prompt_name(name_part.replace('<|', '').replace('|>', ''), f'Prompt {index}')
            body = body_part
            if body.startswith('<|'):
                body = body[2:]
            if body.endswith('|>'):
                body = body[:-2]
            body = body.strip('\n')
        else:
            name = f'Prompt {index}'
            body = piece
        records.append({'name': name, 'body': body})
    return records


def serialize_custom_prompt_storage(records: list[dict]) -> str:
    blocks = []
    for index, record in enumerate(records or [], start=1):
        if not isinstance(record, dict):
            continue
        name = sanitize_custom_prompt_name(record.get('name', ''), f'Prompt {index}')
        body = str(record.get('body', '') or '').replace('\r\n', '\n').replace('\r', '\n').strip('\n')
        if not name and not body:
            continue
        blocks.append(f'<|{name}|><|{body}|>')
    return '\n---\n'.join(blocks)


def load_custom_prompt_records() -> list[dict]:
    return parse_custom_prompt_storage(read_text_file(CUSTOM_PROMPT_PATH, ''))


def load_custom_prompt_items() -> list[tuple[str, str]]:
    items = []
    for index, record in enumerate(load_custom_prompt_records(), start=1):
        if not isinstance(record, dict):
            continue
        title = sanitize_custom_prompt_name(record.get('name', ''), f'Prompt {index}')
        body = str(record.get('body', '') or '')
        if title or body:
            items.append((title or 'Customized prompt', body))
    return items


def sanitize_skill_name(name: str, fallback: str = 'Skill') -> str:
    cleaned = str(name or '').replace('\n', ' ').replace('\r', ' ').replace('---', ' ')
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    return cleaned or fallback


def parse_skill_frontmatter(raw_text: str) -> dict:
    raw = str(raw_text or '').replace('\r\n', '\n').replace('\r', '\n').strip('\ufeff')
    result = {
        'name': '',
        'description': '',
        'body': raw,
        'raw_text': raw,
        'has_frontmatter': False,
    }
    if not raw.lstrip().startswith('---'):
        return result
    stripped = raw.lstrip()
    lines = stripped.split('\n')
    if not lines or lines[0].strip() != '---':
        return result
    end_index = None
    for index in range(1, len(lines)):
        if lines[index].strip() == '---':
            end_index = index
            break
    if end_index is None:
        return result
    meta_lines = lines[1:end_index]
    body = '\n'.join(lines[end_index + 1:]).strip('\n')
    meta = {}
    current_key = ''
    for line in meta_lines:
        if re.match(r'^\s+', line) and current_key:
            meta[current_key] = (meta.get(current_key, '') + ' ' + line.strip()).strip()
            continue
        if ':' not in line:
            current_key = ''
            continue
        key, value = line.split(':', 1)
        key = key.strip().lower()
        if key in {'name', 'description'}:
            meta[key] = value.strip().strip('"').strip("'")
            current_key = key
        else:
            current_key = ''
    result.update(
        {
            'name': sanitize_skill_name(meta.get('name', ''), ''),
            'description': str(meta.get('description', '') or '').strip(),
            'body': body,
            'has_frontmatter': True,
        }
    )
    return result


def normalize_skill_record(record, index: int = 1) -> dict | None:
    if isinstance(record, str):
        raw = record
        enabled = True
    elif isinstance(record, dict):
        raw = str(record.get('raw_text', record.get('content', record.get('body', ''))) or '')
        enabled = bool(record.get('enabled', True))
    else:
        return None
    raw = raw.replace('\r\n', '\n').replace('\r', '\n').strip('\n')
    if not raw:
        raw = DEFAULT_SKILL_TEMPLATE.replace('new-skill', f'new-skill-{index}', 1)
    parsed = parse_skill_frontmatter(raw)
    raw_name = sanitize_skill_name(parsed.get('name', ''), '')
    name = sanitize_skill_name(raw_name, f'Skill {index}')
    description = str(parsed.get('description', '') or '').strip()
    return {
        'name': name,
        'frontmatter_name': raw_name,
        'description': description,
        'body': str(parsed.get('body', '') or ''),
        'raw_text': raw,
        'enabled': enabled,
        'has_frontmatter': bool(parsed.get('has_frontmatter', False)),
    }


def normalize_skill_records(records) -> list[dict]:
    normalized = []
    if isinstance(records, str):
        try:
            decoded = json.loads(records)
            records = decoded if isinstance(decoded, list) else []
        except Exception:
            records = []
    for index, record in enumerate(records or [], start=1):
        normalized_record = normalize_skill_record(record, index)
        if normalized_record is not None:
            normalized.append(normalized_record)
    return normalized


def serialize_skill_records(records, *, validate: bool = False) -> list[dict]:
    serialized = []
    seen_names = set()
    for index, record in enumerate(records or [], start=1):
        normalized = normalize_skill_record(record, index)
        if normalized is None:
            continue
        name = sanitize_skill_name(normalized.get('name', ''), f'Skill {index}')
        description = str(normalized.get('description', '') or '').strip()
        if validate:
            if not normalized.get('has_frontmatter'):
                raise ValueError(f'Skill "{name}" must start with frontmatter delimited by ---.')
            if not normalized.get('frontmatter_name'):
                raise ValueError(f'Skill {index} is missing name.')
            if not description:
                raise ValueError(f'Skill "{name}" is missing description.')
            lowered = name.lower()
            if lowered in seen_names:
                raise ValueError(f'Duplicate skill name: {name}')
            seen_names.add(lowered)
        serialized.append(
            {
                'raw_text': str(normalized.get('raw_text', '') or '').strip('\n'),
                'enabled': bool(normalized.get('enabled', True)),
            }
        )
    return serialized


def load_skill_records_from_store(store: dict | None = None, *, enabled_only: bool = False) -> list[dict]:
    if store is None:
        store = load_settings_store()
    globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
    records = normalize_skill_records(globals_store.get('skills', []))
    if enabled_only:
        records = [record for record in records if record.get('enabled', True)]
    return records


def skill_catalog_text(skills: list[dict]) -> str:
    lines = []
    for record in skills or []:
        name = sanitize_skill_name(record.get('name', ''), '')
        description = str(record.get('description', '') or '').strip()
        if not name or not description:
            continue
        lines.append(f'- {name}: {description}')
    text = '\n'.join(lines)
    if len(text) > SKILL_CATALOG_MAX_CHARS:
        text = text[:SKILL_CATALOG_MAX_CHARS].rstrip() + '\n[Skill catalog truncated.]'
    return text


def find_skill_record(skills: list[dict], name: str) -> dict | None:
    target = str(name or '').strip().lower()
    if not target:
        return None
    for record in skills or []:
        if str(record.get('name', '') or '').strip().lower() == target:
            return record
    return None


def skill_step_label(step: dict) -> str:
    if str(step.get('capability', '') or '').strip() == SPECIALIZED_SKILL_CAPABILITY:
        skill_name = str(step.get('skill_name', '') or '').strip()
        return f'skill:{skill_name or "unnamed"}'
    return str(step.get('capability', '') or '').strip()


def extract_code_candidates(text: str) -> list[dict]:
    content = str(text or '')
    candidates = []
    for match in re.finditer(r'```([^\n`]*)\n(.*?)```', content, re.DOTALL | re.IGNORECASE):
        language = normalize_code_runner_language(match.group(1).strip().lower(), '')
        code = match.group(2).strip()
        if not code:
            continue
        if language in CODE_EXECUTION_IGNORE_LANGUAGES:
            continue
        if language:
            candidates.append({'language': language, 'code': code, 'explicit': True})
        elif re.search(r'\b(print|len|import|from|def|for|while|if)\b', code):
            candidates.append({'language': 'python', 'code': code, 'explicit': False})
        elif re.search(r'\b(console\.log|const|let|var|function)\b', code):
            candidates.append({'language': 'node', 'code': code, 'explicit': False})
    if candidates:
        return candidates

    lines = content.replace('\r\n', '\n').replace('\r', '\n').split('\n')
    code_line_re = re.compile(
        r'^\s*(?:'
        r'import\s+\w+|from\s+\w+\s+import\s+|'
        r'[A-Za-z_]\w*\s*=|'
        r'print\s*\(|'
        r'for\s+.+:|while\s+.+:|if\s+.+:|elif\s+.+:|else:|'
        r'def\s+\w+\s*\(|class\s+\w+|#)'
    )
    current = []
    for line in lines + ['']:
        stripped = line.strip()
        if stripped and code_line_re.match(line):
            current.append(line)
            continue
        if stripped == '' and current:
            current.append(line)
            continue
        candidate = '\n'.join(current).strip()
        if candidate and 'print' in candidate and len(candidate.splitlines()) >= 2:
            candidates.append({'language': 'python', 'code': candidate, 'explicit': False})
        current = []
    return candidates


def _limit_code_execution_text(text: str, limit: int = CODE_EXECUTION_MAX_OUTPUT_CHARS) -> str:
    content = str(text or '')
    if len(content) <= limit:
        return content
    return content[:limit].rstrip() + '\n[Code execution output truncated.]'


def run_code_in_worker_thread(language: str,
                              code: str,
                              *,
                              store: dict | None = None,
                              timeout: int | None = None) -> dict:
    if store is None:
        store = load_settings_store()
    globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
    if not bool(globals_store.get('code_execution_enabled', True)):
        return {
            'ok': False,
            'skipped': True,
            'language': normalize_code_runner_language(language, ''),
            'returncode': None,
            'stdout': '',
            'stderr': 'Code execution is disabled in Settings.',
            'timed_out': False,
            'supported_languages': [],
        }
    lang = normalize_code_runner_language(language, '')
    source = str(code or '').strip()
    if not source:
        return {'ok': False, 'skipped': False, 'language': lang, 'returncode': None, 'stdout': '', 'stderr': 'No code was provided.', 'timed_out': False}
    if len(source) > CODE_EXECUTION_MAX_CODE_CHARS:
        return {
            'ok': False,
            'skipped': False,
            'language': lang,
            'returncode': None,
            'stdout': '',
            'stderr': f'Code is too long to execute safely ({len(source)} chars).',
            'timed_out': False,
        }

    runners = load_code_runner_records_from_store(store, enabled_only=True)
    runner = None
    for record in runners:
        if normalize_code_runner_language(record.get('language', ''), '') == lang:
            runner = record
            break
    supported = supported_code_runner_languages(store)
    if runner is None:
        return {
            'ok': False,
            'skipped': True,
            'language': lang,
            'returncode': None,
            'stdout': '',
            'stderr': (
                f'Code execution skipped: language "{lang or "unknown"}" is not configured. '
                + (f'Supported executable languages: {", ".join(supported)}.' if supported else 'No executable languages are available.')
            ),
            'timed_out': False,
            'supported_languages': supported,
        }
    argv = _build_runner_argv(str(runner.get('command', '') or ''), str(runner.get('args', '') or ''), source)
    if not argv:
        return {
            'ok': False,
            'skipped': True,
            'language': lang,
            'returncode': None,
            'stdout': '',
            'stderr': f'Code execution skipped: runner for "{lang}" has no valid executable command.',
            'timed_out': False,
            'supported_languages': supported,
        }
    run_timeout = normalize_code_execution_timeout(timeout or globals_store.get('code_execution_timeout', CODE_EXECUTION_DEFAULT_TIMEOUT_SECONDS))
    result_queue = queue.Queue(maxsize=1)

    def worker_main():
        try:
            completed = subprocess.run(
                argv,
                cwd='/tmp',
                capture_output=True,
                text=True,
                timeout=run_timeout,
            )
            result_queue.put(
                {
                    'ok': completed.returncode == 0,
                    'skipped': False,
                    'language': lang,
                    'returncode': completed.returncode,
                    'stdout': _limit_code_execution_text(completed.stdout),
                    'stderr': _limit_code_execution_text(completed.stderr),
                    'timed_out': False,
                    'supported_languages': supported,
                }
            )
        except subprocess.TimeoutExpired as exc:
            result_queue.put(
                {
                    'ok': False,
                    'skipped': False,
                    'language': lang,
                    'returncode': None,
                    'stdout': _limit_code_execution_text(getattr(exc, 'stdout', '') or ''),
                    'stderr': 'Code execution timed out.',
                    'timed_out': True,
                    'supported_languages': supported,
                }
            )
        except Exception as exc:
            result_queue.put(
                {
                    'ok': False,
                    'skipped': False,
                    'language': lang,
                    'returncode': None,
                    'stdout': '',
                    'stderr': str(exc),
                    'timed_out': False,
                    'supported_languages': supported,
                }
            )

    worker = threading.Thread(target=worker_main, daemon=True)
    worker.start()
    worker.join(max(2, run_timeout + 2))
    if worker.is_alive():
        return {'ok': False, 'skipped': False, 'language': lang, 'returncode': None, 'stdout': '', 'stderr': 'Code runner worker thread timed out.', 'timed_out': True, 'supported_languages': supported}
    try:
        return result_queue.get_nowait()
    except queue.Empty:
        return {'ok': False, 'skipped': False, 'language': lang, 'returncode': None, 'stdout': '', 'stderr': 'Code runner returned no result.', 'timed_out': False, 'supported_languages': supported}


def format_code_execution_feedback(executions: list[dict]) -> str:
    parts = [
        'The app handled the code block below through its configured code runners.',
        'Use stdout/stderr here as the source of truth. If your previous answer claimed different computed values, correct them.',
        'If execution was skipped because the language is unsupported, rewrite equivalent code in the first supported executable language and return one fenced code block.',
        'If the task still needs deterministic verification after revising text, return another fenced code block in a supported language.',
    ]
    for index, execution in enumerate(executions, start=1):
        code = str(execution.get('code', '') or '').strip()
        language = normalize_code_runner_language(execution.get('language', '') or (execution.get('result') or {}).get('language', ''), 'text')
        result = execution.get('result') or {}
        parts.append(
            f'\nExecution {index} language: {language}\n'
            f'Code:\n```{language}\n{code}\n```\n'
            f'Return code: {result.get("returncode")}\n'
            f'Skipped: {bool(result.get("skipped", False))}\n'
            f'Timed out: {bool(result.get("timed_out", False))}\n'
            f'Supported executable languages: {", ".join(result.get("supported_languages", []) or []) or "(none)"}\n'
            f'STDOUT:\n{str(result.get("stdout", "") or "").strip() or "(empty)"}\n'
            f'STDERR:\n{str(result.get("stderr", "") or "").strip() or "(empty)"}'
        )
    return '\n'.join(parts)


def build_question_prefix(existing_output: str, question_display: str) -> str:
    history = normalize_conversation_text(existing_output).rstrip()
    history = re.sub(r'(?:\n\s*---\s*)+\Z', '', history)
    if history:
        history = history + '\n\n---\n\n'
    return history + '- Q: ' + question_display + '\n\n- A: '


def normalize_attachment_record(item: dict) -> dict | None:
    if not isinstance(item, dict):
        return None
    name = str(item.get('name', '')).strip()
    stored_path = str(item.get('stored_path', '')).strip()
    if not name and not stored_path:
        return None
    normalized = {
        'name': name or os.path.basename(stored_path) or 'Attachment',
        'kind': str(item.get('kind', '')).strip() or 'file',
        'send_mode': str(item.get('send_mode', '')).strip() or 'file_direct',
        'use_embedding': bool(item.get('use_embedding', False)),
    }
    for key in ('original_path', 'stored_path', 'stored_rel_path', 'source_path'):
        value = str(item.get(key, '')).strip()
        if value:
            normalized[key] = value
    extracted_text = str(item.get('extracted_text', ''))
    if extracted_text:
        normalized['extracted_text'] = extracted_text
    retrieval_chunks = []
    if isinstance(item.get('retrieval_chunks'), list):
        for chunk in item['retrieval_chunks']:
            if not isinstance(chunk, dict):
                continue
            text = str(chunk.get('text', '')).strip()
            if not text:
                continue
            retrieval_chunks.append(
                {
                    'id': str(chunk.get('id', '')).strip() or f"att-{abs(hash(text))}",
                    'text': text,
                    'display_text': str(chunk.get('display_text', '')).strip() or text,
                    'name': str(chunk.get('name', normalized['name'])).strip() or normalized['name'],
                }
            )
    if retrieval_chunks:
        normalized['retrieval_chunks'] = retrieval_chunks
    return normalized


def attachment_markdown_link(attachment: dict) -> str:
    name = str(attachment.get('name', 'Attachment')).replace(']', '\\]')
    stored_path = str(attachment.get('stored_path', '')).strip()
    if stored_path:
        try:
            uri = Path(stored_path).as_uri()
            return f'[{name}]({uri})'
        except Exception:
            pass
    return name


def attachment_file_uri(attachment: dict) -> str:
    stored_path = str(attachment.get('stored_path', '')).strip()
    if not stored_path:
        return ''
    try:
        return Path(stored_path).as_uri()
    except Exception:
        return ''


def attachment_markdown_block(message: dict) -> str:
    attachments = message.get('attachments') or []
    if not attachments:
        return ''
    lines = ['**Attachments**']
    for attachment in attachments:
        marker = ' [retrieval]' if attachment.get('use_embedding') else ''
        lines.append(f"- {attachment_markdown_link(attachment)}{marker}")
    return '\n'.join(lines)


def attachment_plaintext_block(message: dict) -> str:
    attachments = message.get('attachments') or []
    if not attachments:
        return ''
    lines = ['Attachments:']
    for attachment in attachments:
        name = str(attachment.get('name', 'Attachment'))
        stored_path = str(attachment.get('stored_path', '')).strip()
        suffix = ' [retrieval]' if attachment.get('use_embedding') else ''
        if stored_path:
            lines.append(f'- {name}{suffix} ({stored_path})')
        else:
            lines.append(f'- {name}{suffix}')
    return '\n'.join(lines)


def attachment_display_html_block(message: dict) -> str:
    attachments = message.get('attachments') or []
    if not attachments:
        return ''
    rows = ['<div class="attachment-display-block"><div class="attachment-display-title">Attachments</div><ul>']
    for attachment in attachments:
        name = str(attachment.get('name', 'Attachment')).strip() or 'Attachment'
        stored_path = str(attachment.get('stored_path', '')).strip()
        uri = attachment_file_uri(attachment)
        badge = '<span class="attachment-badge">retrieval</span>' if attachment.get('use_embedding') else ''
        if uri:
            label = f'<a href="{html.escape(uri, quote=True)}" title="{html.escape(stored_path, quote=True)}">{html.escape(name)}</a>'
        else:
            label = f'<span>{html.escape(name)}</span>'
        rows.append(f'<li>{label}{badge}</li>')
    rows.append('</ul></div>')
    return ''.join(rows)


def render_message_markdown(message: dict) -> str:
    content = str(message.get('content', '')).strip('\n')
    attachment_block = attachment_markdown_block(message)
    if attachment_block:
        return (content + '\n\n' + attachment_block).strip()
    return content


def render_message_display_markup(message: dict, display_prefix_placeholder: str = '') -> str:
    role = str(message.get('role', '')).strip().lower()
    if role != 'user':
        content = render_message_markdown(message)
        if display_prefix_placeholder:
            content = (display_prefix_placeholder + '\n\n' + content).strip()
        return content
    content = str(message.get('content', '')).strip('\n')
    text_html = f'<div class="user-message-plain">{html.escape(content)}</div>' if content else ''
    attachment_html = attachment_display_html_block(message)
    return (text_html + attachment_html).strip()


def render_message_plaintext(message: dict) -> str:
    content = str(message.get('content', '')).strip('\n')
    attachment_block = attachment_plaintext_block(message)
    if attachment_block:
        return (content + '\n\n' + attachment_block).strip()
    return content


def normalize_memory_item_record(item) -> dict | None:
    if isinstance(item, dict):
        text = str(item.get('text', '')).strip()
        if not text:
            return None
        return {
            'text': text,
            'created_at': str(item.get('created_at', '')).strip() or datetime.datetime.now().isoformat(timespec='seconds'),
            'kind': str(item.get('kind', '')).strip() or 'manual',
            'source_date': str(item.get('source_date', '')).strip(),
        }
    text = str(item or '').strip()
    if not text:
        return None
    return {
        'text': text,
        'created_at': datetime.datetime.now().isoformat(timespec='seconds'),
        'kind': 'manual',
        'source_date': '',
    }


def normalize_memory_item_records(items) -> list[dict]:
    normalized = []
    if not isinstance(items, list):
        return normalized
    for item in items:
        record = normalize_memory_item_record(item)
        if record:
            normalized.append(record)
    return normalized


def memory_item_display_text(record: dict) -> str:
    text = str(record.get('text', '')).strip()
    if not text:
        return ''
    source_date = str(record.get('source_date', '')).strip()
    if source_date:
        return f'{source_date} · {text}'
    return text


def prune_memory_item_records(items: list[dict], retention_days: int, now: datetime.datetime | None = None) -> list[dict]:
    retention_days = max(1, int(retention_days or 30))
    now = now or datetime.datetime.now()
    kept = []
    for item in normalize_memory_item_records(items):
        created_at = str(item.get('created_at', '')).strip()
        try:
            created_dt = datetime.datetime.fromisoformat(created_at)
        except Exception:
            created_dt = now
        age_days = (now.date() - created_dt.date()).days
        if age_days < retention_days:
            kept.append(item)
    return kept


def normalize_chat_history_message(item: dict) -> dict | None:
    if not isinstance(item, dict):
        return None
    role = str(item.get('role', '')).strip().lower()
    if role not in {'user', 'assistant'}:
        return None
    content = str(item.get('content', ''))
    timestamp = str(item.get('timestamp', '')).strip()
    normalized = {'role': role, 'content': content}
    if timestamp:
        normalized['timestamp'] = timestamp
    source = str(item.get('source', '') or '').strip()
    if source:
        normalized['source'] = source[:40]
    display_prefix_html = str(item.get('display_prefix_html', '') or '').strip()
    if display_prefix_html and role == 'assistant':
        normalized['display_prefix_html'] = display_prefix_html
    if isinstance(item.get('attachments'), list):
        attachments = []
        for attachment in item['attachments']:
            normalized_attachment = normalize_attachment_record(attachment)
            if normalized_attachment:
                attachments.append(normalized_attachment)
        if attachments:
            normalized['attachments'] = attachments
    return normalized


def current_chat_timestamp() -> str:
    return datetime.datetime.now().strftime('%H:%M')


def format_message_label(role: str, timestamp: str = '') -> str:
    label = 'Q' if role == 'user' else 'A'
    return f'{label} · {timestamp}' if timestamp else label


def load_chat_history_messages() -> list[dict]:
    ensure_broccoli_data_dir()
    if not os.path.exists(CHAT_HISTORY_PATH):
        return []
    try:
        with open(CHAT_HISTORY_PATH, 'r', encoding='utf-8') as handle:
            raw_messages = json.load(handle)
    except Exception:
        return []
    if not isinstance(raw_messages, list):
        return []
    messages = []
    for item in raw_messages:
        normalized = normalize_chat_history_message(item)
        if normalized:
            messages.append(normalized)
    return messages


def render_chat_history_markdown(messages: list[dict]) -> str:
    blocks = []
    for index, message in enumerate(messages):
        blocks.append(f'### {format_message_label(message["role"], message.get("timestamp", ""))}')
        blocks.append(render_message_markdown(message))
    return '\n\n'.join(block for block in blocks if block).strip()


def render_chat_history_display_markup(messages: list[dict]) -> tuple[str, dict[str, str]]:
    blocks = []
    display_prefix_map = {}
    for index, message in enumerate(messages):
        if index > 0 and message['role'] == 'user':
            blocks.append('<div class="chat-separator"></div>')
        blocks.append(f'<div id="msg-{index}" class="chat-anchor"></div>')
        label = 'Q' if message['role'] == 'user' else 'A'
        label_class = 'q' if message['role'] == 'user' else 'a'
        timestamp = message.get('timestamp', '')
        source = str(message.get('source', '') or '').strip()
        meta_parts = []
        if timestamp:
            meta_parts.append(f'<span class="qa-time">{html.escape(timestamp)}</span>')
        if source:
            meta_parts.append(f'<span class="qa-source">{html.escape(source)}</span>')
        if meta_parts:
            blocks.append(
                f'<div class="qa-meta-row"><span class="qa-label qa-label-{label_class}">{label}</span>'
                f'{"".join(meta_parts)}</div>'
            )
        else:
            blocks.append(f'<span class="qa-label qa-label-{label_class}">{label}</span>')
        display_prefix_html = str(message.get('display_prefix_html', '') or '').strip()
        placeholder = ''
        if display_prefix_html and message['role'] == 'assistant':
            placeholder = f'@@BROCCOLI_DISPLAY_PREFIX_{index}@@'
            display_prefix_map[placeholder] = display_prefix_html
        blocks.append(render_message_display_markup(message, placeholder))
    return '\n\n'.join(block for block in blocks if block).strip(), display_prefix_map


def render_chat_history_plaintext(messages: list[dict]) -> str:
    blocks = []
    for index, message in enumerate(messages):
        if index > 0 and message['role'] == 'user':
            blocks.append('--------------------')
        blocks.append(format_message_label(message['role'], message.get('timestamp', '')))
        blocks.append(render_message_plaintext(message))
    return '\n\n'.join(block for block in blocks if block).strip()


def save_chat_history_messages(messages: list[dict]) -> str:
    ensure_broccoli_data_dir()
    normalized_messages = []
    for item in messages:
        normalized = normalize_chat_history_message(item)
        if normalized:
            normalized_messages.append(normalized)
    with open(CHAT_HISTORY_PATH, 'w', encoding='utf-8') as handle:
        json.dump(normalized_messages, handle, ensure_ascii=False, indent=2)
    markdown = render_chat_history_markdown(normalized_messages)
    write_text_file(BasePath + 'output.txt', markdown)
    return markdown


def clear_chat_history_messages(clear_output: bool = True) -> None:
    ensure_broccoli_data_dir()
    with open(CHAT_HISTORY_PATH, 'w', encoding='utf-8') as handle:
        json.dump([], handle, ensure_ascii=False, indent=2)
    if clear_output:
        write_text_file(BasePath + 'output.txt', '')


def get_current_chat_history_messages() -> list[dict]:
    messages = load_chat_history_messages()
    if not messages:
        return []
    current_output = read_file_contents(BasePath + 'output.txt', '').strip()
    rendered_output = render_chat_history_markdown(messages).strip()
    if current_output != rendered_output:
        return []
    return messages


def append_chat_turn(history_messages: list[dict], question_text: str, answer_text: str, attachments: list[dict] | None = None, assistant_display_prefix_html: str = '') -> tuple[list[dict], str]:
    new_messages = list(history_messages)
    user_message = {'role': 'user', 'content': question_text.strip(), 'timestamp': current_chat_timestamp()}
    if attachments:
        normalized_attachments = []
        for attachment in attachments:
            normalized_attachment = normalize_attachment_record(attachment)
            if normalized_attachment:
                normalized_attachments.append(normalized_attachment)
        if normalized_attachments:
            user_message['attachments'] = normalized_attachments
    new_messages.append(user_message)
    assistant_message = {'role': 'assistant', 'content': answer_text.strip(), 'timestamp': current_chat_timestamp()}
    if str(assistant_display_prefix_html or '').strip():
        assistant_message['display_prefix_html'] = str(assistant_display_prefix_html).strip()
    new_messages.append(assistant_message)
    markdown = save_chat_history_messages(new_messages)
    return new_messages, markdown


def output_kind_from_path(path: str) -> str:
    suffix = Path(str(path or '')).suffix.lower()
    if suffix in ATTACHMENT_IMAGE_EXTS:
        return 'image'
    if suffix in ATTACHMENT_AUDIO_EXTS:
        return 'audio'
    if suffix in ATTACHMENT_VIDEO_EXTS:
        return 'video'
    if suffix in {'.py', '.js', '.ts', '.html', '.css', '.json', '.xml', '.sh', '.swift', '.kt', '.java', '.go', '.rs', '.c', '.cpp', '.h'}:
        return 'code'
    if suffix in {'.txt', '.md', '.csv', '.yaml', '.yml', '.toml'}:
        return 'text'
    return 'file'


def default_output_filename(record: dict) -> str:
    filename = str(record.get('filename', '')).strip()
    if filename:
        return filename
    title = sanitize_conversation_filename(str(record.get('title', '') or 'broccoli-output'), max_len=48)
    kind = str(record.get('kind', 'text')).strip().lower()
    if kind == 'code':
        return f'{title}.txt'
    if kind == 'text':
        return f'{title}.txt'
    path = str(record.get('path', '')).strip()
    if path:
        return os.path.basename(path)
    return f'{title}.txt'


def normalize_output_record(item: dict, fallback_index: int = 0) -> dict | None:
    if not isinstance(item, dict):
        return None
    content = str(item.get('content', '') or '')
    path = str(item.get('path', '') or '').strip()
    if not content.strip() and not path:
        return None
    kind = str(item.get('kind', '') or '').strip().lower()
    if kind not in {'code', 'text', 'image', 'audio', 'video', 'file'}:
        kind = output_kind_from_path(path) if path else 'text'
    try:
        question_index = int(item.get('question_index', -1))
    except (TypeError, ValueError):
        question_index = -1
    try:
        assistant_index = int(item.get('assistant_index', -1))
    except (TypeError, ValueError):
        assistant_index = -1
    created_at = str(item.get('created_at', '') or '').strip() or datetime.datetime.now().isoformat(timespec='seconds')
    output_id = str(item.get('id', '') or '').strip()
    if not output_id:
        seed = f'{created_at}-{question_index}-{assistant_index}-{fallback_index}-{kind}-{path}-{content[:80]}'
        output_id = f'out-{abs(hash(seed))}'
    title = str(item.get('title', '') or '').strip()
    if not title:
        if question_index >= 0:
            title = f'Output from Q{question_index // 2 + 1}'
        else:
            title = f'Output {fallback_index + 1}'
    normalized = {
        'id': output_id,
        'kind': kind,
        'title': title,
        'filename': str(item.get('filename', '') or '').strip(),
        'content': content,
        'path': path,
        'question': str(item.get('question', '') or '').strip(),
        'question_index': question_index,
        'assistant_index': assistant_index,
        'created_at': created_at,
        'source': str(item.get('source', '') or '').strip() or 'assistant',
    }
    annotations = []
    if isinstance(item.get('annotations'), list):
        for ann_index, annotation in enumerate(item.get('annotations') or []):
            if not isinstance(annotation, dict):
                continue
            comment = str(annotation.get('comment', '') or '').strip()
            if not comment:
                continue
            normalized_annotation = dict(annotation)
            normalized_annotation['id'] = str(annotation.get('id', '') or f'ann-{fallback_index}-{ann_index}').strip()
            normalized_annotation['comment'] = comment
            normalized_annotation['kind'] = str(annotation.get('kind', 'note') or 'note').strip()
            annotations.append(normalized_annotation)
    if annotations:
        normalized['annotations'] = annotations
    model_name = str(item.get('model_name', '') or '').strip()
    if model_name:
        normalized['model_name'] = model_name
    return normalized


def normalize_output_records(items) -> list[dict]:
    normalized = []
    seen = set()
    if not isinstance(items, list):
        return normalized
    for index, item in enumerate(items):
        record = normalize_output_record(item, fallback_index=index)
        if not record or record['id'] in seen:
            continue
        seen.add(record['id'])
        normalized.append(record)
    return normalized


def merge_output_records(existing: list, new_items: list) -> list[dict]:
    merged = normalize_output_records(existing)
    by_id = {item['id']: item for item in merged}
    for item in normalize_output_records(new_items):
        by_id[item['id']] = item
    merged = list(by_id.values())
    merged.sort(key=lambda item: (str(item.get('created_at', '')), int(item.get('assistant_index', -1))), reverse=False)
    return merged


def build_memory_retrieval_chunks(memory_text: str, memory_items: list[dict]) -> list[dict]:
    chunks = []
    permanent = str(memory_text or '').strip()
    if permanent:
        for chunk_index, chunk_text in enumerate(chunk_text_for_retrieval(permanent)):
            chunks.append(
                {
                    'id': f'perm-{chunk_index}',
                    'name': 'Permanent memory',
                    'text': chunk_text,
                    'display_text': f'Permanent memory\n{chunk_text}',
                }
            )
    for item_index, item in enumerate(normalize_memory_item_records(memory_items)):
        item_text = item['text']
        name = str(item.get('source_date', '')).strip() or f'Memory note {item_index + 1}'
        chunks.append(
            {
                'id': f'item-{item_index}',
                'name': name,
                'text': item_text,
                'display_text': f'{name}\n{item_text}',
            }
        )
    return chunks


def build_memory_context_block(relevant_chunks: list[dict]) -> str:
    if not relevant_chunks:
        return ''
    blocks = []
    for index, chunk in enumerate(relevant_chunks, start=1):
        blocks.append(
            f"[Relevant memory {index} — {chunk.get('name', 'Memory')}]\n"
            f"{chunk.get('text', '').strip()}"
        )
    return 'Relevant saved memory:\n' + '\n\n'.join(block for block in blocks if block)


def build_saved_memory_context(question_text: str,
                               embedding_config: dict | None,
                               embedding_ok: bool) -> str:
    store = load_settings_store()
    globals_store = store.get('globals', {})
    memory_text = str(globals_store.get('memory_text', '')).strip()
    memory_items = normalize_memory_item_records(globals_store.get('memory_items', []))
    chunks = build_memory_retrieval_chunks(memory_text, memory_items)
    if not chunks:
        return ''

    relevant_chunks = []
    strategy = 'keyword'
    if embedding_ok and embedding_config is not None:
        try:
            relevant_chunks = retrieve_attachment_chunks(
                chunks,
                question_text,
                embedding_config['api_key'],
                embedding_config['endpoint'],
                embedding_config['timeout'],
                embedding_config['model'],
            )
            strategy = 'embedding'
        except Exception:
            relevant_chunks = []
    if not relevant_chunks:
        relevant_chunks = keyword_retrieve_attachment_chunks(chunks, question_text)
        strategy = 'keyword'

    # print_retrieval_debug('memory', strategy, question_text, relevant_chunks)

    return build_memory_context_block(relevant_chunks)


def format_conversation_updated_label(updated_at: str) -> str:
    try:
        dt = datetime.datetime.fromisoformat(updated_at)
        return 'Updated ' + dt.strftime('%Y-%m-%d %H:%M')
    except Exception:
        return 'Updated recently'


def sanitize_conversation_title(title: str, max_len: int = 48) -> str:
    text = re.sub(r'\s+', ' ', str(title or '').strip())
    if not text:
        return 'Untitled chat'
    return text[:max_len].rstrip()


def sanitize_conversation_filename(title: str, max_len: int = 48) -> str:
    safe = sanitize_conversation_title(title, max_len=max_len)
    safe = re.sub(r'[\\/:*?"<>|]+', '-', safe)
    safe = re.sub(r'\s+', '-', safe).strip(' .-_')
    return safe or 'Untitled-chat'


def conversation_attachment_dir(conversation_path: str) -> str:
    convo_id = Path(conversation_path).stem.split('_', 1)[0]
    return os.path.join(CONVERSATIONS_DIR, f'{convo_id}_attachments')


def _copy_attachment_into_conversation(conversation_path: str, source_path: str) -> tuple[str, str]:
    attach_dir = conversation_attachment_dir(conversation_path)
    os.makedirs(attach_dir, exist_ok=True)
    source = Path(source_path)
    safe_name = sanitize_conversation_filename(source.stem, max_len=72)
    suffix = source.suffix.lower()
    base_name = f"{datetime.datetime.now().strftime('%Y%m%d-%H%M%S-%f')}_{safe_name}{suffix}"
    target_path = os.path.join(attach_dir, base_name)
    counter = 2
    while os.path.exists(target_path):
        target_path = os.path.join(attach_dir, f"{datetime.datetime.now().strftime('%Y%m%d-%H%M%S-%f')}_{safe_name}-{counter}{suffix}")
        counter += 1
    shutil.copy2(source_path, target_path)
    return target_path, os.path.relpath(target_path, os.path.dirname(conversation_path))


def persist_conversation_attachments(conversation_path: str, attachment_items: list[dict]) -> tuple[list, list, list]:
    direct_attachments = []
    retrieval_documents = []
    saved_records = []
    for item in attachment_items:
        path = str(item.get('path', '')).strip()
        if not path or not os.path.exists(path):
            continue
        use_embedding = bool(item.get('use_embedding'))
        stored_path, stored_rel_path = _copy_attachment_into_conversation(conversation_path, path)
        ext = os.path.splitext(path)[1].lower()
        kind = 'image' if ext in ATTACHMENT_IMAGE_EXTS else ext.lstrip('.') or 'file'
        record = {
            'name': os.path.basename(path),
            'original_path': path,
            'stored_path': stored_path,
            'stored_rel_path': stored_rel_path,
            'kind': kind,
            'use_embedding': use_embedding,
        }

        extracted = None
        if attachment_supports_embedding(path):
            extracted = extract_attachment_text(path, allow_ocr=use_embedding, limit_chars=None if use_embedding else 512 * 1024)
            if extracted and extracted.get('content', '').strip():
                record['extracted_text'] = extracted['content']

        if use_embedding and extracted and extracted.get('content', '').strip():
            record['send_mode'] = 'retrieval_text'
            retrieval_chunks = build_attachment_retrieval_chunks([{'name': record['name'], 'content': extracted['content']}])
            if retrieval_chunks:
                record['retrieval_chunks'] = retrieval_chunks
            retrieval_documents.append({'name': record['name'], 'content': extracted['content']})
        else:
            encoded = _encode_attachment_file(path)
            if encoded:
                direct_attachments.append(encoded)
                if isinstance(encoded, list):
                    record['send_mode'] = 'image_direct' if any(att.get('kind') == 'image' for att in encoded if isinstance(att, dict)) else 'file_direct'
                else:
                    record['send_mode'] = 'image_direct' if encoded.get('kind') == 'image' else 'text_direct'
            else:
                record['send_mode'] = 'file_direct'
        saved_records.append(record)
    return direct_attachments, retrieval_documents, saved_records


def conversation_title_from_messages(messages: list[dict], fallback: str = 'Untitled chat') -> str:
    for message in messages:
        if message.get('role') == 'user':
            return sanitize_conversation_title(message.get('content', ''), max_len=48)
    return fallback


def conversation_turns_from_messages(messages: list[dict]) -> list[dict]:
    turns = []
    pending_question = None
    for message in messages:
        role = message.get('role')
        if role == 'user':
            pending_question = {
                'question': render_message_plaintext(message),
                'question_time': message.get('timestamp', ''),
                'answer': '',
                'answer_time': '',
            }
            turns.append(pending_question)
            continue
        if role == 'assistant':
            if pending_question is None:
                pending_question = {
                    'question': '',
                    'question_time': '',
                    'answer': render_message_plaintext(message),
                    'answer_time': message.get('timestamp', ''),
                }
                turns.append(pending_question)
            else:
                pending_question['answer'] = render_message_plaintext(message)
                pending_question['answer_time'] = message.get('timestamp', '')
            pending_question = None
    return turns


def chunk_text_for_retrieval(text: str,
                             max_chars: int = CONVERSATION_RETRIEVAL_CHARS,
                             overlap: int = CONVERSATION_RETRIEVAL_OVERLAP) -> list[str]:
    content = str(text or '').strip()
    if not content:
        return []
    if len(content) <= max_chars:
        return [content]
    chunks = []
    start = 0
    text_len = len(content)
    while start < text_len:
        end = min(text_len, start + max_chars)
        chunk = content[start:end].strip()
        if chunk:
            chunks.append(chunk)
        if end >= text_len:
            break
        start = max(0, end - overlap)
    return chunks


def build_retrieval_chunks(messages: list[dict]) -> list[dict]:
    chunks = []
    for message_index, message in enumerate(messages):
        role = message.get('role', '')
        label = 'Q' if role == 'user' else 'A'
        timestamp = message.get('timestamp', '')
        prefix = f'{label}'
        if timestamp:
            prefix += f' · {timestamp}'
        prefix += '\n'
        for chunk_index, chunk_text in enumerate(chunk_text_for_retrieval(message.get('content', ''))):
            chunks.append(
                {
                    'id': f'm{message_index}-c{chunk_index}',
                    'message_index': message_index,
                    'role': role,
                    'timestamp': timestamp,
                    'text': chunk_text,
                    'display_text': prefix + chunk_text,
                }
            )
        for attachment_index, attachment in enumerate(message.get('attachments', []) or []):
            attachment_name = str(attachment.get('name', 'Attachment')).strip() or 'Attachment'
            attachment_chunks = []
            if isinstance(attachment.get('retrieval_chunks'), list):
                attachment_chunks = [chunk for chunk in attachment['retrieval_chunks'] if isinstance(chunk, dict) and str(chunk.get('text', '')).strip()]
            elif str(attachment.get('extracted_text', '')).strip():
                attachment_chunks = [
                    {'id': f'm{message_index}-a{attachment_index}-c{chunk_index}', 'text': chunk_text}
                    for chunk_index, chunk_text in enumerate(chunk_text_for_retrieval(attachment['extracted_text']))
                ]
            for chunk_index, chunk in enumerate(attachment_chunks):
                chunk_text = str(chunk.get('text', '')).strip()
                if not chunk_text:
                    continue
                display_text = str(chunk.get('display_text', '')).strip() or f'Attachment · {attachment_name}\n{chunk_text}'
                chunk_id = str(chunk.get('id', '')).strip() or f'm{message_index}-a{attachment_index}-c{chunk_index}'
                chunks.append(
                    {
                        'id': chunk_id,
                        'message_index': message_index,
                        'role': role,
                        'timestamp': message.get('timestamp', ''),
                        'text': chunk_text,
                        'display_text': display_text,
                    }
                )
    return chunks


def normalize_retrieval_chunk(chunk: dict) -> dict | None:
    if not isinstance(chunk, dict):
        return None
    text = str(chunk.get('text', '')).strip()
    if not text:
        return None
    role = str(chunk.get('role', '')).strip().lower()
    if role not in {'user', 'assistant'}:
        role = 'assistant'
    timestamp = str(chunk.get('timestamp', '')).strip()
    try:
        message_index = int(chunk.get('message_index', 0))
    except (TypeError, ValueError):
        message_index = 0
    normalized = {
        'id': str(chunk.get('id', '')).strip() or f'{role}-{abs(hash(text))}',
        'message_index': message_index,
        'role': role,
        'timestamp': timestamp,
        'text': text,
        'display_text': str(chunk.get('display_text', '')).strip() or (
            ('Q' if role == 'user' else 'A') + (f' · {timestamp}' if timestamp else '') + '\n' + text
        ),
    }
    embedding = chunk.get('embedding')
    if isinstance(embedding, list):
        vector = []
        for item in embedding:
            try:
                vector.append(float(item))
            except (TypeError, ValueError):
                vector = []
                break
        if vector:
            normalized['embedding'] = vector
    return normalized


URL_EXTRACT_RE = re.compile(r'https?://[^\s<>"\']+')
HREF_EXTRACT_RE = re.compile(r'''href\s*=\s*["']([^"']+)["']''', re.IGNORECASE)


def clean_extracted_url(url: str) -> str:
    cleaned = str(url or '').strip()
    while cleaned and cleaned[-1] in '.,;:!?)]}>\'"':
        cleaned = cleaned[:-1]
    return cleaned


def extract_urls_from_text(text: str) -> list[str]:
    urls = []
    seen = set()
    for match in URL_EXTRACT_RE.findall(str(text or '')):
        url = clean_extracted_url(match)
        if not url or url in seen:
            continue
        seen.add(url)
        urls.append(url)
    return urls


def extract_urls_from_html_fragment(fragment: str) -> list[str]:
    urls = []
    seen = set()
    raw_fragment = str(fragment or '')
    for match in HREF_EXTRACT_RE.findall(raw_fragment):
        url = clean_extracted_url(html.unescape(match))
        if not url or not url.startswith(('http://', 'https://')) or url in seen:
            continue
        seen.add(url)
        urls.append(url)
    for url in extract_urls_from_text(html.unescape(raw_fragment)):
        if url in seen:
            continue
        seen.add(url)
        urls.append(url)
    return urls


def extract_urls_from_message(message: dict) -> list[str]:
    seen = set()
    urls = []
    for field in ('content', 'display_prefix_html'):
        value = str(message.get(field, '') or '')
        field_urls = extract_urls_from_html_fragment(value) if field == 'display_prefix_html' else extract_urls_from_text(value)
        for url in field_urls:
            if url in seen:
                continue
            seen.add(url)
            urls.append(url)
    return urls


def normalize_link_record(item: dict | str) -> dict | None:
    if isinstance(item, str):
        item = {'url': item}
    if not isinstance(item, dict):
        return None
    url = clean_extracted_url(item.get('url', ''))
    if not url:
        return None
    return {
        'url': url,
        'title': str(item.get('title', '')).strip(),
        'first_seen_at': str(item.get('first_seen_at', '')).strip(),
        'source': str(item.get('source', 'assistant')).strip() or 'assistant',
    }


def merge_conversation_links(existing_links: list, messages: list[dict], fallback_seen_at: str = '') -> list[dict]:
    merged = {}
    for item in existing_links or []:
        normalized = normalize_link_record(item)
        if normalized:
            merged[normalized['url']] = normalized

    for message in messages or []:
        if message.get('role') != 'assistant':
            continue
        seen_at = str(message.get('timestamp', '')).strip() or fallback_seen_at
        for url in extract_urls_from_message(message):
            existing = merged.get(url)
            if existing is not None:
                if not existing.get('first_seen_at'):
                    existing['first_seen_at'] = seen_at
                continue
            merged[url] = {
                'url': url,
                'title': '',
                'first_seen_at': seen_at,
                'source': 'assistant',
            }
    return list(merged.values())


def normalize_conversation_branch_data(branches: dict | None, messages: list[dict]) -> dict:
    valid_user_indices = {
        message_index
        for message_index, message in enumerate(messages or [])
        if str(message.get('role', '')).strip().lower() == 'user'
    }
    roots = []
    seen_indices = set()
    seen_ids = set()

    def unique_node_id(raw_id: str, message_index: int) -> str:
        base = str(raw_id or '').strip() or f'q{message_index + 1}'
        candidate = base
        suffix = 2
        while candidate in seen_ids:
            candidate = f'{base}_{suffix}'
            suffix += 1
        seen_ids.add(candidate)
        return candidate

    def normalize_node(node: dict) -> dict | None:
        if not isinstance(node, dict):
            return None
        try:
            message_index = int(node.get('message_index', -1))
        except (TypeError, ValueError):
            return None
        if message_index not in valid_user_indices or message_index in seen_indices:
            return None
        seen_indices.add(message_index)
        normalized = {
            'id': unique_node_id(node.get('id', ''), message_index),
            'message_index': message_index,
            'text': str(node.get('text', '')).strip(),
            'full_text': str(node.get('full_text', node.get('text', ''))).strip(),
            'children': [],
        }
        for child in node.get('children', []) or []:
            normalized_child = normalize_node(child)
            if normalized_child is not None:
                normalized['children'].append(normalized_child)
        return normalized

    branch_payload = branches if isinstance(branches, dict) else {}
    for node in branch_payload.get('roots', []) or []:
        normalized = normalize_node(node)
        if normalized is not None:
            roots.append(normalized)

    for message_index in sorted(valid_user_indices):
        if message_index in seen_indices:
            continue
        roots.append({
            'id': unique_node_id('', message_index),
            'message_index': message_index,
            'text': '',
            'full_text': '',
            'children': [],
        })

    available_ids = set()

    def collect_ids(node: dict):
        available_ids.add(str(node.get('id', '')).strip())
        for child in node.get('children', []) or []:
            collect_ids(child)

    for root in roots:
        collect_ids(root)

    active_node_id = str(branch_payload.get('active_node_id', '')).strip()
    if active_node_id not in available_ids:
        active_node_id = ''

    return {
        'roots': roots,
        'active_node_id': active_node_id,
        'append_as_child': bool(branch_payload.get('append_as_child', False) and active_node_id),
    }


def normalize_conversation_record(data: dict, path: str) -> dict:
    ensure_broccoli_data_dir()
    messages = []
    if isinstance(data.get('messages'), list):
        for item in data['messages']:
            normalized = normalize_chat_history_message(item)
            if normalized:
                messages.append(normalized)
    convo_id = str(data.get('id', Path(path).stem.split('_', 1)[0])).strip() or datetime.datetime.now().strftime('%Y%m%d-%H%M%S')
    title = sanitize_conversation_title(
        data.get('title', conversation_title_from_messages(messages, fallback=convo_id))
    )
    created_at = str(data.get('created_at', ''))
    updated_at = str(data.get('updated_at', created_at or datetime.datetime.now().isoformat(timespec='seconds')))
    markdown = str(data.get('rendered_markdown', render_chat_history_markdown(messages)))
    display = data.get('display') if isinstance(data.get('display'), dict) else {}
    memory = data.get('memory') if isinstance(data.get('memory'), dict) else {}
    retrieval = data.get('retrieval') if isinstance(data.get('retrieval'), dict) else {}
    raw_outputs = data.get('outputs') if isinstance(data.get('outputs'), list) else []
    raw_links = data.get('links') if isinstance(data.get('links'), list) else []
    display_turns = conversation_turns_from_messages(messages)
    normalized_chunks = []
    if isinstance(retrieval.get('chunks'), list):
        for chunk in retrieval['chunks']:
            normalized_chunk = normalize_retrieval_chunk(chunk)
            if normalized_chunk:
                normalized_chunks.append(normalized_chunk)
    try:
        last_summarized_turn_count = max(0, int(memory.get('last_summarized_turn_count', 0) or 0))
    except (TypeError, ValueError):
        last_summarized_turn_count = 0
    normalized_links = merge_conversation_links(raw_links, messages, fallback_seen_at=updated_at)
    normalized_outputs = normalize_output_records(raw_outputs)
    webfetch = data.get('webfetch') if isinstance(data.get('webfetch'), dict) else {}
    webfetch_attachments = collect_webfetch_attachments_from_messages(messages)
    if isinstance(webfetch.get('attachments'), list):
        for item in webfetch['attachments']:
            normalized = normalize_webfetch_attachment_record(item)
            if normalized is None:
                continue
            stored_path = str(normalized.get('stored_path', '')).strip()
            if stored_path and all(str(att.get('stored_path', '')).strip() != stored_path for att in webfetch_attachments):
                webfetch_attachments.append(normalized)
    normalized_branches = normalize_conversation_branch_data(data.get('branches'), messages)
    return {
        'id': convo_id,
        'title': title,
        'messages': messages,
        'created_at': created_at or updated_at,
        'updated_at': updated_at,
        'rendered_markdown': markdown,
        'display': {
            'turns': display_turns,
            'rendered_markdown': str(display.get('rendered_markdown', markdown)),
        },
        'memory': {
            'running_summary': str(memory.get('running_summary', '')).strip(),
            'last_summarized_turn_count': last_summarized_turn_count,
        },
        'retrieval': {
            'chunks': normalized_chunks,
        },
        'links': normalized_links,
        'outputs': normalized_outputs,
        'webfetch': {
            'attachments': webfetch_attachments,
        },
        'branches': normalized_branches,
        'path': path,
    }


def write_conversation_record(path: str, record: dict) -> dict:
    normalized = normalize_conversation_record(record, path)
    payload = {
        'id': normalized['id'],
        'title': normalized['title'],
        'created_at': normalized['created_at'],
        'updated_at': normalized['updated_at'],
        'messages': normalized['messages'],
        'rendered_markdown': normalized['rendered_markdown'],
        'display': normalized['display'],
        'memory': normalized['memory'],
        'retrieval': normalized['retrieval'],
        'links': normalized['links'],
        'outputs': normalized['outputs'],
        'webfetch': normalized['webfetch'],
        'branches': normalized['branches'],
    }
    with open(path, 'w', encoding='utf-8') as handle:
        json.dump(payload, handle, ensure_ascii=False, indent=2)
    return normalized


def load_conversation_record(path: str) -> dict | None:
    ensure_broccoli_data_dir()
    if not os.path.exists(path):
        return None
    try:
        with open(path, 'r', encoding='utf-8') as handle:
            data = json.load(handle)
    except Exception:
        return None
    if not isinstance(data, dict):
        return None
    return normalize_conversation_record(data, path)


def list_conversation_records() -> list[dict]:
    ensure_broccoli_data_dir()
    records = []
    for path in Path(CONVERSATIONS_DIR).glob('*.json'):
        record = load_conversation_record(str(path))
        if record:
            search_blob = '\n'.join(message['content'] for message in record['messages'])
            attachment_blob = '\n'.join(
                '\n'.join(
                    str(attachment.get('name', '')) + '\n' + str(attachment.get('extracted_text', ''))
                    for attachment in (message.get('attachments') or [])
                )
                for message in record['messages']
            )
            links_blob = '\n'.join(
                (str(link.get('title', '')).strip() + '\n' + str(link.get('url', '')).strip()).strip()
                for link in record.get('links', [])
            )
            outputs_blob = '\n'.join(
                (
                    str(output.get('title', '')).strip()
                    + '\n'
                    + str(output.get('content', '')).strip()
                    + '\n'
                    + str(output.get('path', '')).strip()
                ).strip()
                for output in record.get('outputs', [])
            )
            running_summary = record.get('memory', {}).get('running_summary', '')
            record['search_blob'] = f"{record['title']}\n{search_blob}\n{attachment_blob}\n{links_blob}\n{outputs_blob}".lower()
            if running_summary:
                record['search_blob'] += '\n' + running_summary.lower()
            records.append(record)
    records.sort(key=lambda item: item.get('updated_at', ''), reverse=True)
    return records


def create_conversation_record(first_question: str, history_messages: list[dict] | None = None) -> dict:
    ensure_broccoli_data_dir()
    convo_id = datetime.datetime.now().strftime('%Y%m%d-%H%M%S')
    title = sanitize_conversation_title(first_question)
    filename = f"{convo_id}_{sanitize_conversation_filename(title)}.json"
    path = os.path.join(CONVERSATIONS_DIR, filename)
    base_messages = list(history_messages or [])
    base_messages.append({'role': 'user', 'content': first_question.strip(), 'timestamp': current_chat_timestamp()})
    now = datetime.datetime.now().isoformat(timespec='seconds')
    return write_conversation_record(
        path,
        {
            'id': convo_id,
            'title': title,
            'created_at': now,
            'updated_at': now,
            'messages': base_messages,
            'rendered_markdown': render_chat_history_markdown(base_messages),
        },
    )


def rename_conversation_record(path: str, new_title: str) -> dict | None:
    record = load_conversation_record(path)
    if record is None:
        return None
    title = sanitize_conversation_title(new_title)
    prefix = record['id']
    new_filename = f"{prefix}_{sanitize_conversation_filename(title)}.json"
    new_path = os.path.join(CONVERSATIONS_DIR, new_filename)
    suffix = 2
    while new_path != path and os.path.exists(new_path):
        new_filename = f"{prefix}_{sanitize_conversation_filename(title)}-{suffix}.json"
        new_path = os.path.join(CONVERSATIONS_DIR, new_filename)
        suffix += 1
    record['title'] = title
    record['updated_at'] = datetime.datetime.now().isoformat(timespec='seconds')
    if new_path != path:
        os.replace(path, new_path)
    return write_conversation_record(new_path, record)


def create_openai_client(api_key: str, endpoint: str, timeout: int):
    return OpenAI(api_key=api_key, base_url=endpoint, timeout=timeout)


def capture_all_screens_png_bytes() -> bytes:
    try:
        import Quartz as _Quartz
        from PIL import Image as _PILImage
    except Exception as exc:
        raise RuntimeError(f'Background vision screenshot dependencies unavailable: {exc}') from exc

    image = _Quartz.CGWindowListCreateImage(
        _Quartz.CGRectInfinite,
        _Quartz.kCGWindowListOptionOnScreenOnly,
        _Quartz.kCGNullWindowID,
        _Quartz.kCGWindowImageDefault,
    )
    if image is None:
        raise RuntimeError('No screen image captured. Check macOS Screen Recording permission for Broccoli.')

    width = _Quartz.CGImageGetWidth(image)
    height = _Quartz.CGImageGetHeight(image)
    bytes_per_row = _Quartz.CGImageGetBytesPerRow(image)
    provider = _Quartz.CGImageGetDataProvider(image)
    raw_data = _Quartz.CGDataProviderCopyData(provider)
    pil_image = _PILImage.frombuffer(
        'RGBA',
        (width, height),
        bytes(raw_data),
        'raw',
        'BGRA',
        bytes_per_row,
        1,
    )
    with BytesIO() as output:
        pil_image.save(output, format='PNG')
        return output.getvalue()


class BackgroundVisionWorker(QThread):
    status = pyqtSignal(str)
    error = pyqtSignal(str)
    record_ready = pyqtSignal(object)

    def __init__(self, targets: list[dict], settings: dict, parent=None):
        super().__init__(parent)
        self.targets = [dict(target) for target in targets if isinstance(target, dict)]
        self.settings = normalize_background_vision_settings(settings)
        self._stop_event = threading.Event()
        self._executor = None
        self._round_index = 0
        self._active_rounds = 0
        self._active_rounds_lock = threading.Lock()
        self._history_lock = threading.Lock()
        self._history_turns_by_target = {}
        self._after_completion_event = threading.Event()

    def stop(self):
        self._stop_event.set()

    def _wait_with_countdown(self, total_seconds: float) -> bool:
        deadline = time.monotonic() + max(0.0, float(total_seconds or 0))
        while not self._stop_event.is_set():
            remaining = deadline - time.monotonic()
            if remaining <= 0:
                return False
            if self._stop_event.wait(min(1.0, remaining)):
                return True
        return True

    def _try_reserve_round_slot(self) -> bool:
        with self._active_rounds_lock:
            if self._active_rounds >= int(self.settings.get('background_vision_max_workers', 1)):
                return False
            self._active_rounds += 1
            return True

    def _release_round_slot(self):
        with self._active_rounds_lock:
            if self._active_rounds > 0:
                self._active_rounds -= 1

    def run(self):
        if not self.targets:
            self.error.emit('Background vision has no usable profile target.')
            return
        max_workers = int(self.settings.get('background_vision_max_workers', 1) or 1)
        self._executor = ThreadPoolExecutor(max_workers=max_workers, thread_name_prefix='broccoli-bg-vision')
        try:
            if self.settings.get('background_vision_schedule_mode') == 'after_completion':
                self._run_after_completion_schedule()
            else:
                self._run_fixed_interval_schedule()
        finally:
            if self._executor is not None:
                self._executor.shutdown(wait=True, cancel_futures=False)
                self._executor = None

    def _run_fixed_interval_schedule(self):
        interval = int(self.settings.get('background_vision_interval_sec', DEFAULT_BACKGROUND_VISION_INTERVAL_SECONDS) or DEFAULT_BACKGROUND_VISION_INTERVAL_SECONDS)
        next_run = time.monotonic()
        while not self._stop_event.is_set():
            now = time.monotonic()
            if now < next_run:
                if self._wait_with_countdown(next_run - now):
                    break
                continue
            self._submit_round()
            next_run += max(1, interval)

    def _run_after_completion_schedule(self):
        delay = int(self.settings.get('background_vision_completion_delay_sec', DEFAULT_BACKGROUND_VISION_COMPLETION_DELAY_SECONDS) or 0)
        while not self._stop_event.is_set():
            self._after_completion_event.clear()
            self._submit_round()
            while not self._stop_event.is_set():
                if self._after_completion_event.wait(0.2):
                    break
            if self._stop_event.is_set():
                break
            if delay > 0 and self._wait_with_countdown(delay):
                break

    def _submit_round(self):
        if self._executor is None or self._stop_event.is_set():
            return
        self._round_index += 1
        round_id = self._round_index
        if not self._try_reserve_round_slot():
            self.status.emit('Background vision skipped one round because concurrency is full.')
            return
        try:
            self._executor.submit(self._run_round_and_release, round_id)
        except Exception:
            self._release_round_slot()
            raise

    def _run_round_and_release(self, round_id: int):
        try:
            self._run_single_round(round_id)
        finally:
            self._release_round_slot()

    def _save_capture_image(self, round_id: int, image_png: bytes) -> str:
        if not bool(self.settings.get('background_vision_save_captures', False)):
            return ''
        capture_dir = str(self.settings.get('background_vision_capture_dir', '') or BACKGROUND_VISION_CAPTURE_DIR).strip() or BACKGROUND_VISION_CAPTURE_DIR
        os.makedirs(capture_dir, exist_ok=True)
        timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
        path = os.path.join(capture_dir, f'background_vision_{round_id:04d}_{timestamp}.png')
        with open(path, 'wb') as handle:
            handle.write(image_png)
        return path

    def _encode_image_payload(self, png_bytes: bytes, image_format: str) -> dict:
        image_format = normalize_background_vision_image_format(image_format)
        if image_format == 'webp_lossless':
            try:
                from PIL import Image as _PILImage
                with _PILImage.open(BytesIO(png_bytes)) as image:
                    converted = image.convert('RGBA') if image.mode not in ('RGB', 'RGBA') else image.copy()
                with BytesIO() as output:
                    converted.save(output, format='WEBP', lossless=True, method=6)
                    image_bytes = output.getvalue()
                return {
                    'format': 'webp_lossless',
                    'mime_type': 'image/webp',
                    'base64': base64.b64encode(image_bytes).decode('utf-8'),
                }
            except Exception:
                pass
        return {
            'format': 'png',
            'mime_type': 'image/png',
            'base64': base64.b64encode(png_bytes).decode('utf-8'),
        }

    def _get_history_turns(self, history_key: str) -> list[tuple[str, str]]:
        if not bool(self.settings.get('background_vision_keep_history_context', False)):
            return []
        with self._history_lock:
            return list(self._history_turns_by_target.get(history_key, []))

    def _append_history_turn(self, history_key: str, round_id: int, assistant_text: str):
        if not bool(self.settings.get('background_vision_keep_history_context', False)):
            return
        max_messages = int(self.settings.get('background_vision_max_history_messages', 0) or 0)
        with self._history_lock:
            turns = self._history_turns_by_target.setdefault(history_key, [])
            turns.append((f'Round {round_id}: new full-screen screenshot.', str(assistant_text or '').strip()))
            max_turns = max_messages // 2
            if max_turns <= 0:
                turns.clear()
            elif len(turns) > max_turns:
                self._history_turns_by_target[history_key] = turns[-max_turns:]

    def _run_single_round(self, round_id: int):
        created_at = datetime.datetime.now().isoformat(timespec='seconds')
        record = {
            'id': f'vision-{int(time.time() * 1000)}-{round_id}',
            'round_id': round_id,
            'created_at': created_at,
            'completed_at': '',
            'complete': False,
            'prompt': str(self.settings.get('background_vision_prompt', DEFAULT_BACKGROUND_VISION_PROMPT) or ''),
            'capture_path': '',
            'targets': [],
            'context_text': '',
        }
        try:
            self.status.emit(f'Background vision round {round_id}: capturing screen')
            png_bytes = capture_all_screens_png_bytes()
            record['capture_path'] = self._save_capture_image(round_id, png_bytes)
            payload = self._encode_image_payload(
                png_bytes,
                self.settings.get('background_vision_image_format', 'png'),
            )
            if len(self.targets) == 1:
                results = [self._run_single_target(round_id, self.targets[0], payload)]
            else:
                worker_count = max(1, min(len(self.targets), 16))
                results = []
                with ThreadPoolExecutor(max_workers=worker_count, thread_name_prefix=f'bg-vision-round-{round_id}') as executor:
                    futures = [executor.submit(self._run_single_target, round_id, target, payload) for target in self.targets]
                    for future in as_completed(futures):
                        results.append(future.result())
            record['targets'] = results
            record['complete'] = any(item.get('status') == 'ok' and str(item.get('text', '')).strip() for item in results)
            record['context_text'] = self._build_context_text(results)
            record['completed_at'] = datetime.datetime.now().isoformat(timespec='seconds')
            self.record_ready.emit(record)
            self.status.emit(f'Background vision round {round_id}: complete')
        except Exception as exc:
            record['completed_at'] = datetime.datetime.now().isoformat(timespec='seconds')
            record['targets'] = [{'profile': '', 'model': '', 'status': 'error', 'text': '', 'error': str(exc)}]
            self.record_ready.emit(record)
            self.error.emit(str(exc))
        finally:
            if self.settings.get('background_vision_schedule_mode') == 'after_completion':
                self._after_completion_event.set()

    def _run_single_target(self, round_id: int, target: dict, image_payload: dict) -> dict:
        profile_name = str(target.get('name', '') or 'Profile').strip()
        model = str(target.get('model', '') or '').strip()
        result = {'profile': profile_name, 'model': model, 'status': 'error', 'text': '', 'error': ''}
        try:
            api_key = str(target.get('api_key', '') or '').strip()
            endpoint = str(target.get('endpoint', '') or '').strip()
            timeout = _coerce_int(target.get('timeout', 60), 60, 5, 600)
            if not api_key or not endpoint or not model:
                raise RuntimeError('profile is missing API key, endpoint, or model')
            client = create_openai_client(api_key, endpoint, timeout)
            prompt = str(self.settings.get('background_vision_prompt', DEFAULT_BACKGROUND_VISION_PROMPT) or '').strip() or DEFAULT_BACKGROUND_VISION_PROMPT
            messages = [{'role': 'system', 'content': prompt}]
            for user_text, assistant_text in self._get_history_turns(profile_name):
                messages.append({'role': 'user', 'content': user_text})
                messages.append({'role': 'assistant', 'content': assistant_text})
            data_url = f"data:{image_payload['mime_type']};base64,{image_payload['base64']}"
            messages.append({
                'role': 'user',
                'content': [
                    {'type': 'text', 'text': 'Analyze this current full-screen screenshot for background context.'},
                    {'type': 'image_url', 'image_url': {'url': data_url}},
                ],
            })
            response = client.chat.completions.create(
                model=model,
                messages=messages,
                stream=False,
            )
            text = str(response.choices[0].message.content or '').strip()
            result.update({'status': 'ok', 'text': text, 'error': ''})
            self._append_history_turn(profile_name, round_id, text)
        except Exception as exc:
            result['error'] = str(exc)
        finally:
            if (
                self.settings.get('background_vision_schedule_mode') == 'after_completion'
                and self.settings.get('background_vision_multi_target_wait_mode') == 'first_done'
            ):
                self._after_completion_event.set()
        return result

    def _build_context_text(self, results: list[dict]) -> str:
        ok_items = [
            item for item in results
            if isinstance(item, dict) and item.get('status') == 'ok' and str(item.get('text', '')).strip()
        ]
        if not ok_items:
            return ''
        blocks = []
        for item in ok_items:
            profile_name = str(item.get('profile', '') or 'Vision model').strip()
            text = _compact_background_vision_text(item.get('text', ''), 2400)
            if text:
                blocks.append(f'[{profile_name}] {text}')
        return _compact_background_vision_text('\n'.join(blocks), DEFAULT_BACKGROUND_VISION_CONTEXT_MAX_CHARS)


def get_specialized_profiles_from_store(store: dict | None = None) -> dict:
    if store is None:
        store = load_settings_store()
    globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
    return normalize_specialized_profiles(globals_store.get('specialized_profiles'))


def get_specialized_execution_modes_from_store(store: dict | None = None) -> dict:
    if store is None:
        store = load_settings_store()
    globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
    return normalize_specialized_execution_modes(globals_store.get('specialized_execution_modes'))


def resolve_specialized_execution_mode(store: dict | None, capability: str) -> str:
    modes = get_specialized_execution_modes_from_store(store)
    return str(modes.get(capability, default_specialized_execution_modes().get(capability, '')) or '').strip()


def get_planner_profile_from_store(store: dict | None = None) -> dict:
    if store is None:
        store = load_settings_store()
    specialized = get_specialized_profiles_from_store(store)
    planner_name = str(specialized.get('router', '')).strip()
    if planner_name:
        profile = get_profile_from_store_by_name(store, planner_name)
        if profile is not None:
            return profile
    return load_active_settings_profile()


def resolve_specialized_profile(store: dict, capability: str, fallback_profile: dict | None = None) -> dict | None:
    specialized = get_specialized_profiles_from_store(store)
    profile_name = str(specialized.get(capability, '')).strip()
    if profile_name:
        profile = get_profile_from_store_by_name(store, profile_name)
        if profile is not None:
            return profile
    return fallback_profile


def parse_json_object_from_text(text: str) -> dict | None:
    raw = str(text or '').strip()
    if not raw:
        return None
    try:
        obj = json.loads(raw)
        return obj if isinstance(obj, dict) else None
    except Exception:
        pass
    match = re.search(r'\{.*\}', raw, re.DOTALL)
    if not match:
        return None
    try:
        obj = json.loads(match.group(0))
        return obj if isinstance(obj, dict) else None
    except Exception:
        return None


def summarize_attachment_types(attachment_records: list[dict]) -> str:
    if not attachment_records:
        return 'No attachments.'
    parts = []
    for item in attachment_records:
        name = str(item.get('name', '') or os.path.basename(str(item.get('stored_path', '') or ''))).strip() or 'attachment'
        kind = str(item.get('kind', '')).strip() or 'file'
        parts.append(f'{kind}: {name}')
    return '\n'.join(parts)


def build_planner_messages(user_text: str, attachment_summary: str, skill_catalog: str = '') -> list[dict]:
    skill_rules = ''
    if str(skill_catalog or '').strip():
        skill_rules = (
            '\nAvailable skills:\n'
            + str(skill_catalog or '').strip()
            + '\n\nSkill step rules:\n'
            '- A skill is an isolated inserted task, not global context.\n'
            '- Use capability "skill" only when a listed skill description clearly matches the request.\n'
            '- Set "skill_name" exactly to one of the listed skill names.\n'
            '- The skill will run with the default main model and its full instructions will be loaded only for that step.\n'
            '- Later steps and the final answer will receive only the reviewed skill result, not the full skill prompt.\n'
        )
    else:
        skill_rules = '\nNo skills are configured.\n'
    return [
        {
            'role': 'system',
            'content': (
                'You are a task planner for a desktop AI assistant.\n\n'
                'Analyze the user request and decide whether any specialized capabilities are needed.\n'
                'Available capabilities:\n'
                '- task_reasoning\n'
                '- web_search\n'
                '- text_to_speech\n'
                '- speech_to_text\n'
                '- image_generation\n'
                '- video_generation\n'
                '- video_to_text\n'
                '- skill\n'
                + skill_rules
                + '\n'
                'Step design rules:\n'
                '- Do not include embedding. Retrieval is handled separately by the system.\n'
                '- If no specialized capability is needed, return an empty "steps" list.\n'
                '- Use the fewest steps that fully satisfy the request. Do not add steps that do not materially improve the final answer.\n'
                '- When two sequences both satisfy the request, prefer the one with fewer steps and higher relevance to the user\'s core intent.\n'
                '- Order steps so information-gathering steps (web_search, task_reasoning for research) come before synthesis or generation steps.\n'
                '- For deterministic counting, calculation, parsing, validation, or exact verification, include a task_reasoning step unless a more specific skill step handles it.\n'
                f'- Code execution runners: {code_runner_catalog_text()}\n'
                '- Return JSON only.\n\n'
                'Goal field rules (critical):\n'
                '- Write "goal" as a single precise instruction to the specialist: what to do, what input to use, what output is expected.\n'
                '- Do NOT write vague goals like "help with the request". Be specific: "Search for X and return key facts about Y".\n'
                '- The goal must be self-contained enough that the specialist can act on it without reading the full conversation.\n\n'
                '- Every step must have a non-empty goal. If you cannot write a concrete goal for a step, do not include that step.\n\n'
                'Extract field rules (critical for context efficiency):\n'
                '- When depends_on_previous is true, set "extract" to a short phrase naming exactly what the next step needs from the previous output.\n'
                '- Example: "search result URLs", "translated text", "reasoning summary", "image prompt".\n'
                '- If depends_on_previous is false, omit "extract" or set it to "".\n\n'
                'Finalize field rules:\n'
                '- Set finalize_with_default_chat to true when the step results need to be synthesized into a final user-facing response.\n'
                '- Set "finalize_focus" to a short phrase telling the final chat what to synthesize: e.g. "summarize findings into an answer", "combine image prompt and reasoning into a description".\n\n'
                'Output format:\n'
                '{\n'
                '  "steps": [\n'
                '    {"capability": "...", "skill_name": "only for skill steps", "goal": "...", "depends_on_previous": true, "extract": "..."}\n'
                '  ],\n'
                '  "finalize_with_default_chat": true,\n'
                '  "finalize_focus": "...",\n'
                '  "reason": "..."\n'
                '}'
            ),
        },
        {
            'role': 'user',
            'content': (
                'Latest user request:\n' + str(user_text or '').strip() +
                '\n\nAttachment summary:\n' + str(attachment_summary or 'No attachments.')
            ),
        },
    ]


def normalize_planner_plan(plan: dict | None, available_skill_names: set[str] | None = None) -> dict:
    normalized = {
        'steps': [],
        'finalize_with_default_chat': False,
        'finalize_focus': '',
        'reason': '',
    }
    if not isinstance(plan, dict):
        return normalized
    allowed = {key for key, _label in SPECIALIZED_CAPABILITIES} | {SPECIALIZED_SKILL_CAPABILITY}
    normalized_skill_names = None
    if available_skill_names is not None:
        normalized_skill_names = {str(name or '').strip().lower() for name in available_skill_names if str(name or '').strip()}
    raw_steps = plan.get('steps', [])
    if isinstance(raw_steps, list):
        for step in raw_steps:
            if not isinstance(step, dict):
                continue
            capability = str(step.get('capability', '')).strip()
            if capability not in allowed:
                continue
            skill_name = ''
            if capability == SPECIALIZED_SKILL_CAPABILITY:
                skill_name = sanitize_skill_name(step.get('skill_name', ''), '')
                if not skill_name:
                    continue
                if normalized_skill_names is not None and skill_name.lower() not in normalized_skill_names:
                    continue
            goal = str(step.get('goal', '')).strip()
            if not goal:
                continue
            normalized_step = {
                'capability': capability,
                'goal': goal,
                'depends_on_previous': bool(step.get('depends_on_previous', False)),
                'extract': str(step.get('extract', '')).strip(),
            }
            if skill_name:
                normalized_step['skill_name'] = skill_name
            normalized['steps'].append(normalized_step)
    normalized['finalize_with_default_chat'] = bool(plan.get('finalize_with_default_chat', False))
    normalized['finalize_focus'] = str(plan.get('finalize_focus', '')).strip()
    normalized['reason'] = str(plan.get('reason', '')).strip()
    return normalized


def normalize_dynamic_specialized_step(step: dict | None, available_skill_names: set[str] | None = None) -> dict | None:
    if not isinstance(step, dict):
        return None
    allowed = {key for key, _label in SPECIALIZED_CAPABILITIES} | {SPECIALIZED_SKILL_CAPABILITY}
    normalized_skill_names = None
    if available_skill_names is not None:
        normalized_skill_names = {str(name or '').strip().lower() for name in available_skill_names if str(name or '').strip()}
    capability = str(step.get('capability', '') or '').strip()
    goal = str(step.get('goal', '') or '').strip()
    if capability not in allowed or not goal:
        return None
    normalized = {
        'capability': capability,
        'goal': goal,
        'depends_on_previous': bool(step.get('depends_on_previous', False)),
        'extract': str(step.get('extract', '') or '').strip(),
        'dynamic': True,
    }
    if capability == SPECIALIZED_SKILL_CAPABILITY:
        skill_name = sanitize_skill_name(step.get('skill_name', ''), '')
        if not skill_name:
            return None
        if normalized_skill_names is not None and skill_name.lower() not in normalized_skill_names:
            return None
        normalized['skill_name'] = skill_name
    return normalized


def render_markdown_fragment(mdstr: str) -> str:
    text = str(mdstr or '').strip()
    if not text:
        return ''
    extras = [
        'code-friendly',
        'fenced-code-blocks',
        'footnotes',
        'tables',
        'code-color',
        'pyshell',
        'nofollow',
        'cuddled-lists',
        'header-ids',
        'nofollow',
    ]
    clean_one = text.replace('\\(', '$').replace('\\)', '$').replace('\\[', '$').replace('\\]', '$')
    clean_two = re.sub(
        r'\$(.*?)\$',
        lambda m: '$' + re.sub(r'[\n\t ]+', '', m.group(1)) + '$',
        clean_one,
        flags=re.DOTALL,
    )
    clean_three = re.sub(r'\|(\n(\t)*\n(\t)*)\|', '|\n|', clean_two)
    return markdown2.markdown(clean_three, extras=extras)


