def build_pipeline_display_prefix(plan: dict, step_results: list[dict]) -> str:
    if not step_results:
        return ''

    sections = []
    if plan.get('steps'):
        route_text = ' → '.join(skill_step_label(step) for step in plan['steps'])
        sections.append(
            '<div class="pipeline-step">'
            '<div><strong>Planner</strong></div>'
            f'<div>{render_markdown_fragment("Planned steps: " + route_text)}</div>'
            '</div>'
        )
    for result in step_results:
        label = str(result.get('capability_label', result.get('capability', 'Step'))).strip()
        model_name = str(result.get('model_name', '')).strip()
        title = label + (f' · {model_name}' if model_name else '')
        goal = str((result.get('metadata') or {}).get('goal', '') or '').strip()
        body = str(result.get('text_output', '')).strip()
        if goal:
            body = f'Goal: {goal}\n\n' + body
        code_executions = (result.get('metadata') or {}).get('code_executions') or (result.get('metadata') or {}).get('python_executions') or []
        if code_executions:
            execution_lines = []
            for exec_index, execution in enumerate(code_executions, start=1):
                exec_result = execution.get('result') or {}
                language = normalize_code_runner_language(execution.get('language', '') or exec_result.get('language', ''), 'text')
                stdout = str(exec_result.get('stdout', '') or '').strip()
                stderr = str(exec_result.get('stderr', '') or '').strip()
                line = f'Execution {exec_index} ({language}): return code {exec_result.get("returncode")}'
                if exec_result.get('skipped', False):
                    line += ' · skipped'
                if stdout:
                    line += f'\nstdout: {stdout}'
                if stderr:
                    line += f'\nstderr: {stderr}'
                execution_lines.append(line)
            body = body + ('\n\n' if body else '') + 'Code execution results:\n' + '\n\n'.join(execution_lines)
        artifact_paths = [str(path).strip() for path in (result.get('artifacts') or []) if str(path).strip()]
        if artifact_paths:
            artifact_block = 'Artifacts:\n' + '\n'.join(f'- {path}' for path in artifact_paths)
            body = body + ('\n\n' if body else '') + artifact_block
        sections.append(
            '<div class="pipeline-step">'
            f'<div><strong>{html.escape(title)}</strong></div>'
            f'<div class="pipeline-step-body">{render_markdown_fragment(body)}</div>'
            '</div>'
        )
    return (
        '<details class="pipeline-details">'
        '<summary>Specialized steps</summary>'
        + ''.join(section for section in sections if section)
        + '</details>'
    )


def specialized_step_context_output(result: dict) -> str:
    if not isinstance(result, dict):
        return ''
    if 'context_output' in result:
        return str(result.get('context_output', '') or '').strip()
    return str(result.get('text_output', '') or '').strip()


def limit_specialized_context_output(text: str, limit: int = SPECIALIZED_STEP_CONTEXT_MAX_CHARS) -> str:
    content = str(text or '').strip()
    if len(content) <= limit:
        return content
    return content[:limit].rstrip() + '\n\n[Context output truncated.]'


def specialized_progress_snippet(text: str, limit: int = SPECIALIZED_PROGRESS_SNIPPET_CHARS) -> str:
    content = re.sub(r'\s+', ' ', str(text or '')).strip()
    if len(content) <= limit:
        return content
    return content[:limit].rstrip() + '...'


def build_finalize_prompt(question_text: str,
                          shared_context: str,
                          step_results: list[dict]) -> str:
    step_sections = []
    for result in step_results:
        capability = str(result.get('capability', '')).strip()
        model_name = str(result.get('model_name', '')).strip()
        goal = str((result.get('metadata') or {}).get('goal', '') or '').strip()
        body = specialized_step_context_output(result)
        artifact_paths = [str(path).strip() for path in (result.get('artifacts') or []) if str(path).strip()]
        if artifact_paths:
            body = body + ('\n\n' if body else '') + 'Artifacts:\n' + '\n'.join(f'- {path}' for path in artifact_paths)
        if not body:
            continue
        skill_name = str((result.get('metadata') or {}).get('skill_name', '') or '').strip()
        header_capability = f'{capability}:{skill_name}' if capability == SPECIALIZED_SKILL_CAPABILITY and skill_name else capability
        header = header_capability + (f' ({model_name})' if model_name else '')
        step_body = (f'Goal: {goal}\n' if goal else '') + body
        step_sections.append(header + ':\n' + step_body)
    prompt_parts = [
        'Use the specialized-step outputs below when answering the user.',
        'Original user request:\n' + str(question_text or '').strip(),
    ]
    if shared_context.strip():
        prompt_parts.append('Retrieved context:\n' + shared_context.strip())
    if step_sections:
        prompt_parts.append('Reviewed specialized-step context:\n' + '\n\n'.join(step_sections))
    prompt_parts.append(
        'Now answer the user directly, integrating the useful results above. '
        'If a reviewed skill step already produced a verified final deliverable, preserve that deliverable exactly unless the reviewed context explicitly asks for further changes.'
    )
    return '\n\n'.join(prompt_parts)


def build_specialized_step_review_messages(capability: str,
                                           goal: str,
                                           question_text: str,
                                           downstream_extract: str,
                                           final_focus: str,
                                           output_text: str,
                                           artifact_paths: list[str],
                                           skill_catalog: str = '') -> list[dict]:
    downstream_need = downstream_extract.strip() or final_focus.strip() or 'the final user-facing answer'
    artifact_text = '\n'.join(f'- {path}' for path in artifact_paths if path)
    available = [key for key, _label in SPECIALIZED_CAPABILITIES]
    if str(skill_catalog or '').strip():
        available.append(SPECIALIZED_SKILL_CAPABILITY)
    available_capabilities = ', '.join(available)
    skill_instruction = ''
    if str(skill_catalog or '').strip():
        skill_instruction = (
            '\nAvailable skills for dynamic new_step:\n'
            + str(skill_catalog or '').strip()
            + '\nIf a dynamic new_step uses capability "skill", include skill_name exactly.\n'
        )
    return [
        {
            'role': 'system',
            'content': (
                'You are a strict reviewer and context compressor for a multi-step assistant pipeline.\n\n'
                'Check whether the specialist output satisfies the explicit step goal. Then extract only the parts that are actually useful for the next step or final answer.\n'
                f'Available capabilities for dynamic new_step: {available_capabilities}.\n'
                + skill_instruction +
                'Rules:\n'
                '- Return JSON only.\n'
                '- Do not add facts not present in the specialist output.\n'
                '- context_output must contain only goal-satisfying information from the output.\n'
                '- Remove rambling, repeated text, failed attempts, irrelevant background, and implementation chatter.\n'
                '- If the output only partially satisfies the goal, set meets_goal to false and put only the achieved useful part in context_output.\n'
                '- If nothing useful was achieved, context_output should be empty and missing should explain what is missing.\n'
                '- Keep context_output concise but preserve concrete facts, URLs, file paths, numbers, and decisions needed downstream.\n\n'
                'Dynamic planning rules:\n'
                '- Also decide whether the current plan is still sufficient after seeing this output.\n'
                '- Use next_action="accept" when the next existing step or final answer can proceed.\n'
                '- Use next_action="insert_step" when another specialized step is needed before continuing, such as another web search with a different keyword.\n'
                '- Use next_action="retry_step" only when the same kind of step should be retried with a clearer goal.\n'
                '- If code execution was skipped because a language is unsupported, retry or insert a step that rewrites equivalent code in the first supported executable language.\n'
                '- Use next_action="stop" only when continuing would be misleading or impossible.\n'
                '- If next_action is insert_step or retry_step, provide new_step with capability, goal, depends_on_previous, and extract.\n'
                '- If new_step capability is "skill", also provide skill_name exactly as listed.\n'
                '- The new_step goal must be concrete and self-contained. Do not add broad exploratory steps.\n\n'
                'Output format:\n'
                '{\n'
                '  "meets_goal": true,\n'
                '  "context_output": "only the useful goal-satisfying content",\n'
                '  "missing": "",\n'
                '  "reason": "short assessment",\n'
                '  "next_action": "accept",\n'
                '  "new_step": null\n'
                '}'
            ),
        },
        {
            'role': 'user',
            'content': (
                'Original user request:\n' + str(question_text or '').strip()
                + '\n\nStep capability:\n' + str(capability or '').strip()
                + '\n\nExplicit step goal:\n' + str(goal or '').strip()
                + '\n\nDownstream need:\n' + downstream_need
                + (('\n\nArtifacts produced:\n' + artifact_text) if artifact_text else '')
                + '\n\nSpecialist output to review:\n' + str(output_text or '').strip()
            ),
        },
    ]


def specialized_capability_label(capability: str) -> str:
    if capability == SPECIALIZED_SKILL_CAPABILITY:
        return 'Skill'
    for key, label in SPECIALIZED_CAPABILITIES:
        if key == capability:
            return label
    return capability.replace('_', ' ').title()


def build_skill_step_messages(skill: dict,
                              goal: str,
                              question_text: str,
                              shared_context: str,
                              previous_results: list[dict],
                              downstream_extract: str = '') -> list[dict]:
    skill_name = sanitize_skill_name(skill.get('name', ''), 'Skill')
    skill_description = str(skill.get('description', '') or '').strip()
    skill_body = str(skill.get('raw_text', '') or '').strip()
    if len(skill_body) > SKILL_BODY_MAX_CHARS:
        skill_body = skill_body[:SKILL_BODY_MAX_CHARS].rstrip() + '\n\n[Skill instructions truncated.]'
    previous_sections = []
    for result in previous_results:
        body = specialized_step_context_output(result)
        if not body:
            continue
        previous_sections.append(
            f"{result.get('capability', 'previous_step')} ({result.get('model_name', '')}):\n{body}"
        )
    system_content = (
        'You are executing one inserted skill step inside a desktop assistant pipeline.\n'
        'The skill is not global context. Follow the skill instructions for this step only.\n'
        'Produce the concrete result needed by the step goal. Do not include hidden reasoning.\n'
        'If the skill produces a final deliverable, surface it clearly and avoid unnecessary restatement.\n\n'
        'Code execution rule:\n'
        '- If the skill requires deterministic counting, calculation, parsing, validation, or any actual code execution, do not invent the result.\n'
        '- Return a single fenced code block in a configured runner language that performs the check. The app will run it in a background worker and send you the real stdout/stderr before finalizing this skill step.\n'
        f'- {code_runner_catalog_text()}\n'
        '- After receiving execution output, correct any earlier numbers using the real stdout/stderr.\n\n'
        f'Skill name: {skill_name}\n'
        + (f'Skill description: {skill_description}\n\n' if skill_description else '\n')
        + 'Skill instructions:\n'
        + skill_body
    )
    if downstream_extract:
        system_content += f'\n\nThe next step will use your output for: "{downstream_extract}". Make that handoff explicit.'
    user_parts = [
        'Original user request:\n' + str(question_text or '').strip(),
        'Current skill-step goal:\n' + str(goal or '').strip(),
    ]
    if shared_context.strip():
        user_parts.append('Retrieved context:\n' + shared_context.strip())
    if previous_sections:
        user_parts.append('Previous step output:\n' + '\n\n'.join(previous_sections))
    user_parts.append('Return only the skill-step result.')
    return [
        {'role': 'system', 'content': system_content},
        {'role': 'user', 'content': '\n\n'.join(user_parts)},
    ]


def build_specialized_step_messages(capability: str,
                                    goal: str,
                                    question_text: str,
                                    shared_context: str,
                                    previous_results: list[dict],
                                    downstream_extract: str = '') -> list[dict]:
    capability_prompts = {
        'task_reasoning': 'You are the task-reasoning specialist. Produce the strongest structured intermediate result for downstream use.',
        'web_search': 'You are the web-search specialist. If your model/service has search or current-knowledge capabilities, use them and return concise factual findings with useful URLs when available.',
        'text_to_speech': 'You are the text-to-speech specialist. Return the best textual handoff for speech generation or spoken delivery.',
        'speech_to_text': 'You are the speech-to-text specialist. Return the best transcription-style textual result.',
        'image_generation': 'You are the image-generation specialist. If your model/service can generate images, describe the produced image and the prompt used. Otherwise return a strong image prompt package for downstream use.',
        'video_generation': 'You are the video-generation specialist. If your model/service can generate video, describe the produced video and prompt used. Otherwise return a strong video prompt package for downstream use.',
        'video_to_text': 'You are the video-to-text specialist. Return a concise, useful textual summary/transcript-style result.',
    }
    system_content = capability_prompts.get(capability, 'You are a specialized assistant for this step.')
    system_content += (
        '\nIf this step needs deterministic counting, calculation, parsing, validation, or actual code execution, '
        'return a single fenced code block in a configured runner language. The app will run it in a background worker and send you the real stdout/stderr before finalizing this step. '
        'Do not claim computed results without execution. '
        + code_runner_catalog_text()
    )
    if downstream_extract:
        system_content += f'\nThe next step will use your output for: "{downstream_extract}". Ensure your response clearly surfaces that information.'
    previous_sections = []
    for result in previous_results:
        body = specialized_step_context_output(result)
        if not body:
            continue
        previous_sections.append(
            f"{result.get('capability', 'previous_step')} ({result.get('model_name', '')}):\n{body}"
        )
    user_parts = [
        'Original user request:\n' + str(question_text or '').strip(),
    ]
    if goal.strip():
        user_parts.append('Current step goal:\n' + goal.strip())
    if shared_context.strip():
        user_parts.append('Retrieved context:\n' + shared_context.strip())
    if previous_sections:
        user_parts.append('Previous step output:\n' + '\n\n'.join(previous_sections))
    user_parts.append('Return only the result of this step.')
    return [
        {
            'role': 'system',
            'content': system_content,
        },
        {
            'role': 'user',
            'content': '\n\n'.join(user_parts),
        },
    ]


def query_contains_cjk(text: str) -> bool:
    return bool(re.search(r'[\u4e00-\u9fff]', str(text or '')))


def translate_query_to_english_keywords(query: str) -> str:
    text = str(query or '').strip()
    if not text or not query_contains_cjk(text):
        return ''
    cached = KEYWORD_TRANSLATION_CACHE.get(text)
    if cached is not None:
        return cached

    profile = load_active_settings_profile()
    api_key = str(profile.get('api_key', '')).strip()
    model = str(profile.get('model', '')).strip()
    if not api_key or not model:
        KEYWORD_TRANSLATION_CACHE[text] = ''
        return ''
    endpoint = profile_runtime_base_url(profile)
    try:
        timeout = int(profile.get('timeout', 60) or 60)
    except (TypeError, ValueError):
        timeout = 60

    messages = [
        {
            'role': 'system',
            'content': (
                'Translate the user query into concise English retrieval keywords. '
                'Return only a short English keyword phrase. Preserve names, products, '
                'schools, places, and important entities. Do not explain.'
            ),
        },
        {
            'role': 'user',
            'content': text,
        },
    ]
    translated = ''
    try:
        client = create_openai_client(api_key, endpoint, timeout)
        response = client.chat.completions.create(
            model=model,
            messages=messages,
            stream=False,
        )
        translated = (response.choices[0].message.content or '').strip()
    except Exception:
        translated = ''
    lines = [line.strip() for line in str(translated or '').splitlines() if line.strip()]
    translated = (lines[0] if lines else '').strip('\'"“”')
    KEYWORD_TRANSLATION_CACHE[text] = translated
    return translated


def _retrieval_debug_preview(text: str, limit: int = 220) -> str:
    preview = re.sub(r'\s+', ' ', str(text or '')).strip()
    if len(preview) > limit:
        preview = preview[:limit].rstrip() + '...'
    return preview


def print_retrieval_debug(scope: str, strategy: str, question: str, chunks: list[dict]) -> None:
    try:
        header = f"[Broccoli retrieval] scope={scope} strategy={strategy} hits={len(chunks)} question={_retrieval_debug_preview(question, 120)}"
        print(header)
        if not chunks:
            print("[Broccoli retrieval] (no hits)")
            return
        for index, chunk in enumerate(chunks, start=1):
            name = str(chunk.get('name', '')).strip()
            prefix = f"[Broccoli retrieval] #{index}"
            if name:
                prefix += f" {name}"
            print(prefix + f": {_retrieval_debug_preview(chunk.get('display_text') or chunk.get('text', ''))}")
    except Exception:
        pass


def clone_messages_as_text(messages: list[dict]) -> list[dict]:
    cloned = []
    for message in messages:
        content = message.get('content', '')
        if isinstance(content, list):
            parts = []
            for item in content:
                if not isinstance(item, dict):
                    continue
                if item.get('type') == 'text':
                    parts.append(str(item.get('text', '')))
            content = '\n'.join(part for part in parts if part).strip()
        cloned.append({'role': message.get('role', 'user'), 'content': str(content)})
    return cloned


def update_conversation_running_summary(record: dict,
                                        api_key: str,
                                        endpoint: str,
                                        model: str,
                                        timeout: int) -> dict:
    turns = record.get('display', {}).get('turns', [])
    if not turns:
        record['memory']['running_summary'] = ''
        record['memory']['last_summarized_turn_count'] = 0
        return record

    last_summarized = max(0, int(record.get('memory', {}).get('last_summarized_turn_count', 0) or 0))
    if last_summarized >= len(turns):
        return record

    new_turns = turns[last_summarized:]
    new_turn_blocks = []
    for turn in new_turns:
        if turn.get('question', '').strip():
            label = 'Q'
            if turn.get('question_time'):
                label += f" · {turn['question_time']}"
            new_turn_blocks.append(label + '\n' + turn['question'].strip())
        if turn.get('answer', '').strip():
            label = 'A'
            if turn.get('answer_time'):
                label += f" · {turn['answer_time']}"
            new_turn_blocks.append(label + '\n' + turn['answer'].strip())
    if not new_turn_blocks:
        return record

    existing_summary = record.get('memory', {}).get('running_summary', '').strip()
    client = create_openai_client(api_key, endpoint, timeout)
    summary_messages = [
        {
            'role': 'system',
            'content': (
                'You maintain compact conversation memory for a chat assistant. '
                'Summarize only prior conversation turns. Preserve factual details, '
                'decisions, preferences, open questions, names, numbers, code context, '
                'and unresolved follow-ups. Do not add new content. Keep it concise and '
                'structured for future prompts.'
            ),
        },
        {
            'role': 'user',
            'content': (
                ('Existing memory summary:\n' + existing_summary + '\n\n') if existing_summary else ''
            ) + 'New conversation turns to merge:\n' + '\n\n'.join(new_turn_blocks) + '\n\n'
              'Return the updated memory summary only.'
        },
    ]
    response = client.chat.completions.create(
        model=model,
        messages=summary_messages,
        stream=False,
    )
    updated_summary = (response.choices[0].message.content or '').strip()
    if updated_summary:
        record['memory']['running_summary'] = updated_summary
        record['memory']['last_summarized_turn_count'] = len(turns)
    return record


def ensure_conversation_retrieval_embeddings(record: dict,
                                             api_key: str,
                                             endpoint: str,
                                             timeout: int,
                                             embedding_model: str) -> dict:
    source_chunks = build_retrieval_chunks(record.get('messages', []))
    existing_chunks = {
        (chunk.get('id'), chunk.get('text')): chunk
        for chunk in record.get('retrieval', {}).get('chunks', [])
        if chunk.get('embedding')
    }
    merged_chunks = []
    pending_texts = []
    pending_indexes = []
    for chunk in source_chunks:
        existing = existing_chunks.get((chunk['id'], chunk['text']))
        if existing and existing.get('embedding'):
            chunk['embedding'] = list(existing['embedding'])
        else:
            pending_indexes.append(len(merged_chunks))
            pending_texts.append(chunk['text'])
        merged_chunks.append(chunk)

    if pending_texts:
        client = create_openai_client(api_key, endpoint, timeout)
        response = client.embeddings.create(model=embedding_model, input=pending_texts)
        for response_item, chunk_index in zip(response.data, pending_indexes):
            merged_chunks[chunk_index]['embedding'] = list(response_item.embedding)

    record['retrieval']['chunks'] = merged_chunks
    return record


def retrieve_conversation_chunks(record: dict,
                                 query: str,
                                 api_key: str,
                                 endpoint: str,
                                 timeout: int,
                                 embedding_model: str,
                                 top_k: int = CONVERSATION_RETRIEVAL_TOP_K) -> list[dict]:
    chunks = [
        chunk for chunk in record.get('retrieval', {}).get('chunks', [])
        if chunk.get('embedding') and chunk.get('text', '').strip()
    ]
    if not query.strip() or not chunks:
        return []
    client = create_openai_client(api_key, endpoint, timeout)
    query_embedding = client.embeddings.create(model=embedding_model, input=query).data[0].embedding
    ranked = []
    for chunk in chunks:
        ranked.append((vector_similarity(query_embedding, chunk['embedding']), chunk))
    ranked.sort(key=lambda item: item[0], reverse=True)

    results = []
    seen_texts = set()
    for _, chunk in ranked:
        text_key = chunk['text'].strip()
        if text_key in seen_texts:
            continue
        seen_texts.add(text_key)
        results.append(chunk)
        if len(results) >= top_k:
            break
    return results


def _keyword_query_terms(query: str) -> list[str]:
    text = str(query or '').strip().lower()
    if not text:
        return []
    tokens = []
    if re.search(r'[\u4e00-\u9fff]', text):
        tokens.extend(token.strip() for token in jieba.lcut(text) if token.strip())
    tokens.extend(re.findall(r'[\w\u4e00-\u9fff]+', text))
    ordered = []
    seen = set()
    for token in [text] + tokens:
        token = token.strip()
        if not token:
            continue
        if len(token) == 1 and not token.isdigit():
            continue
        if token in seen:
            continue
        seen.add(token)
        ordered.append(token)
    return ordered


def _rank_keyword_chunks(chunks: list[dict], terms: list[str], top_k: int) -> list[dict]:
    ranked = []
    for chunk in chunks:
        text = chunk.get('text', '').lower()
        if not text:
            continue
        score = 0.0
        for index, term in enumerate(terms):
            if term in text:
                if index == 0:
                    score += 12.0
                score += max(1.0, min(6.0, len(term) / 2.0))
        if score > 0:
            ranked.append((score, chunk))
    ranked.sort(key=lambda item: item[0], reverse=True)
    return [chunk for _, chunk in ranked[:top_k]]


def keyword_retrieve_conversation_chunks(record: dict,
                                         query: str,
                                         top_k: int = CONVERSATION_RETRIEVAL_TOP_K) -> list[dict]:
    chunks = record.get('retrieval', {}).get('chunks', []) or build_retrieval_chunks(record.get('messages', []))
    terms = _keyword_query_terms(query)
    if not terms:
        return chunks[:top_k]
    results = _rank_keyword_chunks(chunks, terms, top_k)
    if results or not query_contains_cjk(query):
        return results
    translated_query = translate_query_to_english_keywords(query)
    translated_terms = _keyword_query_terms(translated_query)
    if not translated_terms:
        return results
    merged_terms = terms + [term for term in translated_terms if term not in terms]
    return _rank_keyword_chunks(chunks, merged_terms, top_k)


def build_conversation_context_block(record: dict,
                                     relevant_chunks: list[dict],
                                     recent_message_count: int = CONVERSATION_RECENT_MESSAGES) -> str:
    blocks = []
    running_summary = record.get('memory', {}).get('running_summary', '').strip()
    if running_summary:
        blocks.append('Conversation memory summary:\n' + running_summary)

    recent_messages = record.get('messages', [])[-recent_message_count:]
    if recent_messages:
        blocks.append('Recent conversation turns:\n' + render_chat_history_plaintext(recent_messages))

    if relevant_chunks:
        excerpt_blocks = []
        for index, chunk in enumerate(relevant_chunks, start=1):
            excerpt_blocks.append(f"[Relevant history excerpt {index}]\n{chunk.get('display_text', chunk.get('text', '')).strip()}")
        blocks.append('Relevant exact history excerpts:\n' + '\n\n'.join(excerpt_blocks))

    return '\n\n'.join(block for block in blocks if block).strip()


def build_history_context(messages: list[dict]) -> str:
    parts = []
    for message in messages:
        label = 'Q' if message['role'] == 'user' else 'A'
        parts.append(f'{label}: {message["content"]}')
    return '\n'.join(parts)


def should_use_display_history_context(messages: list[dict],
                                       max_chars: int = DISPLAY_HISTORY_CONTEXT_MAX_CHARS) -> bool:
    if not messages:
        return False
    try:
        plain = render_chat_history_plaintext(messages).strip()
    except Exception:
        plain = build_history_context(messages).strip()
    return bool(plain) and len(plain) <= max_chars


def build_chat_preview(history_messages: list[dict], question_text: str, answer_text: str = '') -> str:
    preview_messages = list(history_messages)
    preview_messages.append({'role': 'user', 'content': question_text})
    preview_messages.append({'role': 'assistant', 'content': answer_text})
    return render_chat_history_plaintext(preview_messages)


def parse_broccoli_output_attrs(raw_attrs: str) -> dict:
    attrs = {}
    for match in BROCCOLI_OUTPUT_ATTR_RE.finditer(str(raw_attrs or '')):
        key = match.group(1).strip().lower().replace('-', '_')
        value = match.group(3) if match.group(3) is not None else match.group(4)
        attrs[key] = html.unescape(str(value or '').strip())
    return attrs


def split_structured_outputs_from_answer(answer_text: str) -> tuple[str, list[dict]]:
    matches = list(BROCCOLI_OUTPUT_BLOCK_RE.finditer(str(answer_text or '')))
    if not matches:
        return str(answer_text or ''), []
    outputs = []
    # The UI is intentionally single-answer: if a model emits several blocks,
    # keep only the last one as the final chosen deliverable.
    match = matches[-1]
    attrs = parse_broccoli_output_attrs(match.group(1))
    kind = str(attrs.get('type', attrs.get('kind', 'text'))).strip().lower()
    if kind not in {'code', 'text'}:
        kind = 'text'
    content = html.unescape(match.group(2)).strip()
    if content:
        outputs.append(
            {
                'kind': kind,
                'title': str(attrs.get('title', '')).strip(),
                'filename': str(attrs.get('filename', '')).strip(),
                'content': content,
                'source': 'assistant_block',
            }
        )
    cleaned = BROCCOLI_OUTPUT_BLOCK_RE.sub('', str(answer_text or '')).strip()
    return cleaned, outputs


def build_assistant_message_content(answer_text: str, mode_index: int, references: str = '', show_references: bool = False) -> tuple[str, str]:
    cleaned_answer = answer_text.strip()
    if mode_index in (0, 7):
        if show_references and references:
            cleaned_answer = (cleaned_answer + '\n\n' + references.strip()).strip()
        return cleaned_answer, ''

    extracted, remainder = extract_marker_block(cleaned_answer)
    if mode_index == 1:
        command_body = extracted or cleaned_answer
        message_body = remainder.strip()
        if message_body:
            message_body = message_body + '\n\n'
        message_body = message_body + 'Command:\n\n```applescript\n' + command_body.strip() + '\n```'
        return message_body.strip(), command_body.strip()

    body = extracted or cleaned_answer
    if remainder.strip() and remainder.strip() != body:
        body = remainder.strip() + '\n\n' + body
    return body.strip(), body.strip()


def extract_marker_block(text: str) -> tuple[str, str]:
    match = MARKER_BLOCK_RE.search(text)
    if not match:
        return '', text
    extracted = match.group(1).strip('\n').strip('\t').strip()
    remainder = MARKER_BLOCK_RE.sub('', text).strip('\n')
    return extracted, remainder


def format_regular_mode_output(prefix_text: str, answer_text: str) -> str:
    return ensure_message_separator(normalize_conversation_text(prefix_text + answer_text))


def format_special_mode_output(prefix_text: str, answer_text: str, mode_index: int) -> tuple[str, str]:
    combined = normalize_conversation_text(prefix_text + answer_text)
    extracted, remainder = extract_marker_block(combined)
    if not extracted:
        extracted = answer_text.strip()
    if mode_index == 1:
        body = remainder.strip('\n')
        if body:
            body = body + "Your command is:" + '\n\t' + extracted
        else:
            body = "Your command is:" + '\n\t' + extracted
        return ensure_message_separator(body), extracted

    body = remainder.strip('\n')
    if body and extracted:
        body = body + '\n' + extracted
    elif extracted:
        body = extracted
    return ensure_message_separator(body), extracted


def load_saved_timeout(default_timeout: int = 60) -> int:
    timeset = read_text_file(BasePath + 'timeout.txt', str(default_timeout))
    try:
        return int(timeset) if timeset else default_timeout
    except ValueError:
        return default_timeout


def vector_similarity(x: list[float], y: list[float]) -> float:
    return float(np.dot(np.array(x), np.array(y)))


def attachment_supports_embedding(path: str) -> bool:
    ext = os.path.splitext(str(path or ''))[1].lower()
    return ext in ATTACHMENT_TEXT_EXTS or ext in {'.pdf', '.docx'}


def _ocr_pdf_text(path: str) -> str:
    try:
        import fitz  # pymupdf
        import pytesseract
        from PIL import Image as _PILImage
    except Exception:
        return ''

    text_blocks = []
    try:
        doc = fitz.open(path)
        total = len(doc)
        max_pages = load_pdf_max_pages()
        pages_to_scan = total if max_pages == 0 else min(total, max_pages)
        for page_num in range(pages_to_scan):
            page = doc.load_page(page_num)
            pix = page.get_pixmap(matrix=fitz.Matrix(150 / 72, 150 / 72), alpha=False)
            pil_img = _PILImage.frombytes('RGB', (pix.width, pix.height), pix.samples)
            page_text = pytesseract.image_to_string(pil_img).strip()
            if page_text:
                text_blocks.append(page_text)
        doc.close()
    except Exception:
        return ''
    return '\n\n'.join(block for block in text_blocks if block).strip()


def extract_attachment_text(path: str,
                            allow_ocr: bool = True,
                            limit_chars: int | None = None) -> dict | None:
    path = str(path or '')
    if not path:
        return None
    name = os.path.basename(path)
    ext = os.path.splitext(path)[1].lower()
    mime, _ = mimetypes.guess_type(path)
    mime = mime or ''
    content = ''

    if ext == '.pdf' or 'pdf' in mime:
        try:
            from pdfminer.high_level import extract_text as _pdftext
            content = (_pdftext(path) or '').strip()
        except Exception:
            content = ''
        if not content and allow_ocr:
            content = _ocr_pdf_text(path)
    elif ext == '.docx':
        try:
            content = (docx2txt.process(path) or '').strip()
        except Exception:
            content = ''
    elif ext in ATTACHMENT_TEXT_EXTS or mime.startswith('text/'):
        try:
            with open(path, 'r', encoding='utf-8', errors='replace') as f:
                content = f.read()
        except Exception:
            content = ''
    else:
        return None

    if not content:
        return None
    if limit_chars is not None:
        content = content[:limit_chars]
    return {
        'kind': 'text',
        'name': name,
        'content': content,
        'source_path': path,
    }


def build_attachment_retrieval_chunks(documents: list[dict]) -> list[dict]:
    chunks = []
    for doc_index, document in enumerate(documents):
        name = str(document.get('name', f'Document {doc_index + 1}')).strip() or f'Document {doc_index + 1}'
        content = str(document.get('content', '')).strip()
        if not content:
            continue
        for chunk_index, chunk_text in enumerate(chunk_text_for_retrieval(content)):
            chunks.append(
                {
                    'id': f'd{doc_index}-c{chunk_index}',
                    'name': name,
                    'text': chunk_text,
                    'display_text': f'{name}\n{chunk_text}',
                    'source_type': document.get('source_type', ''),
                    'tool_name': document.get('tool_name', ''),
                }
            )
    return chunks


def keyword_retrieve_attachment_chunks(chunks: list[dict],
                                       query: str,
                                       top_k: int = ATTACHMENT_RETRIEVAL_TOP_K) -> list[dict]:
    terms = _keyword_query_terms(query)
    if not terms:
        return chunks[:top_k]
    results = _rank_keyword_chunks(chunks, terms, top_k)
    if results or not query_contains_cjk(query):
        return results
    translated_query = translate_query_to_english_keywords(query)
    translated_terms = _keyword_query_terms(translated_query)
    if not translated_terms:
        return results
    merged_terms = terms + [term for term in translated_terms if term not in terms]
    return _rank_keyword_chunks(chunks, merged_terms, top_k)


def retrieve_attachment_chunks(chunks: list[dict],
                               query: str,
                               api_key: str,
                               endpoint: str,
                               timeout: int,
                               embedding_model: str,
                               top_k: int = ATTACHMENT_RETRIEVAL_TOP_K) -> list[dict]:
    if not query.strip() or not chunks:
        return []
    client = create_openai_client(api_key, endpoint, timeout)
    chunk_texts = [chunk['text'] for chunk in chunks]
    response = client.embeddings.create(model=embedding_model, input=chunk_texts)
    chunk_embeddings = [list(item.embedding) for item in response.data]
    query_embedding = client.embeddings.create(model=embedding_model, input=query).data[0].embedding
    ranked = []
    for chunk, embedding in zip(chunks, chunk_embeddings):
        ranked.append((vector_similarity(query_embedding, embedding), chunk))
    ranked.sort(key=lambda item: item[0], reverse=True)

    results = []
    seen_ids = set()
    for _, chunk in ranked:
        if chunk['id'] in seen_ids:
            continue
        seen_ids.add(chunk['id'])
        results.append(chunk)
        if len(results) >= top_k:
            break
    return results


def build_attachment_context_block(relevant_chunks: list[dict]) -> str:
    if not relevant_chunks:
        return ''
    blocks = []
    for index, chunk in enumerate(relevant_chunks, start=1):
        blocks.append(
            f"[Attached document excerpt {index} — {chunk.get('name', 'Document')}]\n"
            f"{chunk.get('text', '').strip()}"
        )
    return 'Relevant excerpts from attached documents:\n' + '\n\n'.join(block for block in blocks if block)


def build_attachment_references(relevant_chunks: list[dict]) -> str:
    if not relevant_chunks:
        return ''
    names = []
    seen = set()
    for chunk in relevant_chunks:
        name = str(chunk.get('name', '')).strip()
        if not name or name in seen:
            continue
        seen.add(name)
        names.append(name)
    if not names:
        return ''
    return 'References:\n' + '\n'.join(f'- {name}' for name in names)


def _external_source_patterns(source: dict, key: str, default_value: str = '') -> list[str]:
    return _split_context_patterns(str(source.get(key, '') or default_value))


def _external_path_matches(path: str, root: str, include_patterns: list[str], exclude_patterns: list[str]) -> bool:
    rel = os.path.relpath(path, root).replace(os.sep, '/')
    name = os.path.basename(path)
    for pattern in exclude_patterns:
        normalized = pattern.replace(os.sep, '/')
        if fnmatch.fnmatch(rel, normalized) or fnmatch.fnmatch(name, normalized):
            return False
    if not include_patterns:
        return True
    return any(fnmatch.fnmatch(rel, pattern) or fnmatch.fnmatch(name, pattern) for pattern in include_patterns)


def collect_local_external_context_documents(source: dict) -> list[dict]:
    path = str(source.get('path', '') or '').strip()
    if not path or not os.path.exists(path):
        return []
    max_chars = normalize_external_context_max_chars(source.get('max_chars', DEFAULT_EXTERNAL_CONTEXT_MAX_CHARS))
    include_patterns = _external_source_patterns(source, 'include_patterns', DEFAULT_EXTERNAL_CONTEXT_INCLUDE_PATTERNS)
    exclude_patterns = _external_source_patterns(source, 'exclude_patterns', DEFAULT_EXTERNAL_CONTEXT_EXCLUDE_PATTERNS)
    source_name = str(source.get('name', '') or 'Local context').strip()
    documents = []

    def add_file(file_path: str):
        if len(documents) >= DEFAULT_EXTERNAL_CONTEXT_MAX_FILES:
            return
        extracted = extract_attachment_text(
            file_path,
            allow_ocr=False,
            limit_chars=min(DEFAULT_EXTERNAL_CONTEXT_FILE_CHARS, max_chars),
        )
        if not extracted or not str(extracted.get('content', '')).strip():
            return
        try:
            rel_name = os.path.relpath(file_path, path if os.path.isdir(path) else os.path.dirname(path))
        except Exception:
            rel_name = os.path.basename(file_path)
        documents.append(
            {
                'name': f'{source_name} / {rel_name}',
                'content': str(extracted.get('content', '') or ''),
                'source_path': file_path,
                'source_name': source_name,
                'source_type': 'local_path',
            }
        )

    if os.path.isfile(path):
        add_file(path)
        return documents

    for root, dirs, files in os.walk(path):
        dirs[:] = [
            dirname for dirname in dirs
            if dirname not in {'.git', 'node_modules', '.venv', '__pycache__'}
        ]
        for filename in sorted(files):
            file_path = os.path.join(root, filename)
            if _external_path_matches(file_path, path, include_patterns, exclude_patterns):
                add_file(file_path)
            if len(documents) >= DEFAULT_EXTERNAL_CONTEXT_MAX_FILES:
                return documents
    return documents


def collect_external_context_documents(sources: list[dict],
                                       question_text: str = '',
                                       progress_callback=None) -> list[dict]:
    local_documents = []
    mcp_documents = []
    mcp_sources = []
    for source in normalize_external_context_sources(sources):
        if not source.get('enabled', True) or not source.get('auto_context', True):
            continue
        if source.get('type') == 'local_path':
            local_documents.extend(collect_local_external_context_documents(source))
        elif source.get('type') in {'mcp_http', 'mcp_stdio'}:
            mcp_sources.append(source)
    for source in mcp_sources[:MCP_RETRIEVAL_MAX_SOURCES]:
        mcp_documents.extend(collect_mcp_external_context_documents(source, question_text, progress_callback))
    return mcp_documents + local_documents


def build_external_context_full_block(documents: list[dict], max_chars: int) -> str:
    blocks = []
    remaining = max(0, int(max_chars))
    for index, document in enumerate(documents, start=1):
        name = str(document.get('name', f'External source {index}') or f'External source {index}').strip()
        content = str(document.get('content', '') or '').strip()
        if not content or remaining <= 0:
            continue
        excerpt = content[:remaining]
        remaining -= len(excerpt)
        blocks.append(f"[External context {index} - {name}]\n{excerpt}")
    if not blocks:
        return ''
    return 'External context sources:\n' + '\n\n'.join(blocks)


def build_external_context_retrieval_block(relevant_chunks: list[dict]) -> str:
    if not relevant_chunks:
        return ''
    blocks = []
    for index, chunk in enumerate(relevant_chunks, start=1):
        blocks.append(
            f"[External context excerpt {index} - {chunk.get('name', 'External source')}]\n"
            f"{chunk.get('text', '').strip()}"
        )
    return 'Relevant excerpts from external context sources:\n' + '\n\n'.join(block for block in blocks if block)


class AsyncPreflightSignals(QObject):
    progress = pyqtSignal(str)
    finished = pyqtSignal(object)
    failed = pyqtSignal(str)


class AsyncPreflightThread(threading.Thread):
    def __init__(self, owner, config: dict, signals: AsyncPreflightSignals):
        super().__init__(daemon=True)
        self.owner = owner
        self.config = config
        self.signals = signals
        self._stop_event = threading.Event()

    def request_stop(self):
        self._stop_event.set()

    def run(self):
        try:
            owner = self.owner

            def progress(message: str):
                if not self._stop_event.is_set() and str(message or '').strip():
                    self.signals.progress.emit(str(message or '').strip())

            question_text = str(self.config.get('question_text', '') or '')
            history_messages = list(self.config.get('history_messages') or [])
            retrieval_documents = list(self.config.get('retrieval_documents') or [])
            attachment_records = list(self.config.get('attachment_records') or [])
            api_key = str(self.config.get('api_key', '') or '')
            endpoint = str(self.config.get('endpoint', '') or '')
            model = str(self.config.get('model', '') or '')
            timeout = int(self.config.get('timeout', 60) or 60)
            mode_index = int(self.config.get('mode_index', 0) or 0)
            selected_message_indices = set(self.config.get('selected_message_indices') or [])
            skip_retrieval_for_blank_prompt = bool(self.config.get('skip_retrieval_for_blank_prompt', False))

            if self._stop_event.is_set():
                self.signals.finished.emit({'cancelled': True})
                return

            attachment_context = ''
            attachment_references = ''
            if skip_retrieval_for_blank_prompt:
                retrieval_documents = []
            if retrieval_documents:
                progress('Reading attached documents')
                attachment_context, attachment_references = owner._build_attachment_retrieval_context(
                    question_text,
                    retrieval_documents,
                    api_key,
                    endpoint,
                    timeout,
                )

            if self._stop_event.is_set():
                self.signals.finished.emit({'cancelled': True})
                return

            context_blocks = []
            if not skip_retrieval_for_blank_prompt:
                progress('Preparing external context and MCP sources')
                external_context = owner._build_external_context_prompt_context(question_text, progress_callback=progress)
                if external_context:
                    context_blocks.append(external_context)
            active_profile = load_active_settings_profile()
            if not skip_retrieval_for_blank_prompt and read_text_file(BasePath + 'history.txt', '0') == '1':
                progress('Retrieving conversation history')
                history_context = owner._build_active_history_context(
                    question_text,
                    history_messages,
                    api_key,
                    endpoint,
                    model,
                    timeout,
                    selected_message_indices=selected_message_indices,
                    refresh_ui=False,
                )
                if history_context:
                    context_blocks.append(history_context)
            if not skip_retrieval_for_blank_prompt and active_profile.get('remember_memory', True):
                progress('Retrieving saved memory')
                memory_context = owner._build_saved_memory_prompt_context(question_text)
                if memory_context:
                    context_blocks.append(memory_context)
            if not skip_retrieval_for_blank_prompt:
                vision_context = owner._build_background_vision_prompt_context()
                if vision_context:
                    context_blocks.append(vision_context)
            history = '\n\n'.join(block for block in context_blocks if block).strip()
            shared_context = '\n\n'.join(
                block for block in ([history, attachment_context] if attachment_context else [history]) if block
            ).strip()

            plan = {'steps': [], 'finalize_with_default_chat': False, 'reason': ''}
            step_results = []
            if mode_index == 0 and not skip_retrieval_for_blank_prompt:
                try:
                    enabled_skill_count = len(load_skill_records_from_store(enabled_only=True))
                    progress(
                        'Planning specialized steps'
                        + (f'\nEnabled skills available: {enabled_skill_count}' if enabled_skill_count else '')
                    )
                    plan = owner._plan_specialized_request(question_text, attachment_records)
                except Exception:
                    plan = {'steps': [], 'finalize_with_default_chat': False, 'reason': ''}
                if self._stop_event.is_set():
                    self.signals.finished.emit({'cancelled': True})
                    return
                if plan.get('steps'):
                    step_results = owner._execute_specialized_plan(
                        plan,
                        question_text,
                        shared_context,
                        attachment_records,
                        progress_callback=progress,
                    )

            if self._stop_event.is_set():
                self.signals.finished.emit({'cancelled': True})
                return

            self.signals.finished.emit(
                {
                    'cancelled': False,
                    'attachment_context': attachment_context,
                    'attachment_references': attachment_references,
                    'history': history,
                    'shared_context': shared_context,
                    'plan': plan,
                    'step_results': step_results,
                }
            )
        except Exception as exc:
            self.signals.failed.emit(str(exc))


class AsyncChatSignals(QObject):
    delta = pyqtSignal(str)
    status = pyqtSignal(str)
    tool_permission = pyqtSignal(object)
    finished = pyqtSignal(object)
    failed = pyqtSignal(str)


class AsyncChatThread(threading.Thread):
    def __init__(self, config: dict, signals: AsyncChatSignals):
        super().__init__(daemon=True)
        self.config  = config
        self.signals = signals
        self._stop_event = threading.Event()

    def request_stop(self):
        self._stop_event.set()

    def _stream_completion(self, client, messages: list[dict]) -> tuple[str, str, list[str]]:
        chunks = []
        finish_reason = ''
        citation_urls = []
        response_stream = client.chat.completions.create(
            model=self.config['model'],
            messages=messages,
            stream=True,
        )
        for response in response_stream:
            if self._stop_event.is_set():
                return ''.join(chunks), 'stopped', citation_urls
            if not getattr(response, 'choices', None):
                for url in extract_perplexity_citation_urls(getattr(response, 'citations', None)):
                    if url not in citation_urls:
                        citation_urls.append(url)
                continue
            choice = response.choices[0]
            delta = getattr(choice.delta, 'content', None)
            if delta:
                chunks.append(delta)
                self.signals.delta.emit(delta)
            if getattr(choice, 'finish_reason', None):
                finish_reason = choice.finish_reason
            # Perplexity streams can expose provider-specific citations on the
            # stream chunks; keep this isolated to the Perplexity path instead
            # of assuming generic OpenAI-compatible behavior.
            for url in extract_perplexity_citation_urls(getattr(response, 'citations', None)):
                if url not in citation_urls:
                    citation_urls.append(url)
        return ''.join(chunks), finish_reason, citation_urls

    def _summarize_answer_excerpt(self, client, existing_summary: str, excerpt: str) -> str:
        excerpt = str(excerpt or '').strip()
        if not excerpt:
            return existing_summary
        messages = [
            {
                'role': 'system',
                'content': (
                    'You compress already-written assistant output into compact continuation memory. '
                    'Preserve facts, numbering progress, code context, unresolved steps, and structural '
                    'state needed to continue seamlessly. Do not add new content.'
                ),
            },
            {
                'role': 'user',
                'content': (
                    ('Existing continuation memory:\n' + existing_summary + '\n\n') if existing_summary else ''
                ) + 'New excerpt to fold into continuation memory:\n' + excerpt + '\n\n'
                    'Return only the updated continuation memory.'
            },
        ]
        try:
            response = client.chat.completions.create(
                model=self.config['model'],
                messages=messages,
                stream=False,
            )
            candidate = (response.choices[0].message.content or '').strip()
            return candidate or existing_summary
        except Exception:
            if existing_summary:
                merged = (existing_summary + '\n' + excerpt[-1200:]).strip()
                return merged[-4000:]
            return excerpt[-1800:]

    def _build_continuation_messages(self, base_messages: list[dict], answer_summary: str, answer_tail: str) -> list[dict]:
        continuation_messages = clone_messages_as_text(base_messages)
        prompt_parts = [
            'Continue your previous answer to the same request.',
        ]
        if answer_summary.strip():
            prompt_parts.append('Compressed memory of the earlier part of your answer:\n' + answer_summary.strip())
        if answer_tail.strip():
            prompt_parts.append('Recent exact tail of your answer:\n' + answer_tail.strip())
        prompt_parts.append(
            'Continue from exactly where the answer stopped. Do not repeat prior text. '
            'Preserve the same language, tone, formatting, numbering, and code fences. '
            'Output only the continuation text.'
        )
        continuation_messages.append({'role': 'user', 'content': '\n\n'.join(prompt_parts)})
        return continuation_messages

    def _request_mcp_tool_permission(self, tool_meta: dict, arguments: dict) -> bool:
        permission_key = f"{tool_meta.get('source', {}).get('id', '')}:{tool_meta.get('tool_name', '')}"
        allowlist = self.config.setdefault('mcp_conversation_allowlist', set())
        if permission_key in allowlist:
            return True
        needs_confirmation = (not bool(tool_meta.get('read_only', True))) or bool(tool_meta.get('mutating', False))
        if not needs_confirmation:
            return True
        request = {
            'source_name': tool_meta.get('source_name', 'MCP source'),
            'tool_name': tool_meta.get('tool_name', ''),
            'arguments': arguments,
            'mutating': bool(tool_meta.get('mutating', False)),
            'read_only': bool(tool_meta.get('read_only', True)),
            'permission_key': permission_key,
            'decision': 'deny',
            'event': threading.Event(),
        }
        self.signals.tool_permission.emit(request)
        if not request['event'].wait(300):
            return False
        decision = str(request.get('decision', 'deny') or 'deny')
        if decision == 'always':
            allowlist.add(permission_key)
            return True
        return decision == 'allow'

    def _run_completion_with_mcp_tools(self, client, messages: list[dict]) -> tuple[str, str]:
        sources = self.config.get('mcp_sources') or []
        self.signals.status.emit('Discovering enabled MCP tools')
        tool_defs, tool_map = build_mcp_tool_runtime_bundle(sources)
        if not tool_defs:
            return '', 'no_tools'
        current_messages = clone_messages_as_text(messages)
        finish_reason = ''
        for round_index in range(MCP_TOOL_RUNTIME_MAX_ROUNDS):
            self.signals.status.emit(f'Asking model to choose MCP tools, round {round_index + 1}')
            response = client.chat.completions.create(
                model=self.config['model'],
                messages=current_messages,
                tools=tool_defs,
                tool_choice='auto',
                stream=False,
            )
            choice = response.choices[0]
            message = choice.message
            finish_reason = getattr(choice, 'finish_reason', '') or ''
            tool_calls = getattr(message, 'tool_calls', None) or []
            if not tool_calls:
                return message.content or '', finish_reason
            assistant_message = {
                'role': 'assistant',
                'content': message.content or '',
                'tool_calls': [],
            }
            for tool_call in tool_calls:
                function = getattr(tool_call, 'function', None)
                function_name = getattr(function, 'name', '') if function is not None else ''
                arguments_text = getattr(function, 'arguments', '{}') if function is not None else '{}'
                assistant_message['tool_calls'].append(
                    {
                        'id': getattr(tool_call, 'id', ''),
                        'type': 'function',
                        'function': {
                            'name': function_name,
                            'arguments': arguments_text or '{}',
                        },
                    }
                )
            current_messages.append(assistant_message)
            for tool_call in tool_calls:
                function = getattr(tool_call, 'function', None)
                function_name = getattr(function, 'name', '') if function is not None else ''
                arguments_text = getattr(function, 'arguments', '{}') if function is not None else '{}'
                tool_meta = tool_map.get(function_name)
                try:
                    arguments = json.loads(arguments_text or '{}')
                    if not isinstance(arguments, dict):
                        arguments = {}
                except Exception:
                    arguments = {}
                if tool_meta is None:
                    result_text = f'MCP tool is unavailable: {function_name}'
                elif self._request_mcp_tool_permission(tool_meta, arguments):
                    try:
                        self.signals.status.emit(
                            f"Calling {tool_meta.get('source_name', 'MCP source')} / {tool_meta.get('tool_name', '')}"
                        )
                        result = call_mcp_source_tool(tool_meta['source'], tool_meta['tool_name'], arguments)
                        result_text = _mcp_tool_result_to_text(result)
                    except Exception as exc:
                        result_text = f'MCP tool call failed: {exc}'
                else:
                    result_text = 'MCP tool call was denied by the user.'
                current_messages.append(
                    {
                        'role': 'tool',
                        'tool_call_id': getattr(tool_call, 'id', ''),
                        'content': (result_text or '')[:MCP_TOOL_RUNTIME_RESULT_CHARS],
                    }
                )
        self.signals.status.emit('Finishing answer from MCP tool results')
        response = client.chat.completions.create(
            model=self.config['model'],
            messages=current_messages + [
                {
                    'role': 'user',
                    'content': 'Finish the answer using the tool results already provided. Do not call more tools.',
                }
            ],
            stream=False,
        )
        return response.choices[0].message.content or '', getattr(response.choices[0], 'finish_reason', '') or finish_reason

    def run(self):
        try:
            timeout = self.config.get('timeout', 60)
            client = OpenAI(
                api_key=self.config['api_key'],
                base_url=self.config['endpoint'],
                timeout=timeout,
            )
            base_messages = clone_messages_as_text(self.config['messages'])
            references = ''

            messages = clone_messages_as_text(base_messages)

            # Inject attachment content into the last user message (multimodal)
            attachments = self.config.get('attachments', [])
            if attachments:
                # Work on a shallow copy of the list so we don't mutate config
                messages = list(messages)
                for i in range(len(messages) - 1, -1, -1):
                    if messages[i]['role'] == 'user':
                        original_content = messages[i]['content']
                        # Build a multimodal content list.
                        # Each attachment is either a single dict or a list of
                        # dicts (multi-page PDF → one entry per page).
                        content_list: list = [{"type": "text", "text": original_content}]
                        for att_or_list in attachments:
                            items = att_or_list if isinstance(att_or_list, list) else [att_or_list]
                            for att in items:
                                if att['kind'] == 'image':
                                    content_list.append({
                                        "type": "image_url",
                                        "image_url": {
                                            "url": f"data:{att['mime']};base64,{att['b64']}"
                                        },
                                    })
                                else:
                                    content_list.append({
                                        "type": "text",
                                        "text": (
                                            f"\n\n[Attached file: {att['name']}]\n"
                                            f"{att['content']}"
                                        ),
                                    })
                        messages[i] = dict(messages[i])
                        messages[i]['content'] = content_list
                        break

            if (
                self.config.get('mcp_tool_runtime_enabled', False)
                and int(self.config.get('mode_index', 0) or 0) == 0
            ):
                try:
                    answer_text, finish_reason = self._run_completion_with_mcp_tools(client, messages)
                    if finish_reason != 'no_tools':
                        self.signals.delta.emit(answer_text)
                        self.signals.finished.emit(
                            {
                                'answer': answer_text,
                                'references': references,
                                'finish_reason': finish_reason,
                                'mcp_tools_used': True,
                            }
                        )
                        return
                except Exception:
                    pass

            if self.config.get('stream', True):
                answer_segments = []
                answer_summary = ''
                live_tail = ''
                finish_reason = ''
                continuation_passes = 0
                current_messages = messages
                all_citation_urls = []

                while not self._stop_event.is_set():
                    segment_text, finish_reason, citation_urls = self._stream_completion(client, current_messages)
                    answer_segments.append(segment_text)
                    live_tail += segment_text
                    for url in citation_urls:
                        if url not in all_citation_urls:
                            all_citation_urls.append(url)

                    if finish_reason != 'length':
                        break

                    continuation_passes += 1
                    if continuation_passes >= CONTINUATION_MAX_PASSES:
                        break

                    if len(live_tail) > CONTINUATION_TAIL_CHARS:
                        excerpt_to_compress = live_tail[:-CONTINUATION_TAIL_CHARS]
                        live_tail = live_tail[-CONTINUATION_TAIL_CHARS:]
                        answer_summary = self._summarize_answer_excerpt(client, answer_summary, excerpt_to_compress)

                    current_messages = self._build_continuation_messages(base_messages, answer_summary, live_tail)

                # Only emit finished if we weren't stopped — StopX already
                # called on_async_chat_finished directly on the main thread.
                if not self._stop_event.is_set():
                    answer_text = ''.join(answer_segments)
                    if is_perplexity_endpoint(self.config.get('endpoint', '')):
                        citations_block = format_perplexity_citations_block(all_citation_urls)
                        if citations_block:
                            answer_text = answer_text + ('\n\n' if answer_text else '') + citations_block
                    self.signals.finished.emit(
                        {
                            'answer': answer_text,
                            'references': references,
                            'finish_reason': finish_reason,
                            'continuation_passes': continuation_passes,
                        }
                    )
                return

            response = client.chat.completions.create(
                model=self.config['model'],
                messages=messages,
                stream=False,
            )
            answer_text = response.choices[0].message.content or ''
            # Perplexity exposes citations on its chat-compatible responses, but
            # the field is provider-specific rather than OpenAI-standard.
            if is_perplexity_endpoint(self.config.get('endpoint', '')):
                citations_block = format_perplexity_citations_block(getattr(response, 'citations', None))
                if citations_block:
                    answer_text = answer_text + ('\n\n' if answer_text else '') + citations_block
            self.signals.finished.emit(
                {
                    'answer': answer_text,
                    'references': references,
                    'finish_reason': getattr(response.choices[0], 'finish_reason', ''),
                }
            )
        except Exception as exc:
            self.signals.failed.emit(str(exc))


class AsyncRenderSignals(QObject):
    finished = pyqtSignal(object)
    failed = pyqtSignal(object)


class AsyncRenderThread(threading.Thread):
    def __init__(self, config: dict, signals: AsyncRenderSignals):
        super().__init__(daemon=True)
        self.config = config
        self.signals = signals

    def run(self):
        try:
            history_messages = list(self.config.get('history_messages') or [])
            markdown_text = str(self.config.get('markdown_text', '') or '')
            display_prefix_map = {}
            if history_messages:
                display_text, display_prefix_map = render_chat_history_display_markup(history_messages)
            else:
                display_text = markdown_text
            html_text = render_markdown_document_to_html(
                display_text,
                bool(self.config.get('dark', False)),
                str(self.config.get('display_prefix_html', '') or ''),
                display_prefix_map=display_prefix_map,
            )
            self.signals.finished.emit(
                {
                    'request_id': int(self.config.get('request_id', 0) or 0),
                    'html': html_text,
                }
            )
        except Exception as exc:
            self.signals.failed.emit(
                {
                    'request_id': int(self.config.get('request_id', 0) or 0),
                    'error': str(exc),
                    'markdown_text': str(self.config.get('markdown_text', '') or ''),
                    'display_prefix_html': str(self.config.get('display_prefix_html', '') or ''),
                    'history_messages': history_messages,
                }
            )


def share_pixel_is_background(image: QImage, x: int, y: int, bg: QColor, tolerance: int = 18) -> bool:
    pixel = image.pixel(x, y)
    alpha = (pixel >> 24) & 0xFF
    if alpha < 8:
        return True
    red = (pixel >> 16) & 0xFF
    green = (pixel >> 8) & 0xFF
    blue = pixel & 0xFF
    return (
        abs(red - bg.red()) <= tolerance
        and abs(green - bg.green()) <= tolerance
        and abs(blue - bg.blue()) <= tolerance
    )


def share_row_has_content(image: QImage, y: int, bg: QColor, x1: int = 0, x2: int | None = None) -> bool:
    width = image.width()
    if x2 is None:
        x2 = width - 1
    x1 = max(0, min(width - 1, int(x1)))
    x2 = max(0, min(width - 1, int(x2)))
    if x2 < x1:
        return False
    step = 1 if (x2 - x1) <= 900 else 2
    for x in range(x1, x2 + 1, step):
        if not share_pixel_is_background(image, x, y, bg):
            return True
    if step > 1 and not share_pixel_is_background(image, x2, y, bg):
        return True
    return False


def share_column_has_content(image: QImage, x: int, bg: QColor, y1: int, y2: int) -> bool:
    height = image.height()
    y1 = max(0, min(height - 1, int(y1)))
    y2 = max(0, min(height - 1, int(y2)))
    if y2 < y1:
        return False
    step = 1 if (y2 - y1) <= 1600 else 2
    for y in range(y1, y2 + 1, step):
        if not share_pixel_is_background(image, x, y, bg):
            return True
    if step > 1 and not share_pixel_is_background(image, x, y2, bg):
        return True
    return False


def share_image_content_bounds(image: QImage, bg: QColor) -> QRect:
    if image.isNull():
        return QRect()
    width = image.width()
    height = image.height()
    top = None
    bottom = None
    for y in range(height):
        if share_row_has_content(image, y, bg):
            top = y
            break
    if top is None:
        return QRect()
    for y in range(height - 1, top - 1, -1):
        if share_row_has_content(image, y, bg):
            bottom = y
            break
    left = None
    right = None
    for x in range(width):
        if share_column_has_content(image, x, bg, top, bottom):
            left = x
            break
    if left is None:
        return QRect()
    for x in range(width - 1, left - 1, -1):
        if share_column_has_content(image, x, bg, top, bottom):
            right = x
            break
    pad_left = 36
    pad_right = 128
    pad_y = 64
    left = max(0, left - pad_left)
    top = max(0, top - pad_y)
    right = min(width - 1, right + pad_right)
    bottom = min(height - 1, bottom + pad_y)
    return QRect(left, top, right - left + 1, bottom - top + 1)


def crop_share_image_to_content(image: QImage, bg: QColor) -> QImage:
    if image.isNull():
        return image
    bounds = share_image_content_bounds(image, bg)
    if not bounds.isValid() or bounds.isNull():
        return image
    return image.copy(bounds)


def compress_share_vertical_whitespace(image: QImage, bg: QColor) -> QImage:
    if image.isNull():
        return image
    width = image.width()
    height = image.height()
    row_has_content = [share_row_has_content(image, y, bg) for y in range(height)]
    bands = []
    y = 0
    max_blank = 48
    while y < height:
        start = y
        has_content = row_has_content[y]
        while y < height and row_has_content[y] == has_content:
            y += 1
        length = y - start
        if has_content:
            bands.append((start, length, length))
            continue
        keep = min(length, max_blank)
        if keep > 0 and bands and y < height:
            bands.append((start, length, keep))
    new_h = max(1, sum(keep for _start, _length, keep in bands))
    if new_h >= height:
        return image
    result = QImage(width, new_h, QImage.Format.Format_ARGB32)
    result.fill(bg)
    painter = QPainter(result)
    target_y = 0
    for start, length, keep in bands:
        if keep <= 0:
            continue
        if keep == length:
            painter.drawImage(0, target_y, image.copy(0, start, width, length))
        target_y += keep
    painter.end()
    return result


def add_share_image_outer_padding(image: QImage, bg: QColor) -> QImage:
    if image.isNull():
        return image
    pad_left = 28
    pad_top = 52
    pad_right = 36
    pad_bottom = 64
    result = QImage(
        image.width() + pad_left + pad_right,
        image.height() + pad_top + pad_bottom,
        QImage.Format.Format_ARGB32,
    )
    result.fill(bg)
    painter = QPainter(result)
    painter.drawImage(pad_left, pad_top, image)
    painter.end()
    return result


def finalize_share_image_worker(image: QImage, bg: QColor) -> QImage:
    if image.isNull():
        return image
    image = crop_share_image_to_content(image, bg)
    image = compress_share_vertical_whitespace(image, bg)
    image = crop_share_image_to_content(image, bg)
    image = add_share_image_outer_padding(image, bg)
    return image


class AsyncShareImageSignals(QObject):
    finished = pyqtSignal(object)


class AsyncShareImageThread(threading.Thread):
    def __init__(self, image: QImage, bg: QColor, signals: AsyncShareImageSignals, request_id: int):
        super().__init__(daemon=True)
        self.image = image
        self.bg = bg
        self.signals = signals
        self.request_id = request_id

    def run(self):
        try:
            image = finalize_share_image_worker(self.image, self.bg)
            self.signals.finished.emit({'request_id': self.request_id, 'image': image})
        except Exception:
            self.signals.finished.emit({'request_id': self.request_id, 'image': self.image})


class NativeHotkeyTapThread(threading.Thread):
    def __init__(self, manager):
        super().__init__(daemon=True)
        self.manager = manager
        self._runloop = None
        self._tap_port = None
        self._callback = None

    def run(self):
        if not HOTKEY_BACKEND_AVAILABLE:
            return

        event_mask = CGEventMaskBit(kCGEventKeyDown)

        def callback(proxy, event_type, event, refcon):
            if event_type == kCGEventKeyDown:
                flags = int(CGEventGetFlags(event)) & HOTKEY_ALLOWED_FLAGS
                keycode = int(CGEventGetIntegerValueField(event, kCGKeyboardEventKeycode))
                self.manager.handle_keydown(flags, keycode)
            return event

        self._callback = callback
        self._tap_port = CGEventTapCreate(
            kCGHIDEventTap,
            kCGHeadInsertEventTap,
            kCGEventTapOptionDefault,
            event_mask,
            self._callback,
            None,
        )
        if self._tap_port is None:
            logging.error("Failed to create native hotkey event tap.")
            self.manager.mark_backend_failed()
            return

        source = CFMachPortCreateRunLoopSource(None, self._tap_port, 0)
        self._runloop = CFRunLoopGetCurrent()
        CFRunLoopAddSource(self._runloop, source, kCFRunLoopDefaultMode)
        CGEventTapEnable(self._tap_port, True)
        self.manager.mark_backend_ready()
        CFRunLoopRun()

    def stop(self):
        if self._runloop is not None:
            CFRunLoopStop(self._runloop)


BROWSER_BRIDGE_PORT = 49152


class BrowserBridgeSignals(QObject):
    received = pyqtSignal(dict)


class BrowserBridgeServer(threading.Thread):
    def __init__(self, signals: BrowserBridgeSignals):
        super().__init__(daemon=True)
        self.signals = signals
        self._server = None

    def run(self):
        import socketserver
        from http.server import BaseHTTPRequestHandler

        signals = self.signals

        class Handler(BaseHTTPRequestHandler):
            def log_message(self, *args):
                pass

            def _cors(self):
                self.send_header('Access-Control-Allow-Origin', '*')
                self.send_header('Access-Control-Allow-Methods', 'POST, GET, OPTIONS')
                self.send_header('Access-Control-Allow-Headers', 'Content-Type')

            def do_OPTIONS(self):
                self.send_response(204)
                self._cors()
                self.end_headers()

            def do_GET(self):
                if self.path == '/ping':
                    body = b'pong'
                    self.send_response(200)
                    self._cors()
                    self.send_header('Content-Type', 'text/plain')
                    self.send_header('Content-Length', str(len(body)))
                    self.end_headers()
                    self.wfile.write(body)
                else:
                    self.send_response(404)
                    self.end_headers()

            def do_POST(self):
                if self.path not in {'/ask', '/translate-popup'}:
                    self.send_response(404)
                    self.end_headers()
                    return
                length = int(self.headers.get('Content-Length', 0))
                raw = self.rfile.read(length)
                try:
                    payload = json.loads(raw.decode('utf-8'))
                except Exception:
                    payload = {}
                body = b'ok'
                self.send_response(200)
                self._cors()
                self.send_header('Content-Type', 'text/plain')
                self.send_header('Content-Length', str(len(body)))
                self.end_headers()
                self.wfile.write(body)
                if self.path == '/translate-popup':
                    payload['action'] = 'translate_popup'
                signals.received.emit(payload)

        class ReusableTCPServer(socketserver.TCPServer):
            allow_reuse_address = True

        try:
            self._server = ReusableTCPServer(('127.0.0.1', BROWSER_BRIDGE_PORT), Handler)
            self._server.serve_forever()
        except Exception as exc:
            logging.warning('BrowserBridgeServer failed to start: %s', exc)

    def stop(self):
        if self._server is not None:
            self._server.shutdown()


class GlobalHotkeyManager(QObject):
    ui_hotkey_pressed = pyqtSignal()
    same_position_screenshot_pressed = pyqtSignal()
    shortcut_recorded = pyqtSignal(str, str)
    shortcut_record_failed = pyqtSignal(str, str)
    backend_ready = pyqtSignal()
    backend_failed = pyqtSignal()

    def __init__(self):
        super().__init__()
        self._lock = threading.Lock()
        self._thread = None
        self._record_target = None
        self._backend_ready_flag = False
        self._cooldown_seconds = 0.35
        self._last_trigger = 0.0
        self._ui_spec = self._read_shortcut_spec(UI_SHORTCUT_PATH, DEFAULT_UI_SHORTCUT)
        self._same_position_screenshot_spec = self._read_settings_shortcut_spec('same_position_screenshot_shortcut')

    @property
    def available(self) -> bool:
        return HOTKEY_BACKEND_AVAILABLE

    @property
    def record_target(self):
        with self._lock:
            return self._record_target

    def _read_shortcut_spec(self, path: str, default_shortcut: str) -> dict:
        try:
            return build_shortcut_spec(read_text_file(path, ''), default_shortcut)
        except ValueError:
            logging.warning("Invalid shortcut in %s. Falling back to %s.", path, default_shortcut)
            normalized = normalize_shortcut_text('', default_shortcut)
            write_text_file(path, normalized)
            return build_shortcut_spec(normalized, default_shortcut)

    def _read_settings_shortcut_spec(self, key: str) -> dict | None:
        text = str(load_settings_store().get('globals', {}).get(key, '') or '').strip()
        if not text:
            return None
        try:
            return build_shortcut_spec(text, text)
        except ValueError:
            logging.warning("Invalid optional shortcut setting %s. Shortcut disabled.", key)
            return None

    def start(self):
        if not self.available or self._thread is not None:
            return
        self._thread = NativeHotkeyTapThread(self)
        self._thread.start()

    def stop(self):
        if self._thread is not None:
            self._thread.stop()
            self._thread = None
        self._backend_ready_flag = False

    def reload_shortcuts(self):
        with self._lock:
            self._ui_spec = self._read_shortcut_spec(UI_SHORTCUT_PATH, DEFAULT_UI_SHORTCUT)
            self._same_position_screenshot_spec = self._read_settings_shortcut_spec('same_position_screenshot_shortcut')

    def begin_recording(self, target: str) -> bool:
        if not self.available or not self._backend_ready_flag or target not in {'ui', 'same_position_screenshot'}:
            return False
        with self._lock:
            self._record_target = target
        return True

    def cancel_recording(self):
        with self._lock:
            self._record_target = None

    def mark_backend_ready(self):
        self._backend_ready_flag = True
        self.backend_ready.emit()

    def mark_backend_failed(self):
        self._backend_ready_flag = False
        self.backend_failed.emit()

    def handle_keydown(self, flags: int, keycode: int):
        key_token = KEYCODE_TO_TOKEN.get(keycode)
        if key_token is None:
            return

        now = time.monotonic()
        with self._lock:
            record_target = self._record_target
            ui_spec = dict(self._ui_spec)
            same_position_screenshot_spec = (
                dict(self._same_position_screenshot_spec)
                if self._same_position_screenshot_spec is not None
                else None
            )

        if record_target is not None:
            if flags == 0:
                self.shortcut_record_failed.emit(record_target, 'Shortcut must include at least one modifier key.')
                return

            normalized = serialize_shortcut(flags, key_token)
            updated_spec = build_shortcut_spec(normalized, normalized)

            with self._lock:
                if record_target == 'ui':
                    write_text_file(UI_SHORTCUT_PATH, normalized)
                    self._ui_spec = build_shortcut_spec(normalized, DEFAULT_UI_SHORTCUT)
                elif record_target == 'same_position_screenshot':
                    self._same_position_screenshot_spec = updated_spec
                self._record_target = None

            self.shortcut_recorded.emit(record_target, normalized)
            return

        matched_action = None
        if keycode == ui_spec['keycode'] and flags == ui_spec['flags']:
            matched_action = 'ui'
        elif (
            same_position_screenshot_spec is not None
            and keycode == same_position_screenshot_spec['keycode']
            and flags == same_position_screenshot_spec['flags']
        ):
            matched_action = 'same_position_screenshot'
        if matched_action is None:
            return
        if now - self._last_trigger < self._cooldown_seconds:
            return
        self._last_trigger = now
        if matched_action == 'same_position_screenshot':
            self.same_position_screenshot_pressed.emit()
        else:
            self.ui_hotkey_pressed.emit()


