class window_about(QWidget):  # 增加说明页面(About)
    def __init__(self):
        super().__init__()
        self.radius = 16
        self.drag_pos = None
        self.setWindowFlags(
            Qt.WindowType.FramelessWindowHint |
            Qt.WindowType.Window |
            Qt.WindowType.WindowStaysOnTopHint
        )
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        self.setAttribute(Qt.WidgetAttribute.WA_NoSystemBackground)
        self.initUI()

    def initUI(self):  # 说明页面内信息
        self.setUpMainWindow()
        self.setFixedSize(400, 600)
        self.center()
        self.setWindowTitle('About')
        self.setFocus()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        painter.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform)
        rect = QRectF(self.rect())
        path = QPainterPath()
        path.addRoundedRect(rect, self.radius, self.radius)
        painter.setClipPath(path)
        bg_color = self.palette().color(QPalette.ColorRole.Window)
        painter.fillPath(path, bg_color)

    def mousePressEvent(self, event):
        if event.button() == Qt.MouseButton.LeftButton:
            self.drag_pos = event.globalPosition().toPoint() - self.frameGeometry().topLeft()
            event.accept()

    def mouseMoveEvent(self, event):
        if event.buttons() == Qt.MouseButton.LeftButton and self.drag_pos is not None:
            self.move(event.globalPosition().toPoint() - self.drag_pos)
            event.accept()

    @staticmethod
    def _centered_row(*widgets):
        container = QWidget()
        layout = QHBoxLayout()
        layout.setContentsMargins(0, 0, 0, 0)
        layout.addStretch()
        for widget in widgets:
            layout.addWidget(widget)
        layout.addStretch()
        container.setLayout(layout)
        return container

    def setUpMainWindow(self):
        self.close_button = MacWindowButton("#FF605C", "x", self)
        self.close_button.move(10, 10)
        self.close_button.clicked.connect(self.close)

        l1 = QLabel(self)
        png = PyQt6.QtGui.QPixmap(BasePath + 'Broccolimen.png')
        l1.setPixmap(png)
        l1.setMaximumWidth(100)
        l1.setMaximumHeight(100)
        l1.setScaledContents(True)
        widg1 = self._centered_row(l1)

        lbl0 = QLabel(NAME, self)
        font = PyQt6.QtGui.QFont()
        font.setFamily("Arial")
        font.setBold(True)
        font.setPointSize(20)
        lbl0.setFont(font)
        widg2 = self._centered_row(lbl0)

        lbl1 = QLabel(f'Version {VERSION}', self)
        widg3 = self._centered_row(lbl1)

        lbl2 = QLabel('This app is open-sourced.', self)
        widg4 = self._centered_row(lbl2)

        lbl3 = QLabel('本软件开源，感谢您的喜爱！', self)
        widg5 = self._centered_row(lbl3)

        lbl4 = QLabel('Thanks for your love.', self)
        widg6 = self._centered_row(lbl4)

