class window_update(QWidget):  # 增加更新页面（Check for Updates）
    def __init__(self):
        super().__init__()
        self.radius = 16
        self.drag_pos = None
        self.setWindowFlags(
            Qt.WindowType.FramelessWindowHint |
            Qt.WindowType.Window |
            Qt.WindowType.WindowStaysOnTopHint
        )
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        self.setAttribute(Qt.WidgetAttribute.WA_NoSystemBackground)
        self.initUI()

    def initUI(self):  # 说明页面内信息
        self.setUpMainWindow()
        self.setFixedSize(320, 250)
        self.center()
        self.setWindowTitle('Broccoli Updates')
        self.setFocus()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        painter.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform)
        rect = QRectF(self.rect())
        path = QPainterPath()
        path.addRoundedRect(rect, self.radius, self.radius)
        painter.setClipPath(path)
        bg_color = self.palette().color(QPalette.ColorRole.Window)
        painter.fillPath(path, bg_color)

    def mousePressEvent(self, event):
        if event.button() == Qt.MouseButton.LeftButton:
            self.drag_pos = event.globalPosition().toPoint() - self.frameGeometry().topLeft()
            event.accept()

    def mouseMoveEvent(self, event):
        if event.buttons() == Qt.MouseButton.LeftButton and self.drag_pos is not None:
            self.move(event.globalPosition().toPoint() - self.drag_pos)
            event.accept()

    def setUpMainWindow(self):
        self.close_button = MacWindowButton("#FF605C", "x", self)
        self.close_button.move(10, 10)
        self.close_button.clicked.connect(self.close)

        title = QLabel("<h2>Broccoli Update</h2>", self)
        title.setAlignment(Qt.AlignmentFlag.AlignCenter)

        widg5 = QWidget()
        lbl1 = QLabel('Latest version:', self)
        self.lbl2 = QLabel('', self)
        self.lbl2.setWordWrap(True)
        blay5 = QHBoxLayout()
        blay5.setContentsMargins(0, 0, 0, 0)
        blay5.addWidget(lbl1)
        blay5.addWidget(self.lbl2, 1)
        widg5.setLayout(blay5)

        widg3 = QWidget()
        self.lbl = QLabel(f'Current version: v{VERSION}', self)
        blay3 = QHBoxLayout()
        blay3.setContentsMargins(0, 0, 0, 0)
        blay3.addWidget(self.lbl)
        blay3.addStretch()
        widg3.setLayout(blay3)

        widg4 = QWidget()
        widg4.setFixedHeight(50)
        lbl0 = QLabel('Check release:', self)
        bt1 = WhiteButton('Github')
        bt1.setFixedWidth(120)
        bt1.clicked.connect(self.upd)
        blay4 = QHBoxLayout()
        blay4.setContentsMargins(0, 0, 0, 0)
        blay4.addWidget(lbl0)
        blay4.addWidget(bt1)
        blay4.addStretch()
        widg4.setLayout(blay4)

        main_h_box = QVBoxLayout()
        main_h_box.setContentsMargins(20, 40, 20, 20)
        main_h_box.addWidget(title)
        main_h_box.addSpacing(5)
        main_h_box.addWidget(widg5)
        main_h_box.addSpacing(5)
        main_h_box.addWidget(widg3)
        main_h_box.addWidget(widg4)
        self.setLayout(main_h_box)

    def upd(self):
        webbrowser.open('https://github.com/Ryan-the-hito/Broccoli/releases')

    def center(self):  # 设置窗口居中
        qr = self.frameGeometry()
        cp = self.screen().availableGeometry().center()
        qr.moveCenter(cp)
        self.move(qr.topLeft())

    def activate(self):  # 设置窗口显示
        self.show()
        self.checkupdate()

    def checkupdate(self):
        try:
            text = self.fetch_latest_version_text()
            result = self.extract_latest_tag(text)
            if not result:
                alertupdate = 'No Intrenet'
            else:
                nowversion = 'v' + VERSION
                if result == nowversion:
                    alertupdate = result + ' (up-to-date)'
                else:
                    alertupdate = result + ' is ready!'
        except Exception:
            alertupdate = 'No Intrenet'
        self.lbl2.setText(alertupdate)
        self.lbl2.adjustSize()

    @staticmethod
    def fetch_latest_version_text():
        targetURL = 'https://github.com/Ryan-the-hito/Broccoli/releases'
        try:
            urllib3.disable_warnings()
            logging.captureWarnings(True)
            s = requests.session()
            s.keep_alive = False
            response = s.get(targetURL, verify=False, timeout=15)
            response.encoding = 'utf-8'
            html_content = response.text
            soup = BeautifulSoup(html_content, "html.parser")
            for img in soup.find_all("img"):
                img.decompose()
            text_maker = html2text.HTML2Text()
            text_maker.ignore_links = True
            text_maker.ignore_images = True
            plain_text = text_maker.handle(str(soup))
            plain_text_utf8 = plain_text.encode(response.encoding).decode("utf-8")
            for _ in range(10):
                plain_text_utf8 = (plain_text_utf8
                                   .replace('\n\n\n\n', '\n\n')
                                   .replace('\n\n\n', '\n\n')
                                   .replace('   ', ' ')
                                   .replace('  ', ' '))
            return plain_text_utf8
        except Exception:
            return None

    @staticmethod
    def extract_latest_tag(plain_text_utf8: str) -> str | None:
        if not plain_text_utf8:
            return None
        pattern2 = re.compile(r'(v\d+\.\d+\.\d+)\sLatest')
        result = pattern2.findall(plain_text_utf8)
        if result:
            return result[0]
        return None


