class WebFetchPanel(QWidget):
    close_requested = pyqtSignal()
    selection_changed = pyqtSignal()
    collapse_toggled = pyqtSignal(bool)

    PANEL_W = 460
    PANEL_H = 260
    COLLAPSED_D = 40

    def __init__(self, parent=None):
        super().__init__(parent)
        self._theme_updating = False
        self._records = []
        self._collapsed = False
        self._block_items = False
        self._build_ui()

    def _build_ui(self):
        self.setObjectName('WebFetchPanel')
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self.resize(self.PANEL_W, self.PANEL_H)
        self.setMinimumSize(self.COLLAPSED_D, self.COLLAPSED_D)
        shadow = QGraphicsDropShadowEffect(self)
        shadow.setBlurRadius(28)
        shadow.setXOffset(0)
        shadow.setYOffset(8)
        shadow.setColor(QColor(0, 0, 0, 45))
        self.setGraphicsEffect(shadow)

        self._main_layout = QVBoxLayout(self)
        self._main_layout.setContentsMargins(18, 14, 18, 14)
        self._main_layout.setSpacing(10)

        self._header_layout = QHBoxLayout()
        self._header_layout.setContentsMargins(0, 0, 0, 0)
        self._header_layout.setSpacing(6)
        self.title_lbl = QLabel('Web pages', self)
        self.meta_lbl = QLabel('No imported pages detected yet.', self)
        self.meta_lbl.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
        self.collapse_btn = QPushButton('Collapse', self)
        self.close_btn = QPushButton('Close', self)
        self.collapse_btn.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
        self.close_btn.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
        self.collapse_btn.clicked.connect(self.toggle_collapsed)
        self.close_btn.clicked.connect(self.close_requested.emit)
        self._header_layout.addWidget(self.title_lbl)
        self._header_layout.addWidget(self.meta_lbl, 1)
        self._header_layout.addWidget(self.collapse_btn)
        self._header_layout.addWidget(self.close_btn)

        self.list_widget = QListWidget(self)
        self.list_widget.itemChanged.connect(self._on_item_changed)

        self._main_layout.addLayout(self._header_layout)
        self._main_layout.addWidget(self.list_widget, 1)
        self._apply_theme()

    def _apply_theme(self):
        if self._theme_updating:
            return
        self._theme_updating = True
        dark = is_dark_theme(app)
        try:
            radius = self.COLLAPSED_D // 2 if self._collapsed else 26
            self.setStyleSheet(
                f'QWidget#WebFetchPanel {{ border: 1px solid {"#2D2D2D" if dark else "#ECECEC"}; '
                f'background: {"#2D2D2D" if dark else "#FFFFFF"}; border-radius: {radius}px; }}'
            )
            self.title_lbl.setStyleSheet(
                f'color: {"#F2F2F7" if dark else "#20242B"}; font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; '
                'font-size: 15px; font-weight: 600;'
            )
            self.meta_lbl.setStyleSheet(
                f'color: {"#A7AEB8" if dark else "#7A8391"}; font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; '
                'font-size: 12px;'
            )
            if self._collapsed:
                self.collapse_btn.setStyleSheet(
                    f'''
                    QPushButton {{
                        background: {"#3A3A3A" if dark else "#F4F4F5"};
                        color: {"#F2F2F7" if dark else "#20242B"};
                        border: none;
                        border-radius: {self.COLLAPSED_D // 2}px;
                        font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
                        font-size: 13px;
                        font-weight: 700;
                    }}
                    QPushButton:hover {{
                        background: {"#474747" if dark else "#EBEBED"};
                    }}
                    QPushButton:pressed {{
                        background: {"#505050" if dark else "#E1E1E4"};
                    }}
                    '''
                )
            else:
                capsule_bg = "#3A3A3A" if dark else "#F5F6F8"
                capsule_hover = "#454547" if dark else "#EEF1F5"
                capsule_pressed = "#2E5C91" if dark else "#E4E8EE"
                capsule_fg = "#F2F2F7" if dark else "#20242B"
                capsule_style = f'''
                    QPushButton {{
                        border: none;
                        border-radius: 17px;
                        padding: 0 18px;
                        background: {capsule_bg};
                        color: {capsule_fg};
                        font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
                        font-size: 14px;
                        font-weight: 600;
                    }}
                    QPushButton:hover {{ background: {capsule_hover}; }}
                    QPushButton:pressed {{ background: {capsule_pressed}; }}
                '''
                self.collapse_btn.setStyleSheet(capsule_style)
                self.close_btn.setStyleSheet(capsule_style)
            if self._collapsed:
                self.collapse_btn.setFixedSize(self.COLLAPSED_D, self.COLLAPSED_D)
            else:
                collapse_w = max(110, self.collapse_btn.fontMetrics().horizontalAdvance('Collapse') + 36)
                close_w = max(92, self.close_btn.fontMetrics().horizontalAdvance('Close') + 36)
                self.collapse_btn.setFixedSize(collapse_w, 34)
                self.close_btn.setFixedSize(close_w, 34)
            self.list_widget.setStyleSheet(_input_card_stylesheet(dark))
        finally:
            self._theme_updating = False

    def changeEvent(self, event):
        super().changeEvent(event)
        if self._theme_updating:
            return
        if event.type() in (QEvent.Type.PaletteChange, QEvent.Type.ApplicationPaletteChange):
            self._apply_theme()

    def set_export_records(self, records: list[dict] | None):
        previous = {
            (
                str(page.get('_source_path', '')).strip(),
                str(page.get('url', '')).strip(),
            )
            for page in self.selected_pages()
        }
        normalized_records = []
        for record in records or []:
            if isinstance(record, dict):
                normalized_records.append(record)
        self._records = normalized_records
        self._block_items = True
        self.list_widget.clear()
        pages = []
        for record in self._records:
            source_path = str(record.get('path', '')).strip()
            for page in list(record.get('pages', [])):
                if not isinstance(page, dict):
                    continue
                page_copy = dict(page)
                page_copy['_source_path'] = source_path
                pages.append(page_copy)
        if pages:
            for index, page in enumerate(pages):
                title = str(page.get('title', '')).strip() or str(page.get('url', '')).strip() or f'Page {index + 1}'
                url = str(page.get('url', '')).strip()
                item = QListWidgetItem(f'{title}\n{url}' if url and url != title else title)
                item.setData(Qt.ItemDataRole.UserRole, page)
                item.setFlags(item.flags() | Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsUserCheckable)
                page_key = (str(page.get('_source_path', '')).strip(), url)
                item.setCheckState(Qt.CheckState.Checked if not previous or page_key in previous else Qt.CheckState.Unchecked)
                item.setSizeHint(QSize(0, 44))
                self.list_widget.addItem(item)
            batch_count = len(self._records)
            self.meta_lbl.setText(f'{len(pages)} pages · {batch_count} batch{"es" if batch_count != 1 else ""}')
        else:
            self.meta_lbl.setText('No imported pages detected yet.')
        self._block_items = False
        self.selection_changed.emit()

    def append_export_record(self, record: dict | None):
        if not isinstance(record, dict):
            return
        existing = list(self._records)
        record_path = str(record.get('path', '')).strip()
        if record_path:
            existing = [item for item in existing if str(item.get('path', '')).strip() != record_path]
        existing.append(record)
        existing.sort(key=lambda item: str(item.get('exported_at', '')).strip(), reverse=True)
        self.set_export_records(existing)

    def selected_pages(self) -> list[dict]:
        pages = []
        for index in range(self.list_widget.count()):
            item = self.list_widget.item(index)
            if item is None or item.checkState() != Qt.CheckState.Checked:
                continue
            page = item.data(Qt.ItemDataRole.UserRole)
            if isinstance(page, dict):
                pages.append(page)
        return pages

    def has_selection(self) -> bool:
        return bool(self.selected_pages())

    def toggle_collapsed(self):
        self.set_collapsed(not self._collapsed)

    def set_collapsed(self, collapsed: bool):
        collapsed = bool(collapsed)
        if self._collapsed == collapsed:
            return
        self._collapsed = collapsed
        self.title_lbl.setVisible(not collapsed)
        self.meta_lbl.setVisible(not collapsed)
        self.close_btn.setVisible(not collapsed)
        self.list_widget.setVisible(not collapsed)
        if collapsed:
            self._main_layout.setContentsMargins(0, 0, 0, 0)
            self._main_layout.setSpacing(0)
            self._header_layout.setContentsMargins(0, 0, 0, 0)
            self.collapse_btn.setText('📑')
            self.collapse_btn.setFixedSize(self.COLLAPSED_D, self.COLLAPSED_D)
        else:
            self._main_layout.setContentsMargins(18, 14, 18, 14)
            self._main_layout.setSpacing(10)
            self._header_layout.setContentsMargins(0, 0, 0, 0)
            self.collapse_btn.setText('Collapse')
        self._apply_theme()
        self.collapse_toggled.emit(collapsed)

    def is_collapsed(self) -> bool:
        return self._collapsed

    def _on_item_changed(self, item):
        if not self._block_items:
            self.selection_changed.emit()


