def branch_question_preview(text: str, limit: int = 42) -> str:
    text = re.sub(r'\s+', ' ', str(text or '')).strip()
    if len(text) <= limit:
        return text
    return text[:max(1, limit - 1)].rstrip() + '…'


class BranchTreeItem(QStandardItem):
    def __init__(self, text: str, node_id: str, checked: bool = True):
        super().__init__(text)
        self.setEditable(False)
        self.setCheckable(True)
        self.setCheckState(Qt.CheckState.Checked if checked else Qt.CheckState.Unchecked)
        self.setData(node_id, Qt.ItemDataRole.UserRole)


class BranchTreeView(QTreeView):
    row_activated = pyqtSignal(object)

    def mousePressEvent(self, event):
        index = self.indexAt(event.pos())
        should_activate = False
        if index.isValid():
            rect = self.visualRect(index)
            check_zone_right = rect.left() + 28
            should_activate = event.position().x() > check_zone_right
        super().mousePressEvent(event)
        if should_activate and index.isValid():
            self.row_activated.emit(index)


class BranchGraphWidget(QWidget):
    def __init__(self, parent=None):
        super().__init__(parent)
        self._theme_updating = False
        self._active_node_id = ''
        self._checked_node_ids = set()
        self._scene = QGraphicsScene(self)
        self._frame = QFrame(self)
        self._frame.setObjectName('BranchGraphFrame')
        self._view = QGraphicsView(self._scene, self._frame)
        self._view.setFrameShape(QFrame.Shape.NoFrame)
        self._view.setRenderHints(
            QPainter.RenderHint.Antialiasing | QPainter.RenderHint.TextAntialiasing | QPainter.RenderHint.SmoothPixmapTransform
        )
        self._view.setHorizontalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAsNeeded)
        self._view.setVerticalScrollBarPolicy(Qt.ScrollBarPolicy.ScrollBarAsNeeded)
        frame_layout = QVBoxLayout(self._frame)
        frame_layout.setContentsMargins(12, 12, 12, 12)
        frame_layout.addWidget(self._view)
        layout = QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.addWidget(self._frame)
        self._node_d = 44
        self._h_gap = 42
        self._v_gap = 84
        self._apply_theme()

    def _apply_theme(self):
        if self._theme_updating:
            return
        self._theme_updating = True
        dark = is_dark_theme(app)
        try:
            frame_bg = '#343436' if dark else '#FBFBFC'
            frame_border = '#4A4B4F' if dark else '#E4E8EE'
            track = '#2F3033' if dark else '#E8ECF2'
            handle = '#7D828A' if dark else '#98A4B3'
            handle_hover = '#A2A8B0' if dark else '#6F7C8C'
            self.setStyleSheet(
                'QWidget { background: transparent; }'
                f'QFrame#BranchGraphFrame {{ border: 1px solid {frame_border}; border-radius: 18px; background: {frame_bg}; }}'
                'QGraphicsView { border: none; background: transparent; }'
                f'QScrollBar:horizontal {{ height: 10px; margin: 6px 12px 2px 12px; background: {track}; border-radius: 5px; }}'
                f'QScrollBar::handle:horizontal {{ background: {handle}; min-width: 36px; border-radius: 5px; }}'
                f'QScrollBar::handle:horizontal:hover {{ background: {handle_hover}; }}'
                f'QScrollBar:vertical {{ width: 10px; margin: 12px 2px 12px 6px; background: {track}; border-radius: 5px; }}'
                f'QScrollBar::handle:vertical {{ background: {handle}; min-height: 36px; border-radius: 5px; }}'
                f'QScrollBar::handle:vertical:hover {{ background: {handle_hover}; }}'
                'QScrollBar::add-line, QScrollBar::sub-line, QScrollBar::add-page, QScrollBar::sub-page { background: transparent; border: none; }'
            )
        finally:
            self._theme_updating = False

    def changeEvent(self, event):
        super().changeEvent(event)
        if self._theme_updating:
            return
        if event.type() in (QEvent.Type.PaletteChange, QEvent.Type.ApplicationPaletteChange):
            self._apply_theme()

    def update_graph(self, root_nodes: list[dict], active_node_id: str = '', checked_node_ids: set | None = None):
        self._scene.clear()
        self._active_node_id = str(active_node_id or '')
        self._checked_node_ids = set(checked_node_ids or set())
        dark = is_dark_theme(app)
        if not root_nodes:
            text = self._scene.addText('No questions yet.')
            text.setDefaultTextColor(QColor('#A7AEB8' if dark else '#7A8391'))
            text.setPos(20, 20)
            return
        self._draw_nodes(root_nodes, 28, 24, None)
        self._scene.setSceneRect(self._scene.itemsBoundingRect().adjusted(-24, -24, 24, 24))

    def _draw_nodes(self, nodes: list[dict], x: float, y: float, parent_center: tuple[float, float] | None) -> float:
        dark = is_dark_theme(app)
        line_color = QColor('#5A5C61' if dark else '#D6DCE5')
        text_color = QColor('#F2F2F7' if dark else '#20242B')
        for node in nodes:
            node_id = str(node.get('id', ''))
            checked = bool(node.get('checked', True))
            is_active = node_id == self._active_node_id
            if is_active:
                fill = QColor('#0A84FF' if dark else '#2E5C91')
                border = QColor('#5AC8FA' if dark else '#1F4F86')
            elif checked:
                fill = QColor('#44627F' if dark else '#DCEAFB')
                border = QColor('#5A86AD' if dark else '#94B8E5')
            else:
                fill = QColor('#3A3A3A' if dark else '#F1F3F6')
                border = QColor('#5A5C61' if dark else '#D6DCE5')
            ellipse = QGraphicsEllipseItem(0, 0, self._node_d, self._node_d)
            ellipse.setBrush(QBrush(fill))
            ellipse.setPen(QPen(border, 2))
            ellipse.setPos(x, y)
            self._scene.addItem(ellipse)
            label = branch_question_preview(node.get('text', ''), 10)
            text = QGraphicsTextItem(label)
            font = text.font()
            font.setPixelSize(10)
            font.setBold(is_active)
            text.setFont(font)
            text.setDefaultTextColor(text_color)
            text.setTextWidth(self._node_d - 10)
            text.setPos(x + 5, y + 10)
            self._scene.addItem(text)
            center = (x + self._node_d / 2.0, y + self._node_d / 2.0)
            if parent_center is not None:
                line = QGraphicsLineItem(parent_center[0], parent_center[1], center[0], center[1])
                line.setPen(QPen(line_color, 2))
                self._scene.addItem(line)
            children = list(node.get('children') or [])
            if children:
                x = self._draw_nodes(children, x, y + self._v_gap, center)
            else:
                x += self._node_d + self._h_gap
        return x


class BranchPanel(QWidget):
    close_requested = pyqtSignal()
    branch_changed = pyqtSignal(dict)
    jump_requested = pyqtSignal(int)

    def __init__(self, parent=None):
        super().__init__(parent)
        self._theme_updating = False
        self._block_item_changes = False
        self._state = None
        self._display_root_item = None
