class AnnotatedTextPreview(QPlainTextEdit):
    annotation_requested = pyqtSignal(int, int, str)

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.customContextMenuRequested.connect(self._show_context_menu)

    def _show_context_menu(self, pos):
        menu = self.createStandardContextMenu()
        cursor = self.textCursor()
        if cursor.hasSelection():
            action = menu.addAction('Add Comment')
            action.triggered.connect(self._request_annotation)
        menu.exec(self.mapToGlobal(pos))

    def _request_annotation(self):
        cursor = self.textCursor()
        if not cursor.hasSelection():
            return
        start = min(cursor.selectionStart(), cursor.selectionEnd())
        end = max(cursor.selectionStart(), cursor.selectionEnd())
        quote = cursor.selectedText().replace('\u2029', '\n')
        self.annotation_requested.emit(start, end, quote)


class AnnotatableImageLabel(QWidget):
    annotation_created = pyqtSignal(dict)

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self.setMouseTracking(True)
        self._pixmap = QPixmap()
        self._annotations = []
        self._drawing = False
        self._current_points = []
        self._pen_color = '#FF3B30'
        self._placeholder = ''

    def set_pen_color(self, color: str):
        value = str(color or '').strip()
        if not QColor(value).isValid():
            value = '#FF3B30'
        self._pen_color = value
        self.update()

    def set_placeholder(self, text: str):
        self._placeholder = str(text or '')
        self.update()

    def set_pixmap(self, pixmap: QPixmap):
        self._pixmap = pixmap if isinstance(pixmap, QPixmap) else QPixmap()
        self.update()

    def set_annotations(self, annotations: list[dict]):
        self._annotations = [dict(item) for item in annotations or [] if isinstance(item, dict)]
        self.update()

    def _image_rect(self) -> QRectF:
        if self._pixmap.isNull():
            return QRectF()
        area = self.rect().adjusted(14, 14, -14, -14)
        if area.width() <= 0 or area.height() <= 0:
            return QRectF()
        scaled = self._pixmap.size()
        scaled.scale(area.size(), Qt.AspectRatioMode.KeepAspectRatio)
        x = area.x() + (area.width() - scaled.width()) / 2
        y = area.y() + (area.height() - scaled.height()) / 2
        return QRectF(x, y, scaled.width(), scaled.height())

    def _to_image_point(self, point) -> tuple[float, float] | None:
        rect = self._image_rect()
        if rect.isNull() or not rect.contains(point):
            return None
        x = (point.x() - rect.x()) / max(1.0, rect.width()) * self._pixmap.width()
        y = (point.y() - rect.y()) / max(1.0, rect.height()) * self._pixmap.height()
        return (max(0.0, min(float(self._pixmap.width()), x)), max(0.0, min(float(self._pixmap.height()), y)))

    def _to_widget_point(self, point: list | tuple) -> QPoint:
        rect = self._image_rect()
        if rect.isNull():
            return QPoint(0, 0)
        x = rect.x() + float(point[0]) / max(1, self._pixmap.width()) * rect.width()
        y = rect.y() + float(point[1]) / max(1, self._pixmap.height()) * rect.height()
        return QPoint(int(x), int(y))

    def mousePressEvent(self, event):
        if event.button() != Qt.MouseButton.LeftButton or self._pixmap.isNull():
            super().mousePressEvent(event)
            return
        point = self._to_image_point(event.position())
        if point is None:
            return
        self._drawing = True
        self._current_points = [point]
        self.update()

    def mouseMoveEvent(self, event):
        if not self._drawing:
            return
        point = self._to_image_point(event.position())
        if point is not None:
            self._current_points.append(point)
            self.update()

    def mouseReleaseEvent(self, event):
        if not self._drawing:
            return
        self._drawing = False
        if len(self._current_points) < 2:
            self._current_points = []
            self.update()
            return
        dialog = AnnotationDialog('Image comment', parent=self)
        if dialog.exec() == QDialog.DialogCode.Accepted and dialog.text():
            annotation = {
                'id': f'ann-{int(time.time() * 1000)}',
                'kind': 'image_region',
                'points': [[round(x, 2), round(y, 2)] for x, y in self._current_points],
                'color': self._pen_color,
                'comment': dialog.text(),
            }
            self.annotation_created.emit(annotation)
        self._current_points = []
        self.update()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        if self._pixmap.isNull():
            painter.setPen(QColor('#7A8391'))
            painter.drawText(self.rect(), Qt.AlignmentFlag.AlignCenter, self._placeholder or 'No image.')
            return
        rect = self._image_rect()
        painter.drawPixmap(rect.toRect(), self._pixmap)
        for annotation in self._annotations:
            self._draw_points(painter, annotation.get('points', []), annotation.get('color', self._pen_color))
        if self._current_points:
            self._draw_points(painter, self._current_points, self._pen_color)

    def _draw_points(self, painter: QPainter, points, color: str):
        if len(points or []) < 2:
            return
        pen = QPen(QColor(color if QColor(str(color)).isValid() else '#FF3B30'), 3)
        pen.setCapStyle(Qt.PenCapStyle.RoundCap)
        pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
        painter.setPen(pen)
        prev = self._to_widget_point(points[0])
        for point in points[1:]:
            cur = self._to_widget_point(point)
            painter.drawLine(prev, cur)
            prev = cur

    def composited_pixmap(self) -> QPixmap:
        if self._pixmap.isNull():
            return QPixmap()
        result = QPixmap(self._pixmap)
        painter = QPainter(result)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        for annotation in self._annotations:
            points = annotation.get('points', [])
            if len(points or []) < 2:
                continue
            pen = QPen(QColor(annotation.get('color', self._pen_color)), max(3, int(self._pixmap.width() / 300)))
            pen.setCapStyle(Qt.PenCapStyle.RoundCap)
            pen.setJoinStyle(Qt.PenJoinStyle.RoundJoin)
            painter.setPen(pen)
            prev = QPoint(int(points[0][0]), int(points[0][1]))
            for point in points[1:]:
                cur = QPoint(int(point[0]), int(point[1]))
                painter.drawLine(prev, cur)
                prev = cur
        painter.end()
        return result


class LinksPanel(QWidget):
    open_requested = pyqtSignal(str)
    open_all_requested = pyqtSignal(list)

    def __init__(self, parent=None):
        super().__init__(parent)
        self._theme_updating = False
        self._links = []
        self._visible_links = []
        self._build_ui()

    def _build_ui(self):
        self.setObjectName('LinksPanel')
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self.setFixedSize(500, 760)
        shadow = QGraphicsDropShadowEffect(self)
        shadow.setBlurRadius(34)
        shadow.setXOffset(0)
        shadow.setYOffset(10)
        shadow.setColor(QColor(0, 0, 0, 45))
        self.setGraphicsEffect(shadow)

        self.search_input = QLineEdit(self)
        self.search_input.setPlaceholderText('Search links')
        self.search_input.textChanged.connect(self._refresh_list)
        self.list_widget = QListWidget(self)
        self.list_widget.setFrameShape(QFrame.Shape.NoFrame)
        self.list_widget.setSpacing(6)
        self.list_widget.itemClicked.connect(self._on_item_clicked)
        self.open_all_button = QPushButton('Open All In Browser', self)
        self.open_all_button.setCursor(Qt.CursorShape.PointingHandCursor)
        self.open_all_button.clicked.connect(self._open_all_clicked)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(24, 24, 24, 24)
        layout.setSpacing(14)
        layout.addWidget(self.search_input)
        layout.addWidget(self.list_widget, 1)
        layout.addWidget(self.open_all_button)
        self._apply_theme()

    def _apply_theme(self):
        if self._theme_updating:
            return
        self._theme_updating = True
        dark = is_dark_theme(app)
        try:
            self.setStyleSheet(
                f'QWidget#LinksPanel {{ border: 1px solid {"#2D2D2D" if dark else "#ECECEC"}; '
                f'background: {"#2D2D2D" if dark else "#FFFFFF"}; border-radius: 26px; }}'
            )
            self.search_input.setStyleSheet(_search_input_stylesheet(dark))
            self.open_all_button.setStyleSheet(_secondary_capsule_stylesheet(dark))
            if dark:
                self.list_widget.setStyleSheet('''
                    QListWidget {
                        border: none;
                        background: transparent;
                        outline: none;
                        font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
                        font-size: 15px;
                        color: #F2F2F7;
                    }
                    QListWidget::item {
                        border-radius: 14px;
                        padding: 12px 14px;
                        background: #3A3A3A;
                        margin: 0 0 6px 0;
                    }
                    QListWidget::item:selected {
                        background: #2E5C91;
                        color: #FFFFFF;
                    }
                    QListWidget::item:hover {
                        background: #454547;
                    }
                ''')
            else:
                self.list_widget.setStyleSheet('''
                    QListWidget {
                        border: none;
                        background: transparent;
                        outline: none;
                        font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
                        font-size: 15px;
                        color: #20242B;
                    }
                    QListWidget::item {
                        border-radius: 14px;
                        padding: 12px 14px;
                        background: #F7F7F8;
                        margin: 0 0 6px 0;
                    }
                    QListWidget::item:selected {
                        background: #E8EEF8;
                        color: #1A4B7A;
                    }
                    QListWidget::item:hover {
                        background: #EEF1F5;
                    }
                ''')
            self._refresh_list()
        finally:
            self._theme_updating = False

    def changeEvent(self, event):
        super().changeEvent(event)
        if self._theme_updating:
            return
        if event.type() in (QEvent.Type.PaletteChange, QEvent.Type.ApplicationPaletteChange):
            self._apply_theme()

    def set_links(self, links: list[dict]):
        self._links = [normalize_link_record(item) for item in links or []]
        self._links = [item for item in self._links if item]
        self._refresh_list()

    def _refresh_list(self):
        query = self.search_input.text().strip().lower()
        self._visible_links = []
        self.list_widget.clear()
        for link in self._links:
            title = str(link.get('title', '')).strip()
            url = str(link.get('url', '')).strip()
            haystack = (title + '\n' + url).lower()
            if query and query not in haystack:
                continue
            self._visible_links.append(link)
            item = QListWidgetItem()
            item.setData(Qt.ItemDataRole.UserRole, url)
            item.setSizeHint(QSize(0, 58))
            self.list_widget.addItem(item)
            self.list_widget.setItemWidget(item, LinkListItemWidget(title or url, url))
        self.open_all_button.setEnabled(bool(self._visible_links))

    def _on_item_clicked(self, item):
        url = str(item.data(Qt.ItemDataRole.UserRole) or '').strip()
        if url:
            self.open_requested.emit(url)

    def _open_all_clicked(self):
        urls = [str(item.get('url', '')).strip() for item in self._visible_links if str(item.get('url', '')).strip()]
        if urls:
            self.open_all_requested.emit(urls)


