    def _set_prompt_edit_read_only(self, enabled: bool):
        self.text1.setReadOnly(bool(enabled))
        if hasattr(self, '_text1_popup'):
            self._text1_popup.edit.setReadOnly(bool(enabled))

    def _install_selection_context_menus(self):
        if not hasattr(self, '_selection_context_widgets'):
            self._selection_context_widgets = set()
        widgets = []
        for name in ('real1', 'real2'):
            widget = getattr(self, name, None)
            if widget is not None:
                widgets.append(widget)
        terminal = getattr(self, 'terminal_widget', None)
        if terminal is not None:
            for widget in (getattr(terminal, 'output', None), getattr(terminal, 'input_line', None)):
                if widget is not None:
                    widgets.append(widget)
        for panel_name in ('ai_web_panel', 'localhost_panel'):
            panel = getattr(self, panel_name, None)
            for view in list(getattr(panel, '_views', []) or []):
                if view is not None:
                    widgets.append(view)
        for widget in widgets:
            ident = id(widget)
            if ident in self._selection_context_widgets:
                continue
            try:
                if isinstance(widget, QWebEngineView):
                    widget.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
                    widget.customContextMenuRequested.connect(
                        lambda pos, w=widget: self._handle_selection_context_menu_at(w, w.mapToGlobal(pos))
                    )
                    self._selection_context_widgets.add(ident)
                    continue
                if self._is_terminal_selection_context_widget(widget):
                    widget.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
                    widget.customContextMenuRequested.connect(
                        lambda pos, w=widget: self._handle_selection_context_menu_at(w, w.mapToGlobal(pos))
                    )
                    self._selection_context_widgets.add(ident)
                    continue
                widget.installEventFilter(self)
                self._selection_context_widgets.add(ident)
            except Exception:
                pass

    def eventFilter(self, obj, event):
        if isinstance(obj, QWebEngineView):
            return False
        if event.type() == QEvent.Type.ContextMenu and self._is_selection_context_widget(obj):
            if self._handle_selection_context_menu(obj, event):
                return True
        return super().eventFilter(obj, event)

    def _selection_context_owner(self, obj):
        current = obj
        terminal = getattr(self, 'terminal_widget', None)
        terminal_output = getattr(terminal, 'output', None) if terminal is not None else None
        terminal_input = getattr(terminal, 'input_line', None) if terminal is not None else None
        while current is not None:
            if current in (getattr(self, 'real1', None), getattr(self, 'real2', None)):
                return current
            if current in (terminal_output, terminal_input):
                return current
            for panel_name in ('ai_web_panel', 'localhost_panel'):
                panel = getattr(self, panel_name, None)
                if current in list(getattr(panel, '_views', []) or []):
                    return current
            if isinstance(current, QWebEngineView):
                return current
            current = current.parentWidget() if hasattr(current, 'parentWidget') else None
        return obj

    def _is_selection_context_widget(self, obj) -> bool:
        owner = self._selection_context_owner(obj)
        if owner in (getattr(self, 'real1', None), getattr(self, 'real2', None)):
            return True
        terminal = getattr(self, 'terminal_widget', None)
        if terminal is not None and owner in (getattr(terminal, 'output', None), getattr(terminal, 'input_line', None)):
            return True
        for panel_name in ('ai_web_panel', 'localhost_panel'):
            panel = getattr(self, panel_name, None)
            if owner in list(getattr(panel, '_views', []) or []):
                return True
        return isinstance(owner, QWebEngineView)

    def _is_terminal_selection_context_widget(self, obj) -> bool:
        obj = self._selection_context_owner(obj)
        terminal = getattr(self, 'terminal_widget', None)
        return bool(terminal is not None and obj in (getattr(terminal, 'output', None), getattr(terminal, 'input_line', None)))

    def _selected_text_from_widget(self, obj) -> str:
        obj = self._selection_context_owner(obj)
        try:
            if isinstance(obj, QWebEngineView):
                return str(obj.page().selectedText() or '').strip()
        except Exception:
            return ''
        try:
            if isinstance(obj, QLineEdit):
                return str(obj.selectedText() or '').strip()
            if hasattr(obj, 'textCursor'):
                cursor = obj.textCursor()
                if cursor.hasSelection():
                    return cursor.selectedText().replace('\u2029', '\n').strip()
        except Exception:
            return ''
        return ''

    def _handle_selection_context_menu(self, obj, event) -> bool:
        return self._handle_selection_context_menu_at(obj, event.globalPos())

    def _handle_selection_context_menu_at(self, obj, global_pos) -> bool:
        obj = self._selection_context_owner(obj)
        selected_text = self._selected_text_from_widget(obj)
        if isinstance(obj, QWebEngineView):
            if not selected_text:
                return True
            menu = QMenu(self)
            copy_action = menu.addAction('Copy')
            copy_action.triggered.connect(
                lambda _checked=False, view=obj: view.page().triggerAction(QWebEnginePage.WebAction.Copy)
            )
        else:
            try:
                menu = obj.createStandardContextMenu()
            except Exception:
                menu = QMenu(self)
            if not selected_text:
                if menu is not None:
                    menu.exec(global_pos)
                    return True
                return False
        if menu.actions():
            menu.addSeparator()
        replace_menu = menu.addMenu('Replace prompt with selection')
        append_menu = menu.addMenu('Append selection to prompt')
        targets = [
            ('Web', 0),
            ('API', 1),
            ('Localhost', 2),
            ('Terminal', 3),
        ]
        for label, target in targets:
            replace_action = replace_menu.addAction(label)
            replace_action.triggered.connect(
                lambda _checked=False, t=target, text=selected_text: self._route_selection_to_prompt(t, text, append=False)
            )
            append_action = append_menu.addAction(label)
            append_action.triggered.connect(
                lambda _checked=False, t=target, text=selected_text: self._route_selection_to_prompt(t, text, append=True)
            )
        if self._is_terminal_selection_context_widget(obj):
            favorite_action = menu.addAction('Add selection to Terminal favorites')
            favorite_action.triggered.connect(
                lambda _checked=False, text=selected_text: self._add_terminal_favorite_from_text(text)
            )
        output_action = menu.addAction('Add selection to Generated outputs')
        output_action.triggered.connect(lambda _checked=False, text=selected_text: self._add_selected_text_output(text))
        menu.exec(global_pos)
        return True

    def _set_plain_text_prompt(self, editor, text: str, append: bool):
        text = str(text or '')
        if append:
            current = editor.toPlainText() if hasattr(editor, 'toPlainText') else editor.text()
            merged = (str(current).rstrip() + '\n\n' + text).strip() if str(current).strip() else text
        else:
            merged = text
        if hasattr(editor, 'setPlainText'):
            editor.setPlainText(merged)
            try:
                cursor = editor.textCursor()
                cursor.movePosition(QTextCursor.MoveOperation.End)
                editor.setTextCursor(cursor)
            except Exception:
                pass
        else:
            editor.setText(merged)
            try:
                editor.end(False)
            except Exception:
                pass

    def _select_main_tab(self, index: int):
        index = max(0, min(3, int(index)))
        try:
            self.pill_nav.select(index)
        except Exception:
            self.stacked_widget.setCurrentIndex(index)
        if self.stacked_widget.currentIndex() != index:
            self.stacked_widget.setCurrentIndex(index)

    def _route_selection_to_prompt(self, target_index: int, text: str, append: bool = False):
        text = str(text or '').strip()
        if not text:
            return
        target_index = int(target_index)
        if target_index == 0:
            self._select_main_tab(0)
            panel, dock = self._external_prompt_panel_for_index(0)
            if panel is not None and dock is not None:
                panel.set_prompt_dock_visible(True, animated=True)
                self._set_plain_text_prompt(dock.prompt_edit, text, append)
                dock.prompt_edit.setFocus()
            return
        if target_index == 1:
            self._select_main_tab(1)
            self._set_plain_text_prompt(self.text1, text, append)
            self.text1.setFocus()
            self._refresh_text1_popup_visibility()
            return
        if target_index == 2:
            self._select_main_tab(2)
            panel, dock = self._external_prompt_panel_for_index(2)
            if panel is not None and dock is not None:
                panel.set_prompt_dock_visible(True, animated=True)
                self._set_plain_text_prompt(dock.prompt_edit, text, append)
                dock.prompt_edit.setFocus()
            return
        if target_index == 3:
            self._select_main_tab(3)
            terminal = getattr(self, 'terminal_widget', None)
            if terminal is not None:
                self._set_plain_text_prompt(terminal.input_line, text, append)
                terminal.input_line.setFocus()

    def _add_selected_text_output(self, text: str):
        text = str(text or '').strip()
        if not text:
            return
        created_at = datetime.datetime.now().isoformat(timespec='seconds')
        snippet = re.sub(r'\s+', ' ', text).strip()
        if len(snippet) > 48:
            snippet = snippet[:48].rstrip() + '...'
        tab_labels = ['Web', 'API', 'Localhost', 'Terminal']
        current_index = self.stacked_widget.currentIndex()
        tab_label = tab_labels[current_index] if 0 <= current_index < len(tab_labels) else 'Selection'
        scope_key = self._tab_output_scope_key(current_index)
        output = {
            'id': f'sel-{int(time.time() * 1000)}',
            'kind': 'text',
            'title': f'Selected text · {created_at}',
            'filename': 'selected-text.txt',
            'content': text,
            'path': '',
            'question': f'{tab_label} selection · {snippet or "Selected text"}',
            'question_index': -1,
            'assistant_index': -1,
            'created_at': created_at,
            'source': 'manual_selection',
            'tab_scope': scope_key or 'api',
        }
        if scope_key:
            outputs = merge_output_records(self._load_tab_outputs(scope_key), [output])
            self._save_tab_outputs(scope_key, outputs)
        else:
            history_messages = get_current_chat_history_messages()
            self._ensure_active_conversation(text, history_messages)
            record = load_conversation_record(self._active_conversation_path) if self._active_conversation_path else None
            if record is None:
                record = create_conversation_record('Selected outputs', history_messages=history_messages)
                self._active_conversation_path = record['path']
            record['outputs'] = merge_output_records(record.get('outputs', []), [output])
            record['updated_at'] = created_at
            saved = write_conversation_record(self._active_conversation_path, record)
            self._active_conversation_path = saved['path']
        self._refresh_outputs_panel(prefer_latest=True)
        self.show_outputs_panel()

    def _sync_prompt_from_inline(self):
        if getattr(self, '_prompt_syncing', False):
            return
        text = self.text1.toPlainText()
        cursor_pos = self.text1.textCursor().position()
        self._prompt_syncing = True
        try:
            if self._text1_popup.edit.toPlainText() != text:
                blocker = QSignalBlocker(self._text1_popup.edit)
                self._text1_popup.edit.setPlainText(text)
                del blocker
            cursor = self._text1_popup.edit.textCursor()
            cursor.setPosition(min(cursor_pos, len(text)))
            self._text1_popup.edit.setTextCursor(cursor)
        finally:
            self._prompt_syncing = False
        self._refresh_text1_popup_visibility()

    def _sync_prompt_from_popup(self):
        if getattr(self, '_prompt_syncing', False):
            return
        text = self._text1_popup.edit.toPlainText()
        cursor_pos = self._text1_popup.edit.textCursor().position()
        self._prompt_syncing = True
        try:
            if self.text1.toPlainText() != text:
                blocker = QSignalBlocker(self.text1)
                self.text1.setPlainText(text)
                del blocker
            cursor = self.text1.textCursor()
            cursor.setPosition(min(cursor_pos, len(text)))
            self.text1.setTextCursor(cursor)
        finally:
            self._prompt_syncing = False
        self.text1._emit_multiline_if_needed()
        self._refresh_text1_popup_visibility()

    def _prompt_widget_has_focus(self, widget) -> bool:
        current = widget
        while current is not None:
            if current is self.text1 or current is self._text1_popup or current is self._text1_popup.edit:
                return True
            current = current.parentWidget()
        return False

    def _should_show_text1_popup(self) -> bool:
        if not hasattr(self, '_text1_popup'):
            return False
        if not self.isVisible() or not self._is_assistant_tab():
            return False
        if not self._right_pill._active or not self.text1.isVisible():
            return False
        if not self.text1.has_multiline_content():
            return False
        return self._prompt_widget_has_focus(QApplication.focusWidget())

    def _update_text1_popup_geometry(self):
        if not hasattr(self, '_text1_popup'):
            return
        if self._text1_popup.isVisible():
            self._text1_popup.show_for_anchor(self.text1)

    def _refresh_text1_popup_visibility(self):
        if not hasattr(self, '_text1_popup'):
            return
        if self._should_show_text1_popup():
            self._text1_popup.show_for_anchor(self.text1)
        else:
            focus_widget = QApplication.focusWidget()
            if (
                self._text1_popup.isVisible()
                and not self.text1.has_multiline_content()
                and self._prompt_widget_has_focus(focus_widget)
                and focus_widget is not self.text1
            ):
                self.text1.setFocus()
            self._text1_popup.hide_animated()

    def _on_prompt_focus_changed(self, _old, _new):
        QTimer.singleShot(0, self._refresh_text1_popup_visibility)

    def _sync_branch_state_metadata(self, state: dict | None):
        if not isinstance(state, dict):
            return
        node_by_id = {}
        checked_node_ids = set()
        message_index_to_node_id = {}

        def walk(node: dict, parent_id: str = ''):
            node['parent_id'] = parent_id
            node_id = str(node.get('id', '')).strip()
            if not node_id:
                return
            node_by_id[node_id] = node
            try:
                msg_idx = int(node.get('message_index', -1))
            except (TypeError, ValueError):
                msg_idx = -1
            if msg_idx >= 0:
                message_index_to_node_id[msg_idx] = node_id
            if bool(node.get('checked', True)):
                checked_node_ids.add(node_id)
            for child in node.get('children', []) or []:
                walk(child, node_id)

        for root in state.get('roots', []) or []:
            walk(root, '')
        state['node_by_id'] = node_by_id
        state['checked_node_ids'] = checked_node_ids
        state['message_index_to_node_id'] = message_index_to_node_id
        if not bool(state.get('append_as_child', False)):
            state['active_node_id'] = ''
        elif str(state.get('active_node_id', '')).strip() not in node_by_id:
            if node_by_id:
                latest = max(node_by_id.values(), key=lambda node: int(node.get('message_index', -1) or -1))
                state['active_node_id'] = str(latest.get('id', ''))
            else:
                state['active_node_id'] = ''
        next_id = 1
        for node_id in node_by_id:
            if node_id.startswith('q'):
                try:
                    next_id = max(next_id, int(node_id[1:]) + 1)
                except Exception:
                    pass
        state['next_id'] = max(1, int(state.get('next_id', next_id) or next_id))

    def _sort_branch_nodes_by_message_index(self, nodes: list[dict]) -> list[dict]:
        ordered = []
        for node in list(nodes or []):
            if not isinstance(node, dict):
                continue
            node['children'] = self._sort_branch_nodes_by_message_index(node.get('children', []) or [])
            ordered.append(node)
        ordered.sort(key=lambda node: int(node.get('message_index', -1) or -1))
        return ordered

    def _build_branch_state_from_messages(self, messages: list[dict], stored_branches: dict | None = None) -> dict:
        state = {
            'conversation_path': str(self._active_conversation_path or ''),
            'roots': [],
            'node_by_id': {},
            'checked_node_ids': set(),
            'message_index_to_node_id': {},
            'active_node_id': '',
            'next_id': 1,
            'append_as_child': False,
        }
        user_messages = {
            message_index: str(message.get('content', '')).strip()
            for message_index, message in enumerate(messages or [])
            if str(message.get('role', '')).strip().lower() == 'user'
        }
        used_indices = set()
        used_ids = set()

        def unique_node_id(raw_id: str, message_index: int) -> str:
            base = str(raw_id or '').strip() or f"q{message_index + 1}"
            candidate = base
            suffix = 2
            while candidate in used_ids:
                candidate = f'{base}_{suffix}'
                suffix += 1
            used_ids.add(candidate)
            return candidate

        def build_node(node_data: dict, parent_id: str = '') -> dict | None:
            if not isinstance(node_data, dict):
                return None
            try:
                message_index = int(node_data.get('message_index', -1))
            except (TypeError, ValueError):
                return None
            if message_index not in user_messages or message_index in used_indices:
                return None
            used_indices.add(message_index)
            full_text = user_messages[message_index]
            node_id = unique_node_id(node_data.get('id', ''), message_index)
            node = {
                'id': node_id,
                'text': full_text,
                'full_text': full_text,
                'message_index': message_index,
                'checked': True,
                'children': [],
                'parent_id': parent_id,
            }
            for child_data in node_data.get('children', []) or []:
                child = build_node(child_data, node_id)
                if child is not None:
                    node['children'].append(child)
            return node

        branch_payload = stored_branches if isinstance(stored_branches, dict) else {}
        for root_data in branch_payload.get('roots', []) or []:
            root_node = build_node(root_data, '')
            if root_node is not None:
                state['roots'].append(root_node)

        for message_index in sorted(user_messages):
            if message_index in used_indices:
                continue
            node_id = unique_node_id('', message_index)
            full_text = user_messages[message_index]
            state['roots'].append({
                'id': node_id,
                'text': full_text,
                'full_text': full_text,
                'message_index': message_index,
                'checked': True,
                'children': [],
                'parent_id': '',
            })

        state['roots'] = self._sort_branch_nodes_by_message_index(state.get('roots', []))
        self._sync_branch_state_metadata(state)
        active_node_id = str(branch_payload.get('active_node_id', '')).strip()
        if bool(branch_payload.get('append_as_child', False)) and active_node_id in state['node_by_id']:
            state['active_node_id'] = active_node_id
        else:
            state['active_node_id'] = ''
        state['append_as_child'] = bool(branch_payload.get('append_as_child', False) and state.get('active_node_id'))
        return state

    def _serialize_branch_state_for_storage(self, state: dict | None) -> dict:
        if not isinstance(state, dict):
            return {'roots': [], 'active_node_id': '', 'append_as_child': False}

        def serialize_node(node: dict) -> dict:
            return {
                'id': str(node.get('id', '')).strip(),
                'message_index': int(node.get('message_index', -1) or -1),
                'children': [serialize_node(child) for child in node.get('children', []) or []],
            }

        active_node_id = str(state.get('active_node_id', '')).strip()
        if not bool(state.get('append_as_child', False)) or active_node_id not in state.get('node_by_id', {}):
            active_node_id = ''
        return {
            'roots': [serialize_node(node) for node in state.get('roots', []) or []],
            'active_node_id': active_node_id,
            'append_as_child': bool(state.get('append_as_child', False) and active_node_id),
        }

    def _persist_active_branch_structure(self, state: dict | None = None):
        if not self._active_conversation_path:
            return
        if state is None:
            state = self._current_branch_state()
        if not isinstance(state, dict):
            return
        record = self._load_active_conversation_record()
        if record is None:
            return
        record['branches'] = self._serialize_branch_state_for_storage(state)
        saved = write_conversation_record(self._active_conversation_path, record)
        self._active_conversation_path = saved['path']

    def _current_branch_state(self) -> dict | None:
        path = self._branch_state_key()
        if not path:
            return None
        return self._branch_states.get(path)

    def _branch_state_key(self, history_messages: list[dict] | None = None) -> str:
        path = str(self._active_conversation_path or '').strip()
        if path:
            return path
        if history_messages is None:
            history_messages = get_current_chat_history_messages()
        return '__current__' if history_messages else ''

    def _ensure_branch_state_loaded(self, history_messages: list[dict] | None = None) -> dict | None:
        path = self._branch_state_key(history_messages)
        if not path:
            self.branch_panel.set_branch_state(None)
            return None
        state = self._branch_states.get(path)
        if state is None:
            record = None
            if history_messages is None:
                record = self._load_active_conversation_record() if path == str(self._active_conversation_path or '').strip() else load_conversation_record(path) if path and path != '__current__' else None
                history_messages = list(record.get('messages', [])) if record else []
            elif path == str(self._active_conversation_path or '').strip():
                record = self._load_active_conversation_record()
            elif path and path != '__current__':
                record = load_conversation_record(path)
            stored_branches = record.get('branches') if record else None
            state = self._build_branch_state_from_messages(history_messages or [], stored_branches)
            state['conversation_path'] = path
            self._branch_states[path] = state
        else:
            state['conversation_path'] = path
            self._sync_branch_state_metadata(state)
        self.branch_panel.set_branch_state(state)
        return state

    def _selected_branch_message_indices(self, history_messages: list[dict], state: dict | None = None) -> set[int]:
        if state is None:
            state = self._ensure_branch_state_loaded(history_messages)
        if not state:
            return set(range(len(history_messages or [])))
        selected_user_indices = {
            int(node.get('message_index', -1))
            for node_id, node in state.get('node_by_id', {}).items()
            if node_id in state.get('checked_node_ids', set())
        }
        if not selected_user_indices:
            return set()
        selected_indices = set()
        keep = False
        for message_index, message in enumerate(history_messages or []):
            if str(message.get('role', '')).strip().lower() == 'user':
                keep = message_index in selected_user_indices
                if keep:
                    selected_indices.add(message_index)
            elif keep:
                selected_indices.add(message_index)
        return selected_indices

    def _filter_history_messages_by_branch(self, history_messages: list[dict]) -> tuple[list[dict], set[int]]:
        state = self._ensure_branch_state_loaded(history_messages)
        selected_indices = self._selected_branch_message_indices(history_messages, state)
        if not selected_indices:
            return [], set()
        return [
            message for message_index, message in enumerate(history_messages)
            if message_index in selected_indices
        ], selected_indices

    def _append_question_to_branch_state(self, question_text: str, message_index: int):
        path = self._branch_state_key()
        if not path:
            return
        state = self._ensure_branch_state_loaded(get_current_chat_history_messages())
        if state is None:
            state = self._build_branch_state_from_messages([])
            state['conversation_path'] = path
            self._branch_states[path] = state
        node_id = f"q{int(state.get('next_id', 1) or 1)}"
        state['next_id'] = int(state.get('next_id', 1) or 1) + 1
        parent_id = str(state.get('active_node_id', '') or '').strip()
        append_as_child = bool(state.get('append_as_child', False))
        parent = state.get('node_by_id', {}).get(parent_id) if (append_as_child and parent_id) else None
        node = {
            'id': node_id,
            'text': str(question_text or '').strip(),
            'full_text': str(question_text or '').strip(),
            'message_index': int(message_index),
            'checked': True,
            'children': [],
            'parent_id': parent_id if parent is not None else '',
        }
        if parent is None:
            state.setdefault('roots', []).append(node)
        else:
            parent.setdefault('children', []).append(node)
            current = parent
            while current is not None:
                current['checked'] = True
                current = state.get('node_by_id', {}).get(str(current.get('parent_id', '')).strip())
        state['roots'] = self._sort_branch_nodes_by_message_index(state.get('roots', []))
        state['active_node_id'] = node_id
        if parent is not None:
            state['append_as_child'] = True
        self._sync_branch_state_metadata(state)
        self.branch_panel.set_branch_state(state)
        self._persist_active_branch_structure(state)

    def _refresh_branch_state_from_current_conversation(self):
        if not self._active_conversation_path:
            self.branch_panel.set_branch_state(None)
            return
        record = self._load_active_conversation_record()
        history_messages = list(record.get('messages', [])) if record else get_current_chat_history_messages()
        self._ensure_branch_state_loaded(history_messages)

    def _on_branch_state_changed(self, state: dict):
        path = self._branch_state_key()
        if not path:
            return
        self._sync_branch_state_metadata(state)
        self._branch_states[path] = state

    def _jump_to_message_index(self, message_index: int):
        message_index = max(0, int(message_index))
        self.real2.page().runJavaScript(
            "(() => { const el = document.getElementById('msg-%d'); if (el) { el.scrollIntoView({behavior:'smooth', block:'center'}); } })();" % message_index
        )

    def _branch_panel_shown_rect(self):
        width = min(500, max(320, self.qw3.width() - 36))
        height = min(760, max(360, self.qw3.height() - 36))
        x = max(18, (self.qw3.width() - width) // 2)
        return QRect(x, 18, width, height)

    def _branch_panel_hidden_rect(self):
        shown = self._branch_panel_shown_rect()
        return QRect(shown.x(), -shown.height() - 24, shown.width(), shown.height())

    def _update_branch_overlay_geometry(self):
        if not hasattr(self, '_branch_scrim'):
            return
        stacked_pos = self.stacked_widget.mapTo(self.qw3, QPoint(0, 0))
        trigger_w = max(0, self.stacked_widget.width() - 20)
        self._branch_trigger_btn.setGeometry(
            stacked_pos.x() + 10,
            stacked_pos.y(),
            trigger_w,
            self._branch_trigger_band_h,
        )
        self._branch_trigger_btn.raise_()
        self._branch_scrim.setGeometry(self.qw3.rect())
        if self._branch_panel_visible:
            self.branch_panel.setGeometry(self._branch_panel_shown_rect())
        else:
            self.branch_panel.setGeometry(self._branch_panel_hidden_rect())
        self._raise_webfetch_panel_if_visible()

    def _raise_webfetch_panel_if_visible(self):
        if hasattr(self, 'webfetch_panel') and self.webfetch_panel.isVisible():
            self.webfetch_panel.raise_()

    def _outputs_panel_shown_rect(self):
        safe_w = max(280, self.qw3.width() - 56)
        safe_h = max(320, self.qw3.height() - 96)
        width = min(620, safe_w)
        height = min(620, safe_h)
        x = max(28, (self.qw3.width() - width) // 2)
        y = max(38, (self.qw3.height() - height) // 2)
        return QRect(x, y, width, height)

    def _outputs_panel_hidden_rect(self):
        shown = self._outputs_panel_shown_rect()
        return QRect(shown.x(), -shown.height() - 24, shown.width(), shown.height())

    def _update_outputs_overlay_geometry(self):
        if not hasattr(self, '_outputs_scrim'):
            return
        pill_pos = self.pill_nav.mapTo(self, QPoint(0, 0))
        trigger_y = max(self.qw3.pos().y() + 2, pill_pos.y() - self._branch_trigger_band_h - 2)
        self._outputs_trigger_btn.setGeometry(
            pill_pos.x(),
            trigger_y,
            max(0, self.pill_nav.width()),
            self._branch_trigger_band_h,
        )
        self._outputs_trigger_btn.raise_()
        self._outputs_scrim.setGeometry(self.qw3.rect())
        if self._outputs_panel_visible:
            self.outputs_panel.setGeometry(self._outputs_panel_shown_rect())
        else:
            self.outputs_panel.setGeometry(self._outputs_panel_hidden_rect())

    def _share_panel_shown_rect(self):
        safe_w = max(280, self.qw3.width() - 56)
        safe_h = max(320, self.qw3.height() - 96)
        width = min(620, safe_w)
        height = min(620, safe_h)
        x = max(28, (self.qw3.width() - width) // 2)
        y = max(38, (self.qw3.height() - height) // 2)
        return QRect(x, y, width, height)

    def _share_panel_hidden_rect(self):
        shown = self._share_panel_shown_rect()
        return QRect(shown.x(), shown.y() - 32, shown.width(), shown.height())

    def _update_share_overlay_geometry(self):
        if not hasattr(self, '_share_scrim'):
            return
        self._share_scrim.setGeometry(self.qw3.rect())
        if self._share_panel_visible:
            self.share_panel.setGeometry(self._share_panel_shown_rect())
        else:
            self.share_panel.setGeometry(self._share_panel_hidden_rect())

