    def ShareX(self):
        if self.stacked_widget.currentIndex() != 1:
            return
        if self.real2.isVisible():
            self.real2.page().runJavaScript(
                """
                (() => {
                  const sel = window.getSelection();
                  if (!sel || sel.rangeCount === 0 || !sel.toString().trim()) return null;
                  const container = document.createElement('div');
                  for (let i = 0; i < sel.rangeCount; i++) {
                    const range = sel.getRangeAt(i);
                    const fragment = range.cloneContents();
                    let host = range.commonAncestorContainer;
                    if (host && host.nodeType !== Node.ELEMENT_NODE) host = host.parentElement;
                    const styledHost = host && host.closest
                      ? host.closest('.qa-label, .user-message-plain, .attachment-display-block, .pipeline-details, .pipeline-step-body, pre, code, blockquote, table, p, li, h1, h2, h3, h4, h5, h6, td, th')
                      : null;
                    if (styledHost && styledHost !== document.body && styledHost !== document.documentElement) {
                      const wrapper = styledHost.cloneNode(false);
                      wrapper.appendChild(fragment);
                      container.appendChild(wrapper);
                    } else {
                      container.appendChild(fragment);
                    }
                  }
                  const styles = Array.from(document.querySelectorAll('style, link[rel~="stylesheet"]'))
                    .map(el => el.outerHTML)
                    .join('\\n');
                  return {
                    html: container.innerHTML,
                    text: sel.toString(),
                    styles,
                    base: document.baseURI || '',
                    width: Math.ceil((document.documentElement && document.documentElement.clientWidth) || window.innerWidth || 0)
                  };
                })();
                """,
                self._handle_real2_share_selection,
            )
            return
        cursor = self.real1.textCursor()
        text = cursor.selectedText().replace('\u2029', '\n') if cursor.hasSelection() else self.real1.toPlainText()
        self._capture_text_as_share_image(text)

    def _handle_real2_share_selection(self, selection):
        if isinstance(selection, dict) and str(selection.get('text', '') or '').strip():
            fragment = str(selection.get('html', '') or '').strip()
            if fragment:
                width = int(float(selection.get('width', self.real2.width()) or self.real2.width()))
                width = max(360, min(max(360, self.real2.width()), width))
                self._capture_html_fragment_as_share_image(
                    fragment,
                    extra_head_html=str(selection.get('styles', '') or ''),
                    width=width,
                    base_url=str(selection.get('base', '') or ''),
                )
                return
            self._capture_text_as_share_image(str(selection.get('text', '') or ''))
            return
        self._capture_real2_full_share_image()

    def _share_html_document(self, body_html: str, extra_head_html: str = '') -> str:
        dark = is_dark_theme(app)
        bg = '#2D2D2D' if dark else '#FFFFFF'
        fg = '#F2F2F7' if dark else '#20242B'
        table_border = '#4A4B4F' if dark else '#D9DDE4'
        code_bg = '#343436' if dark else '#F7F8FA'
        return f"""
        <html>
        <head>
          <meta charset="utf-8">
          {extra_head_html}
          <style>
            body {{
              margin: 0;
              padding: 24px;
              background: {bg};
              color: {fg};
              font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
              font-size: 15px;
              line-height: 1.62;
            }}
            body > .share-capture {{
              max-width: 860px;
              margin: 0 auto;
            }}
            pre, code {{
              font-family: "SF Mono", Menlo, Monaco, monospace;
              background: {code_bg};
              border-radius: 10px;
            }}
            pre {{
              padding: 14px;
              white-space: pre-wrap;
              word-break: break-word;
            }}
            table {{
              border-collapse: collapse;
              max-width: 100%;
            }}
            th, td {{
              border: 1px solid {table_border};
              padding: 8px;
            }}
            img, video {{
              max-width: 100%;
            }}
            .user-message-plain {{
              white-space: pre-wrap;
              word-break: break-word;
            }}
          </style>
        </head>
        <body><div class="share-capture">{body_html}</div></body>
        </html>
        """

    def _capture_text_as_share_image(self, text: str):
        text = str(text or '').strip()
        if not text:
            return
        body = f'<div style="white-space: pre-wrap; word-break: break-word;">{html.escape(text)}</div>'
        self._capture_html_fragment_as_share_image(body)

    def _capture_html_fragment_as_share_image(self,
                                             fragment_html: str,
                                             extra_head_html: str = '',
                                             width: int | None = None,
                                             base_url: str = ''):
        width = int(width or min(900, max(360, self.qw3.width() - 96)))
        self._capture_html_document_as_share_image(
            self._share_html_document(fragment_html, extra_head_html=extra_head_html),
            width,
            base_url,
        )

    def _capture_html_document_as_share_image(self, html_document: str, width: int, base_url: str = ''):
        width = min(1600, max(320, int(width or 0) + 180))
        view = QWebEngineView(self.qw3)
        view.setGeometry(-10000, -10000, width, 200)
        view.show()
        self._share_temp_view = view

        def _loaded(ok):
            try:
                view.loadFinished.disconnect(_loaded)
            except Exception:
                pass
            if not ok:
                view.deleteLater()
                if self._share_temp_view is view:
                    self._share_temp_view = None
                return
            self._capture_webview_static_page(
                view,
                lambda pixmap: self._finish_temp_share_capture(view, pixmap),
            )

        view.loadFinished.connect(_loaded)
        if base_url:
            view.setHtml(html_document, QUrl(base_url))
        else:
            view.setHtml(html_document)

    def _finish_temp_share_capture(self, view: QWebEngineView, pixmap: QPixmap):
        if view is not None:
            view.deleteLater()
        if self._share_temp_view is view:
            self._share_temp_view = None
        self.show_share_panel(pixmap)

    def _share_background_color(self) -> QColor:
        return QColor('#2D2D2D' if is_dark_theme(app) else '#FFFFFF')

    def _share_pixel_is_background(self, image: QImage, x: int, y: int, bg: QColor, tolerance: int = 18) -> bool:
        pixel = image.pixel(x, y)
        alpha = (pixel >> 24) & 0xFF
        if alpha < 8:
            return True
        red = (pixel >> 16) & 0xFF
        green = (pixel >> 8) & 0xFF
        blue = pixel & 0xFF
        return (
            abs(red - bg.red()) <= tolerance
            and abs(green - bg.green()) <= tolerance
            and abs(blue - bg.blue()) <= tolerance
        )

    def _share_row_has_content(self, image: QImage, y: int, bg: QColor, x1: int = 0, x2: int | None = None) -> bool:
        width = image.width()
        if x2 is None:
            x2 = width - 1
        x1 = max(0, min(width - 1, int(x1)))
        x2 = max(0, min(width - 1, int(x2)))
        if x2 < x1:
            return False
        step = 1 if (x2 - x1) <= 900 else 2
        for x in range(x1, x2 + 1, step):
            if not self._share_pixel_is_background(image, x, y, bg):
                return True
        if step > 1 and not self._share_pixel_is_background(image, x2, y, bg):
            return True
        return False

    def _share_column_has_content(self, image: QImage, x: int, bg: QColor, y1: int, y2: int) -> bool:
        height = image.height()
        y1 = max(0, min(height - 1, int(y1)))
        y2 = max(0, min(height - 1, int(y2)))
        if y2 < y1:
            return False
        step = 1 if (y2 - y1) <= 1600 else 2
        for y in range(y1, y2 + 1, step):
            if not self._share_pixel_is_background(image, x, y, bg):
                return True
        if step > 1 and not self._share_pixel_is_background(image, x, y2, bg):
            return True
        return False

    def _share_image_content_bounds(self, image: QImage, bg: QColor) -> QRect:
        return share_image_content_bounds(image, bg)

    def _crop_share_image_to_content(self, image: QImage) -> QImage:
        return crop_share_image_to_content(image, self._share_background_color())

    def _compress_share_vertical_whitespace(self, image: QImage) -> QImage:
        return compress_share_vertical_whitespace(image, self._share_background_color())

    def _finalize_share_image(self, image: QImage) -> QImage:
        return finalize_share_image_worker(image, self._share_background_color())

    def _finalize_share_image_async(self, image: QImage, callback):
        if image.isNull():
            return
        self._share_finalize_request_id += 1
        request_id = self._share_finalize_request_id
        self._share_finalize_callback = callback
        self._share_finalize_signals = AsyncShareImageSignals()
        self._share_finalize_signals.finished.connect(
            self._on_share_image_finalized,
            Qt.ConnectionType.QueuedConnection,
        )
        self._share_finalize_thread = AsyncShareImageThread(
            image.copy(),
            self._share_background_color(),
            self._share_finalize_signals,
            request_id,
        )
        self._share_finalize_thread.start()

    def _on_share_image_finalized(self, payload):
        if not isinstance(payload, dict):
            return
        if int(payload.get('request_id', 0) or 0) != self._share_finalize_request_id:
            return
        image = payload.get('image')
        callback = self._share_finalize_callback
        self._share_finalize_callback = None
        self._share_finalize_signals = None
        self._share_finalize_thread = None
        if not isinstance(image, QImage) or image.isNull():
            return
        pixmap = QPixmap.fromImage(image)
        pixmap.setDevicePixelRatio(1.0)
        if callable(callback):
            callback(pixmap)

    def _capture_real2_full_share_image(self):
        self.real2.page().runJavaScript(
            """
            (() => ({
              html: document.documentElement ? document.documentElement.outerHTML : '',
              base: document.baseURI || '',
              width: Math.ceil((document.documentElement && document.documentElement.clientWidth) || window.innerWidth || 0)
            }))();
            """,
            self._capture_real2_html_payload_as_share_image,
        )

    def _capture_real2_html_payload_as_share_image(self, payload):
        if not isinstance(payload, dict):
            self._capture_text_as_share_image(self.real1.toPlainText())
            return
        html_document = str(payload.get('html', '') or '')
        if not html_document.strip():
            return
        width = int(float(payload.get('width', self.real2.width()) or self.real2.width()))
        width = max(360, min(1600, max(width, self.real2.width())))
        self._capture_html_document_as_share_image(
            html_document,
            width,
            str(payload.get('base', '') or ''),
        )

    def _capture_webview_full_page(self, view: QWebEngineView, callback):
        if self._capture_webview_static_page(view, callback):
            return
        self._capture_webview_full_page_by_scroll(view, callback)

    def _capture_webview_static_page(self, view: QWebEngineView, callback) -> bool:
        if view is None or view.width() <= 0 or view.height() <= 0:
            return False
        view.page().runJavaScript(
            """
            (() => {
              const doc = document.documentElement;
              const body = document.body || doc;
              const originalX = window.scrollX || doc.scrollLeft || 0;
              const originalY = window.scrollY || doc.scrollTop || 0;
              window.scrollTo(0, 0);
              const docW = Math.ceil(Math.max(
                body ? body.scrollWidth : 0,
                doc ? doc.scrollWidth : 0,
                doc ? doc.clientWidth : 0,
                window.innerWidth || 0
              ));
              const docH = Math.ceil(Math.max(
                body ? body.scrollHeight : 0,
                doc ? doc.scrollHeight : 0,
                doc ? doc.clientHeight : 0,
                window.innerHeight || 0
              ));
              const rects = [];
              const addRect = (rect) => {
                if (!rect || rect.width < 1 || rect.height < 1) return;
                rects.push({
                  left: rect.left,
                  top: rect.top,
                  right: rect.right,
                  bottom: rect.bottom
                });
              };
              const root = document.querySelector('.share-capture') || body;
              const walker = document.createTreeWalker(
                root,
                NodeFilter.SHOW_TEXT,
                {
                  acceptNode: (node) => (
                    node.nodeValue && node.nodeValue.trim()
                      ? NodeFilter.FILTER_ACCEPT
                      : NodeFilter.FILTER_REJECT
                  )
                }
              );
              const range = document.createRange();
              let node;
              while ((node = walker.nextNode())) {
                range.selectNodeContents(node);
                for (const rect of range.getClientRects()) addRect(rect);
              }
              if (range.detach) range.detach();
              const mediaSelector = [
                'img', 'video', 'canvas', 'svg', 'table', 'pre', 'blockquote',
                '.attachment-display-block', '.pipeline-details',
                '.qa-label', '.pipeline-default-heading'
              ].join(',');
              root.querySelectorAll(mediaSelector).forEach((el) => {
                const st = window.getComputedStyle(el);
                if (!st || st.display === 'none' || st.visibility === 'hidden' || Number(st.opacity || 1) === 0) {
                  return;
                }
                addRect(el.getBoundingClientRect());
              });
              if (!rects.length) addRect((root || body).getBoundingClientRect());
              const padLeft = 56;
              const padRight = 160;
              const padTop = 88;
              const padBottom = 96;
              const left = Math.max(0, Math.floor(Math.min(...rects.map(r => r.left)) - padLeft));
              const top = Math.max(0, Math.floor(Math.min(...rects.map(r => r.top)) - padTop));
              const right = Math.ceil(Math.max(...rects.map(r => r.right)) + padRight);
              const bottom = Math.ceil(Math.max(...rects.map(r => r.bottom)) + padBottom);
              return {
                originalX,
                originalY,
                contentLeft: left,
                contentTop: top,
                contentWidth: Math.max(1, right - left),
                contentHeight: Math.max(1, bottom - top),
                layoutWidth: Math.ceil((doc && doc.clientWidth) || window.innerWidth || 0)
              };
            })();
            """,
            lambda metrics: self._start_webview_static_capture(view, metrics, callback),
        )
        return True

    def _start_webview_static_capture(self, view: QWebEngineView, metrics, callback):
        if not isinstance(metrics, dict):
            self._capture_webview_full_page_by_scroll(view, callback)
            return
        content_left = max(0, int(float(metrics.get('contentLeft', 0) or 0)))
        content_top = max(0, int(float(metrics.get('contentTop', 0) or 0)))
        content_w = max(1, int(float(metrics.get('contentWidth', view.width()) or view.width())))
        content_h = max(1, int(float(metrics.get('contentHeight', view.height()) or view.height())))
        layout_w = max(content_w, int(float(metrics.get('layoutWidth', view.width()) or view.width())), view.width())
        capture_w = max(layout_w, content_left + content_w)
        state = {
            'view': view,
            'callback': callback,
            'content_left': content_left,
            'content_top': content_top,
            'content_w': content_w,
            'content_h': content_h,
            'layout_w': layout_w,
            'capture_w': capture_w,
            'offset': 0,
            'segments': [],
            'segment_h': 1400,
            'render_scale': 2.0,
        }
        self._share_static_capture_state = state
        self._capture_next_webview_static_segment()

    def _capture_next_webview_static_segment(self):
        state = getattr(self, '_share_static_capture_state', None)
        if not state:
            return
        offset = int(state['offset'])
        content_h = int(state['content_h'])
        if offset >= content_h:
            self._finish_webview_static_capture()
            return
        view = state['view']
        segment_h = min(int(state['segment_h']), content_h - offset)
        layout_w = int(state['layout_w'])
        capture_w = int(state.get('capture_w', layout_w))
        render_scale = max(1.0, float(state.get('render_scale', 1.0) or 1.0))
        view.setGeometry(
            -10000,
            -10000,
            max(1, int(capture_w * render_scale)),
            max(1, int(segment_h * render_scale)),
        )
        bg = '#2D2D2D' if is_dark_theme(app) else '#FFFFFF'
        content_left = int(state['content_left'])
        content_top = int(state['content_top'])
        style_css = f"""
          html {{
            overflow: hidden !important;
            scrollbar-width: none !important;
            background: {bg} !important;
            width: {layout_w}px !important;
            min-width: {layout_w}px !important;
            max-width: {layout_w}px !important;
          }}
          body {{
            overflow: visible !important;
            width: {layout_w}px !important;
            min-width: {layout_w}px !important;
            max-width: {layout_w}px !important;
            transform: scale({render_scale}) translate(-{content_left}px, -{content_top + offset}px) !important;
            transform-origin: 0 0 !important;
            background: {bg} !important;
          }}
          ::-webkit-scrollbar {{
            display: none !important;
            width: 0 !important;
            height: 0 !important;
          }}
        """
        view.page().runJavaScript(
            f"""
            (() => {{
              const styleId = 'broccoli-share-static-capture-style';
              let style = document.getElementById(styleId);
              if (!style) {{
                style = document.createElement('style');
                style.id = styleId;
                document.head.appendChild(style);
              }}
              style.textContent = {json.dumps(style_css)};
              window.scrollTo(0, 0);
            }})();
            """,
            lambda _result: QTimer.singleShot(180, self._grab_current_webview_static_segment),
        )

    def _grab_current_webview_static_segment(self):
        state = getattr(self, '_share_static_capture_state', None)
        if not state:
            return
        view = state['view']
        pixmap = view.grab()
        if pixmap.isNull():
            self._share_static_capture_state = None
            self._capture_webview_full_page_by_scroll(view, state['callback'])
            return
        dpr = max(1.0, float(pixmap.devicePixelRatio()))
        render_scale = max(1.0, float(state.get('render_scale', 1.0) or 1.0))
        effective_dpr = dpr * render_scale
        image = pixmap.toImage()
        crop_w = min(image.width(), max(1, int(round(int(state['content_w']) * effective_dpr))))
        crop_h = min(image.height(), max(1, int(round((int(state['content_h']) - int(state['offset'])) * effective_dpr))))
        segment = image.copy(0, 0, crop_w, crop_h)
        state['segments'].append((int(state['offset']), segment, effective_dpr))
        state['offset'] = int(state['offset']) + max(1, int(round(crop_h / effective_dpr)))
        self._capture_next_webview_static_segment()

    def _finish_webview_static_capture(self):
        state = getattr(self, '_share_static_capture_state', None)
        self._share_static_capture_state = None
        if not state:
            return
        segments = state.get('segments') or []
        if not segments:
            self._capture_webview_full_page_by_scroll(state['view'], state['callback'])
            return
        dpr = max(1.0, float(segments[0][2]))
        canvas_w = max(1, int(int(state['content_w']) * dpr))
        canvas_h = max(1, int(int(state['content_h']) * dpr))
        max_canvas_h = 120000
        if canvas_h > max_canvas_h:
            scale = max_canvas_h / canvas_h
            canvas_h = max_canvas_h
            canvas_w = max(1, int(canvas_w * scale))
        else:
            scale = 1.0
        canvas = QImage(canvas_w, canvas_h, QImage.Format.Format_ARGB32)
        canvas.fill(QColor('#2D2D2D' if is_dark_theme(app) else '#FFFFFF'))
        painter = QPainter(canvas)
        for offset, segment, _dpr in segments:
            y = int(offset * dpr * scale)
            if scale != 1.0:
                target_w = max(1, int(segment.width() * scale))
                target_h = max(1, int(segment.height() * scale))
                painter.drawImage(QRect(0, y, target_w, target_h), segment)
            else:
                painter.drawImage(0, y, segment)
        painter.end()
        callback = state.get('callback')
        self._finalize_share_image_async(canvas, callback)

    def _capture_webview_pdf_page(self, view: QWebEngineView, callback) -> bool:
        if view is None or view.width() <= 0 or view.height() <= 0:
            return False
        page = view.page()
        if page is None or not hasattr(page, 'printToPdf'):
            return False
        page.runJavaScript(
            """
            (() => {
              const doc = document.documentElement;
              const body = document.body || doc;
              const originalX = window.scrollX || doc.scrollLeft || 0;
              const originalY = window.scrollY || doc.scrollTop || 0;
              const docW = Math.ceil(Math.max(
                body ? body.scrollWidth : 0,
                doc ? doc.scrollWidth : 0,
                doc ? doc.clientWidth : 0,
                window.innerWidth || 0
              ));
              const docH = Math.ceil(Math.max(
                body ? body.scrollHeight : 0,
                doc ? doc.scrollHeight : 0,
                doc ? doc.clientHeight : 0,
                window.innerHeight || 0
              ));
              const rects = [];
              const addRect = (rect) => {
                if (!rect || rect.width < 1 || rect.height < 1) return;
                rects.push({
                  left: rect.left + originalX,
                  top: rect.top + originalY,
                  right: rect.right + originalX,
                  bottom: rect.bottom + originalY
                });
              };
              const root = document.querySelector('.share-capture') || body;
              const walker = document.createTreeWalker(
                root,
                NodeFilter.SHOW_TEXT,
                {
                  acceptNode: (node) => (
                    node.nodeValue && node.nodeValue.trim()
                      ? NodeFilter.FILTER_ACCEPT
                      : NodeFilter.FILTER_REJECT
                  )
                }
              );
              const range = document.createRange();
              let node;
              while ((node = walker.nextNode())) {
                range.selectNodeContents(node);
                for (const rect of range.getClientRects()) addRect(rect);
              }
              if (range.detach) range.detach();
              const mediaSelector = [
                'img', 'video', 'canvas', 'svg', 'table', 'pre', 'blockquote',
                '.attachment-display-block', '.pipeline-details',
                '.qa-label', '.pipeline-default-heading'
              ].join(',');
              root.querySelectorAll(mediaSelector).forEach((el) => {
                const st = window.getComputedStyle(el);
                if (!st || st.display === 'none' || st.visibility === 'hidden' || Number(st.opacity || 1) === 0) {
                  return;
                }
                addRect(el.getBoundingClientRect());
              });
              if (!rects.length) addRect((root || body).getBoundingClientRect());
              const padLeft = 56;
              const padRight = 160;
              const padTop = 88;
              const padBottom = 96;
              const left = Math.max(0, Math.floor(Math.min(...rects.map(r => r.left)) - padLeft));
              const top = Math.max(0, Math.floor(Math.min(...rects.map(r => r.top)) - padTop));
              const right = Math.ceil(Math.max(...rects.map(r => r.right)) + padRight);
              const bottom = Math.ceil(Math.max(...rects.map(r => r.bottom)) + padBottom);
              return {
                originalX,
                originalY,
                contentLeft: left,
                contentTop: top,
                contentWidth: Math.max(1, right - left),
                contentHeight: Math.max(1, bottom - top)
              };
            })();
            """,
            lambda metrics: self._start_webview_pdf_capture(view, metrics, callback),
        )
        return True

    def _start_webview_pdf_capture(self, view: QWebEngineView, metrics, callback):
        if not isinstance(metrics, dict):
            self._capture_webview_full_page_by_scroll(view, callback)
            return
        try:
            from PyQt6.QtCore import QMarginsF, QSizeF
            from PyQt6.QtGui import QPageLayout, QPageSize
            content_left = max(0, int(float(metrics.get('contentLeft', 0) or 0)))
            content_top = max(0, int(float(metrics.get('contentTop', 0) or 0)))
            content_w = max(1, int(float(metrics.get('contentWidth', view.width()) or view.width())))
            content_h = max(1, int(float(metrics.get('contentHeight', view.height()) or view.height())))
            original_x = int(float(metrics.get('originalX', 0) or 0))
            original_y = int(float(metrics.get('originalY', 0) or 0))
            px_to_pt = 72.0 / 96.0
            page_size_f = QSizeF(content_w * px_to_pt, content_h * px_to_pt)
            try:
                page_size = QPageSize(page_size_f, QPageSize.Unit.Point, 'Broccoli Share')
            except TypeError:
                page_size = QPageSize(page_size_f, QPageSize.Unit.Point)
            try:
                layout = QPageLayout(
                    page_size,
                    QPageLayout.Orientation.Portrait,
                    QMarginsF(0, 0, 0, 0),
                    QPageLayout.Unit.Point,
                )
                try:
                    layout.setMode(QPageLayout.Mode.FullPageMode)
                except Exception:
                    pass
            except Exception:
                layout = None
            style_css = f"""
              html, body {{ scrollbar-width: none !important; }}
              ::-webkit-scrollbar {{
                display: none !important;
                width: 0 !important;
                height: 0 !important;
              }}
              @media print {{
                @page {{ size: {content_w}px {content_h}px; margin: 0; }}
                html, body {{
                  margin: 0 !important;
                  padding: 0 !important;
                  width: {content_w}px !important;
                  min-width: {content_w}px !important;
                  height: {content_h}px !important;
                  min-height: {content_h}px !important;
                  overflow: visible !important;
                }}
                body {{
                  transform: translate(-{content_left}px, -{content_top}px) !important;
                  transform-origin: 0 0 !important;
                }}
              }}
            """
            state = {
                'view': view,
                'callback': callback,
                'fallback': lambda: self._capture_webview_full_page_by_scroll(view, callback),
                'original_x': original_x,
                'original_y': original_y,
                'content_w': content_w,
                'content_h': content_h,
            }
            self._share_pdf_capture_state = state
            view.page().runJavaScript(
                f"""
                (() => {{
                  const styleId = 'broccoli-share-pdf-style';
                  let style = document.getElementById(styleId);
                  if (!style) {{
                    style = document.createElement('style');
                    style.id = styleId;
                    document.head.appendChild(style);
                  }}
                  style.textContent = {json.dumps(style_css)};
                }})();
                """,
                lambda _result: QTimer.singleShot(
                    80,
                    lambda: self._run_webview_print_to_pdf(view, layout),
                ),
            )
        except Exception:
            self._capture_webview_full_page_by_scroll(view, callback)

    def _run_webview_print_to_pdf(self, view: QWebEngineView, layout):
        try:
            if layout is not None:
                view.page().printToPdf(
                    lambda data: self._finish_webview_pdf_capture(data),
                    layout,
                )
            else:
                view.page().printToPdf(lambda data: self._finish_webview_pdf_capture(data))
        except TypeError:
            try:
                view.page().printToPdf(lambda data: self._finish_webview_pdf_capture(data))
            except Exception:
                self._finish_webview_pdf_capture(b'')
        except Exception:
            self._finish_webview_pdf_capture(b'')

    def _finish_webview_pdf_capture(self, data):
        state = getattr(self, '_share_pdf_capture_state', None)
        self._share_pdf_capture_state = None
        if not state:
            return
        view = state['view']
        view.page().runJavaScript(
            f"""
            (() => {{
              const style = document.getElementById('broccoli-share-pdf-style');
              if (style) style.remove();
              window.scrollTo({int(state['original_x'])}, {int(state['original_y'])});
            }})();
            """
        )
        try:
            pdf_bytes = bytes(data)
        except Exception:
            pdf_bytes = b''
        if not pdf_bytes:
            state['fallback']()
            return
        try:
            from PyQt6.QtCore import QByteArray, QBuffer, QIODevice
            from PyQt6.QtPdf import QPdfDocument
            pdf_doc = QPdfDocument(self)
            buffer = QBuffer(self)
            buffer.setData(QByteArray(pdf_bytes))
            buffer.open(QIODevice.OpenModeFlag.ReadOnly)
            status = pdf_doc.load(buffer)
            if status != QPdfDocument.Status.Ready or pdf_doc.pageCount() <= 0:
                buffer.close()
                state['fallback']()
                return
            scale = 2.0
            pages = []
            total_h = 0
            max_w = 1
            for i in range(pdf_doc.pageCount()):
                point_size = pdf_doc.pagePointSize(i)
                image_size = QSize(
                    max(1, int(point_size.width() * scale)),
                    max(1, int(point_size.height() * scale)),
                )
                image = pdf_doc.render(i, image_size)
                if image.isNull():
                    continue
                pages.append(image)
                max_w = max(max_w, image.width())
                total_h += image.height()
            buffer.close()
            if not pages:
                state['fallback']()
                return
            max_canvas_h = 120000
            if total_h > max_canvas_h:
                shrink = max_canvas_h / total_h
                canvas_w = max(1, int(max_w * shrink))
                canvas_h = max_canvas_h
            else:
                shrink = 1.0
                canvas_w = max_w
                canvas_h = total_h
            canvas = QImage(canvas_w, canvas_h, QImage.Format.Format_ARGB32)
            canvas.fill(QColor('#2D2D2D' if is_dark_theme(app) else '#FFFFFF'))
            painter = QPainter(canvas)
            y = 0
            for image in pages:
                if shrink != 1.0:
                    target_h = max(1, int(image.height() * shrink))
                    target_w = max(1, int(image.width() * shrink))
                    painter.drawImage(QRect(0, y, target_w, target_h), image)
                    y += target_h
                else:
                    painter.drawImage(0, y, image)
                    y += image.height()
            painter.end()
            callback = state.get('callback')
            self._finalize_share_image_async(canvas, callback)
        except Exception:
            state['fallback']()

    def _capture_webview_full_page_by_scroll(self, view: QWebEngineView, callback):
        if view is None or view.width() <= 0 or view.height() <= 0:
            return
        view.page().runJavaScript(
            """
            (() => {
              const styleId = 'broccoli-share-capture-style';
              let style = document.getElementById(styleId);
              if (!style) {
                style = document.createElement('style');
                style.id = styleId;
                document.head.appendChild(style);
              }
              style.textContent = `
                html, body { scrollbar-width: none !important; }
                ::-webkit-scrollbar {
                  display: none !important;
                  width: 0 !important;
                  height: 0 !important;
                }
              `;

              const doc = document.documentElement;
              const body = document.body || doc;
              const originalX = window.scrollX || doc.scrollLeft || 0;
              const originalY = window.scrollY || doc.scrollTop || 0;
              const docW = Math.ceil(Math.max(
                body ? body.scrollWidth : 0,
                doc ? doc.scrollWidth : 0,
                doc ? doc.clientWidth : 0,
                window.innerWidth || 0
              ));
              const docH = Math.ceil(Math.max(
                body ? body.scrollHeight : 0,
                doc ? doc.scrollHeight : 0,
                doc ? doc.clientHeight : 0,
                window.innerHeight || 0
              ));
              const rects = [];
              const addRect = (rect) => {
                if (!rect || rect.width < 1 || rect.height < 1) return;
                rects.push({
                  left: rect.left + originalX,
                  top: rect.top + originalY,
                  right: rect.right + originalX,
                  bottom: rect.bottom + originalY
                });
              };
              const root = document.querySelector('.share-capture') || body;
              const walker = document.createTreeWalker(
                root,
                NodeFilter.SHOW_TEXT,
                {
                  acceptNode: (node) => (
                    node.nodeValue && node.nodeValue.trim()
                      ? NodeFilter.FILTER_ACCEPT
                      : NodeFilter.FILTER_REJECT
                  )
                }
              );
              const range = document.createRange();
              let node;
              while ((node = walker.nextNode())) {
                range.selectNodeContents(node);
                for (const rect of range.getClientRects()) addRect(rect);
              }
              if (range.detach) range.detach();

              const mediaSelector = [
                'img', 'video', 'canvas', 'svg', 'table', 'pre', 'blockquote',
                '.attachment-display-block', '.pipeline-details',
                '.qa-label', '.pipeline-default-heading'
              ].join(',');
              root.querySelectorAll(mediaSelector).forEach((el) => {
                const st = window.getComputedStyle(el);
                if (!st || st.display === 'none' || st.visibility === 'hidden' || Number(st.opacity || 1) === 0) {
                  return;
                }
                addRect(el.getBoundingClientRect());
              });

              if (!rects.length) {
                addRect((root || body).getBoundingClientRect());
              }
              const padLeft = 56;
              const padRight = 160;
              const padTop = 88;
              const padBottom = 96;
              const left = Math.max(0, Math.floor(Math.min(...rects.map(r => r.left)) - padLeft));
              const top = Math.max(0, Math.floor(Math.min(...rects.map(r => r.top)) - padTop));
              const right = Math.ceil(Math.max(...rects.map(r => r.right)) + padRight);
              const bottom = Math.ceil(Math.max(...rects.map(r => r.bottom)) + padBottom);
              return {
                originalX,
                originalY,
                contentLeft: left,
                contentTop: top,
                contentWidth: Math.max(1, right - left),
                contentHeight: Math.max(1, bottom - top),
                viewportWidth: Math.ceil((doc && doc.clientWidth) || window.innerWidth || 0),
                viewportHeight: Math.ceil((doc && doc.clientHeight) || window.innerHeight || 0)
              };
            })();
            """,
            lambda metrics: self._start_webview_segment_capture(view, metrics, callback),
        )

    def _start_webview_segment_capture(self, view: QWebEngineView, metrics, callback):
        if not isinstance(metrics, dict):
            return
        content_left = max(0, int(float(metrics.get('contentLeft', 0) or 0)))
        content_top = max(0, int(float(metrics.get('contentTop', 0) or 0)))
        content_w = max(1, int(float(metrics.get('contentWidth', view.width()) or view.width())))
        content_h = max(1, int(float(metrics.get('contentHeight', view.height()) or view.height())))
        original_x = int(float(metrics.get('x', 0) or 0))
        original_y = int(float(metrics.get('y', 0) or 0))
        original_x = int(float(metrics.get('originalX', original_x) or original_x))
        original_y = int(float(metrics.get('originalY', original_y) or original_y))
        viewport_h = max(1, min(view.height(), int(float(metrics.get('viewportHeight', view.height()) or view.height()))))
        viewport_w = max(1, min(view.width(), int(float(metrics.get('viewportWidth', view.width()) or view.width()))))
        state = {
            'view': view,
            'callback': callback,
            'content_left': content_left,
            'content_top': content_top,
            'content_w': content_w,
            'content_h': content_h,
            'content_right': content_left + content_w,
            'content_bottom': content_top + content_h,
            'original_x': original_x,
            'original_y': original_y,
            'viewport_h': viewport_h,
            'viewport_w': viewport_w,
            'segments': [],
            'next_top': content_top,
            'safety': 0,
        }
        self._share_full_capture_state = state
        self._capture_next_webview_segment()

    def _capture_next_webview_segment(self):
        state = self._share_full_capture_state
        if not state:
            return
        view = state['view']
        y = int(state['next_top'])
        if y >= int(state['content_bottom']) or int(state.get('safety', 0)) > 320:
            self._finish_webview_segment_capture()
            return
        state['safety'] = int(state.get('safety', 0)) + 1
        view.page().runJavaScript(f"window.scrollTo({int(state['content_left'])}, {y});")
        QTimer.singleShot(140, self._grab_current_webview_segment)

    def _grab_current_webview_segment(self):
        state = self._share_full_capture_state
        if not state:
            return
        view = state['view']
        view.page().runJavaScript(
            """
            (() => {
              const doc = document.documentElement;
              return {
                x: window.scrollX || doc.scrollLeft || 0,
                y: window.scrollY || doc.scrollTop || 0,
                viewportWidth: Math.ceil((doc && doc.clientWidth) || window.innerWidth || 0),
                viewportHeight: Math.ceil((doc && doc.clientHeight) || window.innerHeight || 0)
              };
            })();
            """,
            self._grab_current_webview_segment_after_scroll,
        )

    def _grab_current_webview_segment_after_scroll(self, viewport_metrics):
        state = self._share_full_capture_state
        if not state:
            return
        view = state['view']
        if not isinstance(viewport_metrics, dict):
            viewport_metrics = {}
        scroll_x = int(float(viewport_metrics.get('x', 0) or 0))
        scroll_y = int(float(viewport_metrics.get('y', 0) or 0))
        viewport_w = max(1, min(view.width(), int(float(viewport_metrics.get('viewportWidth', state['viewport_w']) or state['viewport_w']))))
        viewport_h = max(1, min(view.height(), int(float(viewport_metrics.get('viewportHeight', state['viewport_h']) or state['viewport_h']))))
        content_left = int(state['content_left'])
        content_top = int(state['content_top'])
        content_right = int(state['content_right'])
        content_bottom = int(state['content_bottom'])
        visible_left = max(content_left, scroll_x)
        visible_top = max(content_top, scroll_y)
        visible_right = min(content_right, scroll_x + viewport_w)
        visible_bottom = min(content_bottom, scroll_y + viewport_h)
        logical_take_w = max(0, visible_right - visible_left)
        logical_take_h = max(0, visible_bottom - visible_top)
        if logical_take_w <= 0 or logical_take_h <= 0:
            state['next_top'] = min(content_bottom, int(state['next_top']) + viewport_h)
            self._capture_next_webview_segment()
            return
        pixmap = view.grab()
        if pixmap.isNull():
            self._finish_webview_segment_capture()
            return
        dpr = max(1.0, float(pixmap.devicePixelRatio()))
        image = pixmap.toImage()
        crop_x = max(0, int(round((visible_left - scroll_x) * dpr)))
        crop_y = max(0, int(round((visible_top - scroll_y) * dpr)))
        crop_w = min(image.width() - crop_x, max(1, int(round(logical_take_w * dpr))))
        crop_h = min(image.height() - crop_y, max(1, int(round(logical_take_h * dpr))))
        if crop_w <= 0 or crop_h <= 0:
            state['next_top'] = min(content_bottom, int(state['next_top']) + viewport_h)
            self._capture_next_webview_segment()
            return
        segment = image.copy(crop_x, crop_y, crop_w, crop_h)
        dest_x = max(0, visible_left - content_left)
        dest_y = max(0, visible_top - content_top)
        state['segments'].append((dest_x, dest_y, segment, dpr))
        next_top = visible_bottom
        if next_top <= int(state['next_top']) + 1:
            next_top = int(state['next_top']) + max(1, viewport_h)
        state['next_top'] = min(content_bottom, next_top)
        self._capture_next_webview_segment()

    def _finish_webview_segment_capture(self):
        state = self._share_full_capture_state
        self._share_full_capture_state = None
        if not state:
            return
        view = state['view']
        segments = state.get('segments', [])
        view.page().runJavaScript(
            f"""
            (() => {{
              const style = document.getElementById('broccoli-share-capture-style');
              if (style) style.remove();
              window.scrollTo({int(state['original_x'])}, {int(state['original_y'])});
            }})();
            """
        )
        if not segments:
            return
        dpr = max(1.0, float(segments[0][3]))
        canvas_w = max(1, int(int(state['content_w']) * dpr))
        canvas_h = max(1, int(int(state['content_h']) * dpr))
        max_canvas_h = 120000
        if canvas_h > max_canvas_h:
            scale = max_canvas_h / canvas_h
            canvas_h = max_canvas_h
            canvas_w = max(1, int(canvas_w * scale))
        else:
            scale = 1.0
        canvas = QImage(canvas_w, canvas_h, QImage.Format.Format_ARGB32)
        canvas.fill(QColor('#2D2D2D' if is_dark_theme(app) else '#FFFFFF'))
        painter = QPainter(canvas)
        for x, y, segment, _seg_dpr in segments:
            target_x = int(x * dpr * scale)
            target_y = int(y * dpr * scale)
            if scale != 1.0:
                target_h = max(1, int(segment.height() * scale))
                target_w = max(1, int(segment.width() * scale))
                painter.drawImage(QRect(target_x, target_y, target_w, target_h), segment)
            else:
                painter.drawImage(target_x, target_y, segment)
        painter.end()
        callback = state.get('callback')
        self._finalize_share_image_async(canvas, callback)

    def _external_prompt_panel_for_index(self, index: int):
        if index == 0:
            return getattr(self, 'ai_web_panel', None), getattr(self, 'web_prompt_dock', None)
        if index == 2:
            return getattr(self, 'localhost_panel', None), getattr(self, 'localhost_prompt_dock', None)
        return None, None

    def _current_external_prompt_pair(self):
        return self._external_prompt_panel_for_index(self.stacked_widget.currentIndex())

    def _active_external_prompt_dock(self):
        _panel, dock = self._current_external_prompt_pair()
        return dock

    @staticmethod
    def _sync_external_prompt_dock_height(panel, dock):
        try:
            if panel is not None and dock is not None and panel.is_prompt_dock_visible():
                panel.set_prompt_dock_height(dock.sizeHint().height())
        except Exception:
            pass

    def _toggle_current_external_prompt_dock(self):
        panel, _dock = self._current_external_prompt_pair()
        if panel is None:
            return
        panel.set_prompt_dock_visible(not panel.is_prompt_dock_visible(), animated=True)
        if panel.is_prompt_dock_visible() and getattr(self, '_webfetch_records', None) and not getattr(self, '_webfetch_panel_dismissed', False):
            self._show_webfetch_panel()
        elif hasattr(self, 'webfetch_panel'):
            self.webfetch_panel.hide()

    def _update_external_prompt_trigger_geometry(self):
        if not hasattr(self, '_external_prompt_trigger_btn'):
            return
        index = self.stacked_widget.currentIndex() if hasattr(self, 'stacked_widget') else -1
        if index not in (0, 2):
            self._external_prompt_trigger_btn.hide()
            return
        try:
            top = self.stacked_widget.mapTo(self.qw3, QPoint(0, 0)).y()
            height = self.stacked_widget.height()
        except Exception:
            top = 58
            height = max(0, self.qw3.height() - top)
        self._external_prompt_trigger_btn.setGeometry(
            0,
            max(0, top),
            int(getattr(self, '_external_prompt_trigger_w', 28)),
            max(0, height),
        )
        self._external_prompt_trigger_btn.show()
        self._external_prompt_trigger_btn.raise_()
        self._update_web_conversation_sync_button_geometry()

    def _web_conversation_sync_button_rect(self) -> QRect:
        diameter = WebConversationSyncButton.DIAMETER
        try:
            y = self._webfetch_panel_rect().y()
        except Exception:
            y = 58
        return QRect(20, max(0, y), diameter, diameter)

    def _update_web_conversation_sync_button_geometry(self):
        if not hasattr(self, 'web_conversation_sync_button'):
            return
        index = self.stacked_widget.currentIndex() if hasattr(self, 'stacked_widget') else -1
        if index not in (0, 2):
            self.web_conversation_sync_button.hide()
            return
        panel, _dock = self._external_prompt_panel_for_index(index)
        if panel is None or not panel.is_prompt_dock_visible():
            self.web_conversation_sync_button.hide()
            return
        self.web_conversation_sync_button.setGeometry(self._web_conversation_sync_button_rect())
        self.web_conversation_sync_button.show()
        self.web_conversation_sync_button.raise_()

    def _sync_current_web_conversation_to_api(self):
        index = self.stacked_widget.currentIndex() if hasattr(self, 'stacked_widget') else -1
        panel, _dock = self._external_prompt_panel_for_index(index)
        if panel is None or not hasattr(panel, 'active_view'):
            return
        view = panel.active_view()
        if view is None:
            return
        self.web_conversation_sync_button.setEnabled(False)

        def after_capture(payload, tab_index=index):
            self.web_conversation_sync_button.setEnabled(True)
            self._show_web_conversation_sync_menu(tab_index, payload)

        try:
            view.page().runJavaScript(_WEB_CONVERSATION_CAPTURE_JS, after_capture)
        except Exception:
            self.web_conversation_sync_button.setEnabled(True)

    def _web_conversation_source_key(self, tab_index: int) -> str:
        panel, _dock = self._external_prompt_panel_for_index(tab_index)
        scope = 'web' if tab_index == 0 else 'localhost' if tab_index == 2 else 'unknown'
        try:
            active_idx = int(panel.active_index()) if panel is not None else 0
        except Exception:
            active_idx = 0
        return f'{scope}:{active_idx}'

    def _normalize_web_conversation_capture(self, payload) -> dict:
        capture = payload if isinstance(payload, dict) else {}
        now = current_chat_timestamp()
        messages = []
        seen = set()
        for item in capture.get('messages', []) if isinstance(capture.get('messages'), list) else []:
            if not isinstance(item, dict):
                continue
            role = str(item.get('role', '')).strip().lower()
            if role not in {'user', 'assistant'}:
                continue
            content = re.sub(r'\n{3,}', '\n\n', str(item.get('content', '') or '')).strip()
            if not content:
                continue
            key = (role, content)
            if key in seen:
                continue
            seen.add(key)
            source = str(item.get('source', '') or capture.get('source', '') or '').strip()
            message = {'role': role, 'content': content, 'timestamp': now}
            if source:
                message['source'] = source[:40]
            messages.append(message)
        title = sanitize_conversation_title(
            capture.get('title', '') or conversation_title_from_messages(messages, fallback='Web conversation')
        )
        source = str(capture.get('source', '') or '').strip()
        if not source:
            for message in messages:
                source = str(message.get('source', '') or '').strip()
                if source:
                    break
        return {
            'title': title,
            'url': str(capture.get('url', '') or '').strip(),
            'source': source,
            'captured_at': str(capture.get('captured_at', '') or '').strip(),
            'messages': messages,
        }

    def _show_web_conversation_sync_menu(self, tab_index: int, payload):
        capture = self._normalize_web_conversation_capture(payload)
        messages = capture.get('messages', [])
        if not messages:
            self.web_conversation_sync_button.setToolTip('No conversation messages were detected on this page.')
            return
        source_key = self._web_conversation_source_key(tab_index)
        bindings = load_web_conversation_bindings()
        linked_path = str(bindings.get(source_key, '') or '').strip()
        linked_exists = bool(linked_path and os.path.exists(linked_path))
        active_exists = bool(self._active_conversation_path and os.path.exists(self._active_conversation_path))

        menu = QMenu(self)
        title_action = QAction(f"{len(messages)} messages detected", menu)
        title_action.setEnabled(False)
        menu.addAction(title_action)
        menu.addSeparator()

        new_action = QAction('New API history', menu)
        new_action.triggered.connect(lambda _checked=False: self._save_web_conversation_new(source_key, capture))
        menu.addAction(new_action)

        update_action = QAction('Update linked API history', menu)
        update_action.setEnabled(linked_exists)
        update_action.triggered.connect(lambda _checked=False, path=linked_path: self._save_web_conversation_update(path, source_key, capture))
        menu.addAction(update_action)

        append_action = QAction('Append to current API history', menu)
        append_action.setEnabled(active_exists)
        append_action.triggered.connect(lambda _checked=False: self._save_web_conversation_append(self._active_conversation_path, source_key, capture))
        menu.addAction(append_action)

        records = list_conversation_records()
        if records:
            choose_menu = menu.addMenu('Choose API history...')
            for record in records[:24]:
                label = str(record.get('title', '') or os.path.basename(record.get('path', ''))).strip()
                if len(label) > 48:
                    label = label[:45].rstrip() + '...'
                action = QAction(label, choose_menu)
                action.setToolTip(str(record.get('path', '')))
                action.triggered.connect(
                    lambda _checked=False, path=record.get('path', ''): self._save_web_conversation_append(path, source_key, capture)
                )
                choose_menu.addAction(action)

        anchor = self.web_conversation_sync_button
        menu.exec(anchor.mapToGlobal(QPoint(0, anchor.height() + 6)))

    @staticmethod
    def _web_message_signature(message: dict) -> tuple[str, str]:
        return (
            str(message.get('role', '')).strip().lower(),
            re.sub(r'\s+', ' ', str(message.get('content', '') or '').strip()),
        )

    def _merge_web_conversation_messages(self, existing: list[dict], incoming: list[dict]) -> list[dict]:
        existing = [msg for msg in existing or [] if normalize_chat_history_message(msg)]
        incoming = [msg for msg in incoming or [] if normalize_chat_history_message(msg)]
        if not existing:
            return incoming
        if not incoming:
            return existing
        existing_sig = [self._web_message_signature(msg) for msg in existing]
        incoming_sig = [self._web_message_signature(msg) for msg in incoming]
        max_overlap = min(len(existing_sig), len(incoming_sig))
        overlap = 0
        for size in range(max_overlap, 0, -1):
            if existing_sig[-size:] == incoming_sig[:size]:
                overlap = size
                break
        if overlap:
            return existing + incoming[overlap:]
        if len(incoming_sig) >= len(existing_sig) and incoming_sig[:len(existing_sig)] == existing_sig:
            return incoming
        return existing + incoming

    def _save_web_conversation_record(self,
                                      path: str,
                                      capture: dict,
                                      messages: list[dict],
                                      source_key: str,
                                      bind: bool = True) -> dict | None:
        if not path or not messages:
            return None
        now = datetime.datetime.now().isoformat(timespec='seconds')
        existing = load_conversation_record(path)
        title_with_source = web_conversation_title_with_source(
            capture.get('title') or conversation_title_from_messages(messages, fallback='Web conversation'),
            capture.get('source', ''),
        )
        record = existing if existing is not None else {
            'id': Path(path).stem.split('_', 1)[0],
            'title': title_with_source,
            'created_at': now,
            'messages': [],
        }
        record['messages'] = list(messages)
        record['title'] = sanitize_conversation_title(record.get('title') or title_with_source)
        record['updated_at'] = now
        record['rendered_markdown'] = render_chat_history_markdown(messages)
        saved = write_conversation_record(path, record)
        if bind:
            bindings = load_web_conversation_bindings()
            bindings[source_key] = saved['path']
            save_web_conversation_bindings(bindings)
        self._active_conversation_path = saved['path']
        save_chat_history_messages(saved['messages'])
        self.render_final_output(saved['rendered_markdown'], history_messages=saved['messages'])
        self._refresh_history_panel()
        self._refresh_links_panel()
        self._refresh_outputs_panel()
        self._refresh_branch_state_from_current_conversation()
        return saved

    def _save_web_conversation_new(self, source_key: str, capture: dict):
        messages = list(capture.get('messages') or [])
        convo_id = datetime.datetime.now().strftime('%Y%m%d-%H%M%S')
        title = web_conversation_title_with_source(
            capture.get('title') or conversation_title_from_messages(messages, fallback='Web conversation'),
            capture.get('source', ''),
        )
        filename = f"{convo_id}_{sanitize_conversation_filename(title)}.json"
        path = os.path.join(CONVERSATIONS_DIR, filename)
        suffix = 2
        while os.path.exists(path):
            filename = f"{convo_id}_{sanitize_conversation_filename(title)}-{suffix}.json"
            path = os.path.join(CONVERSATIONS_DIR, filename)
            suffix += 1
        self._save_web_conversation_record(path, capture, messages, source_key, bind=True)

    def _save_web_conversation_update(self, path: str, source_key: str, capture: dict):
        if not path:
            return
        self._save_web_conversation_record(path, capture, list(capture.get('messages') or []), source_key, bind=True)

    def _save_web_conversation_append(self, path: str, source_key: str, capture: dict):
        if not path:
            return
        record = load_conversation_record(path)
        existing_messages = list(record.get('messages', [])) if record else []
        merged = self._merge_web_conversation_messages(existing_messages, list(capture.get('messages') or []))
        self._save_web_conversation_record(path, capture, merged, source_key, bind=True)

    def _prepare_web_external_attachments(self, dock: ExternalPromptDock) -> tuple[list, list]:
        direct_attachments = []
        retrieval_documents = []
        for item in dock.attachment_items():
            path = str(item.get('path', '')).strip()
            if not path or not os.path.exists(path):
                continue
            use_embedding = bool(item.get('use_embedding'))
            if use_embedding and attachment_supports_embedding(path):
                extracted = extract_attachment_text(path, allow_ocr=True, limit_chars=None)
                if extracted and str(extracted.get('content', '')).strip():
                    retrieval_documents.append({
                        'name': extracted.get('name') or os.path.basename(path),
                        'content': extracted.get('content', ''),
                    })
                    continue
            encoded = _encode_attachment_file(path)
            if encoded:
                direct_attachments.append(encoded)
        return direct_attachments, retrieval_documents

    def _build_web_external_prompt(self, raw_question: str, dock: ExternalPromptDock, skip_retrieval: bool = False) -> tuple[str, list[dict], list]:
        full_history_messages = get_current_chat_history_messages()
        history_messages, selected_message_indices = self._filter_history_messages_by_branch(full_history_messages)
        attachments, retrieval_documents = self._prepare_web_external_attachments(dock)
        if skip_retrieval:
            retrieval_documents = []
        webfetch_pages = self._selected_webfetch_pages()
        webfetch_full_text_blocks = []
        if webfetch_pages and not skip_retrieval:
            webfetch_documents = webfetch_documents_from_pages(webfetch_pages)
            if self._webfetch_context_use_embedding_enabled():
                retrieval_documents.extend(webfetch_documents)
            else:
                webfetch_full_text_blocks.extend(
                    f"[Web page: {doc.get('name', 'Web page')}]\n{doc.get('content', '')}"
                    for doc in webfetch_documents
                    if str(doc.get('content', '')).strip()
                )

        api_key, endpoint = load_runtime_openai_client_config()
        modelnow = read_text_file(BasePath + 'modelnow.txt', DEFAULT_MODEL)
        timeout = load_saved_timeout()
        attachment_context = ''
        if retrieval_documents and not skip_retrieval:
            attachment_context, _refs = self._build_attachment_retrieval_context(
                raw_question,
                retrieval_documents,
                api_key,
                endpoint,
                timeout,
            )

        context_blocks = []
        if not skip_retrieval:
            external_context = self._build_external_context_prompt_context(raw_question)
            if external_context:
                context_blocks.append(external_context)
        active_profile = load_active_settings_profile()
        if not skip_retrieval and read_text_file(BasePath + 'history.txt', '0') == '1':
            history_context = self._build_active_history_context(
                raw_question,
                history_messages,
                api_key,
                endpoint,
                modelnow,
                timeout,
                selected_message_indices=selected_message_indices,
            )
            if history_context:
                context_blocks.append(history_context)
        if not skip_retrieval and active_profile.get('remember_memory', True):
            memory_context = self._build_saved_memory_prompt_context(raw_question)
            if memory_context:
                context_blocks.append(memory_context)
        if not skip_retrieval:
            vision_context = self._build_background_vision_prompt_context()
            if vision_context:
                context_blocks.append(vision_context)
        if attachment_context:
            context_blocks.append(attachment_context)

        direct_text_blocks = []
        for item in attachments:
            items = item if isinstance(item, list) else [item]
            for att in items:
                if isinstance(att, dict) and att.get('kind') == 'text' and str(att.get('content', '')).strip():
                    direct_text_blocks.append(f"[Attached file: {att.get('name', 'Attachment')}]\n{att.get('content', '')}")

        final_parts = []
        context_text = '\n\n'.join(block for block in context_blocks if str(block).strip()).strip()
        if context_text:
            final_parts.append('Use the following context if relevant:\n' + context_text)
        if direct_text_blocks:
            final_parts.append('Attached text:\n' + '\n\n'.join(direct_text_blocks))
        if webfetch_full_text_blocks:
            final_parts.append('Web page content:\n' + '\n\n'.join(webfetch_full_text_blocks))
        if raw_question.strip() or not skip_retrieval:
            final_parts.append('User request:\n' + raw_question)
        base_prompt = '\n\n---\n\n'.join(final_parts).strip()
        if skip_retrieval and not raw_question.strip() and not base_prompt:
            return '', [], attachments
        return dock.build_mode_prompt(base_prompt), [], attachments

    def SendExternalPromptDockX(self, tab_index: int):
        panel, dock = self._external_prompt_panel_for_index(int(tab_index))
        view = panel.active_view() if panel is not None else None
        selected_views = dock.selected_target_views(panel) if panel is not None and dock is not None and hasattr(dock, 'selected_target_views') else []
        if (
            view is not None
            and dock is not None
            and len(selected_views) == 1
            and selected_views[0] is view
            and self._is_claude_web_view(view)
        ):
            self.SendClaudeDockX(tab_index)
            return
        self.SendWebX(tab_index=tab_index, force_auto_send=True)

    def SendClaudeDockX(self, tab_index: int):
        index = int(tab_index)
        panel, dock = self._external_prompt_panel_for_index(index)
        if panel is None or dock is None:
            return
        view = panel.active_view()
        if view is None:
            return
        globals_store = load_settings_store().get('globals', {})
        raw_question = dock.prompt_text().strip()
        has_pending_attachments = bool(
            getattr(dock, 'attachment_tray', None) is not None
            and dock.attachment_tray.has_cards()
        )
        if not raw_question and not has_pending_attachments:
            try:
                raw_question = subprocess.check_output('pbpaste', env={'LANG': 'en_US.UTF-8'}).decode('utf-8').strip()
                if raw_question:
                    dock.prompt_edit.setPlainText(raw_question)
            except Exception:
                pass
        if not raw_question and not has_pending_attachments:
            return

        skip_retrieval = bool(globals_store.get('skip_retrieval_for_blank_prompt', False)) and not raw_question and has_pending_attachments
        final_prompt, _attachment_records, direct_attachments = self._build_web_external_prompt(
            raw_question,
            dock,
            skip_retrieval=skip_retrieval,
        )
        image_items = self._collect_direct_image_attachments(direct_attachments)
        upload_paths = self._collect_web_upload_paths(dock)
        clear_after_send = self._clear_attachments_after_send_enabled()

        def wait_then_submit(v=view, d=dock):
            if clear_after_send:
                d.clear_attachments()
            self._wait_then_click_web_send_button(v)

        def wait_for_manual_claude_presence(v=view, d=dock, paths=None):
            names = [os.path.basename(str(path)) for path in (paths or []) if str(path).strip()]
            QTimer.singleShot(
                1600,
                lambda vv=v, nn=names, dd=d: self._wait_for_web_attachment_presence(
                    vv,
                    nn,
                    timeout_ms=30000,
                    callback=lambda ok, vvv=vv, ddd=dd: (
                        wait_then_submit(vvv, ddd) if ok else self._wait_then_click_web_send_button(vvv, timeout_ms=12000)
                    ),
                ),
            )

        QTimer.singleShot(0, lambda v=view, prompt=final_prompt: self._inject_text_to_web_view(v, prompt))
        if upload_paths:
            QTimer.singleShot(
                260,
                lambda v=view, paths=list(upload_paths): self._activate_claude_composer(
                    v,
                    callback=lambda vv=v, pp=list(paths): self._inject_files_to_claude_by_drop(
                        vv,
                        pp,
                        fallback_callback=lambda vvv=vv, ppp=list(pp): wait_for_manual_claude_presence(vvv, dock, ppp),
                        callback=lambda vvv=vv, ppp=list(pp): wait_for_manual_claude_presence(vvv, dock, ppp),
                    ),
                ),
            )
        elif image_items:
            QTimer.singleShot(
                220,
                lambda v=view, imgs=image_items: self._inject_images_to_web_view(
                    v,
                    imgs,
                    callback=lambda vv=v: wait_then_submit(vv, dock),
                ),
            )
        else:
            QTimer.singleShot(850, lambda v=view: wait_then_submit(v, dock))
        dock.clear_prompt()

    def SendWebX(self, tab_index: int | None = None, force_auto_send: bool = False):
        index = self.stacked_widget.currentIndex() if tab_index is None else int(tab_index)
        panel, dock = self._external_prompt_panel_for_index(index)
        if panel is None or dock is None:
            return
        globals_store = load_settings_store().get('globals', {})
        raw_question = dock.prompt_text().strip()
        allow_blank_with_attachments = bool(globals_store.get('allow_blank_prompt_with_attachments', False))
        force_blank_prompt_once = bool(getattr(self, '_force_external_blank_prompt_once', False))
        self._force_external_blank_prompt_once = False
        has_pending_attachments = bool(
            getattr(dock, 'attachment_tray', None) is not None
            and dock.attachment_tray.has_cards()
        )
        can_send_blank_prompt = (
            allow_blank_with_attachments or force_blank_prompt_once or bool(force_auto_send)
        ) and has_pending_attachments
        if not raw_question and not can_send_blank_prompt:
            try:
                raw_question = subprocess.check_output('pbpaste', env={'LANG': 'en_US.UTF-8'}).decode('utf-8').strip()
                if raw_question:
                    dock.prompt_edit.setPlainText(raw_question)
            except Exception:
                pass
        if not raw_question and not can_send_blank_prompt:
            return
        skip_retrieval = bool(globals_store.get('skip_retrieval_for_blank_prompt', False)) and not raw_question and can_send_blank_prompt
        final_prompt, _attachment_records, direct_attachments = self._build_web_external_prompt(
            raw_question,
            dock,
            skip_retrieval=skip_retrieval,
        )
        views = dock.selected_target_views(panel) if hasattr(dock, 'selected_target_views') else [panel.active_view()]
        if not views:
            return
        image_items = self._collect_direct_image_attachments(direct_attachments)
        upload_paths = self._collect_web_upload_paths(dock)
        force_web_auto_send_once = bool(getattr(self, '_force_web_auto_send_once', False))
        self._force_web_auto_send_once = False
        auto_send = bool(force_auto_send) or self._web_auto_send_after_inject_enabled() or force_web_auto_send_once
        clear_after_send = self._clear_attachments_after_send_enabled()

        def after_attachment_handoff(v, d, click):
            log_broccoli_claude(f'attachment handoff confirmed; auto_send={click}')
            if clear_after_send:
                d.clear_attachments()
            if click:
                self._wait_then_click_web_send_button(v)

        def after_attachment_timeout():
            show_broccoli_message(
                self,
                'Attachment upload',
                'The web page did not confirm that the attachment was added. The attachment was kept in Broccoli.',
            )

        def after_claude_detection_timeout(v, click):
            log_broccoli_claude(f'attachment detection timeout; auto_send={click}')
            if click:
                self._wait_then_click_web_send_button(v, timeout_ms=12000)
            else:
                after_attachment_timeout()

        def wait_for_claude_presence(v, d, paths, click, on_failure):
            names = [os.path.basename(str(path)) for path in paths or [] if str(path).strip()]
            QTimer.singleShot(
                1600,
                lambda vv=v, nn=names, dd=d, cc=click, fail=on_failure: self._wait_for_web_attachment_presence(
                    vv,
                    nn,
                    timeout_ms=30000,
                    callback=lambda ok, vvv=vv, ddd=dd, ccc=cc, fff=fail: (
                        after_attachment_handoff(vvv, ddd, ccc) if ok else fff()
                    ),
                ),
            )

        def start_claude_drop_first(v, d, paths, click):
            self._activate_claude_composer(
                v,
                callback=lambda vv=v, dd=d, pp=list(paths), cc=click: self._inject_files_to_claude_by_drop(
                    vv,
                    pp,
                    fallback_callback=lambda vvv=vv, ddd=dd, ppp=list(pp), ccc=cc: wait_for_claude_presence(
                        vvv,
                        ddd,
                        ppp,
                        ccc,
                        on_failure=lambda vvvv=vvv, cccc=ccc: after_claude_detection_timeout(vvvv, cccc),
                    ),
                    callback=lambda vvv=vv, ddd=dd, ppp=list(pp), ccc=cc: wait_for_claude_presence(
                        vvv,
                        ddd,
                        ppp,
                        ccc,
                        on_failure=lambda vvvv=vvv, cccc=ccc: after_claude_detection_timeout(vvvv, cccc),
                    ),
                ),
            )

        for offset, view in enumerate(views):
            delay = offset * 450
            QTimer.singleShot(delay, lambda v=view: self._inject_text_to_web_view(v, final_prompt))
            if self._is_claude_web_view(view) and upload_paths:
                QTimer.singleShot(
                    delay + 260,
                    lambda v=view, paths=list(upload_paths), click=auto_send: start_claude_drop_first(
                        v,
                        dock,
                        paths,
                        click,
                    ),
                )
            elif image_items:
                if self._is_grok_web_view(view) or self._is_perplexity_web_view(view):
                    QTimer.singleShot(
                        delay + 220,
                        lambda v=view, imgs=image_items, click=auto_send: self._activate_web_composer(
                            v,
                            callback=lambda vv=v, ii=imgs, cc=click: self._inject_images_to_web_view(
                                vv,
                                ii,
                                callback=lambda vvv=vv, ddd=dock, ccc=cc: after_attachment_handoff(vvv, ddd, ccc),
                            ),
                        ),
                    )
                else:
                    QTimer.singleShot(
                        delay + 220,
                        lambda v=view, imgs=image_items, click=auto_send: self._inject_images_to_web_view(
                            v,
                            imgs,
                            callback=lambda vv=v, ddd=dock, ccc=click: after_attachment_handoff(vv, ddd, ccc),
                        ),
                    )
            elif auto_send:
                QTimer.singleShot(delay + 850, lambda v=view: self._wait_then_click_web_send_button(v, timeout_ms=5000))
        if clear_after_send and not upload_paths and not image_items and has_pending_attachments:
            dock.clear_attachments()
        dock.clear_prompt()

    def _collect_direct_image_attachments(self, direct_attachments: list) -> list[dict]:
        images = []
        for item in direct_attachments or []:
            items = item if isinstance(item, list) else [item]
            for att in items:
                if isinstance(att, dict) and att.get('kind') == 'image' and att.get('b64'):
                    images.append(att)
        return images

    def _collect_web_upload_paths(self, dock: ExternalPromptDock) -> list[str]:
        paths = []
        allowed = set(ATTACHMENT_IMAGE_EXTS) | {'.pdf', '.docx'}
        for path in dock.attachment_paths():
            ext = os.path.splitext(str(path))[1].lower()
            if ext in allowed and os.path.exists(str(path)):
                paths.append(str(path))
        return paths

    @staticmethod
    def _is_claude_web_view(view: QWebEngineView) -> bool:
        try:
            host = view.url().host().lower()
        except Exception:
            host = ''
        return host.endswith('claude.ai')

    @staticmethod
    def _is_grok_web_view(view: QWebEngineView) -> bool:
        try:
            host = view.url().host().lower()
        except Exception:
            host = ''
        return host.endswith('grok.com')

    @staticmethod
    def _is_perplexity_web_view(view: QWebEngineView) -> bool:
        try:
            host = view.url().host().lower()
        except Exception:
            host = ''
        return host.endswith('perplexity.ai')

    @staticmethod
    def _web_auto_send_after_inject_enabled() -> bool:
        return bool(load_settings_store().get('globals', {}).get('web_auto_send_after_inject', False))

    @staticmethod
    def _webfetch_context_use_embedding_enabled() -> bool:
        return bool(load_settings_store().get('globals', {}).get('webfetch_context_use_embedding', True))

    @staticmethod
    def _clear_attachments_after_send_enabled() -> bool:
        return bool(load_settings_store().get('globals', {}).get('clear_attachments_after_send', True))

    @staticmethod
    def _generated_output_context_use_embedding_enabled() -> bool:
        return bool(load_settings_store().get('globals', {}).get('generated_output_context_use_embedding', False))

    def _send_web_view_mouse_click(self, view: QWebEngineView, x: float, y: float):
        try:
            view_point = QPoint(int(x), int(y))
            target = view.childAt(view_point) or view.focusProxy() or view
            if target is not view:
                target_point = target.mapFrom(view, view_point)
            else:
                target_point = view_point
            local = QPointF(float(target_point.x()), float(target_point.y()))
            global_point = target.mapToGlobal(target_point)
            global_pos = QPointF(float(global_point.x()), float(global_point.y()))
            press = PyQt6.QtGui.QMouseEvent(
                QEvent.Type.MouseButtonPress,
                local,
                global_pos,
                Qt.MouseButton.LeftButton,
                Qt.MouseButton.LeftButton,
                Qt.KeyboardModifier.NoModifier,
            )
            release = PyQt6.QtGui.QMouseEvent(
                QEvent.Type.MouseButtonRelease,
                local,
                global_pos,
                Qt.MouseButton.LeftButton,
                Qt.MouseButton.NoButton,
                Qt.KeyboardModifier.NoModifier,
            )
            view.setFocus(Qt.FocusReason.MouseFocusReason)
            target.setFocus(Qt.FocusReason.MouseFocusReason)
            QApplication.sendEvent(target, press)
            QApplication.sendEvent(target, release)
        except Exception:
            pass

    def _send_web_view_cmd_return(self, view: QWebEngineView):
        log_broccoli_claude('sending Claude submit shortcut sequence')
        try:
            target = QApplication.focusWidget()
            if target is None or (target is not view and not view.isAncestorOf(target)):
                target = view.focusProxy() or view.childAt(QPoint(max(1, view.width() // 2), max(1, view.height() // 2))) or view
            log_broccoli_claude(f'shortcut target={type(target).__name__}')
            view.setFocus(Qt.FocusReason.ShortcutFocusReason)
            target.setFocus(Qt.FocusReason.ShortcutFocusReason)

            def send_qt_key(key, modifiers, label):
                log_broccoli_claude(f'Qt key event: {label}')
                press = PyQt6.QtGui.QKeyEvent(
                    QEvent.Type.KeyPress,
                    key,
                    modifiers,
                    '\r',
                )
                release = PyQt6.QtGui.QKeyEvent(
                    QEvent.Type.KeyRelease,
                    key,
                    modifiers,
                    '\r',
                )
                QApplication.sendEvent(target, press)
                QApplication.sendEvent(target, release)

            # On macOS Qt maps Command to ControlModifier; keep MetaModifier as a fallback for embedded Chromium.
            for qt_key_name, qt_key in (('Return', Qt.Key.Key_Return), ('Enter', Qt.Key.Key_Enter)):
                send_qt_key(qt_key, Qt.KeyboardModifier.ControlModifier, f'Command+{qt_key_name}')
                send_qt_key(qt_key, Qt.KeyboardModifier.MetaModifier, f'Meta+{qt_key_name}')

            log_broccoli_claude('scheduling pyautogui submit fallback sequence')
            QTimer.singleShot(180, lambda: (
                log_broccoli_claude('pyautogui command+enter fallback fired'),
                pyautogui.hotkey('command', 'enter')
            ))
            QTimer.singleShot(360, lambda: (
                log_broccoli_claude('pyautogui ctrl+enter fallback fired'),
                pyautogui.hotkey('ctrl', 'enter')
            ))
            QTimer.singleShot(540, lambda: (
                log_broccoli_claude('pyautogui command+return fallback fired'),
                pyautogui.hotkey('command', 'return')
            ))
        except Exception as exc:
            log_broccoli_claude(f'shortcut send failed: {exc}')
            try:
                pyautogui.hotkey('command', 'enter')
                pyautogui.hotkey('ctrl', 'enter')
            except Exception:
                pass

    def _activate_web_composer(self, view: QWebEngineView, callback=None):
        js = """
        (function() {
            const visible = (node) => {
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                const style = window.getComputedStyle(node);
                return rect.width > 8 && rect.height > 8 && style.display !== 'none' && style.visibility !== 'hidden';
            };
            const input = Array.from(document.querySelectorAll('div[contenteditable="true"], textarea'))
                .filter(visible)
                .sort((a, b) => b.getBoundingClientRect().bottom - a.getBoundingClientRect().bottom)[0];
            if (!input) return null;
            const rect = input.getBoundingClientRect();
            return {
                x: Math.max(8, Math.min(window.innerWidth - 8, rect.left + Math.min(80, Math.max(12, rect.width * 0.18)))),
                y: Math.max(8, Math.min(window.innerHeight - 8, rect.top + Math.min(24, Math.max(10, rect.height * 0.5))))
            };
        })()
        """

        def after(result):
            if isinstance(result, dict) and result.get('x') is not None and result.get('y') is not None:
                self._send_web_view_mouse_click(view, float(result.get('x')), float(result.get('y')))
            if callback:
                QTimer.singleShot(140, callback)

        try:
            view.page().runJavaScript(js, after)
        except Exception:
            if callback:
                QTimer.singleShot(0, callback)

    def _activate_claude_composer(self, view: QWebEngineView, callback=None):
        self._activate_web_composer(view, callback=callback)

    def _click_claude_send_button_if_present(self, view: QWebEngineView):
        js = """
        (function() {
            const visible = (node) => {
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                const style = window.getComputedStyle(node);
                return rect.width > 8
                    && rect.height > 8
                    && style.display !== 'none'
                    && style.visibility !== 'hidden'
                    && Number(style.opacity || 1) > 0.01;
            };
            const disabled = (node) => {
                const className = String(node.className || '');
                return node.disabled
                    || node.getAttribute('aria-disabled') === 'true'
                    || node.getAttribute('disabled') !== null
                    || /(?:^|\\s)(disabled|is-disabled)(?:\\s|$)/i.test(className);
            };
            const btn = Array.from(document.querySelectorAll('button')).find(node => {
                return visible(node)
                    && !disabled(node)
                    && String(node.getAttribute('aria-label') || '').trim().toLowerCase() === 'send message';
            });
            if (!btn) return null;
            const rect = btn.getBoundingClientRect();
            btn.focus && btn.focus();
            btn.click && btn.click();
            btn.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, composed: true }));
            btn.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, composed: true }));
            btn.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true, composed: true }));
            return {
                x: Math.max(8, Math.min(window.innerWidth - 8, rect.left + rect.width / 2)),
                y: Math.max(8, Math.min(window.innerHeight - 8, rect.top + rect.height / 2))
            };
        })()
        """

        def after(result):
            if isinstance(result, dict) and result.get('x') is not None and result.get('y') is not None:
                self._send_web_view_mouse_click(view, float(result.get('x')), float(result.get('y')))

        try:
            view.page().runJavaScript(js, after)
        except Exception:
            pass

    def _submit_claude_with_shortcut(self, view: QWebEngineView):
        log_broccoli_claude('submit via shortcut requested')
        self._activate_claude_composer(
            view,
            callback=lambda v=view: (
                QTimer.singleShot(120, lambda: self._send_web_view_cmd_return(v)),
                QTimer.singleShot(900, lambda: self._click_claude_send_button_if_present(v)),
            ),
        )

    @staticmethod
    def _inject_text_to_web_view(view: QWebEngineView, text: str):
        escaped = str(text or '').replace('\\', '\\\\').replace('`', '\\`')
        js = f"""
        (function() {{
            const t = `{escaped}`;
            const ce = document.querySelector('div[contenteditable="true"]');
            if (ce) {{
                ce.focus();
                document.execCommand('selectAll', false, null);
                document.execCommand('insertText', false, t);
                return 'ce';
            }}
            const ta = document.querySelector('textarea');
            if (ta) {{
                const setter = Object.getOwnPropertyDescriptor(
                    HTMLTextAreaElement.prototype, 'value').set;
                setter.call(ta, t);
                ta.dispatchEvent(new Event('input', {{bubbles: true}}));
                ta.focus();
                return 'ta';
            }}
            return null;
        }})()
        """
        view.page().runJavaScript(js)

    def _prepare_web_upload_file_payloads(self, paths: list[str], max_bytes: int = 25 * 1024 * 1024) -> list[dict]:
        payloads = []
        for path in paths or []:
            path = str(path)
            if not path or not os.path.exists(path) or not os.path.isfile(path):
                continue
            try:
                if os.path.getsize(path) > max_bytes:
                    continue
                with open(path, 'rb') as fh:
                    encoded = base64.b64encode(fh.read()).decode('ascii')
            except Exception:
                continue
            payloads.append({
                'name': os.path.basename(path),
                'mime': mimetypes.guess_type(path)[0] or 'application/octet-stream',
                'b64': encoded,
            })
        return payloads

    def _wait_for_web_attachment_presence(self,
                                          view: QWebEngineView,
                                          expected_names: list[str] | None = None,
                                          timeout_ms: int = 6000,
                                          interval_ms: int = 350,
                                          callback=None):
        names = [
            os.path.basename(str(name)).lower()
            for name in (expected_names or [])
            if str(name).strip()
        ]
        started_at = time.monotonic()
        names_json = json.dumps(names, ensure_ascii=False)
        probe_js = """
        (function() {
            const names = __EXPECTED_NAMES__;
            const visible = (node) => {
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                const style = window.getComputedStyle(node);
                return rect.width > 8 && rect.height > 8 && style.display !== 'none' && style.visibility !== 'hidden';
            };
            const textOf = (node) => [
                node.innerText,
                node.getAttribute && node.getAttribute('aria-label'),
                node.getAttribute && node.getAttribute('title'),
                node.getAttribute && node.getAttribute('data-testid'),
                node.getAttribute && node.getAttribute('alt'),
                node.id,
                node.className
            ].filter(Boolean).join(' ').toLowerCase();
            const input = document.querySelector('div[contenteditable="true"], textarea');
            const composerCandidates = [
                input && input.closest('form'),
                input && input.closest('[data-testid*="composer"]'),
                input && input.closest('[class*="composer"]'),
                input && input.closest('[class*="prompt"]'),
                input && input.parentElement && input.parentElement.parentElement,
                input && input.parentElement
            ].filter(node => node && visible(node));
            const area = (node) => {
                const rect = node.getBoundingClientRect();
                return rect.width * rect.height;
            };
            const composer = composerCandidates
                .sort((a, b) => area(b) - area(a))
                .find(node => {
                    const rect = node.getBoundingClientRect();
                    return rect.width >= 180 && rect.height >= 36;
                }) || null;
            const composerRect = composer ? composer.getBoundingClientRect() : null;
            const inAttachmentArea = (node) => {
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                if (!composerRect) {
                    return rect.top > window.innerHeight * 0.32;
                }
                return rect.bottom >= composerRect.top - 120
                    && rect.top <= composerRect.bottom + 80
                    && rect.right >= composerRect.left - 40
                    && rect.left <= composerRect.right + 40;
            };
            const scopedVisible = Array.from(document.querySelectorAll('body *'))
                .filter(node => visible(node) && inAttachmentArea(node));
            if (names.length) {
                const named = scopedVisible.find(node => {
                    const text = textOf(node);
                    return names.some(name => name && text.includes(name));
                });
                if (named) return { present: true, reason: 'filename' };
            }
            const attachmentLike = scopedVisible.find(node => {
                const tag = String(node.tagName || '').toLowerCase();
                const text = textOf(node);
                const isControl = tag === 'button'
                    || tag === 'label'
                    || node.getAttribute('role') === 'button'
                    || /(remove|delete|trash|close|clear|attach|upload|削除|消去|删除|移除|上传|アップロード)/.test(text);
                if (!isControl && /(attachment|attached|thumbnail|preview|image attached|file attached|添付済|附件已添加|已添加附件)/.test(text)) return true;
                if (['img', 'canvas', 'figure', 'picture'].includes(tag) || node.getAttribute('role') === 'img') {
                    const rect = node.getBoundingClientRect();
                    return rect.width >= 24 && rect.height >= 24;
                }
                if (!isControl) {
                    const rect = node.getBoundingClientRect();
                    const style = window.getComputedStyle(node);
                    const hasBgImage = style.backgroundImage && style.backgroundImage !== 'none' && /url\\(/.test(style.backgroundImage);
                    if (hasBgImage && rect.width >= 24 && rect.height >= 24) return true;
                    if (/(attachment|attached|thumbnail|preview|image|file|upload)/.test(text)
                        && rect.width >= 36
                        && rect.height >= 24
                        && node.querySelector('img, canvas, figure, picture, [role="img"]')) {
                        return true;
                    }
                }
                return false;
            });
            if (attachmentLike) return { present: true, reason: 'attachment-node' };
            const busy = scopedVisible.find(node => {
                const text = textOf(node);
                return node.getAttribute('role') === 'progressbar'
                    || node.getAttribute('aria-busy') === 'true'
                    || /(uploading|upload in progress|attaching|processing file|processing image|正在上传|上传中|処理中|アップロード中)/.test(text);
            });
            if (busy) return { present: true, reason: 'uploading' };
            return { present: false, reason: 'not-found' };
        })()
        """.replace('__EXPECTED_NAMES__', names_json)

        def probe():
            if time.monotonic() - started_at > max(1, timeout_ms) / 1000:
                if callback:
                    callback(False)
                return
            try:
                page = view.page()
            except Exception:
                if callback:
                    callback(False)
                return

            def after(result):
                result = result if isinstance(result, dict) else {}
                if bool(result.get('present')):
                    if callback:
                        callback(True)
                    return
                QTimer.singleShot(max(100, int(interval_ms)), probe)

            try:
                page.runJavaScript(probe_js, after)
            except Exception:
                QTimer.singleShot(max(100, int(interval_ms)), probe)

        probe()

    def _inject_files_to_claude_by_drop(self, view: QWebEngineView, paths: list[str], fallback_callback=None, callback=None):
        payloads = self._prepare_web_upload_file_payloads(paths)
        if not payloads:
            if fallback_callback:
                QTimer.singleShot(0, fallback_callback)
            elif callback:
                QTimer.singleShot(0, callback)
            return
        payload_json = json.dumps(payloads, ensure_ascii=False)
        js = f"""
        (async function() {{
            const payloads = {payload_json};
            const visible = (node) => {{
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                const style = window.getComputedStyle(node);
                return rect.width > 0 && rect.height > 0 && style.display !== 'none' && style.visibility !== 'hidden';
            }};
            const b64ToBytes = (b64) => {{
                const bin = atob(b64);
                const bytes = new Uint8Array(bin.length);
                for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
                return bytes;
            }};
            const files = payloads.map(item => new File(
                [b64ToBytes(item.b64)],
                item.name || 'attachment',
                {{ type: item.mime || 'application/octet-stream', lastModified: Date.now() }}
            ));
            if (!files.length) return 'no-files';
            const target =
                Array.from(document.querySelectorAll('[contenteditable="true"], textarea'))
                    .filter(visible)
                    .sort((a, b) => b.getBoundingClientRect().bottom - a.getBoundingClientRect().bottom)[0]
                || Array.from(document.querySelectorAll('[data-testid*="composer"], form, main'))
                    .filter(visible)
                    .sort((a, b) => b.getBoundingClientRect().bottom - a.getBoundingClientRect().bottom)[0]
                || document.body;
            if (!target) return 'no-target';
            target.focus && target.focus();
            target.click && target.click();
            const makeDataTransfer = () => {{
                const dt = new DataTransfer();
                files.forEach(file => dt.items.add(file));
                return dt;
            }};
            const dragDt = makeDataTransfer();
            for (const type of ['dragenter', 'dragover', 'drop']) {{
                target.dispatchEvent(new DragEvent(type, {{
                    bubbles: true,
                    cancelable: true,
                    composed: true,
                    dataTransfer: dragDt
                }}));
            }}
            const pasteDt = makeDataTransfer();
            try {{
                target.dispatchEvent(new ClipboardEvent('paste', {{
                    bubbles: true,
                    cancelable: true,
                    composed: true,
                    clipboardData: pasteDt
                }}));
            }} catch (err) {{
                const ev = new Event('paste', {{ bubbles: true, cancelable: true, composed: true }});
                Object.defineProperty(ev, 'clipboardData', {{ value: pasteDt }});
                target.dispatchEvent(ev);
            }}
            return 'dropped';
        }})()
        """

        def after(result):
            if str(result or '') == 'dropped':
                if callback:
                    QTimer.singleShot(0, callback)
            elif fallback_callback:
                QTimer.singleShot(0, fallback_callback)
            elif callback:
                QTimer.singleShot(0, callback)

        try:
            view.page().runJavaScript(js, after)
        except Exception:
            if fallback_callback:
                QTimer.singleShot(0, fallback_callback)
            elif callback:
                QTimer.singleShot(0, callback)

    def _submit_grok_with_button(self, view: QWebEngineView):
        js = """
        (function() {
            const visible = (node) => {
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                const style = window.getComputedStyle(node);
                return rect.width > 8
                    && rect.height > 8
                    && style.display !== 'none'
                    && style.visibility !== 'hidden'
                    && Number(style.opacity || 1) > 0.01;
            };
            const disabled = (node) => {
                const className = String(node.className || '');
                return node.disabled
                    || node.getAttribute('aria-disabled') === 'true'
                    || node.getAttribute('disabled') !== null
                    || /(?:^|\\s)(disabled|is-disabled)(?:\\s|$)/i.test(className);
            };
            const buttons = Array.from(document.querySelectorAll('button'));
            const btn = buttons.find(node => {
                if (!visible(node) || disabled(node)) return false;
                const label = String(node.getAttribute('aria-label') || '').trim().toLowerCase();
                const testid = String(node.getAttribute('data-testid') || '').trim().toLowerCase();
                const type = String(node.getAttribute('type') || '').trim().toLowerCase();
                return label === 'submit' && (testid === 'chat-submit' || type === 'submit');
            });
            if (!btn) return null;
            const rect = btn.getBoundingClientRect();
            btn.focus && btn.focus();
            btn.click && btn.click();
            btn.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, composed: true }));
            btn.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, composed: true }));
            btn.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true, composed: true }));
            return {
                x: Math.max(8, Math.min(window.innerWidth - 8, rect.left + rect.width / 2)),
                y: Math.max(8, Math.min(window.innerHeight - 8, rect.top + rect.height / 2))
            };
        })()
        """

        def after(result):
            if isinstance(result, dict) and result.get('x') is not None and result.get('y') is not None:
                self._send_web_view_mouse_click(view, float(result.get('x')), float(result.get('y')))

        try:
            view.page().runJavaScript(js, after)
        except Exception:
            pass

