    def _click_web_view_send_button(self, view: QWebEngineView):
        claude = self._is_claude_web_view(view)
        if claude:
            self._submit_claude_with_shortcut(view)
            return
        if self._is_grok_web_view(view):
            self._submit_grok_with_button(view)
            return
        if self._is_perplexity_web_view(view):
            self._submit_perplexity_with_button(view)
            return
        js = """
        (function() {
            const visible = (node) => {
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                const style = window.getComputedStyle(node);
                return rect.width > 8 && rect.height > 8 && style.display !== 'none' && style.visibility !== 'hidden';
            };
            const disabled = (node) => {
                const className = String(node.className || '');
                return node.disabled
                    || node.getAttribute('aria-disabled') === 'true'
                    || node.getAttribute('disabled') !== null
                    || /(?:^|\s)(disabled|is-disabled)(?:\s|$)/i.test(className);
            };
            const clickButton = (btn) => {
                btn.focus && btn.focus();
                btn.click();
                btn.dispatchEvent(new MouseEvent('mousedown', {bubbles: true, cancelable: true, composed: true}));
                btn.dispatchEvent(new MouseEvent('mouseup', {bubbles: true, cancelable: true, composed: true}));
                btn.dispatchEvent(new MouseEvent('click', {bubbles: true, cancelable: true, composed: true}));
            };
            const buttons = Array.from(document.querySelectorAll('button, [role="button"]'));
            const candidates = buttons.filter(btn => {
                if (!visible(btn) || disabled(btn)) return false;
                const text = [
                    btn.innerText,
                    btn.getAttribute('aria-label'),
                    btn.getAttribute('title'),
                    btn.getAttribute('data-testid')
                ].filter(Boolean).join(' ').toLowerCase();
                if (/(stop|cancel|停止|中止|キャンセル|voice|mic|audio)/.test(text)) return false;
                return /(send|submit|发送|送信|送出)/.test(text);
            });
            if (candidates.length) {
                clickButton(candidates[candidates.length - 1]);
                return 'button';
            }
            const input = document.querySelector('div[contenteditable="true"], textarea');
            if (input) {
                input.focus();
                const opts = {
                    key: 'Enter',
                    code: 'Enter',
                    bubbles: true,
                    cancelable: true,
                    composed: true,
                    metaKey: false,
                    ctrlKey: false,
                    shiftKey: false,
                    altKey: false
                };
                input.dispatchEvent(new KeyboardEvent('keydown', opts));
                input.dispatchEvent(new KeyboardEvent('keypress', opts));
                input.dispatchEvent(new KeyboardEvent('keyup', opts));
                return 'enter';
            }
            return 'not-found';
        })()
        """
        try:
            view.page().runJavaScript(js)
        except Exception:
            pass

    def _wait_then_click_web_send_button(self,
                                         view: QWebEngineView,
                                         timeout_ms: int = 15000,
                                         interval_ms: int = 450,
        stable_hits: int = 2):
        claude = self._is_claude_web_view(view)
        grok = self._is_grok_web_view(view)
        perplexity = self._is_perplexity_web_view(view)
        started_at = time.monotonic()
        state = {'ready_hits': 0, 'last_reason': '', 'next_debug_at': 0.0}
        probe_js = """
        (function() {
            const isClaude = __IS_CLAUDE__;
            const isGrok = __IS_GROK__;
            const isPerplexity = __IS_PERPLEXITY__;
            const visible = (node) => {
                if (!node) return false;
                const rect = node.getBoundingClientRect();
                const style = window.getComputedStyle(node);
                return rect.width > 8 && rect.height > 8 && style.display !== 'none' && style.visibility !== 'hidden';
            };
            const disabled = (node) => {
                const className = String(node.className || '');
                return node.disabled
                    || node.getAttribute('aria-disabled') === 'true'
                    || node.getAttribute('disabled') !== null
                    || /(?:^|\s)(disabled|is-disabled)(?:\s|$)/i.test(className);
            };
            const visibleText = (node) => {
                if (!node || !visible(node)) return '';
                return [
                    node.innerText,
                    node.getAttribute('aria-label'),
                    node.getAttribute('title'),
                    node.getAttribute('data-testid'),
                    node.id
                ].filter(Boolean).join(' ').toLowerCase();
            };
            const buttons = Array.from(document.querySelectorAll('button, [role="button"]'));
            if (isClaude) {
                const candidates = buttons.filter(btn => {
                    if (!visible(btn) || disabled(btn)) return false;
                    return String(btn.getAttribute('aria-label') || '').trim().toLowerCase() === 'send message';
                });
                if (candidates.length) {
                    return { ready: true, reason: 'claude-send-message-button-ready', count: candidates.length };
                }
                const labels = buttons
                    .filter(visible)
                    .map(btn => String(btn.getAttribute('aria-label') || btn.innerText || '').trim())
                    .filter(Boolean)
                    .slice(-8)
                    .join(' | ');
                return {
                    ready: false,
                    reason: labels ? 'claude-no-send-message-button: ' + labels : 'claude-no-visible-buttons',
                    count: 0
                };
            }
            if (isGrok) {
                const candidates = buttons.filter(btn => {
                    if (!visible(btn) || disabled(btn)) return false;
                    const label = String(btn.getAttribute('aria-label') || '').trim().toLowerCase();
                    const testid = String(btn.getAttribute('data-testid') || '').trim().toLowerCase();
                    const type = String(btn.getAttribute('type') || '').trim().toLowerCase();
                    return label === 'submit' && (testid === 'chat-submit' || type === 'submit');
                });
                if (candidates.length) {
                    return { ready: true, reason: 'grok-chat-submit-button-ready', count: candidates.length };
                }
                const labels = buttons
                    .filter(visible)
                    .map(btn => String(btn.getAttribute('aria-label') || btn.getAttribute('data-testid') || btn.innerText || '').trim())
                    .filter(Boolean)
                    .slice(-8)
                    .join(' | ');
                return {
                    ready: false,
                    reason: labels ? 'grok-no-chat-submit-button: ' + labels : 'grok-no-visible-buttons',
                    count: 0
                };
            }
            if (isPerplexity) {
                const candidates = buttons.filter(btn => {
                    if (!visible(btn) || disabled(btn)) return false;
                    const label = String(btn.getAttribute('aria-label') || '').trim().toLowerCase();
                    const type = String(btn.getAttribute('type') || '').trim().toLowerCase();
                    return label === 'submit' && type === 'button';
                });
                if (candidates.length) {
                    return { ready: true, reason: 'perplexity-submit-button-ready', count: candidates.length };
                }
                const labels = buttons
                    .filter(visible)
                    .map(btn => String(btn.getAttribute('aria-label') || btn.innerText || '').trim())
                    .filter(Boolean)
                    .slice(-8)
                    .join(' | ');
                return {
                    ready: false,
                    reason: labels ? 'perplexity-no-submit-button: ' + labels : 'perplexity-no-visible-buttons',
                    count: 0
                };
            }
            const busyNode = Array.from(document.querySelectorAll('[role="progressbar"], [aria-busy="true"]'))
                .find(node => visible(node) && node.getAttribute('aria-busy') !== 'false');
            if (busyNode) {
                return { ready: false, reason: 'upload-busy' };
            }
            const statusNodes = Array.from(document.querySelectorAll('[role="status"], [aria-live], [data-testid], [class]'))
                .slice(-500);
            const busyTextNode = statusNodes.find(node => {
                const text = visibleText(node);
                return /(uploading|upload in progress|attaching|processing file|processing image|正在上传|上传中|処理中|アップロード中)/.test(text);
            });
            if (busyTextNode) {
                return { ready: false, reason: 'upload-status' };
            }
            const candidates = buttons.filter(btn => {
                if (!visible(btn) || disabled(btn)) return false;
                const text = visibleText(btn);
                if (/(stop|cancel|停止|中止|キャンセル|voice|mic|audio)/.test(text)) return false;
                return /(send|submit|发送|送信|送出)/.test(text);
            });
            if (candidates.length) {
                return { ready: true, reason: 'button-ready' };
            }
            const input = document.querySelector('div[contenteditable="true"], textarea');
            if (input && visible(input)) {
                return { ready: true, reason: 'keyboard-fallback' };
            }
            return { ready: false, reason: 'send-not-ready' };
        })()
        """.replace('__IS_CLAUDE__', 'true' if claude else 'false').replace(
            '__IS_GROK__',
            'true' if grok else 'false',
        ).replace(
            '__IS_PERPLEXITY__',
            'true' if perplexity else 'false',
        )

        def probe():
            if time.monotonic() - started_at > max(1, timeout_ms) / 1000:
                if claude:
                    log_broccoli_claude(f'auto send skipped after timeout; last_reason={state.get("last_reason", "")}')
                show_broccoli_message(
                    self,
                    'Auto send skipped',
                    'The web page did not finish enabling Send after the attachment was added. The prompt and attachment were left in the page.',
                )
                return
            try:
                page = view.page()
            except Exception:
                return

            def after(result):
                result = result if isinstance(result, dict) else {}
                if bool(result.get('ready')):
                    state['ready_hits'] += 1
                    required_hits = max(2 if (claude or grok or perplexity) else 1, int(stable_hits))
                    if claude:
                        log_broccoli_claude(
                            f'send readiness hit {state["ready_hits"]}/{required_hits}: {result.get("reason", "")}'
                        )
                    if state['ready_hits'] >= required_hits:
                        self._click_web_view_send_button(view)
                        return
                else:
                    if claude:
                        reason = str(result.get('reason', '') or '')
                        now = time.monotonic()
                        if state['ready_hits']:
                            log_broccoli_claude(f'send readiness reset: {reason}')
                        if reason != state.get('last_reason') or now >= float(state.get('next_debug_at', 0.0) or 0.0):
                            log_broccoli_claude(f'send readiness waiting: {reason}')
                            state['last_reason'] = reason
                            state['next_debug_at'] = now + 2.0
                    state['ready_hits'] = 0
                QTimer.singleShot(max(100, int(interval_ms)), probe)

            try:
                page.runJavaScript(probe_js, after)
            except Exception:
                QTimer.singleShot(max(100, int(interval_ms)), probe)

        probe()

    def _inject_images_to_web_view(self, view: QWebEngineView, image_items: list[dict], callback=None):
        items = [item for item in image_items if isinstance(item, dict) and item.get('b64')]
        if not items:
            if callback:
                QTimer.singleShot(0, callback)
            return
        focus_js = """
        (function() {
            const el = document.querySelector('div[contenteditable="true"]')
                    || document.querySelector('textarea');
            if (el) { el.focus(); return true; }
            return false;
        })()
        """

        def paste_next(idx: int):
            if idx >= len(items):
                if callback:
                    QTimer.singleShot(650, callback)
                return
            item = items[idx]
            try:
                raw = base64.b64decode(item.get('b64', ''))
                qimg = QImage.fromData(raw)
            except Exception:
                QTimer.singleShot(50, lambda: paste_next(idx + 1))
                return
            if qimg.isNull():
                QTimer.singleShot(50, lambda: paste_next(idx + 1))
                return
            QGuiApplication.clipboard().setImage(qimg)

            def do_paste(focused):
                if focused:
                    view.page().triggerAction(QWebEnginePage.WebAction.Paste)
                QTimer.singleShot(350, lambda: paste_next(idx + 1))

            view.page().runJavaScript(focus_js, do_paste)

        paste_next(0)

    def _on_tab_changed(self, index):
        """Tab 切换时更新 DrawingLayer 可见性和 qw3 背景色。"""
        self._install_selection_context_menus()
        is_assistant = (index == 1)
        is_terminal = (index == 3)
        is_external_prompt_tab = index in (0, 2)
        self.pill_nav.set_theme('dark' if (index == 3 or is_dark_theme(app)) else 'light')
        self.settings_panel.set_force_dark(index == 3)
        self.outputs_panel.set_force_dark(index == 3)
        if not is_assistant:
            self._history_trigger_btn.hide()
            self._links_trigger_btn.hide()
            self._branch_trigger_btn.hide()
            if hasattr(self, 'webfetch_panel') and not is_external_prompt_tab:
                self.webfetch_panel.hide()
            if self._history_panel_visible:
                self.hide_history_panel()
            if self._links_panel_visible:
                self.hide_links_panel()
            if self._branch_panel_visible:
                self.hide_branch_panel()
            if self._share_panel_visible:
                self.hide_share_panel()
            self._text1_popup.hide()
        else:
            self._branch_trigger_btn.show()
            self._branch_trigger_btn.raise_()
            self._raise_webfetch_panel_if_visible()
            self._history_trigger_btn.show()
            self._history_trigger_btn.raise_()
            self._links_trigger_btn.show()
            self._links_trigger_btn.raise_()
            if getattr(self, '_webfetch_records', None) and not getattr(self, '_webfetch_panel_dismissed', False):
                self._show_webfetch_panel()
            self._refresh_text1_popup_visibility()
            self._refresh_branch_state_from_current_conversation()
        if not is_terminal:
            self._hide_terminal_side_triggers()
            if self._terminal_history_panel_visible:
                self.hide_terminal_history_panel()
            if self._terminal_favorites_panel_visible:
                self.hide_terminal_favorites_panel()
        else:
            self._refresh_terminal_history_panel()
            self._refresh_terminal_favorites_panel()
            self._show_terminal_side_triggers()
        self._outputs_trigger_btn.show()
        self._outputs_trigger_btn.raise_()
        self._refresh_outputs_panel()
        if is_external_prompt_tab:
            self._update_external_prompt_trigger_geometry()
            self._update_web_conversation_sync_button_geometry()
            panel, _dock = self._external_prompt_panel_for_index(index)
            if panel is not None and panel.is_prompt_dock_visible() and getattr(self, '_webfetch_records', None) and not getattr(self, '_webfetch_panel_dismissed', False):
                self._show_webfetch_panel()
            elif hasattr(self, 'webfetch_panel'):
                self.webfetch_panel.hide()
        elif hasattr(self, '_external_prompt_trigger_btn'):
            self._external_prompt_trigger_btn.hide()
            if hasattr(self, 'web_conversation_sync_button'):
                self.web_conversation_sync_button.hide()
        if not self._settings_panel_visible:
            self._settings_trigger_btn.show()
            self._settings_trigger_btn.raise_()
        # self.btn0_2.setVisible(is_assistant)

        if not is_assistant:
            self.drawing_layer.setVisible(False)
        else:
            is_expanded = (self.i % 2 == 1)
            trans = getattr(self, 'trans', 0)
            is_html_view = (trans % 2 == 0)
            self.drawing_layer.setVisible(is_expanded and is_html_view)

        if index == 0:   # AI Web
            self.ai_web_panel.active_view().page().runJavaScript(self._BG_JS, self._apply_web_bg)
        elif index == 1:  # Assistant
            self._set_qw3_bg('#2D2D2D' if is_dark_theme(app) else '#FFFFFF')
        elif index == 2:  # Localhost
            self.localhost_panel.active_view().page().runJavaScript(self._BG_JS, self._apply_web_bg)
        elif index == 3:  # Terminal
            self._set_qw3_bg('#2D2D2D', border='#2D2D2D')

    # JS 取背景色：按优先级检查多个候选元素，跳过透明色，回退白色
    _BG_JS = (
        "(function(){"
        "  function isOpaque(c){"
        "    if(!c||c==='transparent') return false;"
        "    if(c.startsWith('rgba')){"
        "      var a=parseFloat(c.split(',')[3]);"
        "      return !isNaN(a)&&a>0.1;"
        "    }"
        "    return c!=='rgba(0, 0, 0, 0)';"
        "  }"
        "  var candidates=["
        "    document.documentElement,"
        "    document.body,"
        "    document.querySelector('main,#root,#app,[data-theme],#__next,.app-container')"
        "  ];"
        "  for(var el of candidates){"
        "    if(!el) continue;"
        "    var c=getComputedStyle(el).backgroundColor;"
        "    if(isOpaque(c)) return c;"
        "  }"
        "  return '#FFFFFF';"
        "})()"
    )

    def _on_web_loaded(self, ok, panel, tab_index):
        """活跃 view 加载完成后，若该 tab 正在显示则更新背景色。"""
        if ok and self.stacked_widget.currentIndex() == tab_index:
            panel.active_view().page().runJavaScript(self._BG_JS, self._apply_web_bg)

    def _apply_web_bg(self, color_str):
        """将 JS 返回的颜色应用到 qw3；透明/空时回退白色。"""
        if not color_str or color_str.strip() in ('rgba(0, 0, 0, 0)', 'transparent', ''):
            color_str = '#FFFFFF'
        self._set_qw3_bg(color_str)

    def _set_qw3_bg(self, bg_css, border='#ECECEC'):
        """动态覆盖 qw3 的背景色（保留其他样式属性）。"""
        if border == '#ECECEC' and is_dark_theme(app):
            border = '#2D2D2D'
        self.qw3.setStyleSheet(
            f"QWidget#Main-1 {{ border: 1px solid {border};"
            f" background: {bg_css}; border-radius: 26px; }}"
        )

    def _apply_assistant_surfaces_theme(self, dark_mode: bool):
        self.real1.setStyleSheet(_assistant_readonly_text_stylesheet(dark_mode))
        self.real2.setStyleSheet(_assistant_webview_stylesheet(dark_mode))
        try:
            self.text1._apply_theme()
        except Exception:
            pass
        try:
            self._text1_popup._apply_theme()
        except Exception:
            pass
        try:
            self._bar_transfer_btn._apply_theme()
            self.btn_sub1._apply_theme()
        except Exception:
            pass

    def _refresh_assistant_render_for_theme(self):
        if self.trans % 2 == 1:
            return
        history_messages = get_current_chat_history_messages()
        all_text = read_file_contents(BasePath + 'output.txt', '')
        if history_messages or all_text.strip():
            self.render_final_output(all_text, history_messages=history_messages or None)
        else:
            self.show_welcome_state()

    def _refresh_current_tab_background(self):
        current_index = self.stacked_widget.currentIndex()
        if current_index == 0:
            try:
                self.ai_web_panel.active_view().page().runJavaScript(self._BG_JS, self._apply_web_bg)
            except Exception:
                pass
        elif current_index == 1:
            self._set_qw3_bg('#2D2D2D' if is_dark_theme(app) else '#FFFFFF')
        elif current_index == 2:
            try:
                self.localhost_panel.active_view().page().runJavaScript(self._BG_JS, self._apply_web_bg)
            except Exception:
                pass
        elif current_index == 3:
            self._set_qw3_bg('#2D2D2D', border='#2D2D2D')

    def _refresh_web_surfaces_for_theme(self):
        self._refresh_assistant_render_for_theme()
        for panel in (self.ai_web_panel, self.localhost_panel):
            try:
                panel.reload_all_views()
            except Exception:
                pass
        QTimer.singleShot(0, self._refresh_current_tab_background)
        QTimer.singleShot(250, self._refresh_current_tab_background)

    def apply_theme(self, dark_mode: bool):
        current_index = self.stacked_widget.currentIndex()
        self.pill_nav.set_theme('dark' if (current_index == 3 or dark_mode) else 'light')
        self._apply_assistant_surfaces_theme(dark_mode)
        self._refresh_web_surfaces_for_theme()
        _apply_window_palette(self, dark_mode)
        for panel in (self.settings_panel, self.history_panel, self.links_panel, self.outputs_panel, self.share_panel, self.webfetch_panel):
            try:
                panel._apply_theme()
            except Exception:
                pass

    def set_hotkey_manager(self, hotkey_manager):
        self.settings_panel.set_hotkey_manager(hotkey_manager)

    def _background_vision_targets_from_store(self, store: dict) -> list[dict]:
        globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
        settings = normalize_background_vision_settings(globals_store)
        selected_names = normalize_background_vision_profile_names(settings.get('background_vision_profile_names', []))
        profiles = list(store.get('profiles', []) if isinstance(store, dict) else [])
        by_name = {
            str(profile.get('name', '') or '').strip(): profile
            for profile in profiles
            if isinstance(profile, dict) and str(profile.get('name', '') or '').strip()
        }
        if not selected_names:
            active_name = str(store.get('active_profile', '') or '').strip() if isinstance(store, dict) else ''
            selected_names = [active_name] if active_name else []
        targets = []
        for name in selected_names:
            profile = by_name.get(name)
            if not profile:
                continue
            target = dict(profile)
            target['endpoint'] = profile_runtime_base_url(profile)
            targets.append(target)
        if not targets and profiles:
            profile = profiles[0]
            target = dict(profile)
            target['endpoint'] = profile_runtime_base_url(profile)
            targets.append(target)
        return targets

    def _background_vision_signature_for(self, settings: dict, targets: list[dict]) -> str:
        compact_targets = [
            {
                'name': str(target.get('name', '') or ''),
                'endpoint': str(target.get('endpoint', '') or ''),
                'model': str(target.get('model', '') or ''),
                'timeout': str(target.get('timeout', '') or ''),
                'api_key_hint': str(target.get('api_key', '') or '')[:8],
            }
            for target in targets
        ]
        payload = {
            'settings': normalize_background_vision_settings(settings),
            'targets': compact_targets,
        }
        return json.dumps(payload, ensure_ascii=False, sort_keys=True)

    def apply_background_vision_settings(self):
        store = load_settings_store()
        globals_store = store.get('globals', {})
        settings = normalize_background_vision_settings(globals_store)
        if not bool(settings.get('background_vision_enabled', False)):
            self.stop_background_vision()
            return
        targets = self._background_vision_targets_from_store(store)
        signature = self._background_vision_signature_for(settings, targets)
        worker = getattr(self, '_background_vision_worker', None)
        if worker is not None and worker.isRunning() and signature == getattr(self, '_background_vision_signature', ''):
            return
        self.stop_background_vision()
        if not targets:
            return
        self._background_vision_generation += 1
        generation = self._background_vision_generation
        worker = BackgroundVisionWorker(targets, settings)
        worker.record_ready.connect(lambda record, gen=generation: self._on_background_vision_record_ready(record, gen))
        worker.error.connect(lambda message, gen=generation: self._on_background_vision_error(message, gen))
        worker.finished.connect(worker.deleteLater)
        self._background_vision_worker = worker
        self._background_vision_signature = signature
        worker.start()

    def stop_background_vision(self):
        self._background_vision_generation += 1
        worker = getattr(self, '_background_vision_worker', None)
        self._background_vision_worker = None
        self._background_vision_signature = ''
        if worker is not None:
            try:
                self._background_vision_stopping_workers.append(worker)
                worker.finished.connect(lambda w=worker: self._background_vision_stopping_workers.remove(w) if w in self._background_vision_stopping_workers else None)
                worker.stop()
                worker.wait(500)
            except Exception:
                pass

    def _on_background_vision_record_ready(self, record, generation: int):
        if generation != getattr(self, '_background_vision_generation', 0):
            return
        if not isinstance(record, dict):
            return
        settings = normalize_background_vision_settings(load_settings_store().get('globals', {}))
        append_background_vision_record(record, settings.get('background_vision_max_records', DEFAULT_BACKGROUND_VISION_MAX_RECORDS))
        if bool(settings.get('background_vision_show_overlay', True)) and bool(record.get('complete')):
            ttl_ms = int(settings.get('background_vision_toast_sec', DEFAULT_BACKGROUND_VISION_TOAST_SECONDS) or DEFAULT_BACKGROUND_VISION_TOAST_SECONDS) * 1000
            self._background_vision_toasts.show_record(record, ttl_ms=ttl_ms)

    def _on_background_vision_error(self, message: str, generation: int):
        if generation != getattr(self, '_background_vision_generation', 0):
            return
        # Keep background failures non-modal; the record file stores round-level errors.
        return

    def _build_background_vision_prompt_context(self) -> str:
        globals_store = load_settings_store().get('globals', {})
        if not bool(globals_store.get('background_vision_enabled', False)):
            return ''
        return load_latest_background_vision_context()

    def _refresh_history_panel(self):
        self.history_panel.set_records(list_conversation_records())

    def _refresh_links_panel(self):
        record = self._load_active_conversation_record()
        links = record.get('links', []) if record else []
        self.links_panel.set_links(links)
        if record:
            for link in links:
                url = str(link.get('url', '')).strip()
                title = str(link.get('title', '')).strip()
                if url and not title and url not in self._link_title_fetch_inflight:
                    self._link_title_fetch_inflight.add(url)
                    self._link_title_fetcher.fetch(url)

    def _tab_output_scope_key(self, index: int | None = None) -> str:
        if index is None:
            index = self.stacked_widget.currentIndex()
        return {0: 'web', 2: 'localhost', 3: 'terminal'}.get(int(index), '')

    def _tab_outputs_path(self, scope_key: str) -> str:
        ensure_broccoli_data_dir()
        safe_key = re.sub(r'[^a-zA-Z0-9_-]+', '-', str(scope_key or '').strip()).strip('-') or 'tab'
        return os.path.join(TAB_GENERATED_OUTPUTS_DIR, f'{safe_key}.json')

    def _tab_outputs_attachment_dir(self, scope_key: str) -> str:
        ensure_broccoli_data_dir()
        safe_key = re.sub(r'[^a-zA-Z0-9_-]+', '-', str(scope_key or '').strip()).strip('-') or 'tab'
        target = os.path.join(TAB_GENERATED_OUTPUTS_DIR, f'{safe_key}_attachments')
        os.makedirs(target, exist_ok=True)
        return target

    def _load_tab_outputs(self, scope_key: str) -> list[dict]:
        path = self._tab_outputs_path(scope_key)
        try:
            with open(path, 'r', encoding='utf-8') as handle:
                payload = json.load(handle)
        except Exception:
            payload = {}
        if isinstance(payload, dict):
            return normalize_output_records(payload.get('outputs', []))
        if isinstance(payload, list):
            return normalize_output_records(payload)
        return []

    def _save_tab_outputs(self, scope_key: str, outputs: list[dict]):
        path = self._tab_outputs_path(scope_key)
        payload = {
            'schema': 'broccoli-tab-generated-outputs/v1',
            'scope': str(scope_key or ''),
            'updated_at': datetime.datetime.now().isoformat(timespec='seconds'),
            'outputs': normalize_output_records(outputs),
        }
        with open(path, 'w', encoding='utf-8') as handle:
            json.dump(payload, handle, ensure_ascii=False, indent=2)

    def _current_outputs_storage_dir(self) -> str:
        scope_key = self._tab_output_scope_key()
        if scope_key:
            return self._tab_outputs_attachment_dir(scope_key)
        if self._active_conversation_path:
            out_dir = conversation_attachment_dir(self._active_conversation_path)
        else:
            out_dir = self._tab_outputs_attachment_dir('api-unsaved')
        os.makedirs(out_dir, exist_ok=True)
        return out_dir

    def _refresh_outputs_panel(self, prefer_latest: bool = False):
        scope_key = self._tab_output_scope_key()
        if scope_key:
            outputs = self._load_tab_outputs(scope_key)
        else:
            record = self._load_active_conversation_record()
            outputs = record.get('outputs', []) if record else []
        self.outputs_panel.set_outputs(outputs, prefer_latest=prefer_latest)

    def _copy_output_record(self, output: dict):
        kind = str(output.get('kind', 'text')).strip().lower()
        path = str(output.get('path', '') or '').strip()
        clipboard = QApplication.clipboard()
        if kind == 'image' and path and os.path.exists(path):
            pixmap = QPixmap(path)
            if not pixmap.isNull():
                clipboard.setPixmap(pixmap)
                return
        content = str(output.get('content', '') or '').strip()
        clipboard.setText(content or path)

    def _save_output_record_as(self, output: dict):
        kind = str(output.get('kind', 'text')).strip().lower()
        path = str(output.get('path', '') or '').strip()
        default_name = default_output_filename(output)
        target, _ = QFileDialog.getSaveFileName(self, 'Save output as', default_name)
        if not target:
            return
        if path and os.path.exists(path):
            shutil.copy2(path, target)
            return
        write_text_file(target, str(output.get('content', '') or ''))

    def _save_output_annotations(self, output: dict):
        output_id = str(output.get('id', '') or '').strip()
        if not output_id:
            return
        scope_key = self._tab_output_scope_key()
        if scope_key:
            outputs = list(self._load_tab_outputs(scope_key))
            updated = False
            for index, item in enumerate(outputs):
                if str(item.get('id', '') or '').strip() == output_id:
                    merged = dict(item)
                    merged['annotations'] = list(output.get('annotations', []) or [])
                    outputs[index] = merged
                    updated = True
                    break
            if updated:
                self._save_tab_outputs(scope_key, outputs)
            return
        if not self._active_conversation_path:
            return
        record = load_conversation_record(self._active_conversation_path)
        if record is None:
            return
        updated = False
        outputs = list(record.get('outputs', []) or [])
        for index, item in enumerate(outputs):
            if str(item.get('id', '') or '').strip() == output_id:
                merged = dict(item)
                merged['annotations'] = list(output.get('annotations', []) or [])
                outputs[index] = merged
                updated = True
                break
        if not updated:
            return
        record['outputs'] = outputs
        saved = write_conversation_record(self._active_conversation_path, record)
        self._active_conversation_path = saved['path']

    def _output_annotations_text(self, output: dict) -> str:
        annotations = list(output.get('annotations', []) or [])
        if not annotations:
            return ''
        lines = [
            f"Output: {str(output.get('title', '') or default_output_filename(output)).strip()}",
            f"Kind: {str(output.get('kind', 'text')).strip()}",
        ]
        question = str(output.get('question', '') or '').strip()
        if question:
            lines.append(f"Question: {question}")
        lines.append('')
        for index, annotation in enumerate(annotations, start=1):
            kind = str(annotation.get('kind', 'note')).replace('_', ' ')
            lines.append(f'[{index}] {kind}')
            if annotation.get('time_seconds') is not None:
                try:
                    seconds = float(annotation.get('time_seconds') or 0)
                    lines.append(f"Time: {int(seconds // 60):02d}:{int(seconds % 60):02d}.{int((seconds % 1) * 1000):03d}")
                except Exception:
                    pass
            quote = str(annotation.get('quote', '') or '').strip()
            if quote:
                lines.append('Selected text:')
                lines.append(quote)
            lines.append('Comment:')
            lines.append(str(annotation.get('comment', '') or '').strip())
            lines.append('')
        return '\n'.join(lines).strip()

    def _annotated_text_for_output(self, output: dict) -> str:
        base = str(output.get('content', '') or '')
        comments = self._output_annotations_text(output)
        if comments:
            return base.rstrip() + '\n\n---\n\nReviewer comments:\n' + comments + '\n'
        return base

    def _write_annotations_attachment(self, output: dict) -> str:
        comments = self._output_annotations_text(output)
        if not comments:
            return ''
        out_dir = self._current_outputs_storage_dir()
        os.makedirs(out_dir, exist_ok=True)
        filename = sanitize_conversation_filename(str(output.get('title', '') or 'output-comments'), max_len=64)
        target = os.path.join(out_dir, f"{datetime.datetime.now().strftime('%Y%m%d-%H%M%S-%f')}_{filename}-comments.txt")
        write_text_file(target, comments)
        return target

    def _write_composited_output_image(self, output: dict) -> str:
        if self.outputs_panel.current_output() and self.outputs_panel.current_output().get('id') == output.get('id'):
            pixmap = self.outputs_panel.image_preview.composited_pixmap()
        else:
            pixmap = QPixmap(str(output.get('path', '') or ''))
        if pixmap.isNull():
            return ''
        out_dir = self._current_outputs_storage_dir()
        os.makedirs(out_dir, exist_ok=True)
        filename = sanitize_conversation_filename(str(output.get('title', '') or 'annotated-output'), max_len=64)
        target = os.path.join(out_dir, f"{datetime.datetime.now().strftime('%Y%m%d-%H%M%S-%f')}_{filename}-annotated.png")
        pixmap.save(target, 'PNG')
        return target

    def _materialize_output_context_file(self, output: dict) -> str:
        path = str(output.get('path', '') or '').strip()
        if path and os.path.exists(path):
            return path
        out_dir = self._current_outputs_storage_dir()
        os.makedirs(out_dir, exist_ok=True)
        filename = sanitize_conversation_filename(Path(default_output_filename(output)).stem, max_len=64)
        suffix = Path(default_output_filename(output)).suffix or '.txt'
        timestamp = datetime.datetime.now().strftime('%Y%m%d-%H%M%S-%f')
        target = os.path.join(out_dir, f'{timestamp}_{filename}{suffix}')
        write_text_file(target, str(output.get('content', '') or ''))
        return target

    def _add_context_files_to_current_tab(self, paths: list[str]):
        paths = [str(path) for path in (paths or []) if path and os.path.exists(str(path))]
        if not paths:
            return
        use_embedding = self._generated_output_context_use_embedding_enabled()
        current_index = self.stacked_widget.currentIndex()
        if current_index == 1:
            for path in paths:
                self._attachment_tray.add_file(path, use_embedding=use_embedding)
            self._show_tray_animated()
            return
        if current_index in (0, 2):
            panel, dock = self._external_prompt_panel_for_index(current_index)
            if panel is not None and dock is not None:
                dock.add_files_instant(paths, use_embedding=use_embedding)
                panel.set_prompt_dock_visible(True, animated=True)
                QTimer.singleShot(0, lambda p=panel, d=dock: self._sync_external_prompt_dock_height(p, d))
                QTimer.singleShot(240, lambda p=panel, d=dock: self._sync_external_prompt_dock_height(p, d))
            return
        if current_index == 3:
            terminal = getattr(self, 'terminal_widget', None)
            if terminal is not None and hasattr(terminal, 'add_context_files'):
                terminal.add_context_files(paths, use_embedding=use_embedding)

    def _use_output_as_context(self, output: dict):
        paths = []
        kind = str(output.get('kind', 'text')).strip().lower()
        if kind in {'text', 'code'}:
            out_dir = self._current_outputs_storage_dir()
            os.makedirs(out_dir, exist_ok=True)
            filename = sanitize_conversation_filename(Path(default_output_filename(output)).stem, max_len=64)
            target = os.path.join(out_dir, f"{datetime.datetime.now().strftime('%Y%m%d-%H%M%S-%f')}_{filename}-with-comments.txt")
            write_text_file(target, self._annotated_text_for_output(output))
            paths.append(target)
        elif kind == 'image':
            annotated = self._write_composited_output_image(output)
            if annotated:
                paths.append(annotated)
            comments = self._write_annotations_attachment(output)
            if comments:
                paths.append(comments)
        elif kind == 'video':
            annotated = self._write_composited_output_image(output)
            if annotated:
                paths.append(annotated)
            comments = self._write_annotations_attachment(output)
            if comments:
                paths.append(comments)
        elif kind == 'audio':
            comments = self._write_annotations_attachment(output)
            if comments:
                paths.append(comments)
        if not paths:
            fallback = self._materialize_output_context_file(output)
            if fallback:
                paths.append(fallback)
        if paths:
            self._add_context_files_to_current_tab(paths)
            if getattr(self, '_outputs_panel_visible', False):
                self.hide_outputs_panel()

    def _run_profile_chat_completion(self, profile: dict, messages: list[dict]) -> str:
        api_key = str(profile.get('api_key', '')).strip()
        model = str(profile.get('model', '')).strip()
        if not api_key or not model:
            raise ValueError('Selected profile is missing API key or model.')
        try:
            timeout = int(profile.get('timeout', 60) or 60)
        except (TypeError, ValueError):
            timeout = 60
        client = create_openai_client(api_key, profile_runtime_base_url(profile), timeout)
        response = client.chat.completions.create(
            model=model,
            messages=messages,
            stream=False,
        )
        answer = str(response.choices[0].message.content or '').strip()
        # Perplexity exposes citations on its chat-compatible responses, but the
        # field shape is provider-specific rather than OpenAI-standard. Keep this
        # special-case local and explicit instead of pretending it is generic.
        if is_perplexity_endpoint(profile.get('endpoint', '')):
            citations_block = format_perplexity_citations_block(getattr(response, 'citations', None))
            if citations_block:
                answer = answer + ('\n\n' if answer else '') + citations_block
        return answer

    def _run_profile_chat_completion_with_code_execution(self,
                                                         profile: dict,
                                                         messages: list[dict]) -> tuple[str, list[dict]]:
        current_messages = clone_messages_as_text(messages)
        output = self._run_profile_chat_completion(profile, current_messages)
        executions = []
        seen_codes = set()
        store = load_settings_store()
        for _round in range(CODE_EXECUTION_MAX_ROUNDS):
            candidates = extract_code_candidates(output)
            selected = None
            for candidate in candidates:
                language = normalize_code_runner_language(candidate.get('language', ''), '')
                code = str(candidate.get('code', '') or '').strip()
                key = f'{language}\n{code}'
                if language and code and key not in seen_codes:
                    selected = {'language': language, 'code': code}
                    break
            if not selected:
                break
            seen_codes.add(f"{selected['language']}\n{selected['code']}")
            result = run_code_in_worker_thread(selected['language'], selected['code'], store=store)
            executions.append({'language': selected['language'], 'code': selected['code'], 'result': result})
            current_messages.append({'role': 'assistant', 'content': output})
            current_messages.append({'role': 'user', 'content': format_code_execution_feedback(executions[-1:])})
            output = self._run_profile_chat_completion(profile, current_messages)
        return output, executions

    def _specialized_output_dir(self) -> str:
        if self._active_conversation_path:
            out_dir = conversation_attachment_dir(self._active_conversation_path)
        else:
            out_dir = os.path.join(BROCCOLI_APP_DATA_DIR, 'SpecializedOutputs')
        os.makedirs(out_dir, exist_ok=True)
        return out_dir

    def _write_specialized_output_bytes(self, prefix: str, suffix: str, data: bytes) -> str:
        out_dir = self._specialized_output_dir()
        base = sanitize_conversation_filename(prefix, max_len=40)
        timestamp = datetime.datetime.now().strftime('%Y%m%d-%H%M%S-%f')
        path = os.path.join(out_dir, f'{timestamp}_{base}{suffix}')
        with open(path, 'wb') as handle:
            handle.write(data)
        return path

    def _response_text_from_response_api(self, response) -> str:
        output_text = str(getattr(response, 'output_text', '') or '').strip()
        if output_text:
            return output_text
        parts = []
        for item in getattr(response, 'output', []) or []:
            try:
                dumped = item.model_dump()
            except Exception:
                dumped = {}
            for content in dumped.get('content', []) if isinstance(dumped, dict) else []:
                if not isinstance(content, dict):
                    continue
                text_value = str(content.get('text', '') or '').strip()
                if text_value:
                    parts.append(text_value)
        return '\n\n'.join(part for part in parts if part).strip()

    def _extract_web_search_sources(self, response) -> list[dict]:
        found = []
        seen = set()

        def walk(value):
            if isinstance(value, dict):
                url = str(value.get('url', '') or '').strip()
                title = str(value.get('title', '') or value.get('name', '') or '').strip()
                if url and url not in seen:
                    seen.add(url)
                    found.append({'url': url, 'title': title})
                for child in value.values():
                    walk(child)
            elif isinstance(value, list):
                for child in value:
                    walk(child)

        for item in getattr(response, 'output', []) or []:
            try:
                walk(item.model_dump())
            except Exception:
                continue
        return found

    def _extract_media_source_path(self, attachment_records: list[dict], allowed_exts: set[str]) -> str:
        for attachment in attachment_records:
            for key in ('stored_path', 'source_path', 'original_path'):
                path = str(attachment.get(key, '')).strip()
                if path and os.path.exists(path) and Path(path).suffix.lower() in allowed_exts:
                    return path
        return ''

    def _build_media_generation_input(self,
                                      question_text: str,
                                      shared_context: str,
                                      previous_results: list[dict],
                                      goal: str) -> str:
        parts = []
        if question_text.strip():
            parts.append(f'User request:\n{question_text.strip()}')
        if goal.strip():
            parts.append(f'Step goal:\n{goal.strip()}')
        if shared_context.strip():
            parts.append(f'Retrieved context:\n{shared_context.strip()}')
        if previous_results:
            prev = []
            for result in previous_results:
                body = specialized_step_context_output(result)
                if body:
                    prev.append(f"{result.get('capability', 'previous_step')}:\n{body}")
            if prev:
                parts.append('Previous step outputs:\n' + '\n\n'.join(prev))
        return '\n\n'.join(part for part in parts if part).strip()

    def _run_web_search_step(self,
                             profile: dict,
                             goal: str,
                             question_text: str,
                             shared_context: str,
                             previous_results: list[dict]) -> dict:
        model_name = str(profile.get('model', '')).strip()
        try:
            timeout = int(profile.get('timeout', 60) or 60)
        except (TypeError, ValueError):
            timeout = 60
        client = create_openai_client(
            str(profile.get('api_key', '')).strip(),
            profile_runtime_base_url(profile),
            timeout,
        )
        prompt = self._build_media_generation_input(question_text, shared_context, previous_results, goal)
        response = client.responses.create(
            model=model_name,
            input=prompt,
            tools=[{'type': 'web_search_preview'}],
            include=['web_search_call.action.sources'],
            stream=False,
        )
        text_output = self._response_text_from_response_api(response)
        sources = self._extract_web_search_sources(response)
        if sources:
            source_block = 'Sources:\n' + '\n'.join(
                f"- {source.get('title', '').strip() or source['url']} ({source['url']})" for source in sources
            )
            text_output = text_output + ('\n\n' if text_output else '') + source_block
        return {
            'capability': 'web_search',
            'capability_label': specialized_capability_label('web_search'),
            'model_name': model_name,
            'text_output': text_output or 'Web search completed.',
            'artifacts': [],
            'metadata': {'goal': goal, 'sources': sources},
        }

    def _run_image_generation_step(self,
                                   profile: dict,
                                   goal: str,
                                   question_text: str,
                                   shared_context: str,
                                   previous_results: list[dict]) -> dict:
        model_name = str(profile.get('model', '')).strip()
        try:
            timeout = int(profile.get('timeout', 60) or 60)
        except (TypeError, ValueError):
            timeout = 60
        client = create_openai_client(
            str(profile.get('api_key', '')).strip(),
            profile_runtime_base_url(profile),
            timeout,
        )
        prompt = self._build_media_generation_input(question_text, shared_context, previous_results, goal)
        response = client.images.generate(
            model=model_name,
            prompt=prompt,
            size='1024x1024',
        )
        artifacts = []
        text_output = 'Image generated successfully.'
        image_data = (getattr(response, 'data', None) or [])
        if image_data:
            first = image_data[0]
            revised_prompt = str(getattr(first, 'revised_prompt', '') or '').strip()
            b64_json = str(getattr(first, 'b64_json', '') or '').strip()
            image_url = str(getattr(first, 'url', '') or '').strip()
            output_format = str(getattr(response, 'output_format', '') or 'png').strip().lower() or 'png'
            if b64_json:
                image_bytes = base64.b64decode(b64_json)
                ext = '.jpg' if output_format == 'jpeg' else f'.{output_format}'
                artifacts.append(self._write_specialized_output_bytes('generated-image', ext, image_bytes))
            elif image_url:
                text_output += f'\nImage URL: {image_url}'
            if revised_prompt:
                text_output += f'\nRevised prompt: {revised_prompt}'
        return {
            'capability': 'image_generation',
            'capability_label': specialized_capability_label('image_generation'),
            'model_name': model_name,
            'text_output': text_output,
            'artifacts': artifacts,
            'metadata': {'goal': goal, 'prompt': prompt},
        }

    def _run_text_to_speech_step(self,
                                 profile: dict,
                                 goal: str,
                                 question_text: str,
                                 previous_results: list[dict]) -> dict:
        model_name = str(profile.get('model', '')).strip()
        try:
            timeout = int(profile.get('timeout', 60) or 60)
        except (TypeError, ValueError):
            timeout = 60
        client = create_openai_client(
            str(profile.get('api_key', '')).strip(),
            profile_runtime_base_url(profile),
            timeout,
        )
        input_text = ''
        for result in reversed(previous_results):
            input_text = specialized_step_context_output(result)
            if input_text:
                break
        if not input_text:
            input_text = str(question_text or '').strip()
        if not input_text:
            raise ValueError('No text is available for text-to-speech generation.')
        if len(input_text) > 3900:
            input_text = input_text[:3900].rstrip()
        audio_response = client.audio.speech.create(
            model=model_name,
            voice='alloy',
            input=input_text,
            response_format='mp3',
        )
        audio_bytes = audio_response.read()
        artifact_path = self._write_specialized_output_bytes('generated-audio', '.mp3', audio_bytes)
        return {
            'capability': 'text_to_speech',
            'capability_label': specialized_capability_label('text_to_speech'),
            'model_name': model_name,
            'text_output': 'Audio generated successfully.',
            'artifacts': [artifact_path],
            'metadata': {'goal': goal},
        }

    def _run_transcription_step(self,
                                capability: str,
                                profile: dict,
                                goal: str,
                                attachment_records: list[dict]) -> dict:
        model_name = str(profile.get('model', '')).strip()
        try:
            timeout = int(profile.get('timeout', 60) or 60)
        except (TypeError, ValueError):
            timeout = 60
        client = create_openai_client(
            str(profile.get('api_key', '')).strip(),
            profile_runtime_base_url(profile),
            timeout,
        )
        allowed_exts = ATTACHMENT_AUDIO_EXTS if capability == 'speech_to_text' else (ATTACHMENT_AUDIO_EXTS | ATTACHMENT_VIDEO_EXTS)
        source_path = self._extract_media_source_path(attachment_records, allowed_exts)
        if not source_path:
            raise ValueError('No compatible media attachment was found for transcription.')
        with open(source_path, 'rb') as media_file:
            transcription = client.audio.transcriptions.create(
                model=model_name,
                file=media_file,
                response_format='text',
            )
        text_output = str(transcription or '').strip() or 'Transcription completed.'
        return {
            'capability': capability,
            'capability_label': specialized_capability_label(capability),
            'model_name': model_name,
            'text_output': text_output,
            'artifacts': [],
            'metadata': {'goal': goal, 'source_path': source_path},
        }

    def _plan_specialized_request(self, question_text: str, attachment_records: list[dict]) -> dict:
        store = load_settings_store()
        planner_profile = get_planner_profile_from_store(store)
        skills = load_skill_records_from_store(store, enabled_only=True)
        catalog = skill_catalog_text(skills)
        skill_names = {record.get('name', '') for record in skills}
        try:
            planner_output = self._run_profile_chat_completion(
                planner_profile,
                build_planner_messages(question_text, summarize_attachment_types(attachment_records), catalog),
            )
        except Exception:
            return {'steps': [], 'finalize_with_default_chat': False, 'reason': ''}
        return normalize_planner_plan(parse_json_object_from_text(planner_output), skill_names)

    def _review_specialized_step_result(self,
                                        result: dict,
                                        *,
                                        capability: str,
                                        goal: str,
                                        question_text: str,
                                        downstream_extract: str = '',
                                        final_focus: str = '') -> dict:
        if not isinstance(result, dict):
            return result
        reviewed = dict(result)
        metadata = dict(reviewed.get('metadata') or {})
        output_text = str(reviewed.get('text_output', '') or '').strip()
        review_output_text = output_text
        code_executions = metadata.get('code_executions') or metadata.get('python_executions') or []
        if code_executions:
            review_output_text = (
                review_output_text
                + ('\n\n' if review_output_text else '')
                + 'Actual code execution feedback from the app:\n'
                + format_code_execution_feedback(code_executions)
            )
        artifact_paths = [str(path).strip() for path in (reviewed.get('artifacts') or []) if str(path).strip()]
        if not review_output_text and not artifact_paths:
            reviewed['context_output'] = ''
            metadata['step_review'] = {
                'reviewed': True,
                'meets_goal': False,
                'missing': 'The step produced no text output or artifacts.',
                'reason': 'No usable step output.',
                'next_action': 'accept',
                'new_step': None,
            }
            reviewed['metadata'] = metadata
            return reviewed

        store = load_settings_store()
        planner_profile = get_planner_profile_from_store(store)
        skills = load_skill_records_from_store(store, enabled_only=True)
        catalog = skill_catalog_text(skills)
        skill_names = {record.get('name', '') for record in skills}
        try:
            review_text = self._run_profile_chat_completion(
                planner_profile,
                build_specialized_step_review_messages(
                    capability,
                    goal,
                    question_text,
                    downstream_extract,
                    final_focus,
                    review_output_text,
                    artifact_paths,
                    catalog,
                ),
            )
            parsed = parse_json_object_from_text(review_text)
            if not isinstance(parsed, dict):
                raise ValueError('Planner review did not return JSON.')
            context_output = limit_specialized_context_output(str(parsed.get('context_output', '') or ''))
            reviewed['context_output'] = context_output
            metadata['step_review'] = {
                'reviewed': True,
                'meets_goal': bool(parsed.get('meets_goal', False)),
                'missing': str(parsed.get('missing', '') or '').strip(),
                'reason': str(parsed.get('reason', '') or '').strip(),
                'downstream_need': str(downstream_extract or final_focus or '').strip(),
                'next_action': str(parsed.get('next_action', 'accept') or 'accept').strip(),
                'new_step': normalize_dynamic_specialized_step(parsed.get('new_step'), skill_names),
            }
        except Exception as exc:
            reviewed['context_output'] = limit_specialized_context_output(review_output_text)
            metadata['step_review'] = {
                'reviewed': False,
                'meets_goal': True,
                'missing': '',
                'reason': f'Review failed; used locally truncated output. {exc}',
                'downstream_need': str(downstream_extract or final_focus or '').strip(),
                'next_action': 'accept',
                'new_step': None,
            }
        reviewed['metadata'] = metadata
        return reviewed

    def _execute_skill_step(self,
                            *,
                            skill_name: str,
                            goal: str,
                            question_text: str,
                            shared_context: str,
                            previous_results: list[dict],
                            downstream_extract: str = '',
                            store: dict | None = None) -> dict:
        if store is None:
            store = load_settings_store()
        skills = load_skill_records_from_store(store, enabled_only=True)
        skill = find_skill_record(skills, skill_name)
        if skill is None:
            return {
                'capability': SPECIALIZED_SKILL_CAPABILITY,
                'capability_label': 'Skill',
                'model_name': '',
                'text_output': f'Skill step failed: skill not found or disabled: {skill_name}',
                'artifacts': [],
                'metadata': {'goal': goal, 'skill_name': skill_name},
            }
        active_profile_name = str(store.get('active_profile', '') or '').strip()
        profile = get_profile_from_store_by_name(store, active_profile_name) or load_active_settings_profile()
        model_name = str(profile.get('model', '') or '').strip()
        executions = []
        try:
            output, executions = self._run_profile_chat_completion_with_code_execution(
                profile,
                build_skill_step_messages(
                    skill=skill,
                    goal=goal,
                    question_text=question_text,
                    shared_context=shared_context,
                    previous_results=previous_results,
                    downstream_extract=downstream_extract,
                ),
            )
        except Exception as exc:
            output = f'Skill step failed: {exc}'
        clean_skill_name = sanitize_skill_name(skill.get('name', skill_name), skill_name or 'Skill')
        return {
            'capability': SPECIALIZED_SKILL_CAPABILITY,
            'capability_label': f'Skill · {clean_skill_name}',
            'model_name': model_name,
            'text_output': output,
            'artifacts': [],
            'metadata': {
                'goal': goal,
                'skill_name': clean_skill_name,
                'skill_description': str(skill.get('description', '') or '').strip(),
                'execution_mode': 'default_main_model',
                'code_executions': executions,
            },
        }

    def _execute_specialized_step(self,
                                  capability: str,
                                  goal: str,
                                  question_text: str,
                                  shared_context: str,
                                  previous_results: list[dict],
                                  attachment_records: list[dict],
                                  downstream_extract: str = '',
                                  skill_name: str = '') -> dict:
        store = load_settings_store()
        if capability == SPECIALIZED_SKILL_CAPABILITY:
            return self._execute_skill_step(
                skill_name=skill_name,
                goal=goal,
                question_text=question_text,
                shared_context=shared_context,
                previous_results=previous_results,
                downstream_extract=downstream_extract,
                store=store,
            )
        profile = resolve_specialized_profile(store, capability, None)
        if profile is None:
            return {}
        model_name = str(profile.get('model', '')).strip()
        execution_mode = resolve_specialized_execution_mode(store, capability)
        if capability == 'web_search':
            if execution_mode == 'generic_chat_completion':
                executions = []
                try:
                    output, executions = self._run_profile_chat_completion_with_code_execution(
                        profile,
                        build_specialized_step_messages(capability, goal, question_text, shared_context, previous_results, downstream_extract),
                    )
                except Exception as exc:
                    output = f'Web search step failed: {str(exc)}'
                return {
                    'capability': capability,
                    'capability_label': specialized_capability_label(capability),
                    'model_name': model_name,
                    'text_output': output,
                    'artifacts': [],
                    'metadata': {'goal': goal, 'execution_mode': execution_mode, 'code_executions': executions},
                }
            try:
                return self._run_web_search_step(profile, goal, question_text, shared_context, previous_results)
            except Exception as exc:
                return {
                    'capability': capability,
                    'capability_label': specialized_capability_label(capability),
                    'model_name': model_name,
                    'text_output': f'Web search step failed: {str(exc)}',
                    'artifacts': [],
                    'metadata': {'goal': goal, 'execution_mode': execution_mode},
                }
        if capability == 'image_generation':
            try:
                return self._run_image_generation_step(profile, goal, question_text, shared_context, previous_results)
            except Exception as exc:
                return {
                    'capability': capability,
                    'capability_label': specialized_capability_label(capability),
                    'model_name': model_name,
                    'text_output': f'Image generation step failed: {str(exc)}',
                    'artifacts': [],
                    'metadata': {'goal': goal, 'execution_mode': execution_mode},
                }
        if capability == 'text_to_speech':
            try:
                return self._run_text_to_speech_step(profile, goal, question_text, previous_results)
            except Exception as exc:
                return {
                    'capability': capability,
                    'capability_label': specialized_capability_label(capability),
                    'model_name': model_name,
                    'text_output': f'Text-to-speech step failed: {str(exc)}',
                    'artifacts': [],
                    'metadata': {'goal': goal, 'execution_mode': execution_mode},
                }
        if capability in {'speech_to_text', 'video_to_text'}:
            try:
                return self._run_transcription_step(capability, profile, goal, attachment_records)
            except Exception as exc:
                return {
                    'capability': capability,
                    'capability_label': specialized_capability_label(capability),
                    'model_name': model_name,
                    'text_output': f'{specialized_capability_label(capability)} step failed: {str(exc)}',
                    'artifacts': [],
                    'metadata': {'goal': goal, 'execution_mode': execution_mode},
                }
        if capability == 'video_generation':
            return {
                'capability': capability,
                'capability_label': specialized_capability_label(capability),
                'model_name': model_name,
                'text_output': 'Video generation is not wired to a dedicated OpenAI client endpoint in this build yet.',
                'artifacts': [],
                'metadata': {'goal': goal, 'execution_mode': execution_mode},
            }
        executions = []
        try:
            output, executions = self._run_profile_chat_completion_with_code_execution(
                profile,
                build_specialized_step_messages(capability, goal, question_text, shared_context, previous_results, downstream_extract),
            )
        except Exception as exc:
            output = f'Step failed: {str(exc)}'
        return {
            'capability': capability,
            'capability_label': specialized_capability_label(capability),
            'model_name': model_name,
            'text_output': output,
            'artifacts': [],
            'metadata': {'goal': goal, 'execution_mode': execution_mode, 'code_executions': executions},
        }

    def _execute_specialized_plan(self,
                                  plan: dict,
                                  question_text: str,
                                  shared_context: str,
                                  attachment_records: list[dict],
                                  progress_callback=None) -> list[dict]:
        steps = list(plan.get('steps', []) or [])
        final_focus = str(plan.get('finalize_focus', '') or '').strip()
        results = []
        i = 0
        dynamic_additions = 0
        executed_steps = 0
        max_executed_steps = len(steps) + SPECIALIZED_DYNAMIC_STEP_MAX_ADDITIONS

        def progress(message: str):
            if progress_callback is None:
                return
            try:
                progress_callback(str(message or '').strip())
            except Exception:
                pass

        while i < len(steps) and executed_steps < max_executed_steps:
            step = steps[i]
            capability = str(step.get('capability', '')).strip()
            if not capability:
                i += 1
                continue
            step_label = skill_step_label(step)
            goal = str(step.get('goal', '')).strip()
            if not goal:
                i += 1
                continue
            progress(
                f'Specialized step {executed_steps + 1}: {step_label}'
                + (' (dynamic)' if step.get('dynamic') else '')
                + f'\nGoal: {goal}'
            )
            if step.get('depends_on_previous', False) and results:
                extract_hint = str(step.get('extract', '')).strip()
                if extract_hint:
                    last = results[-1]
                    context_text = specialized_step_context_output(last)
                    focused = {
                        'capability': last.get('capability', ''),
                        'model_name': last.get('model_name', ''),
                        'context_output': context_text,
                        'text_output': context_text,
                        'metadata': {'extract': extract_hint},
                    }
                    previous = [focused]
                else:
                    previous = results[-1:]
            else:
                previous = []
            next_step = steps[i + 1] if i + 1 < len(steps) else None
            downstream_extract = str((next_step or {}).get('extract', '')).strip() if next_step and next_step.get('depends_on_previous') else ''
            result = self._execute_specialized_step(
                capability=capability,
                goal=goal,
                question_text=question_text,
                shared_context=shared_context,
                previous_results=previous,
                attachment_records=attachment_records,
                downstream_extract=downstream_extract,
                skill_name=str(step.get('skill_name', '') or '').strip(),
            )
            if result:
                progress(
                    f'Specialized step {executed_steps + 1} output ready: {step_label}'
                    + ('\n' + specialized_progress_snippet(str(result.get('text_output', '') or '')) if result.get('text_output') else '')
                )
                reviewed_result = self._review_specialized_step_result(
                    result,
                    capability=capability,
                    goal=goal,
                    question_text=question_text,
                    downstream_extract=downstream_extract,
                    final_focus=final_focus,
                )
                results.append(reviewed_result)
                review = (reviewed_result.get('metadata') or {}).get('step_review', {})
                review_action = str(review.get('next_action', 'accept') or 'accept').strip()
                review_reason = str(review.get('reason', '') or '').strip()
                context_output = specialized_step_context_output(reviewed_result)
                progress(
                    f'Specialized step {executed_steps + 1} reviewed: {step_label}'
                    + f'\nMeets goal: {"yes" if review.get("meets_goal", False) else "no"}'
                    + f'\nNext action: {review_action}'
                    + (f'\nReason: {review_reason}' if review_reason else '')
                    + (f'\nContext for next step: {specialized_progress_snippet(context_output)}' if context_output else '')
                )
                if review_action == 'stop':
                    progress('Specialized pipeline stopped by planner review.')
                    break
                if review_action in {'insert_step', 'retry_step'} and dynamic_additions < SPECIALIZED_DYNAMIC_STEP_MAX_ADDITIONS:
                    new_step = review.get('new_step')
                    if not new_step and review_action == 'retry_step':
                        missing = str(review.get('missing', '') or '').strip()
                        new_step = normalize_dynamic_specialized_step(
                            {
                                'capability': capability,
                                'skill_name': str(step.get('skill_name', '') or '').strip(),
                                'goal': ('Retry the previous step with a corrected approach. ' + (missing or goal)).strip(),
                                'depends_on_previous': bool(results),
                                'extract': downstream_extract,
                            }
                        )
                    if new_step:
                        steps.insert(i + 1, new_step)
                        dynamic_additions += 1
                        progress(
                            'Planner inserted dynamic step: '
                            + f"{skill_step_label(new_step)}\nGoal: {new_step['goal']}"
                        )
                elif review_action in {'insert_step', 'retry_step'}:
                    progress('Dynamic step limit reached; continuing without inserting more steps.')
            executed_steps += 1
            i += 1
        return results

    def _build_output_records_for_turn(self,
                                       *,
                                       question_text: str,
                                       question_index: int,
                                       assistant_index: int,
                                       model_name: str,
                                       structured_outputs: list[dict],
                                       step_results: list[dict]) -> list[dict]:
        created_at = datetime.datetime.now().isoformat(timespec='seconds')
        records = []
        for index, item in enumerate(structured_outputs or []):
            kind = str(item.get('kind', 'text')).strip().lower()
            if kind not in {'code', 'text'}:
                kind = 'text'
            content = str(item.get('content', '') or '').strip()
            if not content:
                continue
            title = str(item.get('title', '') or '').strip() or ('Generated code' if kind == 'code' else 'Generated text')
            records.append(
                {
                    'id': f'out-{assistant_index}-{index}-{kind}',
                    'kind': kind,
                    'title': title,
                    'filename': str(item.get('filename', '') or '').strip(),
                    'content': content,
                    'path': '',
                    'question': question_text,
                    'question_index': question_index,
                    'assistant_index': assistant_index,
                    'created_at': created_at,
                    'source': str(item.get('source', '') or '').strip() or 'assistant_block',
                    'model_name': model_name,
                }
            )
        for step_index, result in enumerate(step_results or []):
            capability = str(result.get('capability', '') or '').strip()
            capability_label = str(result.get('capability_label', '') or capability or 'Generated output').strip()
            for artifact_index, artifact_path in enumerate(result.get('artifacts') or []):
                path = str(artifact_path or '').strip()
                if not path:
                    continue
                kind = output_kind_from_path(path)
                records.append(
                    {
                        'id': f'out-{assistant_index}-artifact-{step_index}-{artifact_index}',
                        'kind': kind,
                        'title': capability_label,
                        'filename': os.path.basename(path),
                        'content': str(result.get('text_output', '') or '').strip(),
                        'path': path,
                        'question': question_text,
                        'question_index': question_index,
                        'assistant_index': assistant_index,
                        'created_at': created_at,
                        'source': capability or 'specialized_step',
                        'model_name': str(result.get('model_name', '') or model_name).strip(),
                    }
                )
        return normalize_output_records(records)

    def _restore_webfetch_from_conversation_record(self, record: dict | None):
        self._webfetch_generated_attachment = None
        self._webfetch_panel_dismissed = False
        records = []
        if isinstance(record, dict):
            for attachment in ((record.get('webfetch') or {}).get('attachments') or []):
                stored_path = str(attachment.get('stored_path', '')).strip()
                if not stored_path:
                    continue
                loaded = load_webfetch_selection_attachment(stored_path)
                if loaded:
                    records.append(loaded)
        self._webfetch_records = records
        self.webfetch_panel.set_export_records(records)
        if records and self.stacked_widget.currentIndex() == 1:
            self.webfetch_panel.set_collapsed(True)
            self._show_webfetch_panel()
        else:
            self.webfetch_panel.hide()

    def _history_panel_shown_rect(self):
        panel_w = self.history_panel.width()
        panel_h = self.history_panel.height()
        x = max(0, (self.qw3.width() - panel_w) // 2)
        y = max(24, (self.qw3.height() - panel_h) // 2)
        return QRect(
            x,
            y,
            panel_w,
            panel_h,
        )

    def _history_panel_hidden_rect(self):
        shown = self._history_panel_shown_rect()
        return QRect(-shown.width() - 24, shown.y(), shown.width(), shown.height())

    def _links_panel_shown_rect(self):
        panel_w = self.links_panel.width()
        panel_h = self.links_panel.height()
        x = max(0, (self.qw3.width() - panel_w) // 2)
        y = max(24, (self.qw3.height() - panel_h) // 2)
        return QRect(
            x,
            y,
            panel_w,
            panel_h,
        )

    def _links_panel_hidden_rect(self):
        shown = self._links_panel_shown_rect()
        return QRect(self.qw3.width() + 24, shown.y(), shown.width(), shown.height())

    def _open_link_url(self, url: str):
        try:
            webbrowser.open(url)
        except Exception:
            pass

    def _open_all_link_urls(self, urls: list[str]):
        for url in urls:
            try:
                webbrowser.open(url)
            except Exception:
                pass

    def _on_link_title_fetched(self, url: str, title: str):
        self._link_title_fetch_inflight.discard(url)
        url = clean_extracted_url(url)
        if not url or not title:
            return
        record = self._load_active_conversation_record()
        if record is None:
            return
        updated = False
        for link in record.get('links', []):
            if str(link.get('url', '')).strip() == url and not str(link.get('title', '')).strip():
                link['title'] = title
                updated = True
        if updated:
            saved = write_conversation_record(record['path'], record)
            self._active_conversation_path = saved['path']
            self._refresh_history_panel()
            self._refresh_links_panel()

    def _bootstrap_conversation_from_messages(self, messages: list[dict]) -> dict:
        ensure_broccoli_data_dir()
        convo_id = datetime.datetime.now().strftime('%Y%m%d-%H%M%S')
        title = conversation_title_from_messages(messages, fallback=convo_id)
        filename = f"{convo_id}_{sanitize_conversation_filename(title)}.json"
        path = os.path.join(CONVERSATIONS_DIR, filename)
        record = write_conversation_record(
            path,
            {
                'id': convo_id,
                'title': title,
                'created_at': datetime.datetime.now().isoformat(timespec='seconds'),
                'updated_at': datetime.datetime.now().isoformat(timespec='seconds'),
                'messages': messages,
                'rendered_markdown': render_chat_history_markdown(messages),
            },
        )
        self._active_conversation_path = record['path']
        self._refresh_history_panel()
        return record

    def _load_active_conversation_record(self) -> dict | None:
        if not self._active_conversation_path:
            return None
        return load_conversation_record(self._active_conversation_path)

    def _refresh_active_conversation_runtime_data(self,
                                                 api_key: str,
                                                 endpoint: str,
                                                 model: str,
                                                 timeout: int,
                                                 refresh_ui: bool = True) -> dict | None:
        record = self._load_active_conversation_record()
        if record is None:
            return None

        mutated = False
        turns = record.get('display', {}).get('turns', [])
        try:
            summarized_count = max(0, int(record.get('memory', {}).get('last_summarized_turn_count', 0) or 0))
        except (TypeError, ValueError):
            summarized_count = 0
        if summarized_count < len(turns):
            try:
                record = update_conversation_running_summary(record, api_key, endpoint, model, timeout)
                mutated = True
            except Exception:
                pass

        fresh_chunks = build_retrieval_chunks(record.get('messages', []))
        current_chunks = record.get('retrieval', {}).get('chunks', [])
        needs_retrieval_refresh = len(fresh_chunks) != len(current_chunks)
        if not needs_retrieval_refresh:
            for fresh_chunk, current_chunk in zip(fresh_chunks, current_chunks):
                if fresh_chunk.get('id') != current_chunk.get('id') or fresh_chunk.get('text') != current_chunk.get('text'):
                    needs_retrieval_refresh = True
                    break
                if not current_chunk.get('embedding'):
                    needs_retrieval_refresh = True
                    break
        if needs_retrieval_refresh:
            record['retrieval']['chunks'] = fresh_chunks
            mutated = True

        embedding_config = load_embedding_runtime_config()
        embedding_ok = False
        if embedding_config is not None:
            embedding_ok, _ = probe_embedding_capability(embedding_config['profile'])
        if embedding_ok and embedding_config is not None:
            embedding_chunks = record.get('retrieval', {}).get('chunks', [])
            if any(not chunk.get('embedding') for chunk in embedding_chunks):
                try:
                    record = ensure_conversation_retrieval_embeddings(
                        record,
                        embedding_config['api_key'],
                        embedding_config['endpoint'],
                        embedding_config['timeout'],
                        embedding_config['model'],
                    )
                    mutated = True
                except Exception:
                    pass

        if mutated:
            saved = write_conversation_record(record['path'], record)
            self._active_conversation_path = saved['path']
            if refresh_ui:
                self._refresh_history_panel()
            return saved
        return record

    def _build_active_history_context(self,
                                      question_text: str,
                                      history_messages: list[dict],
                                      api_key: str,
                                      endpoint: str,
                                      model: str,
                                      timeout: int,
                                      selected_message_indices: set[int] | None = None,
                                      refresh_ui: bool = True) -> str:
        store = load_settings_store()
        globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
        display_limit = normalize_display_history_context_max_chars(
            globals_store.get('display_history_context_max_chars', DISPLAY_HISTORY_CONTEXT_MAX_CHARS)
        )
        if bool(globals_store.get('prefer_displayed_history_context', False)) and should_use_display_history_context(
            history_messages,
            max_chars=display_limit,
        ):
            return build_history_context(history_messages)

        record = self._refresh_active_conversation_runtime_data(
            api_key,
            endpoint,
            model,
            timeout,
            refresh_ui=refresh_ui,
        )
        embedding_config = load_embedding_runtime_config()
        embedding_ok = False
        if embedding_config is not None:
            embedding_ok, _ = probe_embedding_capability(embedding_config['profile'])
        blocks = []

        if history_messages:
            if record is None:
                convo_block = build_history_context(history_messages)
                # print_retrieval_debug('conversation', 'history_fallback', question_text, [])
            else:
                retrieval_record = record
                if selected_message_indices is not None:
                    selected_message_indices = {int(idx) for idx in selected_message_indices}
                    retrieval_record = copy.deepcopy(record)
                    retrieval_record['messages'] = [
                        message for message_index, message in enumerate(record.get('messages', []))
                        if message_index in selected_message_indices
                    ]
                    retrieval_record.setdefault('retrieval', {})
                    retrieval_record['retrieval']['chunks'] = [
                        chunk for chunk in record.get('retrieval', {}).get('chunks', [])
                        if int(chunk.get('message_index', -1) or -1) in selected_message_indices
                    ]
                relevant_chunks = []
                strategy = 'keyword'
                if embedding_ok and embedding_config is not None:
                    try:
                        relevant_chunks = retrieve_conversation_chunks(
                            retrieval_record,
                            question_text,
                            embedding_config['api_key'],
                            embedding_config['endpoint'],
                            embedding_config['timeout'],
                            embedding_config['model'],
                        )
                        strategy = 'embedding'
                    except Exception:
                        relevant_chunks = []
                if not relevant_chunks:
                    relevant_chunks = keyword_retrieve_conversation_chunks(retrieval_record, question_text)
                    strategy = 'keyword'
                # print_retrieval_debug('conversation', strategy, question_text, relevant_chunks)
                convo_block = build_conversation_context_block(retrieval_record, relevant_chunks) or build_history_context(history_messages)
            if convo_block:
                blocks.append(convo_block)

        return '\n\n'.join(block for block in blocks if block).strip()

    def _build_saved_memory_prompt_context(self, question_text: str) -> str:
        embedding_config = load_embedding_runtime_config()
        embedding_ok = False
        if embedding_config is not None:
            embedding_ok, _ = probe_embedding_capability(embedding_config['profile'])
        return build_saved_memory_context(question_text, embedding_config, embedding_ok)

    def _build_external_context_prompt_context(self, question_text: str, progress_callback=None) -> str:
        store = load_settings_store()
        globals_store = store.get('globals', {}) if isinstance(store, dict) else {}
        if not bool(globals_store.get('external_context_enabled', True)):
            return ''
        sources = normalize_external_context_sources(globals_store.get('external_context_sources', []))
        if not sources:
            return ''
        documents = collect_external_context_documents(sources, question_text, progress_callback)
        if not documents:
            return ''
        max_chars = normalize_external_context_max_chars(
            globals_store.get('external_context_max_chars', DEFAULT_EXTERNAL_CONTEXT_MAX_CHARS)
        )
        total_chars = sum(len(str(document.get('content', '') or '')) for document in documents)
        if total_chars <= max_chars:
            return build_external_context_full_block(documents, max_chars)

        chunks = build_attachment_retrieval_chunks(documents)
        if not chunks:
            return ''
        relevant_chunks = []
        embedding_config = load_embedding_runtime_config()
        embedding_ok = False
        if embedding_config is not None:
            embedding_ok, _ = probe_embedding_capability(embedding_config['profile'])
        if bool(globals_store.get('external_context_use_embedding', True)) and embedding_ok and embedding_config is not None:
            try:
                relevant_chunks = retrieve_attachment_chunks(
                    chunks,
                    question_text,
                    embedding_config['api_key'],
                    embedding_config['endpoint'],
                    embedding_config['timeout'],
                    embedding_config['model'],
                )
            except Exception:
                relevant_chunks = []
        if not relevant_chunks:
            relevant_chunks = keyword_retrieve_attachment_chunks(chunks, question_text)
        mcp_chunks = [chunk for chunk in chunks if chunk.get('source_type') in {'mcp_http', 'mcp_stdio'}]
        if mcp_chunks:
            seen = {(chunk.get('name'), chunk.get('text')) for chunk in mcp_chunks[:MCP_HTTP_CONTEXT_MAX_TOOL_CALLS]}
            relevant_chunks = (
                mcp_chunks[:MCP_HTTP_CONTEXT_MAX_TOOL_CALLS]
                + [chunk for chunk in relevant_chunks if (chunk.get('name'), chunk.get('text')) not in seen]
            )
        return build_external_context_retrieval_block(relevant_chunks)

    def _ensure_active_conversation(self, first_question: str, history_messages: list[dict]):
        if self._active_conversation_path:
            return
        record = create_conversation_record(first_question, history_messages=history_messages)
        self._active_conversation_path = record['path']
        self._refresh_history_panel()

    def _save_active_conversation(self, messages: list[dict], new_outputs: list[dict] | None = None):
        if not messages:
            return
        if not self._active_conversation_path:
            self._bootstrap_conversation_from_messages(messages)
            if new_outputs:
                self._save_active_conversation(messages, new_outputs=new_outputs)
                return
            self._refresh_links_panel()
            self._refresh_outputs_panel()
            self._refresh_branch_state_from_current_conversation()
            return
        record = load_conversation_record(self._active_conversation_path)
        if record is None:
            self._bootstrap_conversation_from_messages(messages)
            if new_outputs:
                self._save_active_conversation(messages, new_outputs=new_outputs)
                return
            self._refresh_links_panel()
            self._refresh_outputs_panel()
            self._refresh_branch_state_from_current_conversation()
            return
        record['messages'] = list(messages)
        if new_outputs:
            record['outputs'] = merge_output_records(record.get('outputs', []), new_outputs)
        record['title'] = conversation_title_from_messages(messages, fallback=record['title'])
        record['updated_at'] = datetime.datetime.now().isoformat(timespec='seconds')
        record['rendered_markdown'] = render_chat_history_markdown(messages)
        saved = write_conversation_record(self._active_conversation_path, record)
        self._active_conversation_path = saved['path']
        self._refresh_history_panel()
        self._refresh_links_panel()
        self._refresh_outputs_panel(prefer_latest=True)
        self._refresh_branch_state_from_current_conversation()

    def _load_conversation_from_path(self, path: str):
        record = load_conversation_record(path)
        if record is None:
            return
        self._mcp_conversation_allowlist = set()
        self._active_conversation_path = record['path']
        save_chat_history_messages(record['messages'])
        self.trans = 0
        self.text1.clear()
        self._set_prompt_edit_read_only(False)
        self._attachment_tray.clear()
        if record['messages']:
            self.render_final_output(record['rendered_markdown'], history_messages=record['messages'])
        else:
            self.show_welcome_state()
        self._restore_webfetch_from_conversation_record(record)
        self._refresh_links_panel()
        self._refresh_outputs_panel()
        self._refresh_branch_state_from_current_conversation()
        self.hide_history_panel()

    def _rename_conversation(self, path: str, new_title: str):
        updated = rename_conversation_record(path, new_title)
        if updated is None:
            return
        if path in self._branch_states:
            self._branch_states[updated['path']] = self._branch_states.pop(path)
            self._branch_states[updated['path']]['conversation_path'] = updated['path']
        if self._active_conversation_path == path:
            self._active_conversation_path = updated['path']
        self._refresh_history_panel()
        self._refresh_links_panel()
        self._refresh_outputs_panel()
        self._refresh_branch_state_from_current_conversation()

    def _delete_conversation(self, path: str):
        if not os.path.exists(path):
            return
        attach_dir = conversation_attachment_dir(path)
        os.remove(path)
        if os.path.isdir(attach_dir):
            shutil.rmtree(attach_dir, ignore_errors=True)
        self._branch_states.pop(path, None)
        if self._active_conversation_path == path:
            self._active_conversation_path = None
            self.ClearX()
        self._refresh_history_panel()
        self._refresh_links_panel()

    def apply_webfetch_watch_settings(self, folder: str):
        folder = str(folder or '').strip()
        self._webfetch_watch_manager.start(folder)

    def _on_webfetch_watch_status_changed(self, message: str):
        self._webfetch_watch_status = str(message or '').strip()

    def _on_webfetch_file_imported(self, record: dict):
        self._webfetch_records = [
            item for item in self._webfetch_records
            if str(item.get('path', '')).strip() != str(record.get('path', '')).strip()
        ]
        self._webfetch_records.append(record)
        self._webfetch_records.sort(key=lambda item: str(item.get('exported_at', '')).strip(), reverse=True)
        self._webfetch_panel_dismissed = False
        self._webfetch_generated_attachment = None
        self.webfetch_panel.append_export_record(record)
        current_index = self.stacked_widget.currentIndex()
        panel, _dock = self._external_prompt_panel_for_index(current_index)
        if current_index == 1 or (panel is not None and panel.is_prompt_dock_visible()):
            self.webfetch_panel.set_collapsed(False)
            self._show_webfetch_panel()

    def _close_webfetch_panel(self):
        self._webfetch_panel_dismissed = True
        previous = self._webfetch_generated_attachment or {}
        previous_path = str(previous.get('stored_path', '')).strip()
        if previous_path and os.path.exists(previous_path):
            try:
                os.remove(previous_path)
            except Exception:
                pass
        self.webfetch_panel.hide()
        self._webfetch_generated_attachment = None

    def _on_webfetch_selection_changed(self):
        self._webfetch_generated_attachment = None
        if self._active_conversation_path:
            self._persist_current_webfetch_selection(self._active_conversation_path)

    def _on_webfetch_panel_collapsed(self, collapsed: bool):
        if not hasattr(self, 'webfetch_panel'):
            return
        target = self._webfetch_panel_rect()
        if not self.webfetch_panel.isVisible():
            self.webfetch_panel.setGeometry(target)
            return
        start = self.webfetch_panel.geometry()
        if start == target:
            return
        self._webfetch_panel_anim = QPropertyAnimation(self.webfetch_panel, b'geometry', self)
        self._webfetch_panel_anim.setDuration(180)
        self._webfetch_panel_anim.setEasingCurve(QEasingCurve.Type.OutCubic)
        self._webfetch_panel_anim.setStartValue(start)
        self._webfetch_panel_anim.setEndValue(target)
        self._webfetch_panel_anim.start()

    def _webfetch_panel_rect(self) -> QRect:
        collapsed = self.webfetch_panel.is_collapsed()
        width = self.webfetch_panel.COLLAPSED_D if collapsed else self.webfetch_panel.PANEL_W
        height = self.webfetch_panel.COLLAPSED_D if collapsed else self.webfetch_panel.PANEL_H
        if collapsed:
            x = max(20, self.qw3.width() - width - 20)
        else:
            x = max(0, (self.qw3.width() - width) // 2)
        top_bar_bottom = 0
        if getattr(self, 'pill_nav', None) is not None:
            try:
                top_bar_bottom = self.qw3.mapFrom(self, self.pill_nav.geometry().bottomLeft()).y() + 22
            except Exception:
                top_bar_bottom = 0
        y = max(58, top_bar_bottom)
        return QRect(x, y, width, height)

    def _update_webfetch_panel_geometry(self):
        if not hasattr(self, 'webfetch_panel'):
            return
        self.webfetch_panel.setGeometry(self._webfetch_panel_rect())
        self.webfetch_panel.raise_()

    def _show_webfetch_panel(self):
        if self._webfetch_panel_dismissed:
            return
        current_index = self.stacked_widget.currentIndex()
        panel, _dock = self._external_prompt_panel_for_index(current_index)
        if current_index != 1 and not (panel is not None and panel.is_prompt_dock_visible()):
            return
        target = self._webfetch_panel_rect()
        if not self.webfetch_panel.isVisible():
            self.webfetch_panel.setGeometry(target)
            self.webfetch_panel.show()
        else:
            self._update_webfetch_panel_geometry()
        self.webfetch_panel.show()
        self.webfetch_panel.raise_()

    def _selected_webfetch_pages(self) -> list[dict]:
        if self._webfetch_panel_dismissed:
            return []
        return self.webfetch_panel.selected_pages()

    def _persist_current_webfetch_selection(self, conversation_path: str) -> dict | None:
        pages = self._selected_webfetch_pages()
        previous = self._webfetch_generated_attachment or {}
        previous_path = str(previous.get('stored_path', '')).strip()
        if not pages or not conversation_path:
            if previous_path and os.path.exists(previous_path):
                try:
                    os.remove(previous_path)
                except Exception:
                    pass
            self._webfetch_generated_attachment = None
            return None
        attach_dir = conversation_attachment_dir(conversation_path)
        os.makedirs(attach_dir, exist_ok=True)
        if previous_path and os.path.exists(previous_path):
            try:
                os.remove(previous_path)
            except Exception:
                pass
        payload = {
            'schema': 'broccoli-webfetch-selection/v1',
            'generatedAt': datetime.datetime.now().isoformat(timespec='seconds'),
            'sources': [
                {
                    'path': str(page.get('_source_path', '')).strip(),
                    'url': str(page.get('url', '')).strip(),
                    'title': str(page.get('title', '')).strip(),
                }
                for page in pages
            ],
            'count': len(pages),
            'pages': pages,
        }
        safe_name = f"Broccoli-WebFetch-Selection_{datetime.datetime.now().strftime('%Y-%m-%dT%H-%M-%S')}_{len(pages)}pages.json"
        target_path = os.path.join(attach_dir, safe_name)
        with open(target_path, 'w', encoding='utf-8') as handle:
            json.dump(payload, handle, ensure_ascii=False, indent=2)
        stored_rel_path = os.path.relpath(target_path, os.path.dirname(conversation_path))
        documents = webfetch_documents_from_pages(pages)
        extracted_text = '\n\n'.join(doc['content'] for doc in documents).strip()
        use_embedding = self._webfetch_context_use_embedding_enabled()
        retrieval_chunks = build_attachment_retrieval_chunks(documents) if use_embedding else []
        attachment_record = {
            'name': os.path.basename(target_path),
            'kind': 'json',
            'original_path': '',
            'stored_path': target_path,
            'stored_rel_path': stored_rel_path,
            'send_mode': 'retrieval_text' if use_embedding else 'text_direct',
            'use_embedding': use_embedding,
            'extracted_text': extracted_text,
            'pages': pages,
            'source_path': '',
        }
        if retrieval_chunks:
            attachment_record['retrieval_chunks'] = retrieval_chunks
        self._webfetch_generated_attachment = attachment_record
        return attachment_record

    def _current_webfetch_attachment(self, conversation_path: str) -> dict | None:
        if not conversation_path:
            return None
        if self._webfetch_generated_attachment:
            stored_path = str(self._webfetch_generated_attachment.get('stored_path', '')).strip()
            if (
                stored_path
                and os.path.exists(stored_path)
                and bool(self._webfetch_generated_attachment.get('use_embedding')) == self._webfetch_context_use_embedding_enabled()
            ):
                return self._webfetch_generated_attachment
        return self._persist_current_webfetch_selection(conversation_path)

    def _schedule_daily_memory_rollup(self):
        if not hasattr(self, '_daily_memory_timer'):
            return
        self._daily_memory_timer.stop()
        now = datetime.datetime.now()
        target = now.replace(hour=23, minute=30, second=0, microsecond=0)
        if now >= target:
            target += datetime.timedelta(days=1)
        delay_ms = max(1000, int((target - now).total_seconds() * 1000))
        self._daily_memory_timer.start(delay_ms)

    def _check_daily_memory_rollup_on_startup(self):
        store = load_settings_store()
        globals_store = store.get('globals', {})
        today = datetime.date.today().isoformat()
        now = datetime.datetime.now()
        if now.hour > 23 or (now.hour == 23 and now.minute >= 30):
            if str(globals_store.get('memory_last_rollup_date', '')).strip() != today:
                self._start_daily_memory_rollup(force=True)

    def _start_daily_memory_rollup(self, force: bool = False):
        if getattr(self, '_daily_memory_rollup_running', False):
            return
        self._schedule_daily_memory_rollup()
        self._daily_memory_rollup_running = True
        threading.Thread(
            target=self._run_daily_memory_rollup_worker,
            args=(force,),
            daemon=True,
        ).start()

    def _run_daily_memory_rollup_worker(self, force: bool = False):
        try:
            now = datetime.datetime.now()
            today = now.date().isoformat()
            store = load_settings_store()
            globals_store = store.get('globals', {})
            if not force and (now.hour < 23 or (now.hour == 23 and now.minute < 30)):
                return
            if str(globals_store.get('memory_last_rollup_date', '')).strip() == today:
                return

            retention_days = int(globals_store.get('memory_retention_days', 30) or 30)
            memory_items = normalize_memory_item_records(globals_store.get('memory_items', []))

            summaries = []
            for record in list_conversation_records():
                updated_at = str(record.get('updated_at', '')).strip()
                if not updated_at:
                    continue
                try:
                    updated_dt = datetime.datetime.fromisoformat(updated_at)
                except Exception:
                    continue
                if updated_dt.date().isoformat() != today:
                    continue
                summary = str(record.get('memory', {}).get('running_summary', '')).strip()
                if summary:
                    summaries.append(summary)

            profile = load_active_settings_profile()
            api_key = str(profile.get('api_key', '')).strip()
            endpoint = profile_runtime_base_url(profile)
            model = str(profile.get('model', '')).strip()
            try:
                timeout = int(profile.get('timeout', 60) or 60)
            except (TypeError, ValueError):
                timeout = 60

            daily_note = ''
            if summaries and api_key and model:
                try:
                    client = create_openai_client(api_key, endpoint, timeout)
                    rollup_messages = [
                        {
                            'role': 'system',
                            'content': (
                                'You create one concise daily memory note about the user. '
                                'Based only on the provided conversation summaries, extract the most important '
                                'details that should be remembered later. Include not only stable facts and current '
                                'status, but also user preferences, explicit requirements, repeated constraints, '
                                'working-style expectations, and how the user wants tasks or answers handled. '
                                'Prioritize instructions or preferences that could affect future responses or product behavior. '
                                'Return one short memory note only. If there is nothing worth remembering, return an empty response.'
                            ),
                        },
                        {
                            'role': 'user',
                            'content': 'Today conversation summaries:\n\n' + '\n\n'.join(f'- {summary}' for summary in summaries),
                        },
                    ]
                    response = client.chat.completions.create(
                        model=model,
                        messages=rollup_messages,
                        stream=False,
                    )
                    daily_note = (response.choices[0].message.content or '').strip()
                except Exception:
                    daily_note = ''

            updated_items = []
            for item in memory_items:
                if item.get('kind') == 'daily' and str(item.get('source_date', '')).strip() == today:
                    continue
                updated_items.append(item)
            if daily_note:
                updated_items.append(
                    {
                        'text': daily_note,
                        'created_at': now.isoformat(timespec='seconds'),
                        'kind': 'daily',
                        'source_date': today,
                    }
                )
            updated_items = prune_memory_item_records(updated_items, retention_days, now=now)

            globals_store['memory_items'] = updated_items
            globals_store['memory_last_rollup_date'] = today
            store['globals'] = globals_store
            save_settings_store(store)
        finally:
            self._daily_memory_rollup_running = False

    def _settings_panel_shown_rect(self):
        panel_w = self.settings_panel.width()
        panel_h = self.settings_panel.height()
        x = max(0, (self.qw3.width() - panel_w) // 2)
        y = max(24, (self.qw3.height() - panel_h) // 2)
        return QRect(
            x,
            y,
            panel_w,
            panel_h,
        )

    def _settings_panel_hidden_rect(self):
        shown = self._settings_panel_shown_rect()
        return QRect(shown.x(), self.qw3.height() + 24, shown.width(), shown.height())

    def _update_settings_overlay_geometry(self):
        if not hasattr(self, '_settings_scrim'):
            return
        qw3_pos = self.qw3.pos()
        self._settings_trigger_btn.setGeometry(
            qw3_pos.x() + 20,
            qw3_pos.y() + max(20, self.qw3.height() - self._settings_trigger_band_h),
            max(0, self.qw3.width() - 40),
            self._settings_trigger_band_h,
        )
        self._settings_trigger_btn.raise_()
        self._settings_scrim.setGeometry(self.qw3.rect())
        if self._settings_panel_visible:
            self.settings_panel.setGeometry(self._settings_panel_shown_rect())
        else:
            self.settings_panel.setGeometry(self._settings_panel_hidden_rect())

