    def _copy_plain_text_to_clipboard(self, text: str):
        value = str(text or '')
        if value:
            QApplication.clipboard().setText(value)

    def _refresh_terminal_history_panel(self):
        if hasattr(self, 'terminal_history_panel'):
            self.terminal_history_panel.set_sources(
                parse_zsh_history_records(),
                load_terminal_history_records(),
            )

    def _delete_terminal_history_record(self, record_id: str):
        record_id = str(record_id or '').strip()
        if not record_id:
            return
        records = [
            item for item in load_terminal_history_records()
            if str(item.get('id', '') or '').strip() != record_id
        ]
        save_terminal_history_records(records)
        self._refresh_terminal_history_panel()

    def _refresh_terminal_favorites_panel(self):
        if hasattr(self, 'terminal_favorites_panel'):
            self.terminal_favorites_panel.set_favorites(load_terminal_favorite_records())

    def _add_terminal_favorite_from_text(self, text: str):
        command = str(text or '').strip()
        if command and upsert_terminal_favorite(command):
            self._refresh_terminal_favorites_panel()

    def _delete_terminal_favorite(self, record_id: str):
        record_id = str(record_id or '').strip()
        if not record_id:
            return
        records = [item for item in load_terminal_favorite_records() if str(item.get('id', '')).strip() != record_id]
        save_terminal_favorite_records(records)
        self._refresh_terminal_favorites_panel()

    def _edit_terminal_favorite(self, record_id: str):
        record_id = str(record_id or '').strip()
        if not record_id:
            return
        records = load_terminal_favorite_records()
        current = None
        current_index = -1
        for index, record in enumerate(records):
            if str(record.get('id', '')).strip() == record_id:
                current = record
                current_index = index
                break
        if current is None:
            return
        dialog = TerminalFavoriteEditDialog(
            caption=str(current.get('caption', '') or ''),
            command=str(current.get('command', '') or ''),
            parent=self,
        )
        if dialog.exec() != QDialog.DialogCode.Accepted:
            return
        command = dialog.command()
        if not command:
            return
        updated = dict(current)
        updated['caption'] = dialog.caption()
        updated['command'] = command
        updated['updated_at'] = datetime.datetime.now().isoformat(timespec='seconds')
        normalized = normalize_terminal_favorite_record(updated)
        if normalized is None:
            return
        records[current_index] = normalized
        save_terminal_favorite_records(records)
        self._refresh_terminal_favorites_panel()

