        self._settings_panel_anim.setDuration(260)
        self._settings_panel_anim.setStartValue(start_rect)
        self._settings_panel_anim.setEndValue(end_rect)
        self._settings_panel_anim.setEasingCurve(QEasingCurve.Type.OutCubic)

        self._settings_scrim_anim = QPropertyAnimation(self._settings_scrim_opacity, b'opacity', self)
        self._settings_scrim_anim.setDuration(220)
        self._settings_scrim_anim.setStartValue(0.0)
        self._settings_scrim_anim.setEndValue(1.0)
        self._settings_scrim_anim.setEasingCurve(QEasingCurve.Type.OutCubic)

