    def hide_settings_panel(self):
        if not self._settings_panel_visible:
            return
        if self._settings_panel_anim is not None:
            self._settings_panel_anim.stop()
        if self._settings_scrim_anim is not None:
            self._settings_scrim_anim.stop()

        start_rect = self.settings_panel.geometry()
        end_rect = self._settings_panel_hidden_rect()
        start_opacity = self._settings_scrim_opacity.opacity()
        self._settings_panel_visible = False
        if self.settings_panel.hotkey_manager is not None:
            self.settings_panel.hotkey_manager.cancel_recording()
        self.settings_panel.reset_record_buttons()

        self._settings_panel_anim = QPropertyAnimation(self.settings_panel, b'geometry', self)
        self._settings_panel_anim.setDuration(220)
        self._settings_panel_anim.setStartValue(start_rect)
        self._settings_panel_anim.setEndValue(end_rect)
        self._settings_panel_anim.setEasingCurve(QEasingCurve.Type.InCubic)
        self._settings_panel_anim.finished.connect(self._finish_hide_settings_panel)

        self._settings_scrim_anim = QPropertyAnimation(self._settings_scrim_opacity, b'opacity', self)
        self._settings_scrim_anim.setDuration(200)
