    def timeout_handler(self, signum, frame):
        raise TimeoutException("Timeout")

    def request_real2_scroll_to_bottom(self, delay_ms=0):
        def scroll():
            self.real2.page().runJavaScript("window.scrollTo(0, document.body.scrollHeight);")

        QTimer.singleShot(delay_ms, scroll)
        QTimer.singleShot(delay_ms + 120, scroll)

    def scroll_text_widget_to_end(self, widget):
        widget.ensureCursorVisible()
        cursor = widget.textCursor()
        cursor.setPosition(len(widget.toPlainText()))
        widget.setTextCursor(cursor)

