    def show_welcome_state(self):
        self._active_render_request_id += 1
        self.cleanup_async_render()
        self._pending_real2_scroll = False
        self.real1.clear()
        self.real2.setHtml(self.welcome_html())
        self.real1.setVisible(False)
        self.real2.setVisible(True)
        self.drawing_layer.setVisible(self.stacked_widget.currentIndex() == 1)

    def render_stream_preview(self, text: str):
        self._active_render_request_id += 1
        self.cleanup_async_render()
        self._pending_real2_scroll = False
        self.real1.setPlainText(text)
        self.scroll_text_widget_to_end(self.real1)
        self.real1.setVisible(True)
        self.real2.setVisible(False)
        self.drawing_layer.setVisible(False)

    def render_final_output(self, markdown_text: str, history_messages: list[dict] | None = None, display_prefix_html: str = ''):
        self.cleanup_async_render()
        self._active_render_request_id += 1
        request_id = self._active_render_request_id
        self._active_render_signals = AsyncRenderSignals()
        self._active_render_signals.finished.connect(
            self.on_async_render_finished,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_render_signals.failed.connect(
            self.on_async_render_failed,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_render_thread = AsyncRenderThread(
            {
                'request_id': request_id,
                'markdown_text': str(markdown_text or ''),
                'history_messages': list(history_messages or []),
                'dark': is_dark_theme(app),
                'display_prefix_html': str(display_prefix_html or ''),
            },
            self._active_render_signals,
        )
        self._active_render_thread.start()

    def flush_chat_stream_preview(self):
        if not self._active_chat_request:
            return
        preview = build_chat_preview(
            self._active_chat_request['history_messages'],
            self._active_chat_request['question_text'],
            self._active_chat_request['answer'],
        )
        self.render_stream_preview(preview)

    def start_async_preflight_request(self, config: dict):
        self._active_preflight_request = {'config': config, 'progress_lines': []}
        self._active_preflight_signals = AsyncPreflightSignals()
        self._active_preflight_signals.progress.connect(
            self.on_async_preflight_progress,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_preflight_signals.finished.connect(
            self.on_async_preflight_finished,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_preflight_signals.failed.connect(
            self.on_async_preflight_failed,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_preflight_thread = AsyncPreflightThread(self, config, self._active_preflight_signals)
        self._active_preflight_thread.start()

    def start_async_chat_request(self, config: dict):
        self._active_chat_request = {
            'config': config,
            'history_messages': list(config['history_messages']),
            'storage_history_messages': list(config.get('storage_history_messages') or config['history_messages']),
            'question_text': config['question_text'],
            'answer': '',
            'status_lines': [],
        }
        self._active_chat_signals = AsyncChatSignals()
        self._active_chat_signals.delta.connect(
            self.on_async_chat_delta,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_chat_signals.status.connect(
            self.on_async_chat_status,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_chat_signals.tool_permission.connect(
            self.on_mcp_tool_permission_requested,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_chat_signals.finished.connect(
            self.on_async_chat_finished,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_chat_signals.failed.connect(
            self.on_async_chat_failed,
            Qt.ConnectionType.QueuedConnection,
        )
        self._active_chat_thread = AsyncChatThread(config, self._active_chat_signals)
        self._active_chat_thread.start()

    def cleanup_async_preflight(self):
        self._active_preflight_request = None
        self._active_preflight_signals = None
        self._active_preflight_thread = None

    def cleanup_async_render(self):
        self._active_render_signals = None
        self._active_render_thread = None

    def _launch_main_chat_request(self,
                                  *,
                                  raw_question: str,
                                  history_messages: list[dict],
                                  storage_history_messages: list[dict],
                                  attachments: list,
                                  attachment_records: list[dict],
                                  attachment_references: str,
                                  attachment_context: str,
                                  history: str,
                                  shared_context: str,
                                  api_key: str,
                                  endpoint: str,
                                  modelnow: str,
                                  timeout: int,
                                  mode_index: int,
                                  plan: dict | None = None,
                                  step_results: list[dict] | None = None):
        plan = plan or {'steps': [], 'finalize_with_default_chat': False, 'reason': ''}
        step_results = step_results or []
        pipeline_prefix = build_pipeline_display_prefix(plan, step_results) if step_results else ''

        prompt_input = raw_question
        if attachment_context:
            prompt_input = (
                'Use the following excerpts from attached documents if relevant:\n'
                + attachment_context
                + '\n\nUser request:\n'
                + raw_question
            )
        if step_results:
            prompt_input = build_finalize_prompt(raw_question, shared_context, step_results)

        prompt = prompt_input
        reststr = (history + '\n---\n' + prompt_input) if history else prompt_input
        if mode_index == 0:
            if step_results:
                prompt = prompt_input
            else:
                prompt = "You should only answer the last question but also refer to the prior questions as the background:" + reststr
        if mode_index == 1:
            prompt = f"""Reply only the Applescript to fullfill this command. Don't reply any other explanations. Before the code starts, write "「「START」」" and write "「「END」」" after it ends. Don't reply with method that needs further information and revision. Command: {prompt_input}. """
        if mode_index == 2:
            prompt = build_translation_prompt(prompt_input, self.widget1.currentText(), self.widget2.currentText())
        if mode_index == 3:
            prompt = f"""Revise the text in {self.widget4.currentText()} to remove grammar mistakes and make it more clear, concise, and coherent. Don't reply any other explanations. Before the text starts, write "「「START」」" and write "「「END」」" after it ends. Text: {prompt_input}. """
        if mode_index == 4:
            prompt = f"""You are a text summarizer, you can only summarize the text, don't interpret it. Summarize this text in {self.widget4.currentText()} to make it shorter, logical and clear. Don't reply any other explanations. Before the text starts, write "「「START」」" and write "「「END」」" after it ends. Text: {prompt_input}. """
        if mode_index == 5:
            prompt = f"""You are an expert in semantics and grammar, teaching me how to learn. Please explain in {self.widget4.currentText()} the meaning of every word in the text above and the meaning and the grammar structure of the text. If a word is part of an idiom, please explain the idiom and provide a few examples in {self.widget4.currentText()} with similar meanings, along with their explanations. Before the text starts, write "「「START」」" and write "「「END」」" after it ends. Text: {prompt_input}. """
        if mode_index == 6:
            prompt = f"""You are a code explanation engine, you can only explain the code, do not interpret or translate it. Also, please report any bugs you find in the code to the author of the code. Must repeat in {self.widget4.currentText()}. Before the text starts, write "「「START」」" and write "「「END」」" after it ends. Code: {prompt_input}. """
        if mode_index == 0:
            prompt = prompt + '\n\n' + OUTPUT_CAPTURE_INSTRUCTIONS

        messages = [
            {
                "role": "system",
                "content": (
                    "You are an artificial intelligence assistant and you need to "
                    "engage in a helpful, detailed, polite conversation with a user."
                ),
            },
            {
                "role": "user",
                "content": prompt,
            },
        ]
        globals_store = load_settings_store().get('globals', {})
        mcp_sources = normalize_external_context_sources(globals_store.get('external_context_sources', []))

        self.start_async_chat_request(
            {
                'api_key': api_key,
                'endpoint': endpoint,
                'model': modelnow,
                'messages': messages,
                'timeout': timeout,
                'stream': True,
                'mode_index': mode_index,
                'history_messages': history_messages,
                'storage_history_messages': storage_history_messages,
                'question_text': raw_question,
                'attachments': attachments,
                'attachment_references': attachment_references,
                'attachment_records': attachment_records,
                'show_references': read_text_file(BasePath + 'showref.txt', '0') == '1',
                'pipeline_prefix': pipeline_prefix,
                'pipeline_heading': (
                    f'<div class="pipeline-default-heading"><strong>Default chat · {html.escape(modelnow)}</strong></div>'
                    if step_results else ''
                ),
                'step_results': step_results,
                'mcp_tool_runtime_enabled': bool(globals_store.get('mcp_tool_runtime_enabled', True)),
                'mcp_sources': mcp_sources,
                'mcp_conversation_allowlist': self._mcp_conversation_allowlist,
            }
        )

    def on_async_preflight_progress(self, message: str):
        if not self._active_preflight_request:
            return
        message = str(message or '').strip()
        if not message:
            return
        lines = self._active_preflight_request.setdefault('progress_lines', [])
        if not lines or lines[-1] != message:
            lines.append(message)
        del lines[:-10]
        config = self._active_preflight_request.get('config', {})
        progress_text = 'Preparing context and planning tasks...\n\n' + '\n\n'.join(lines)
        self.render_stream_preview(
            build_chat_preview(
                list(config.get('history_messages') or []),
                str(config.get('question_text', '') or ''),
                progress_text,
            )
        )

    def on_async_preflight_finished(self, payload: dict):
        if not self._active_preflight_request:
            return
        config = self._active_preflight_request['config']
        self.cleanup_async_preflight()
        if payload.get('cancelled'):
            self._set_prompt_edit_read_only(False)
            self._restore_send_button()
            return
        self._launch_main_chat_request(
            raw_question=config['question_text'],
            history_messages=list(config['history_messages']),
            storage_history_messages=list(config.get('storage_history_messages') or config['history_messages']),
            attachments=list(config['attachments']),
            attachment_records=list(config['attachment_records']),
            attachment_references=str(payload.get('attachment_references', '') or ''),
            attachment_context=str(payload.get('attachment_context', '') or ''),
            history=str(payload.get('history', '') or ''),
            shared_context=str(payload.get('shared_context', '') or ''),
            api_key=str(config['api_key']),
            endpoint=str(config['endpoint']),
            modelnow=str(config['model']),
            timeout=int(config['timeout']),
            mode_index=int(config['mode_index']),
            plan=payload.get('plan') or {'steps': [], 'finalize_with_default_chat': False, 'reason': ''},
            step_results=list(payload.get('step_results') or []),
        )

    def on_async_preflight_failed(self, error_text: str):
        if not self._active_preflight_request:
            return
        config = self._active_preflight_request['config']
        history_messages = list(config.get('storage_history_messages') or config['history_messages'])
        raw_question = str(config['question_text'])
        attachment_records = list(config.get('attachment_records') or [])
        self.cleanup_async_preflight()
        new_messages, final_text = append_chat_turn(
            history_messages,
            raw_question,
            f'Error, please try again!{error_text}',
            attachments=attachment_records,
        )
        self.render_final_output(final_text, history_messages=new_messages)
        self._save_active_conversation(new_messages)
        self._append_question_to_branch_state(raw_question, max(0, len(new_messages) - 2))
        self.text1.setPlainText(self.LastQ)
        self._set_prompt_edit_read_only(False)
        self._restore_send_button()

    def on_async_chat_delta(self, delta: str):
        if not self._active_chat_request:
            return
        self._active_chat_request['answer'] += delta
        if not self._chat_stream_timer.isActive():
            self._chat_stream_timer.start(80)

    def on_async_chat_status(self, message: str):
        if not self._active_chat_request:
            return
        if self._active_chat_request.get('answer'):
            return
        message = str(message or '').strip()
        if not message:
            return
        lines = self._active_chat_request.setdefault('status_lines', [])
        if not lines or lines[-1] != message:
            lines.append(message)
        del lines[:-8]
        status_text = 'Running MCP tools...\n' + '\n'.join(f'- {line}' for line in lines)
        self.render_stream_preview(
            build_chat_preview(
                self._active_chat_request['history_messages'],
                self._active_chat_request['question_text'],
                status_text,
            )
        )

    def on_mcp_tool_permission_requested(self, request: dict):
        try:
            source_name = str(request.get('source_name', 'MCP source') or 'MCP source')
            tool_name = str(request.get('tool_name', '') or '')
            arguments = request.get('arguments') or {}
            message = (
                f'MCP tool call requires confirmation.\n\n'
                f'Source: {source_name}\n'
                f'Tool: {tool_name}\n'
                f'Read-only source: {"yes" if request.get("read_only", True) else "no"}\n'
                f'Potential write operation: {"yes" if request.get("mutating", False) else "no"}\n\n'
                f'Arguments:\n{json.dumps(arguments, ensure_ascii=False, indent=2)[:1200]}'
            )
            clicked = ask_broccoli_message(
                self,
                'Allow MCP Tool Call',
                message,
                ['Deny', 'Allow once', 'Always allow this conversation'],
                default_button_text='Allow once',
                size=QSize(560, 420),
            )
            if clicked == 'Always allow this conversation':
                request['decision'] = 'always'
                key = str(request.get('permission_key', '') or '')
                if key:
                    self._mcp_conversation_allowlist.add(key)
            elif clicked == 'Allow once':
                request['decision'] = 'allow'
            else:
                request['decision'] = 'deny'
        finally:
            event = request.get('event')
            if event is not None:
                event.set()

    def _restore_send_button(self):
        """Switch btn_sub1 back from ⏹ Stop → 🔺 Send and restore its shortcut."""
        try:
            self.btn_sub1.clicked.disconnect()
        except Exception:
            pass
        self.btn_sub1.setText('🔺 Send')
        self.btn_sub1.clicked.connect(self.SendX)
        self.btn_sub1.setShortcut("Ctrl+Return")
        self.btn_sub1.setDisabled(False)

    def StopX(self):
        """Immediately stop the running generation and render whatever was received."""
        if self._active_preflight_request:
            if self._active_preflight_thread is not None:
                self._active_preflight_thread.request_stop()
            self.cleanup_async_preflight()
            self._set_prompt_edit_read_only(False)
            self._restore_send_button()
            return
        if not self._active_chat_request:
            return
        # Tell the background thread to exit its loop as soon as possible
        if self._active_chat_thread is not None:
            self._active_chat_thread.request_stop()
        # Flush any pending stream preview timer
        self._chat_stream_timer.stop()
        # Use whatever text has been accumulated so far as the final answer;
        # on_async_chat_finished performs all normal cleanup and rendering
        # (history save, markdown render, divider lines, etc.).
        answer_so_far = self._active_chat_request['answer']
        self.on_async_chat_finished({'answer': answer_so_far, 'references': ''})

    # ── Attachment tray handlers ──────────────────────────────────────────────

    def _on_assistant_drag_active(self, active: bool):
        """Show/hide the attachment tray drop-hint and animate wrapper while dragging."""
        if active:
            self._attachment_tray.show_drop_hint(True)
            self._show_tray_animated()
        else:
            self._attachment_tray.show_drop_hint(False)
            if not self._attachment_tray.has_cards():
                self._hide_tray_animated()

    def _on_files_dropped(self, paths: list):
        """Add dropped files to the attachment tray and animate it open."""
        for path in paths:
            self._attachment_tray.add_file(path)
        self._attachment_tray.show_drop_hint(False)
        self._show_tray_animated()

    def _load_last_screenshot_region(self) -> dict:
        try:
            with open(LAST_SCREENSHOT_REGION_PATH, 'r', encoding='utf-8') as handle:
                data = json.load(handle)
        except Exception:
            return {}
        return self._normalize_screenshot_region(data)

    def _normalize_screenshot_region(self, region: dict) -> dict:
        if not isinstance(region, dict):
            return {}
        try:
            x = int(region.get('x', 0))
            y = int(region.get('y', 0))
            width = int(region.get('width', 0))
            height = int(region.get('height', 0))
        except Exception:
            return {}
        if width < 2 or height < 2:
            return {}
        return {
            'x': x,
            'y': y,
            'width': width,
            'height': height,
            'screen_name': str(region.get('screen_name', '') or ''),
        }

    def _save_last_screenshot_region(self, region: dict):
        normalized = self._normalize_screenshot_region(region)
        if not normalized:
            return
        self._last_screenshot_region = normalized
        ensure_broccoli_data_dir()
        try:
            with open(LAST_SCREENSHOT_REGION_PATH, 'w', encoding='utf-8') as handle:
                json.dump(normalized, handle, ensure_ascii=False, indent=2)
        except Exception:
            logging.warning('Failed to persist last screenshot region.', exc_info=True)

    def _last_screenshot_region_intersects_screen(self, region: dict) -> bool:
        normalized = self._normalize_screenshot_region(region)
        if not normalized:
            return False
        rect = QRect(
            normalized['x'],
            normalized['y'],
            normalized['width'],
            normalized['height'],
        )
        for screen in QGuiApplication.screens() or []:
            if screen.geometry().intersects(rect):
                return True
        return False

    def _show_broccoli_message(self, title: str, message: str, button_text: str = 'OK'):
        show_broccoli_message(self, title, message, button_text)

    def start_region_capture(self):
        """Launch the custom screenshot overlay and send confirmed captures into the API attachment tray."""
        self._start_region_capture()

    def start_region_capture_for_external_prompt(self, tab_index: int):
        panel, dock = self._external_prompt_panel_for_index(tab_index)
        if panel is None or dock is None:
            return
        panel.set_prompt_dock_visible(True, animated=True)
        self._start_region_capture(target_dock=dock, target_panel=panel)

    def _start_region_capture(self, target_dock=None, target_panel=None):
        """Launch the custom screenshot overlay and route confirmed captures to the selected tray."""
        if self._screenshot_overlay is not None:
            try:
                self._screenshot_overlay.close()
            except Exception:
                pass
            self._screenshot_overlay = None
        self._screenshot_target_dock = target_dock
        self._screenshot_target_panel = target_panel
        win_handle = self.windowHandle()
        screen = QGuiApplication.screenAt(QCursor.pos())
        if screen is None and win_handle is not None:
            screen = win_handle.screen()
        if screen is None:
            screen = QGuiApplication.primaryScreen()
        if screen is None:
            self._show_broccoli_message("Screenshot", "No available screen found for capturing.")
            return
        overlay = ScreenshotSelectionOverlay(screen)
        overlay.screenshot_confirmed.connect(self._on_region_capture_confirmed)
        overlay.overlay_closed.connect(self._clear_region_capture_overlay)
        self._screenshot_overlay = overlay
        overlay.show()
        overlay.raise_()
        overlay.activateWindow()

    def _clear_region_capture_overlay(self):
        self._screenshot_overlay = None
        self._screenshot_target_dock = None
        self._screenshot_target_panel = None

    def _on_region_capture_confirmed(self, path: str):
        if not path or not os.path.exists(path):
            return
        overlay = getattr(self, '_screenshot_overlay', None)
        if overlay is not None and hasattr(overlay, 'last_capture_region'):
            self._save_last_screenshot_region(overlay.last_capture_region())
        target_dock = getattr(self, '_screenshot_target_dock', None)
        target_panel = getattr(self, '_screenshot_target_panel', None)
        if target_dock is not None and hasattr(target_dock, 'add_files'):
            if hasattr(target_dock, 'add_files_instant'):
                target_dock.add_files_instant([path])
            else:
                target_dock.add_files([path])
            if target_panel is not None and hasattr(target_panel, 'set_prompt_dock_visible'):
                target_panel.set_prompt_dock_visible(True, animated=True)
                QTimer.singleShot(0, lambda p=target_panel, d=target_dock: self._sync_external_prompt_dock_height(p, d))
                QTimer.singleShot(240, lambda p=target_panel, d=target_dock: self._sync_external_prompt_dock_height(p, d))
            return
        self._attachment_tray.add_file(path)
        self._attachment_tray.show_drop_hint(False)
        self._show_tray_animated()

    def capture_same_position_screenshot_and_send(self):
        if getattr(self, '_silent_screenshot_thread', None) is not None:
            return
        if getattr(self, '_active_preflight_request', None) or getattr(self, '_active_chat_request', None):
            self._show_broccoli_message('Screenshot', 'Current API answer is still running. Stop it before auto-sending another screenshot.')
            return
        region = self._normalize_screenshot_region(getattr(self, '_last_screenshot_region', {}))
        if not region:
            self._show_broccoli_message('Screenshot', 'No previous screenshot region found. Take one region screenshot first.')
            return
        if not self._last_screenshot_region_intersects_screen(region):
            self._show_broccoli_message('Screenshot', 'The previous screenshot region is outside the current screen layout.')
            return
        signals = SilentScreenshotSignals()
        signals.finished.connect(self.silent_screenshot_finished.emit)
        thread = SilentScreenshotThread(region, signals)
        thread.signals = signals
        self._silent_screenshot_thread = thread
        thread.start()

    def _on_silent_screenshot_finished(self, result: object):
        self._silent_screenshot_thread = None
        result = result if isinstance(result, dict) else {}
        path = str(result.get('path', '') or '')
        if not path or not os.path.exists(path):
            self._show_broccoli_message('Screenshot', str(result.get('error', '') or 'Silent screenshot failed.'))
            return
        self._attach_screenshot_to_current_tab_and_send(path)

    def _attach_screenshot_to_current_tab_and_send(self, path: str):
        current_index = self.stacked_widget.currentIndex()
        if current_index == 1:
            self._attachment_tray.add_file(path)
            self._attachment_tray.show_drop_hint(False)
            self._show_tray_animated()
            self._force_send_blank_prompt_once = True
            QTimer.singleShot(0, self.SendX)
            return
        if current_index in (0, 2):
            panel, dock = self._external_prompt_panel_for_index(current_index)
            if panel is not None and dock is not None:
                dock.add_files_instant([path])
                panel.set_prompt_dock_visible(True, animated=True)
                self._force_external_blank_prompt_once = True
                self._force_web_auto_send_once = True
                QTimer.singleShot(180, lambda tab=current_index: self.SendWebX(tab_index=tab))
            return
        if current_index == 3:
            terminal = getattr(self, 'terminal_widget', None)
            if terminal is not None and hasattr(terminal, 'add_context_files'):
                terminal.add_context_files([path])
            self._show_broccoli_message('Screenshot', 'Screenshot was added to Terminal attachments. Terminal does not support auto-send.')
            return
        self._show_broccoli_message('Screenshot', 'The current tab does not support attachment auto-send.')

    def _encode_current_attachments(self, conversation_path: str) -> tuple[list, list, list]:
        """Persist current tray files into the conversation and prepare send metadata."""
        return persist_conversation_attachments(conversation_path, self._attachment_tray.get_items())

    def _build_attachment_retrieval_context(self,
                                            question_text: str,
                                            documents: list[dict],
                                            api_key: str,
                                            endpoint: str,
                                            timeout: int) -> tuple[str, str]:
        chunks = build_attachment_retrieval_chunks(documents)
        if not chunks:
            return '', ''

        relevant_chunks = []
        embedding_config = load_embedding_runtime_config()
        embedding_ok = False
        strategy = 'keyword'
        if embedding_config is not None:
            embedding_ok, _ = probe_embedding_capability(embedding_config['profile'])

        if embedding_ok and embedding_config is not None:
            try:
                relevant_chunks = retrieve_attachment_chunks(
                    chunks,
                    question_text,
                    embedding_config['api_key'],
                    embedding_config['endpoint'],
                    embedding_config['timeout'],
                    embedding_config['model'],
                )
                strategy = 'embedding'
            except Exception:
                relevant_chunks = []

        if not relevant_chunks:
            relevant_chunks = keyword_retrieve_attachment_chunks(chunks, question_text)
            strategy = 'keyword'

        # print_retrieval_debug('attachment', strategy, question_text, relevant_chunks)

        return build_attachment_context_block(relevant_chunks), build_attachment_references(relevant_chunks)

    def _show_tray_animated(self):
        """Slide the attachment tray wrapper open (shrinks content widgets)."""
        self._attachment_tray.setVisible(True)   # tray hides itself on init; ensure it's shown
        if self._tray_anim.state() == QPropertyAnimation.State.Running:
            self._tray_anim.stop()
        cur = self._attachment_tray_wrap.height()
        if cur >= self._TRAY_WRAP_H:
            return
        self._tray_anim.setStartValue(cur)
        self._tray_anim.setEndValue(self._TRAY_WRAP_H)
        self._tray_anim.start()

    def _hide_tray_animated(self):
        """Slide the attachment tray wrapper closed (expands content widgets)."""
        if self._tray_anim.state() == QPropertyAnimation.State.Running:
            self._tray_anim.stop()
        cur = self._attachment_tray_wrap.height()
        if cur == 0:
            return
        self._tray_anim.setStartValue(cur)
        self._tray_anim.setEndValue(0)
        self._tray_anim.start()

    # ─────────────────────────────────────────────────────────────────────────

    def cleanup_async_chat(self):
        self._chat_stream_timer.stop()
        self._active_chat_request = None
        self._active_chat_signals = None
        self._active_chat_thread = None

    def on_async_render_finished(self, payload: dict):
        request_id = int(payload.get('request_id', 0) or 0)
        if request_id != self._active_render_request_id:
            return
        self.cleanup_async_render()
        self._pending_real2_scroll = True
        self.real2.setHtml(str(payload.get('html', '') or ''))
        self.real1.clear()
        self.real1.setVisible(False)
        self.real2.setVisible(True)
        self.drawing_layer.setVisible(self.stacked_widget.currentIndex() == 1)

    def on_async_render_failed(self, payload: dict):
        request_id = int(payload.get('request_id', 0) or 0)
        if request_id != self._active_render_request_id:
            return
        self.cleanup_async_render()
        self._pending_real2_scroll = True
        display_prefix_map = {}
        history_messages = list(payload.get('history_messages') or [])
        markdown_text = str(payload.get('markdown_text', '') or '')
        if history_messages:
            markdown_text, display_prefix_map = render_chat_history_display_markup(history_messages)
        html_text = self.md2html(
            markdown_text,
            display_prefix_html=str(payload.get('display_prefix_html', '') or ''),
            display_prefix_map=display_prefix_map,
        )
        self.real2.setHtml(html_text)
        self.real1.clear()
        self.real1.setVisible(False)
        self.real2.setVisible(True)
        self.drawing_layer.setVisible(self.stacked_widget.currentIndex() == 1)

    def on_async_chat_finished(self, payload: dict):
        if not self._active_chat_request:
            return

        config = self._active_chat_request['config']
        answer_text = payload.get('answer', '')
        pipeline_prefix = str(config.get('pipeline_prefix', '') or '').strip()
        pipeline_heading = str(config.get('pipeline_heading', '') or '').strip()
        display_prefix_html = ''.join(part for part in [pipeline_prefix, pipeline_heading] if part)
        references = payload.get('references', '')
        attachment_references = str(config.get('attachment_references', '') or '').strip()
        if attachment_references:
            references = '\n\n'.join(part for part in [str(references).strip(), attachment_references] if part)
        mode_index = config['mode_index']

        try:
            assistant_content, extracted = build_assistant_message_content(
                answer_text=answer_text,
                mode_index=mode_index,
                references=references,
                show_references=config.get('show_references', False),
            )
            structured_outputs = []
            if mode_index == 0:
                assistant_content, structured_outputs = split_structured_outputs_from_answer(assistant_content)
            elif extracted and mode_index == 1:
                structured_outputs.append(
                    {
                        'kind': 'code',
                        'title': 'Generated AppleScript',
                        'filename': 'command.applescript',
                        'content': extracted,
                        'source': 'mode_marker',
                    }
                )
            elif extracted and mode_index in (2, 3, 4):
                structured_outputs.append(
                    {
                        'kind': 'text',
                        'title': 'Generated text',
                        'filename': 'generated-text.txt',
                        'content': extracted,
                        'source': 'mode_marker',
                    }
                )
            new_messages, final_text = append_chat_turn(
                self._active_chat_request.get('storage_history_messages', self._active_chat_request['history_messages']),
                self._active_chat_request['question_text'],
                assistant_content,
                attachments=config.get('attachment_records'),
                assistant_display_prefix_html=display_prefix_html,
            )
            if mode_index == 1 and extracted:
                write_text_file(BasePath + 'command.txt', extracted)
            elif extracted and mode_index not in (0, 7):
                uid = os.getuid()
                env = os.environ.copy()
                env['__CF_USER_TEXT_ENCODING'] = f'{uid}:0x8000100:0x8000100'
                p = subprocess.Popen(['pbcopy', 'w'], stdin=subprocess.PIPE, env=env)
                p.communicate(input=extracted.encode('utf-8'))

            question_index = max(0, len(new_messages) - 2)
            assistant_index = max(0, len(new_messages) - 1)
            generated_outputs = self._build_output_records_for_turn(
                question_text=self._active_chat_request['question_text'],
                question_index=question_index,
                assistant_index=assistant_index,
                model_name=str(config.get('model', '') or ''),
                structured_outputs=structured_outputs,
                step_results=list(config.get('step_results') or []),
            )
            self.render_final_output(final_text, history_messages=new_messages)
            self._save_active_conversation(new_messages, new_outputs=generated_outputs)
            self._append_question_to_branch_state(self._active_chat_request['question_text'], question_index)
            if config.get('api_key') and config.get('endpoint'):
                self._refresh_active_conversation_runtime_data(
                    config['api_key'],
                    config['endpoint'],
                    config['model'],
                    config.get('timeout', 60),
                )
            self.text1.clear()
        except Exception as exc:
            new_messages, fallback = append_chat_turn(
                self._active_chat_request.get('storage_history_messages', self._active_chat_request['history_messages']),
                self._active_chat_request['question_text'],
                f'Error, please try again!{str(exc)}',
                attachments=config.get('attachment_records'),
                assistant_display_prefix_html=display_prefix_html,
            )
            self.render_final_output(fallback, history_messages=new_messages)
            self._save_active_conversation(new_messages)
            self._append_question_to_branch_state(self._active_chat_request['question_text'], max(0, len(new_messages) - 2))
            self.text1.setPlainText(self.LastQ)
        finally:
            self._set_prompt_edit_read_only(False)
            self._restore_send_button()
            self.cleanup_async_chat()
            if self._clear_attachments_after_send_enabled():
                self._attachment_tray.clear()

    def on_async_chat_failed(self, error_text: str):
        if not self._active_chat_request:
            return
        config = self._active_chat_request['config']
        pipeline_prefix = str(config.get('pipeline_prefix', '') or '').strip()
        pipeline_heading = str(config.get('pipeline_heading', '') or '').strip()
        display_prefix_html = ''.join(part for part in [pipeline_prefix, pipeline_heading] if part)
        fallback_error = f'Error, please try again!{error_text}'
        new_messages, final_text = append_chat_turn(
            self._active_chat_request.get('storage_history_messages', self._active_chat_request['history_messages']),
            self._active_chat_request['question_text'],
            fallback_error,
            attachments=config.get('attachment_records'),
            assistant_display_prefix_html=display_prefix_html,
        )
        self.render_final_output(final_text, history_messages=new_messages)
        self._save_active_conversation(new_messages)
        self._append_question_to_branch_state(self._active_chat_request['question_text'], max(0, len(new_messages) - 2))
        self.text1.setPlainText(self.LastQ)
        self._set_prompt_edit_read_only(False)
        self._restore_send_button()
        self.cleanup_async_chat()

    def on_page_load_finished(self, success):
        if success and self._pending_real2_scroll:
            self._pending_real2_scroll = False
            self.request_real2_scroll_to_bottom(60)

    def _get_userscript_sources(self):
        store = load_settings_store()
        records = store.get('globals', {}).get('userscripts', [])
        sources = []
        for i, r in enumerate(records):
            p = str(r.get('path', '')).strip()
            if p and os.path.isfile(p):
                try:
                    with open(p, 'r', encoding='utf-8') as f:
                        src = f.read().strip()
                    if src:
                        sources.append(build_qt_userscript_source(src, i))
                except Exception:
                    pass
        return sources

    def _web_panels(self):
        panels = []
        if hasattr(self, 'ai_web_panel'):
            panels.append(self.ai_web_panel)
        if hasattr(self, 'localhost_panel'):
            panels.append(self.localhost_panel)
        return panels

    def _inject_userscripts_into_view(self, view):
        sources = self._get_userscript_sources()
        if not sources:
            return
        combined = '\n;\n'.join(sources)
        view.page().runJavaScript(combined)

    def _reload_userscripts(self):
        sources = self._get_userscript_sources()
        for panel in self._web_panels():
            for view in getattr(panel, '_views', []):
                if view is None:
                    continue
                page = view.page()
                scripts = page.scripts()
                for existing in list(scripts.toList()):
                    if existing.name().startswith('userscript_'):
                        scripts.remove(existing)
                for i, source in enumerate(sources):
                    qs = QWebEngineScript()
                    qs.setName(f'userscript_{i}')
                    qs.setSourceCode(source)
                    qs.setInjectionPoint(QWebEngineScript.InjectionPoint.DocumentReady)
                    qs.setWorldId(QWebEngineScript.ScriptWorldId.MainWorld)
                    qs.setRunsOnSubFrames(False)
                    scripts.insert(qs)
                if sources:
                    page.runJavaScript('\n;\n'.join(sources))

    def _on_web_view_load_finished(self, _ok):
        view = self.sender()
        if view is not None:
            self._inject_userscripts_into_view(view)

    def _on_browser_bridge_request(self, payload: dict):
        if str(payload.get('action', '') or '').strip() == 'translate_popup':
            self._on_translate_popup_request(payload)
            return
        question = str(payload.get('question', '')).strip()
        context = str(payload.get('context', '')).strip()
        url = str(payload.get('url', '')).strip()
        title = str(payload.get('title', '')).strip()
        parts = []
        source_lines = []
        if title:
            source_lines.append(f'Title: {title}')
        if url:
            source_lines.append(f'URL: {url}')
        if source_lines:
            parts.append('[Source]\n' + '\n'.join(source_lines))
        if context:
            parts.append(f'[Selected text]\n{context}')
        if question:
            parts.append(question)
        if not parts:
            return
        composed = '\n\n'.join(parts)
        self.activateWindow()
        self.raise_()
        tab = self.stacked_widget.currentIndex()
        if tab == 1:
            self.text1.setPlainText(composed)
            self.SendX()
        elif tab in (0, 2):
            _panel, dock = self._external_prompt_panel_for_index(tab)
            if dock is not None:
                dock.prompt_edit.setPlainText(composed)
                self.SendExternalPromptDockX(tab)

    def _on_translate_popup_request(self, payload: dict):
        selected_text = (
            str(payload.get('text', '') or '').strip()
            or str(payload.get('context', '') or '').strip()
            or str(payload.get('selection', '') or '').strip()
        )
        if not selected_text:
            return
        window = TranslationPopupWindow(selected_text, owner=self)
        window.closed.connect(self._remove_translation_popup_window)
        self._translation_popup_windows.append(window)
        window.show_centered()

    def _remove_translation_popup_window(self, window):
        try:
            if window in self._translation_popup_windows:
                self._translation_popup_windows.remove(window)
        except Exception:
            pass

    def _save_background_translation_record(self, *, source_text: str, translated_text: str, source_language: str, target_language: str):
        source_text = str(source_text or '').strip()
        translated_text = str(translated_text or '').strip()
        if not source_text and not translated_text:
            return None
        ensure_broccoli_data_dir()
        now_iso = datetime.datetime.now().isoformat(timespec='seconds')
        timestamp = current_chat_timestamp()
        preview = sanitize_conversation_title(source_text or translated_text, max_len=34)
        title = sanitize_conversation_title(
            f'Translate {source_language} to {target_language}: {preview}',
            max_len=60,
        )
        convo_id = datetime.datetime.now().strftime('%Y%m%d-%H%M%S')
        filename = f"{convo_id}_{sanitize_conversation_filename(title)}.json"
        path = os.path.join(CONVERSATIONS_DIR, filename)
        suffix = 2
        while os.path.exists(path):
            filename = f"{convo_id}_{sanitize_conversation_filename(title)}-{suffix}.json"
            path = os.path.join(CONVERSATIONS_DIR, filename)
            suffix += 1
        messages = [
            {
                'role': 'user',
                'content': source_text,
                'timestamp': timestamp,
                'source': f'{POPCLIP_TRANSLATE_SOURCE} · {source_language}',
            },
            {
                'role': 'assistant',
                'content': translated_text,
                'timestamp': timestamp,
                'source': f'{POPCLIP_TRANSLATE_SOURCE} · {target_language}',
            },
        ]
        record = write_conversation_record(
            path,
            {
                'id': convo_id,
                'title': title,
                'created_at': now_iso,
                'updated_at': now_iso,
                'messages': messages,
                'rendered_markdown': render_chat_history_markdown(messages),
            },
        )
        try:
            self._refresh_history_panel()
        except Exception:
            pass
        return record

    def SendX(self):
        if self.trans % 2 == 1:
            all_text = read_file_contents(BasePath + 'output.txt', '')
            self.trans += 1
            self.real1.setReadOnly(True)
            self.real1.textChanged.disconnect(self.save_text)
            self.render_final_output(all_text)

        # Switch btn_sub1 to Stop mode while generating
        self.btn_sub1.clicked.disconnect()
        self.btn_sub1.setText('⛔️ Stop')
        self.btn_sub1.setShortcut("")          # clear shortcut — Ctrl+Return shouldn't send again
        self.btn_sub1.clicked.connect(self.StopX)
        # btn_sub1 stays enabled so the user can click to stop at any time

        globals_store = load_settings_store().get('globals', {})
        allow_blank_with_attachments = bool(globals_store.get('allow_blank_prompt_with_attachments', False))
        has_pending_attachments = bool(
            getattr(self, '_attachment_tray', None) is not None
            and self._attachment_tray.has_cards()
        )
        force_blank_prompt_once = bool(getattr(self, '_force_send_blank_prompt_once', False))
        self._force_send_blank_prompt_once = False
        can_send_blank_prompt = (
            allow_blank_with_attachments or force_blank_prompt_once
        ) and has_pending_attachments

        if self.text1.toPlainText() == '' and not can_send_blank_prompt:
            try:
                pasted = subprocess.check_output('pbpaste', env={'LANG': 'en_US.UTF-8'}).decode('utf-8')
                self.text1.setPlainText(pasted)
            except Exception:
                pass

        raw_question = self.text1.toPlainText()
        if raw_question == '' and not can_send_blank_prompt:
            self._restore_send_button()
            return
        skip_retrieval_for_blank_prompt = bool(
            globals_store.get('skip_retrieval_for_blank_prompt', False)
            and can_send_blank_prompt
            and not raw_question.strip()
        )

        self.LastQ = str(raw_question)
        self._set_prompt_edit_read_only(True)
        full_history_messages = get_current_chat_history_messages()
        temp_branch_state = self._branch_states.pop('__current__', None) if not self._active_conversation_path else None
        self._ensure_active_conversation(raw_question, full_history_messages)
        if temp_branch_state is not None and self._active_conversation_path and self._active_conversation_path not in self._branch_states:
            temp_branch_state['conversation_path'] = self._active_conversation_path
            self._branch_states[self._active_conversation_path] = temp_branch_state
        history_messages, selected_message_indices = self._filter_history_messages_by_branch(full_history_messages)
        if skip_retrieval_for_blank_prompt:
            history_messages = []
            selected_message_indices = set()
        attachments = []
        retrieval_documents = []
        attachment_records = []
        if self._active_conversation_path:
            attachments, retrieval_documents, attachment_records = self._encode_current_attachments(self._active_conversation_path)
            webfetch_attachment = self._current_webfetch_attachment(self._active_conversation_path)
            if webfetch_attachment is not None:
                attachment_records.append(webfetch_attachment)
                extracted_text = str(webfetch_attachment.get('extracted_text', '')).strip()
                if extracted_text:
                    webfetch_pages = [
                        page for page in (webfetch_attachment.get('pages') or [])
                        if isinstance(page, dict)
                    ]
                    if skip_retrieval_for_blank_prompt:
                        pass
                    elif bool(webfetch_attachment.get('use_embedding')):
                        retrieval_documents.extend(
                            webfetch_documents_from_pages(webfetch_pages)
                        )
                    else:
                        attachments.append({
                            'kind': 'text',
                            'name': str(webfetch_attachment.get('name', '') or 'Web page content'),
                            'content': extracted_text,
                        })
        modelnow = read_text_file(BasePath + 'modelnow.txt', DEFAULT_MODEL)
        api_key, endpoint = load_runtime_openai_client_config()
        if api_key == '':
            self._set_prompt_edit_read_only(False)
            self._restore_send_button()
            new_messages, final_text = append_chat_turn(
                full_history_messages,
                raw_question,
                'You should set your accounts in Settings.',
                attachments=attachment_records,
            )
            self.render_final_output(final_text, history_messages=new_messages)
            self._save_active_conversation(new_messages)
            self._append_question_to_branch_state(raw_question, max(0, len(new_messages) - 2))
            return

        self.render_stream_preview(build_chat_preview(history_messages, raw_question))

        timeout = load_saved_timeout()
        mode_index = self.widget0.currentIndex()
        if mode_index == 0:
            self.start_async_preflight_request(
                {
                    'question_text': raw_question,
                    'history_messages': history_messages,
                    'storage_history_messages': full_history_messages,
                    'retrieval_documents': retrieval_documents,
                    'attachment_records': attachment_records,
                    'attachments': attachments,
                    'api_key': api_key,
                    'endpoint': endpoint,
                    'model': modelnow,
                    'timeout': timeout,
                    'mode_index': mode_index,
                    'selected_message_indices': sorted(selected_message_indices),
                    'skip_retrieval_for_blank_prompt': skip_retrieval_for_blank_prompt,
                }
            )
            return

        attachment_context = ''
        attachment_references = ''
        if retrieval_documents and not skip_retrieval_for_blank_prompt:
            attachment_context, attachment_references = self._build_attachment_retrieval_context(
                raw_question,
                retrieval_documents,
                api_key,
                endpoint,
                timeout,
            )

        context_blocks = []
        active_profile = load_active_settings_profile()
        if not skip_retrieval_for_blank_prompt and read_text_file(BasePath + 'history.txt', '0') == '1':
            history_context = self._build_active_history_context(
                raw_question,
                history_messages,
                api_key,
                endpoint,
                modelnow,
                timeout,
                selected_message_indices=selected_message_indices,
            )
            if history_context:
                context_blocks.append(history_context)
        if not skip_retrieval_for_blank_prompt and active_profile.get('remember_memory', True):
            memory_context = self._build_saved_memory_prompt_context(raw_question)
            if memory_context:
                context_blocks.append(memory_context)
        if not skip_retrieval_for_blank_prompt:
            vision_context = self._build_background_vision_prompt_context()
            if vision_context:
                context_blocks.append(vision_context)
        history = '\n\n'.join(block for block in context_blocks if block).strip()
        shared_context = '\n\n'.join(block for block in ([history, attachment_context] if attachment_context else [history]) if block).strip()

        self._launch_main_chat_request(
            raw_question=raw_question,
            history_messages=history_messages,
            storage_history_messages=full_history_messages,
            attachments=attachments,
            attachment_records=attachment_records,
            attachment_references=attachment_references,
            attachment_context=attachment_context,
            history=history,
            shared_context=shared_context,
            api_key=api_key,
            endpoint=endpoint,
            modelnow=modelnow,
            timeout=timeout,
            mode_index=mode_index,
        )

