    def _skill_item_text(self, record: dict) -> str:
        name = sanitize_skill_name(record.get('name', ''), 'Skill')
        description = re.sub(r'\s+', ' ', str(record.get('description', '') or '')).strip()
        if len(description) > 140:
            description = description[:140].rstrip() + '...'
        status = 'enabled' if record.get('enabled', True) else 'disabled'
        return f'{name} · {status}' + (f'\n{description}' if description else '\nMissing description')

