    def _add_external_local_folder(self):
        chosen = QFileDialog.getExistingDirectory(self, 'Select external context folder', str(Path.home()))
        if not chosen:
            return
        self._append_external_context_source(
            {
                'id': _new_external_context_source_id('local'),
                'type': 'local_path',
                'name': os.path.basename(chosen.rstrip(os.sep)) or 'Local context',
                'path': chosen,
                'enabled': True,
                'auto_context': True,
                'include_patterns': DEFAULT_EXTERNAL_CONTEXT_INCLUDE_PATTERNS,
                'exclude_patterns': DEFAULT_EXTERNAL_CONTEXT_EXCLUDE_PATTERNS,
                'max_chars': normalize_external_context_max_chars(self.external_context_limit_input.text()),
                'use_embedding': True,
            }
        )

    def _add_external_local_file(self):
        path, _ = QFileDialog.getOpenFileName(self, 'Select external context file', str(Path.home()), 'Context files (*);;All files (*)')
        if not path:
            return
        self._append_external_context_source(
            {
                'id': _new_external_context_source_id('local'),
                'type': 'local_path',
                'name': os.path.basename(path),
                'path': path,
                'enabled': True,
                'auto_context': True,
                'include_patterns': DEFAULT_EXTERNAL_CONTEXT_INCLUDE_PATTERNS,
                'exclude_patterns': '',
                'max_chars': normalize_external_context_max_chars(self.external_context_limit_input.text()),
                'use_embedding': True,
            }
        )

    def _add_external_mcp_stdio(self):
        dialog = ExternalMcpStdioDialog(self)
        self._center_child_dialog(dialog)
        if dialog.exec() != QDialog.DialogCode.Accepted:
            return
        record = dialog.record()
        record['max_chars'] = normalize_external_context_max_chars(self.external_context_limit_input.text())
        self._append_external_context_source(record)

    def _add_external_mcp_http(self):
        dialog = ExternalMcpHttpDialog(self)
        self._center_child_dialog(dialog)
        if dialog.exec() != QDialog.DialogCode.Accepted:
            return
        record = dialog.record()
        record['max_chars'] = normalize_external_context_max_chars(self.external_context_limit_input.text())
        self._append_external_context_source(record)

    def _replace_external_context_item(self, item: QListWidgetItem, record: dict):
        row = self.external_context_list_widget.row(item)
        normalized = normalize_external_context_source_record(record, row + 1)
        if normalized is None:
            return
        normalized['enabled'] = item.checkState() == Qt.CheckState.Checked
        self._external_context_updating = True
        item.setData(Qt.ItemDataRole.UserRole, normalized)
        item.setText(self._external_context_item_text(normalized))
        self._external_context_updating = False
        self._mark_dirty_if_needed()

    def _edit_external_context_source(self):
        item = self.external_context_list_widget.currentItem()
        if item is None:
            return
        row = self.external_context_list_widget.row(item)
        record = normalize_external_context_source_record(item.data(Qt.ItemDataRole.UserRole), row + 1)
        if record is None:
            return
        if record.get('type') == 'mcp_http':
            dialog = ExternalMcpHttpDialog(self, record)
            self._center_child_dialog(dialog)
            if dialog.exec() != QDialog.DialogCode.Accepted:
                return
            updated = dialog.record()
            updated['max_chars'] = normalize_external_context_max_chars(self.external_context_limit_input.text())
            self._replace_external_context_item(item, updated)
            return
        if record.get('type') == 'mcp_stdio':
            dialog = ExternalMcpStdioDialog(self, record)
            self._center_child_dialog(dialog)
            if dialog.exec() != QDialog.DialogCode.Accepted:
                return
            updated = dialog.record()
            updated['max_chars'] = normalize_external_context_max_chars(self.external_context_limit_input.text())
            self._replace_external_context_item(item, updated)
            return
        name, ok = QInputDialog.getText(self, 'Edit local context source', 'Name:', text=record.get('name', 'Local context'))
        if not ok or not name.strip():
            return
        record['name'] = name.strip()
        self._replace_external_context_item(item, record)

    def _show_external_context_new_menu(self):
        menu = QMenu(self)
        folder_action = menu.addAction('Local folder')
        file_action = menu.addAction('Local file')
        menu.addSeparator()
        stdio_action = menu.addAction('MCP stdio server')
        http_action = menu.addAction('MCP HTTP endpoint')
        chosen = menu.exec(QCursor.pos())
        if chosen == folder_action:
            self._add_external_local_folder()
        elif chosen == file_action:
            self._add_external_local_file()
        elif chosen == stdio_action:
            self._add_external_mcp_stdio()
        elif chosen == http_action:
            self._add_external_mcp_http()

    def _delete_external_context_source(self):
        row = self.external_context_list_widget.currentRow()
        if row < 0:
            return
        self.external_context_list_widget.takeItem(row)
        if self.external_context_list_widget.count() > 0:
            self.external_context_list_widget.setCurrentRow(min(row, self.external_context_list_widget.count() - 1))
        else:
            self.external_context_delete_button.setEnabled(False)
            if hasattr(self, 'external_context_edit_button'):
                self.external_context_edit_button.setEnabled(False)
        self._mark_dirty_if_needed()

    def _code_runner_item_text(self, record: dict) -> str:
        language = normalize_code_runner_language(record.get('language', ''), 'runner')
        command = str(record.get('command', '') or '').strip()
        status = 'enabled' if record.get('enabled', True) else 'disabled'
        available = 'available' if command and _resolve_runner_command(command) else 'missing'
        return f'{language} · {status} · {available}\n{command or "No executable set"}'

