    def _on_code_runner_field_changed(self):
        if self._code_runner_updating:
            return
        row = self.code_runner_list_widget.currentRow()
        if not (0 <= row < len(self._code_runner_records)):
            return
        language = normalize_code_runner_language(self.code_runner_language_input.text(), f'runner{row + 1}')
        self._code_runner_records[row] = {
            'language': language,
            'command': self.code_runner_command_input.text().strip(),
            'args': self.code_runner_args_input.text().strip() or default_code_runner_args(language),
            'enabled': self._code_runner_records[row].get('enabled', True),
        }
        self._refresh_code_runner_item(row)
        self._mark_dirty_if_needed()

    def _add_code_runner_record(self):
        existing = {record.get('language', '') for record in self._code_runner_records}
        base = 'runner'
        index = len(self._code_runner_records) + 1
        language = f'{base}{index}'
        while language in existing:
            index += 1
            language = f'{base}{index}'
        record = {
            'language': language,
            'command': '',
            'args': '{code}',
            'enabled': True,
        }
        self._code_runner_records.append(record)
        previous = self._code_runner_updating
        self._code_runner_updating = True
        item = QListWidgetItem(self._code_runner_item_text(record))
        item.setFlags(item.flags() | Qt.ItemFlag.ItemIsUserCheckable | Qt.ItemFlag.ItemIsEnabled | Qt.ItemFlag.ItemIsSelectable)
        item.setCheckState(Qt.CheckState.Checked)
        self.code_runner_list_widget.addItem(item)
        self.code_runner_list_widget.setCurrentItem(item)
        self._code_runner_updating = previous
        self._load_code_runner_fields_for_row(self.code_runner_list_widget.currentRow())
        self._mark_dirty_if_needed()

    def _delete_code_runner_record(self):
        row = self.code_runner_list_widget.currentRow()
        if not (0 <= row < len(self._code_runner_records)):
            return
        del self._code_runner_records[row]
        self.code_runner_list_widget.takeItem(row)
        if self._code_runner_records:
            self.code_runner_list_widget.setCurrentRow(min(row, len(self._code_runner_records) - 1))
        self._load_code_runner_fields_for_row(self.code_runner_list_widget.currentRow())
        self._mark_dirty_if_needed()

    def _browse_code_runner_command(self):
        path, _ = QFileDialog.getOpenFileName(self, 'Select code runner executable', str(Path.home()), 'Executables (*);;All files (*)')
        if path:
            self.code_runner_command_input.setText(path)

    def _auto_detect_code_runner_command(self):
        language = normalize_code_runner_language(self.code_runner_language_input.text(), '')
        detected = auto_detect_code_runner_command(language)
        if detected:
            self.code_runner_command_input.setText(detected)
            if not self.code_runner_args_input.text().strip():
                self.code_runner_args_input.setText(default_code_runner_args(language))
        else:
            show_broccoli_message(self, 'Auto-detect', f'No executable was found for language: {language or "unknown"}')

    def _browse_webfetch_download_path(self):
        home_dir = str(Path.home())
        chosen = QFileDialog.getExistingDirectory(
            self,
            'Select browser download folder',
            self.webfetch_download_input.text().strip() or home_dir,
        )
        if chosen:
            self.webfetch_download_input.setText(chosen)
            self._mark_dirty_if_needed()

    def _choose_annotation_pen_color(self):
        current = QColor(self.annotation_pen_color_input.text().strip() or '#FF3B30')
        if not current.isValid():
            current = QColor('#FF3B30')
        color = QColorDialog.getColor(current, self, 'Annotation pen color')
        if color.isValid():
            self.annotation_pen_color_input.setText(color.name().upper())
            self._mark_dirty_if_needed()

    def _set_general_page(self, index: int):
        if not hasattr(self, 'general_pages'):
            return
        index = max(0, min(self.general_pages.count() - 1, int(index)))
        self.general_pages.setCurrentIndex(index)
        self._update_general_page_controls()

    def _update_general_page_controls(self):
        if not hasattr(self, 'general_pages'):
            return
        index = self.general_pages.currentIndex()
        count = max(1, self.general_pages.count())
        if hasattr(self, 'general_page_label'):
            self.general_page_label.setText(f'{index + 1} / {count}')
        if hasattr(self, 'general_prev_button'):
            self.general_prev_button.setEnabled(index > 0)
        if hasattr(self, 'general_next_button'):
            self.general_next_button.setEnabled(index < count - 1)

    def _set_prompt_page(self, index: int):
        if not hasattr(self, 'prompt_pages'):
            return
        index = max(0, min(self.prompt_pages.count() - 1, int(index)))
        self.prompt_pages.setCurrentIndex(index)
        self._update_prompt_page_controls()

    def _update_prompt_page_controls(self):
        if not hasattr(self, 'prompt_pages'):
            return
        index = self.prompt_pages.currentIndex()
        count = max(1, self.prompt_pages.count())
        if hasattr(self, 'prompt_page_label'):
            self.prompt_page_label.setText(f'{index + 1} / {count}')
        if hasattr(self, 'prompt_prev_button'):
            self.prompt_prev_button.setEnabled(index > 0)
        if hasattr(self, 'prompt_next_button'):
            self.prompt_next_button.setEnabled(index < count - 1)

