    def _bind_dirty_signals(self):
        widgets = [
            self.profile_name_input, self.endpoint_input, self.api_key_input,
            self.model_input,
            self.timeout_input, self.le_ui, self.le_same_position_screenshot, self.webfetch_download_input,
            self.display_history_limit_input,
            self.external_context_limit_input,
            self.code_execution_timeout_input,
            self.code_runner_language_input,
            self.code_runner_command_input,
            self.code_runner_args_input,
            self.background_vision_interval_input,
            self.background_vision_completion_delay_input,
            self.background_vision_toast_duration_input,
            self.background_vision_max_workers_input,
            self.background_vision_max_history_input,
            self.background_vision_capture_dir_input,
            self.background_vision_max_records_input,
        ]
        for widget in widgets:
            widget.textChanged.connect(self._mark_dirty_if_needed)
        for text_edit in (self.memory_text_edit, self.background_vision_prompt_edit):
            text_edit.textChanged.connect(self._mark_dirty_if_needed)
        self.language_list_widget.currentItemChanged.connect(self._mark_dirty_if_needed)
        self.language_list_widget.itemChanged.connect(self._mark_dirty_if_needed)
        self.profile_selector.currentIndexChanged.connect(self._mark_dirty_if_needed)
        self.embedding_profile_combo.currentIndexChanged.connect(self._mark_dirty_if_needed)
        self.router_profile_combo.currentIndexChanged.connect(self._mark_dirty_if_needed)
        for combo in self.specialized_profile_combos.values():
            combo.currentIndexChanged.connect(self._mark_dirty_if_needed)
        for combo in self.specialized_execution_combos.values():
            combo.currentIndexChanged.connect(self._mark_dirty_if_needed)
        self.pdf_pages_combo.currentIndexChanged.connect(self._mark_dirty_if_needed)
        self.memory_retention_combo.currentIndexChanged.connect(self._mark_dirty_if_needed)
        self.checkBox0.toggled.connect(self._mark_dirty_if_needed)
        self.checkBox2.toggled.connect(self._mark_dirty_if_needed)
        self.checkBox2.toggled.connect(self._update_history_context_controls)
        self.checkBox3.toggled.connect(self._mark_dirty_if_needed)
        self.checkBox_display_history.toggled.connect(self._mark_dirty_if_needed)
        self.allow_blank_prompt_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.allow_blank_prompt_checkbox.toggled.connect(self._update_blank_prompt_controls)
        self.skip_blank_retrieval_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.clear_attachments_after_send_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.checkBox_top.toggled.connect(self._mark_dirty_if_needed)
        self.start_on_login_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.terminal_shell_mode_combo.currentIndexChanged.connect(self._mark_dirty_if_needed)
        self.terminal_use_bash_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.web_auto_send_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.webfetch_context_embedding_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.generated_output_context_embedding_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.external_context_enabled_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.external_context_embedding_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.mcp_tool_runtime_checkbox.toggled.connect(self._mark_dirty_if_needed)
        self.code_execution_enabled_checkbox.toggled.connect(self._mark_dirty_if_needed)
