    def _snapshot_form_state(self):
        return {
            'globals': {
                'custom_prompt': serialize_custom_prompt_storage(self._prompt_records),
                'skills': serialize_skill_records(self._current_skill_records(), validate=False),
                'languages': self._current_languages(),
                'always_on_top': self.checkBox_top.isChecked(),
                'prefer_displayed_history_context': self.checkBox_display_history.isChecked(),
                'display_history_context_max_chars': normalize_display_history_context_max_chars(self.display_history_limit_input.text()),
                'allow_blank_prompt_with_attachments': self.allow_blank_prompt_checkbox.isChecked(),
                'skip_retrieval_for_blank_prompt': (
                    self.allow_blank_prompt_checkbox.isChecked()
                    and self.skip_blank_retrieval_checkbox.isChecked()
                ),
                'clear_attachments_after_send': self.clear_attachments_after_send_checkbox.isChecked(),
                'terminal_shell_mode': normalize_terminal_shell_mode(self.terminal_shell_mode_combo.currentData()),
                'terminal_use_bash': self.terminal_use_bash_checkbox.isChecked(),
                'web_auto_send_after_inject': self.web_auto_send_checkbox.isChecked(),
                'webfetch_context_use_embedding': self.webfetch_context_embedding_checkbox.isChecked(),
                'generated_output_context_use_embedding': self.generated_output_context_embedding_checkbox.isChecked(),
                'external_context_enabled': self.external_context_enabled_checkbox.isChecked(),
                'external_context_use_embedding': self.external_context_embedding_checkbox.isChecked(),
                'mcp_tool_runtime_enabled': self.mcp_tool_runtime_checkbox.isChecked(),
                'external_context_max_chars': normalize_external_context_max_chars(self.external_context_limit_input.text()),
                'external_context_sources': self._current_external_context_sources(),
                'code_execution_enabled': self.code_execution_enabled_checkbox.isChecked(),
                'code_execution_timeout': normalize_code_execution_timeout(self.code_execution_timeout_input.text()),
                'code_runners': normalize_code_runner_records(self._current_code_runner_records()),
                'annotation_pen_color': self.annotation_pen_color_input.text().strip() or '#FF3B30',
                'webfetch_download_path': self.webfetch_download_input.text().strip(),
                'memory_text': self.memory_text_edit.toPlainText(),
                'memory_items': self._current_memory_items(),
                'memory_retention_days': self.memory_retention_combo.currentData(),
                'ui_shortcut': self.le_ui.text().strip(),
                'same_position_screenshot_shortcut': self.le_same_position_screenshot.text().strip(),
                'pdf_max_pages': self.pdf_pages_combo.currentData(),
                'embedding_profile': self.embedding_profile_combo.currentData(),
                'specialized_profiles': normalize_specialized_profiles(
                    {
                        'router': self.router_profile_combo.currentData(),
                        **{
                            capability: combo.currentData()
                            for capability, combo in self.specialized_profile_combos.items()
                        },
                    }
                ),
                'specialized_execution_modes': normalize_specialized_execution_modes(
                    {
                        capability: combo.currentData()
                        for capability, combo in self.specialized_execution_combos.items()
                    }
                ),
                'userscripts': self._current_userscripts(),
                **self._current_background_vision_settings(),
            },
            'profile': {
                'profile_name': self.profile_name_input.text().strip(),
                'selected_profile': self.profile_selector.currentData(),
                'endpoint': self.endpoint_input.text().strip(),
                'append_v1': self.endpoint_v1_checkbox.isChecked(),
                'api_key': self.api_key_input.text().strip(),
                'model': self.model_input.text().strip(),
                'timeout': self.timeout_input.text().strip(),
                'show_references': self.checkBox0.isChecked(),
                'remember_history': self.checkBox2.isChecked(),
                'remember_memory': self.checkBox3.isChecked(),
            },
        }

    def _capture_baseline(self):
        self._baseline_snapshot = self._snapshot_form_state()
        self._set_dirty(False)

    def _apply_save_button_style(self):
        if not hasattr(self, 'save_button'):
            return
        if self._dirty:
            self.save_button.setStyleSheet('''
                QPushButton{
                border: 1px solid transparent;
                background-color: #D92D20;
                border-radius: 15px;
                padding: 5px 20px;
                color: #FFFFFF
                }
                QPushButton:hover{
                background-color: #E5483B;
                }
                QPushButton:pressed{
                background-color: #B42318;
                border-radius: 15px;
                padding: 5px 20px;
                color: #FFFFFF
                }
                QPushButton:disabled{
                background-color: #E6E6E6;
                color: #777777;
                }
                ''')
        else:
            if hasattr(self.save_button, 'apply_default_style'):
                self.save_button.apply_default_style()
            else:
                self.save_button.setStyleSheet('')

    def _set_dirty(self, dirty: bool):
        self._dirty = bool(dirty)
        self._apply_save_button_style()

    def _mark_dirty_if_needed(self):
        if self._updating_form or self._baseline_snapshot is None:
            return
        self._set_dirty(self._snapshot_form_state() != self._baseline_snapshot)

    def reload_from_store(self):
        self.settings_store = load_settings_store()
        active_name = self.settings_store.get('active_profile', self.settings_store['profiles'][0]['name'])
        self.refresh_profile_selector(active_name)
        self.load_global_fields()
        self.load_profile_into_form(active_name)
        self.reset_record_buttons()
        self._capture_baseline()

    def SaveAPI(self):
        try:
            self.persist_current_settings()
        except ValueError as exc:
            show_broccoli_message(self, 'Invalid settings', str(exc))
            return
        self.userscripts_changed.emit()
        self.close_requested.emit()

    def recordui(self):
        if self.hotkey_manager is not None and self.hotkey_manager.record_target == 'ui':
            self.hotkey_manager.cancel_recording()
            self.reset_record_buttons()
            return
        self.begin_shortcut_recording('ui')

    def record_same_position_screenshot(self):
        target = 'same_position_screenshot'
        if self.hotkey_manager is not None and self.hotkey_manager.record_target == target:
            self.hotkey_manager.cancel_recording()
            self.reset_record_buttons()
            return
        self.begin_shortcut_recording(target)

    def on_embedding_profile_changed(self):
        self._update_embedding_status_hint()
        self._mark_dirty_if_needed()

    def test_embedding_capability(self):
        profile_name = str(self.embedding_profile_combo.currentData() or '').strip()
        if not profile_name:
            self._update_embedding_status_hint('No embedding profile selected. Retrieval will fall back to keywords.')
            return
        profile = self.get_profile_by_name(profile_name)
        ok, message = probe_embedding_capability(profile, force=True)
        self._update_embedding_status_hint(message)
        if ok:
            show_broccoli_message(self, 'Embedding test', message)
        else:
            show_broccoli_message(self, 'Embedding test', message)

    def keyPressEvent(self, e):  # 当页面显示的时候，按下esc键可关闭窗口
        if e.key() == Qt.Key.Key_Escape.value:
            if self.hotkey_manager is not None:
                self.hotkey_manager.cancel_recording()
            self.reset_record_buttons()
            self.close_requested.emit()
            return
        super().keyPressEvent(e)


