def _apply_window_palette(window, dark_mode):
    if window is None:
        return
    palette = window.palette()
    palette.setColor(window.backgroundRole(), QColor('#2D2D2D' if dark_mode else '#ECECEC'))
    window.setPalette(palette)


def apply_theme(app_obj):
    dark_mode = is_dark_theme(app_obj)
    if dark_mode:
        set_dark_palette(app_obj)
        app_obj.setStyleSheet(style_sheet_dark)
    else:
        set_light_palette(app_obj)
        app_obj.setStyleSheet(style_sheet_ori)

    target = globals().get('w3')
    if target is not None:
        _apply_window_palette(target, dark_mode)
        try:
            target.apply_theme(dark_mode)
        except Exception:
            pass

    _apply_mac_button_theme()
    for widget in app_obj.topLevelWidgets():
        try:
            widget.update()
        except Exception:
            pass


theme_observer = install_theme_observer(app)


